window.HADITH_CACHE["nasai_9"] = {"4501":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا ابْنُ جُدْعَانَ سَمِعَهُ مِنْ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ ابْنِ عُمَرَ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ عَلَى دَرَجَةِ الْكَعْبَةِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَقَالَ الْحَمْدُ لِلَّهِ الَّذِي صَدَقَ وَعْدَهُ وَنَصَرَ عَبْدَهُ وَهَزَمَ الْأَحْزَابَ وَحْدَهُ أَلَا إِنَّ قَتِيلَ الْعَمْدِ الْخَطَإِ بِالسَّوْطِ وَالْعَصَا شِبْهِ الْعَمْدِ فِيهِ مِائَةٌ مِنْ الْإِبِلِ مُغَلَّظَةٌ مِنْهَا أَرْبَعُونَ خَلِفَةً فِي بُطُونِهَا أَوْلَادُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Ibnu Jud'an], dia mendengarnya dari [Al Qasim bin Rabi'ah] dari [Ibnu Umar], dia berkata; \"Pada hari penaklukan Mekkah, Rasulullah shallallahu 'alaihi wasallam berdiri di depan Ka'bah, lalu beliau bertahmid kepada Allah dan memujiNya, beliau bersabda: \"Segala puji bagi Allah yang telah memenuhi janjiNya, menolong hambaNya menghancurkan pasukan sekutu sendirian, ketahuilah, bahwa orang yang terbunuh karena tidak sengaja dengan cambuk dan tongkat adalah menyerupai orang yang terbunuh karena disiksa. Padanya terdapat diyat seratus ekor unta yang ditekankan, empat puluh ekor unta diantaranya sedang bunting.\""},"4502":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا سَهْلُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ الْقَاسِمِ بْنِ رَبِيعَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَطَأُ شِبْهُ الْعَمْدِ يَعْنِي بِالْعَصَا وَالسَّوْطِ مِائَةٌ مِنْ الْإِبِلِ مِنْهَا أَرْبَعُونَ فِي بُطُونِهَا أَوْلَادُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Sahl bin Yusuf] telah menceritakan kepada kami [Humaid] dari [Al Qasim bin Rabi'ah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Terbunuh) karena ketidak sengajaan yang menyerupai terbunuh karena disiksa dengan tongkat dan cambuk, diyatnya adalah seratus ekor unta, di antaranya terdapat empat puluh ekor yang sedang bunting.\""},"4503":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ رَاشِدٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قُتِلَ خَطَأً فَدِيَتُهُ مِائَةٌ مِنْ الْإِبِلِ ثَلَاثُونَ بِنْتَ مَخَاضٍ وَثَلَاثُونَ بِنْتَ لَبُونٍ وَثَلَاثُونَ حِقَّةً وَعَشَرَةُ بَنِي لَبُونٍ ذُكُورٍ قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَوِّمُهَا عَلَى أَهْلِ الْقُرَى أَرْبَعَ مِائَةِ دِينَارٍ أَوْ عِدْلَهَا مِنْ الْوَرِقِ وَيُقَوِّمُهَا عَلَى أَهْلِ الْإِبِلِ إِذَا غَلَتْ رَفَعَ فِي قِيمَتِهَا وَإِذَا هَانَتْ نَقَصَ مِنْ قِيمَتِهَا عَلَى نَحْوِ الزَّمَانِ مَا كَانَ فَبَلَغَ قِيمَتُهَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَيْنَ الْأَرْبَعِ مِائَةِ دِينَارٍ إِلَى ثَمَانِ مِائَةِ دِينَارٍ أَوْ عِدْلِهَا مِنْ الْوَرِقِ قَالَ وَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ مَنْ كَانَ عَقْلُهُ فِي الْبَقَرِ عَلَى أَهْلِ الْبَقَرِ مِائَتَيْ بَقَرَةٍ وَمَنْ كَانَ عَقْلُهُ فِي الشَّاةِ أَلْفَيْ شَاةٍ وَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْعَقْلَ مِيرَاثٌ بَيْنَ وَرَثَةِ الْقَتِيلِ عَلَى فَرَائِضِهِمْ فَمَا فَضَلَ فَلِلْعَصَبَةِ وَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَعْقِلَ عَلَى الْمَرْأَةِ عَصَبَتُهَا مَنْ كَانُوا وَلَا يَرِثُونَ مِنْهُ شَيْئًا إِلَّا مَا فَضَلَ عَنْ وَرَثَتِهَا وَإِنْ قُتِلَتْ فَعَقْلُهَا بَيْنَ وَرَثَتِهَا وَهُمْ يَقْتُلُونَ قَاتِلَهَا","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Muhammad bin Rasyid] dari [Sulaiman bin Musa] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang terbunuh karena kesalahan maka diyatnya adalah seratus ekor unta, tiga puluh unta yang berumur dua tahun, tiga puluh unta betina yang berusia tiga tahun, tiga puluh unta yang berusia empat tahun, dan sepuluh unta jantan yang berumur tiga tahun.\" Dia berkata; \"Rasulullah shallallahu 'alaihi wasallam menaksir harganya untuk penduduk kota, empat ratus dinar atau yang setara dengannya dari uang perak. Sedang untuk para pemilik unta apabila harganya naik maka beliau menaikkan harganya dan apabila turun maka beliau menurunkan harganya sesuai dengan zamannya yang berlaku (pasarannya). Pada zaman Rasulullah shallallahu 'alaihi wasallam, nilai diyatnya mencapai antara empat ratus dinar hingga delapan ratus dinar atau yang setara dengannya dari uang perak.\" Dia berkata lagi; \"Rasulullah shallallahu 'alaihi wasallam menetapkan bahwa orang yang diyatnya dengan sapi, maka atas pemilik sapi diyatnya adalah dua ratus ekor sapi. Dan barang siapa yang diyatnya dengan kambing maka diyatnya adalah seribu kambing. Dan Rasulullah shallallahu 'alaihi wasallam telah memutuskan bahwa diyat adalah warisan antar ahli waris orang yang terbunuh sesuai dengan faraidhnya. Sedangkan kelebihannya adalah untuk 'ashabah (kerabat dari pihak ayah).\"Rasulullah shallallahu 'alaihi wasallam menetapkan atas seorang wanita, hendaknya salah seorang dari 'ashabahnya membayarkan diyatnya dan mereka tidak mewarisi darinya sesuatupun kecuali yang tersisa dari para pewaris wanita tersebut. Dan apabila wanita tersebut dibunuh maka diyatnya dibagi diantara para pewarisnya, dan mereka boleh membunuh orang yang membunuh wanita tersebut.\""},"4504":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ سَعِيدِ بْنِ مَسْرُوقٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ حَجَّاجٍ عَنْ زَيْدِ بْنِ جُبَيْرٍ عَنْ خِشْفِ بْنِ مَالِكٍ قَالَ سَمِعْتُ ابْنَ مَسْعُودٍ يَقُولُقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِيَةَ الْخَطَإِ عِشْرِينَ بِنْتَ مَخَاضٍ وَعِشْرِينَ ابْنَ مَخَاضٍ ذُكُورًا وَعِشْرِينَ بِنْتَ لَبُونٍ وَعِشْرِينَ جَذَعَةً وَعِشْرِينَ حِقَّةً","id":"Telah mengabarkan kepada kami [Ali bin Sa'id bin Masruq] telah menceritakan kepada kami [Yahya bin Zakariya bin Abu Zaidah] dari [Hajjaj] dari [Zaid bin Jubair] dari [Khisyf bin Malik], dia berkata; \"Saya mendengar [Ibnu Mas'ud] berkata; \"Rasulullah shallallahu 'alaihi wasallam memutuskan diyat membunuh karena tidak sengaja dua puluh unta betina yang berumur dua tahun dan dua puluh unta jantan yang berumur dua tahun, dua puluh unta betina yang berumur tiga tahun dan dua puluh unta betina yang berumur lima tahun dan dua puluh unta betina yang berumur empat tahun.\""},"4505":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ مُعَاذِ بْنِ هَانِئٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ ح و أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هَانِئٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَتَلَ رَجُلٌ رَجُلًا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِيَتَهُ اثْنَيْ عَشَرَ أَلْفًا وَذَكَرَ قَوْلَهُ{ إِلَّا أَنْ أَغْنَاهُمْ اللَّهُ وَرَسُولُهُ مِنْ فَضْلِهِ }فِي أَخْذِهِمْ الدِّيَةَوَاللَّفْظُ لِأَبِي دَاوُدَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Mu'adz bin Hani`] telah menceritakan kepadaku [Muhammad bin Muslim] telah menceritakan kepada kami ['Amru bin Dinar]. Dalam jalur lain disebutkan: Telah mengabarkan kepada kami [Abu Daud] telah menceritakan kepada kami [Mu'adz bin Hani`] telah menceritakan kepada kami [Muhammad bin Muslim] dari ['Amru bin Dinar] dari [Ikrimah] dari [Ibnu Abbas], dia berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam ada seseorang yang membunuh seorang laki-laki. Lalu Nabi shallallahu 'alaihi wasallam menjadikan diyatnya dua belas ribu, seraya menyebut firmanNya: (kecuali jika Allah dan rasulNya mencukupkan dari keutamaanNya) pada pengambilan diyat mereka.\" lafadz ini milik Abu Dawud."},"4506":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَيْمُونٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ عِكْرِمَةَ سَمِعْنَاهُ مَرَّةً يَقُولُ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِاثْنَيْ عَشَرَ أَلْفًا يَعْنِي فِي الدِّيَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Maimun] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Ikrimah], suatu kali kami mendengarnya berkata; dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam telah memutuskan dengan dua belas ribu dalam masalah diyat.\""},"4507":{"ar":"أَخْبَرَنَا عِيسَى بْنُ يُونُسَ قَالَ حَدَّثَنَا ضَمْرَةُ عَنْ إِسْمَعِيلَ بْنِ عَيَّاشٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَقْلُ الْمَرْأَةِ مِثْلُ عَقْلِ الرَّجُلِ حَتَّى يَبْلُغَ الثُّلُثَ مِنْ دِيَتِهَا","id":"Telah mengabarkan kepada kami [Isa bin Yunus] telah menceritakan kepada kami [Dhamrah] dari [Isma'il bin 'Ayyasy] dari [Ibnu Juraij] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Diyat seorang wanita seperti diyat seorang laki-laki hingga mencapai sepertiga dari diyatnya.\""},"4508":{"ar":"أَخْبَرَنَا عُمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ مُحَمَّدِ بْنِ رَاشِدٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى وَذَكَرَ كَلِمَةً مَعْنَاهَا عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَقْلُ أَهْلِ الذِّمَّةِ نِصْفُ عَقْلِ الْمُسْلِمِينَ وَهُمْ الْيَهُودُ وَالنَّصَارَى","id":"Telah mengabarkan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Abdur Rahman] dari [Muhammad bin Rasyid] dari [Sulaiman bin Musa] dan dia menyebutkan sebuah kalimat yang maknanya dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Diyat ahli dzimmah adalah setengah diyat orang muslim, mereka (ahlu dzimmah) adalah Yahudi dan Nasrani. "},"4509":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي أُسَامَةُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَقْلُ الْكَافِرِ نِصْفُ عَقْلِ الْمُؤْمِنِ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amru bin As Sarh] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Usamah bin Zaid] dari ['Amru bin Syu'aib] dari [ayahnya] dari [Abdullah bin 'Amru] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Diyat orang kafir adalah setengah diyat orang muslim.\""},"4510":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمُكَاتَبِ يُقْتَلُ بِدِيَةِ الْحُرِّ عَلَى قَدْرِ مَا أَدَّى","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Ali bin Al Mubarak] dari [Yahya] dari [Ikrimah] dari [Ibnu Abbas], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memutuskan bahwa diyat bagi budak mukatab (budak yang mengadakan perjanjian pembebasan dirinya dengan tuannya) apabila dibunuh adalah (seperti) diyat orang yang merdeka sesuai dengan kadar yang telah ia ditunaikan. "},"4511":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ عَبْدِ الرَّحْمَنِ الطَّائِفِيُّ قَالَ حَدَّثَنَا مُعَاوِيَةُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي الْمُكَاتَبِ أَنْ يُودَى بِقَدْرِ مَا عَتَقَ مِنْهُ دِيَةَ الْحُرِّ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ubaidullah bin Yazid] telah menceritakan kepada kami [Utsman bin Abdur Rahman Ath Thaifi] telah menceritakan kepada kami [Mu'awiyah] dari [Yahya bin Abu Katsir] dari [Ikrimah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam memutuskan diyat bagi budak mukatab adalah (seperti) diyat orang yang merdeka sesuai dengan kadar (harga) kebebasannya. "},"4512":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَعْلَى عَنْ الْحَجَّاجِ الصَّوَّافِ عَنْ يَحْيَى عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمُكَاتَبِ يُودَى بِقَدْرِ مَا أَدَّى مِنْ مُكَاتَبَتِهِ دِيَةَ الْحُرِّ وَمَا بَقِيَ دِيَةَ الْعَبْدِ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il bin Ibrahim] telah menceritakan kepada kami [Ya'la] dari [Al Hajjaj As Shawwaf] dari [Yahya] dari [Ikrimah] dari [Ibnu Abbas], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memutuskan bagi budak mukatab untuk diberi diyat orang yang merdeka sesuai dengan kadar kebebasannya.\""},"4513":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى بْنِ النَّقَّاشِ قَالَ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ هَارُونَ قَالَ أَنْبَأَنَا حَمَّادٌ عَنْ قَتَادَةَ عَنْ خِلَاسٍ عَنْ عَلِيٍّ وَعَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُكَاتَبُ يَعْتِقُ بِقَدْرِ مَا أَدَّى وَيُقَامُ عَلَيْهِ الْحَدُّ بِقَدْرِ مَا عَتَقَ مِنْهُ وَيَرِثُ بِقَدْرِ مَا عَتَقَ مِنْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa bin An Naqqasy] telah menceritakan kepada kami [Yazid yaitu Ibnu Harun] telah menceritakan kepada kami [Hammad] dari [Qatadah] dari [Khilas] dari [Ali] dan dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang mukatab bebas sesuai dengan apa yang telah ia tunaikan dan diterapkan hukuman atasnya sesuai dengan kadar kebebasannya dan mewarisi sesuai dengan kadar kebebasannya.\""},"4514":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عَمْرٍو الْأَشْعَثِيُّ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ وَعَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ مُكَاتَبًا قُتِلَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ أَنْ يُودَى مَا أَدَّى دِيَةَ الْحُرِّ وَمَالًا دِيَةَ الْمَمْلُوكِ","id":"Telah menceritakan kepada kami [Al Qasim bin Zakariya bin Dinar] telah menceritakan kepada kami [Sa'id bin 'Amru Al Asy'atsi] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Ikrimah] dan dari [Yahya bin Abu Katsir] dari [Ikrimah] dari [Ibnu Abbas] bahwa terdapat orang mukatab yang terbunuh pada masa Rasulullah shallallahu 'alaihi wasallam lalu beliau memerintahkan agar diberi diyat orang yang merdeka sesuai dengan apa yang telah ia tunaikan dan harta sebagai diyat seorang budak. "},"4515":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ وَإِبْرَاهِيمُ بْنُ يُونُسَ بْنِ مُحَمَّدٍ قَالَا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ حَدَّثَنَا يُوسُفُ بْنُ صُهَيْبٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ امْرَأَةً حَذَفَتْ امْرَأَةً فَأَسْقَطَتْ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَلَدِهَا خَمْسِينَ شَاةً وَنَهَى يَوْمَئِذٍ عَنْ الْخَذْفِأَرْسَلَهُ أَبُو نَعِيمٍ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dan [Ibrahim bin Yunus bin Muhammad], mereka berkata; telah menceritakan kepada kami ['Ubaidullah bin Musa] telah menceritakan kepada kami [Yusuf bin Shuhaib] dari [Abdullah bin Buraidah] dari [ayahnya] bahwa seorang wanita memukul wanita lain hingga mengalami keguguran, lalu Rasulullah shallallahu 'alaihi wasallam menetapkan (diyat) untuk anaknya dengan limapuluh ekor kambing, dan pada hari itu beliau melarang bermain ketapel. Hadits ini dimursalkan oleh Abu Na'im."},"4516":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ يَحْيَى قَالَ حَدَّثَنَا أَبُو نَعِيمٍ قَالَ حَدَّثَنَا يُوسُفُ بْنُ صُهَيْبٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَأَنَّ امْرَأَةً خَذَفَتْ امْرَأَةً فَأَسْقَطَتْ الْمَخْذُوفَةُ فَرُفِعَ ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ عَقْلَ وَلَدِهَا خَمْسَ مِائَةٍ مِنْ الْغُرِّ وَنَهَى يَوْمَئِذٍ عَنْ الْخَذْفِقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا وَهْمٌ وَيَنْبَغِي أَنْ يَكُونَ أَرَادَ مِائَةً مِنْ الْغُرِّ وَقَدْ رُوِيَ النَّهْيُ عَنْ الْخَذْفِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Yahya] telah menceritakan kepada kami [Abu Na'im] telah menceritakan kepada kami [Yusuf bin Shuhaib] telah menceritakan kepadaku [Abdullah bin Buraidah] bahwa seorang wanita melempar wanita lain menggunakan ketapel sehigga ia keguguran karena terkena ketapel tersebut kemudian hal tersebut diangkat kepada Nabi shallallahu 'alaihi wasallam lalu beliau menjadikan diyat anaknya lima ratus budak, dan beliau melarang dari bermain ketapel. Abu Abdur Rahman berkata; hal ini adalah suatu kesalahan selayaknya yang beliau inginkan adalah seratus budak. Dan telah diriwayatkan larangan dari bermain ketapel dari Abdullah bin Buraidah dari Abdullah bin Mughaffal. "},"4517":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَنْبَأَنَا كَهْمَسٌ عَنْ عَبْدِ اللَّه�� بْنِ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍأَنَّهُ رَأَى رَجُلًا يَخْذِفُ فَقَالَ لَا تَخْذِفْ فَإِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْهَى عَنْ الْخَذْفِ أَوْ يَكْرَهُ الْخَذْفَ شَكَّ كَهْمَسٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] telah menceritakan kepada kami [Yazid] telah mengabarkan kepada kami [Kahmas] dari [Abdullah bin Buraidah] dari [Abdullah bin Mughaffal] bahwa dia melihat seorang laki-laki yang bermain ketapel kemudian dia berkata; \"Janganlah bermain ketapel sesungguhnya Nabi shallallahu 'alaihi wasallam melarang dari bermain ketapel atau tidak suka bermain ketapel.\" Kahmas merasa ragu. "},"4518":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ عَمْرٍو عَنْ طَاوُسٍأَنَّ عُمَرَ اسْتَشَارَ النَّاسَ فِي الْجَنِينِ فَقَالَ حَمَلُ بْنُ مَالِكٍ قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْجَنِينِ غُرَّةًقَالَ طَاوُسٌ إِنَّ الْفَرَسَ غُرَّةٌ","id":"Telah mengabarkan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad] dari ['Amru] dari [Thawus] bahwa Umar meminta pendapat orang-orang mengenai janin, lalu [Hamal bin Malik] berkata; \"Rasulullah shallallahu 'alaihi wasallam telah memutuskan (diyat) untuk seorang janin adalah ghurrah (seorang budak).\" Thawus berkata; \"Sesungguhnya kuda terasuk ghurrah.\""},"4519":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَنِينِ امْرَأَةٍ مِنْ بَنِي لِحْيَانَ سَقَطَ مَيِّتًا بِغُرَّةِ عَبْدٍ أَوْ أَمَةٍ ثُمَّ إِنَّ الْمَرْأَةَ الَّتِي قَضَى عَلَيْهَا بِالْغُرَّةِ تُوُفِّيَتْ فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَنَّ مِيرَاثَهَا لِبَنِيهَا وَزَوْجِهَا وَأَنَّ الْعَقْلَ عَلَى عَصَبَتِهَا","id":"Telah mengabarkan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Ibnu Al Musayyab] dari [Abu Hurairah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memutuskan (diyat) untuk janin seorang wanita dari Bani Lihyan yang gugur dan mati dengan ghurrah yaitu budak laki-laki atau wanita. Kemudian wanita yang diputuskan membayar ghurrah tersebut meninggal maka beliau memutuskan bahwa warisannya adalah untuk anak-anaknya dan suaminya, sedangkan diyat menjadi tanggungan ashabahnya.\""},"4520":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ وَسَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَاقْتَتَلَتْ امْرَأَتَانِ مِنْ هُذَيْلٍ فَرَمَتْ إِحْدَاهُمَا الْأُخْرَى بِحَجَرٍ وَذَكَرَ كَلِمَةً مَعْنَاهَا فَقَتَلَتْهَا وَمَا فِي بَطْنِهَا فَاخْتَصَمُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ دِيَةَ جَنِينِهَا غُرَّةٌ عَبْدٌ أَوْ وَلِيدَةٌ وَقَضَى بِدِيَةِ الْمَرْأَةِ عَلَى عَاقِلَتِهَا وَوَرَّثَهَا وَلَدَهَا وَمَنْ مَعَهُمْ فَقَالَ حَمَلُ بْنُ مَالِكِ بْنِ النَّابِغَةِ الْهُذَلِيُّ يَا رَسُولَ اللَّهِ كَيْفَ أُغَرَّمُ مَنْ لَا شَرِبَ وَلَا أَكَلْ وَلَا نَطَقَ وَلَا اسْتَهَلَّ فَمِثْلُ ذَلِكَ يُطَلَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا هَذَا مِنْ إِخْوَانِ الْكُهَّانِ مِنْ أَجْلِ سَجْعِهِ الَّذِي سَجَعَ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amru bin As Sarh] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Abu Salamah] dan [Sa'id bin Al Musayyab] dari [Abu Hurairah] bahwa dia berkata; \"Dua orang wanita dari Hudzail berkelahi, kemudian salah seorang dari mereka melempar dengan batu. Dan ia menyebutkan suatu kalimat yang maknanya adalah; dia membunuhnya beserta kandungannya. Kemudian mereka (membawa) permasalahan tersebut kepada Rasulullah shallallahu 'alaihi wasallam kemudian Rasulullah shallallahu 'alaihi wasallam memutuskan bahwa diyat janinnya adalah ghurrah yaitu budak laki-laki atau perempuan. Dan beliau memutuskan diyat seorang wanita menjadi tanggungan ashabahnya dan orang yang bersama mereka. Dan beliau menjadikan anaknya sebagai pewarisnya. Hamal bin Malik bin An Nabighah Al Hudzali berkata; \"Wahai Rasulullah, bagaimana saya menanggung denda orang yang tidak makan dan minum, tidak berbicara serta menangis? (bukankah) yang seperti ini (termasuk) sesuatu yang dibatalkan?\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya (bayi) ini termasuk di antara saudara dukun karena kalimat sajak yang ia ucapkan.\""},"4521":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ امْرَأَتَيْنِ مِنْ هُذَيْلٍ فِي زَمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَمَتْ إِحْدَاهُمَا الْأُخْرَى فَطَرَحَتْ جَنِينَهَا فَقَضَى فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِغُرَّةٍ عَبْدٍ أَوْ وَلِيدَةٍ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amru bin As Sarh] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Malik] dari [Ibnu Syihab] dari [Abu Salamah bin Abdur Rahman] dari [Abu Hurairah] bahwa pada zaman Rasulullah shallallahu 'alaihi wasallam ada dua orang wanita dari Hudzail yang salah seorang di antaranya melempar yang lainnya hingga janinnya gugur, kemudian Rasulullah shallallahu 'alaihi wasallam memutuskan untuk membayar denda berupa budak laki-laki atau perempuan. "},"4522":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي الْجَنِينِ يُقْتَلُ فِي بَطْنِ أُمِّهِ بِغُرَّةٍ عَبْدٍ أَوْ وَلِيدَةٍ فَقَالَ الَّذِي قَضَى عَلَيْهِ كَيْفَ أُغَرَّمُ مَنْ لَا شَرِبَ وَلَا أَكَلْ وَلَا اسْتَهَلَّ وَلَا نَطَقَ فَمِثْلُ ذَلِكَ يُطَلَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا هَذَا مِنْ الْكُهَّانِ","id":"Telah berkata [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar dari [Ibnu Al Qasim] telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] bahwa Rasulullah shallallahu 'alaihi wasallam memutuskan diyat dalam perkara janin yang terbunuh di dalam perut ibunya berupa seorang budak laki-laki atau perempuan. Kemudian orang yang diputuskan untuk membayar denda berkata; \"Bagaimana saya menanggung denda orang yang tidak minum, tidak makan dan tidak menangis serta tidak berbicara? (bukankah) yang seperti itu termasuk sesuatu yang dibatalkan?\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya (janin) ini termasuk dukun.\""},"4523":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ مُحَمَّدِ بْنِ عَلِيٍّ قَالَ حَدَّثَنَا خَلَفٌ وَهُوَ ابْنُ تَمِيمٍ قَالَ حَدَّثَنَا زَائِدَةُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عُبَيْدِ بْنِ نُضَيْلَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَأَنَّ امْرَأَةً ضَرَبَتْ ضَرَّتَهَا بِعَمُودِ فُسْطَاطٍ فَقَتَلَتْهَا وَهِيَ حُبْلَى فَأُتِيَ فِيهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عَصَبَةِ الْقَاتِلَةِ بِالدِّيَةِ وَفِي الْجَنِينِ غُرَّةً فَقَالَ عَصَبَتُهَا أَدِي مَنْ لَا طَعِمَ وَلَا شَرِبَ وَلَا صَاحَ فَاسْتَهَلَّ فَمِثْلُ هَذَا يُطَلَّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسَجْعٌ كَسَجْعِ الْأَعْرَابِ","id":"Telah mengabarkan kepada kami [Ali bin Muhammad bin Ali] telah menceritakan kepada kami [Khalaf yaitu Ibnu Tamim] telah menceritakan kepada kami [Zaidah] dari [Manshur] dari [Ibrahim] dari ['Ubaid bin Nudhailah] dari [Al Mughirah bin Syu'bah] bahwa seorang wanita memukul madunya dengan tiang tenda sehingga ia membunuhnya padahal madunya tersebut tengah hamil. Kemudian permasalahan tersebut dihadapkan kepada Nabi shallallahu 'alaihi wasallam kemudian Rasulullah shallallahu 'alaihi wasallam memutuskan kepada 'ashabah wanita yang membunuh agar membayar diyat, sedang diyat untuk janin berupa seorang budak. Kemudian 'ashabah wanita tersebut mengatakan; \"Apakah saya menanggung denda orang yang tidak makan, tidak minum dan tidak berteriak serta menangis? Maka yang seperti ini (seharusnya) dibatalkan. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah ini sajak seperti sajaknya orang-orang badui?\""},"4524":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عُبَيْدِ بْنِ نُضَيْلَةَ الْخُزَاعِيِّ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَضَرَبَتْ امْرَأَةٌ ضَرَّتَهَا بِعَمُودِ الْفُسْطَاطِ وَهِيَ حُبْلَى فَقَتَلَتْهَا فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِيَةَ الْمَقْتُولَةِ عَلَى عَصَبَةِ الْقَاتِلَةِ وَغُرَّةً لِمَا فِي بَطْنِهَا فَقَالَ رَجُلٌ مِنْ عَصَبَةِ الْقَاتِلَةِ أَنَغْرَمُ دِيَةَ مَنْ لَا أَكَلْ وَلَا شَرِبَ وَلَا اسْتَهَلَّ فَمِثْلُ ذَلِكَ يُطَلَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسَجْعٌ كَسَجْعِ الْأَعْرَابِ فَجَعَلَ عَلَيْهِمْ الدِّيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Qudamah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari ['Ubaid bin Nudhailah Al Khuza'I] dari [Al Mughirah bin Syu'bah], dia berkata; seorang wanita memukul madunya yang sedang hamil dengan tiang tenda hingga dia membunuhnya. Kemudian Rasulullah shallallahu 'alaihi wasallam menjadikan diyat wanita yang dibunuh ditanggung oleh 'ashabah wanita yang membunuh dan denda berupa seorang budak untuk janin yang ada dalam perutnya. Kemudian seorang laki-laki dari 'ashabah wanita yang membunuh berkata; \"Apakah kami menanggung denda orang yang tidak makan, tidak minum dan tidak menangis? Hal seperti itu adalah sesuatu yang dibatalkan.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah ini sajak seperti sajak orang-orang badui?\" Kemudian beliau menjadikan mereka menanggung diyat. "},"4525":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عُبَيْدِ بْنِ نُضَيْلَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَأَنَّ ضَرَّتَيْنِ ضَرَبَتْ إِحْدَاهُمَا الْأُخْرَى بِعَمُودِ فُسْطَاطٍ فَقَتَلَتْهَا فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالدِّيَةِ عَلَى عَصَبَةِ الْقَاتِلَةِ وَقَضَى لِمَا فِي بَطْنِهَا بِغُرَّةٍ فَقَالَ الْأَعْرَابِيُّ تُغَرِّمُنِي مَنْ لَا أَكَلْ وَلَا شَرِبَ وَلَا صَاحَ فَاسْتَهَلَّ فَمِثْلُ ذَلِكَ يُطَلَّ فَقَالَ سَجْعٌ كَسَجْعِ الْجَاهِلِيَّةِ وَقَضَى لِمَا فِي بَطْنِهَا بِغُرَّةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysysar] telah menceritakan kepada kami [Abdur Rahman] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Ubaid bin Nudhailah] dari [Al Mughirah bin Syu'bah] bahwa salah seorang dari dua orang wanita yang dimadu memukul madunya dengan tiang tenda sehingga ia membunuhnya, kemudian Rasulullah shallallahu 'alaihi wasallam memutuskan agar 'ashabah wanita yang membunuh membayar diyat, dan memutuskan bagi janin yang ada di perutnya dengan denda berupa seorang budak. Kemudian seorang badui berkata; \"Tuan bebankan denda kepadaku untuk orang yang tidak makan, tidak minum, tidak berteriak dan tidak menangis, hal seperti itu adalah sesuatu yang dibatalkan.\" Kemudian beliau bersabda: \"Ini adalah sajak seperti sajak jahiliyah.\" Dan beliau memutuskan bahwa bagi janin yang ada dalam perutnya dengan denda seorang budak."},"4526":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ سَعِيدِ بْنِ مَسْرُوقٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي زَائِدَةَ عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عُبَيْدِ بْنِ نُضَيْلَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَضَرَبَتْ امْرَأَةٌ مِنْ بَنِي لِحْيَانَ ضَرَّتَهَا بِعَمُودِ الْفُسْطَاطِ فَقَتَلَتْهَا وَكَانَ بِالْمَقْتُولَةِ حَمْلٌ فَقَضَى رَ��ُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عَصَبَةِ الْقَاتِلَةِ بِالدِّيَةِ وَلِمَا فِي بَطْنِهَا بِغُرَّةٍ","id":"Telah mengabarkan kepada kami [Ali bin Sa'id bin Masruq] telah menceritakan kepada kami [Yahya bin Abu Zaidah] dari [Israil] dari [Manshur] dari [Ibrahim] dari ['Ubaid bin Nudhailah] dari [Al Mughirah bin Syu'bah], dia berkata; \"Seorang wanita dari Bani Lihyan memukul madunya dengan tiang kemah sehingga dia membunuhnya, padahal wanita yang terbunuh tersebut sedang hamil. Kemudian Rasulullah shallallahu 'alaihi wasallam memutuskan denda menjadi tanggungan 'ashabah wanita yang membunuh, sedang denda untuk janin yang ada dalam perutnya adalah berupa seorang budak.\""},"4527":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ شُعْبَةَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عُبَيْدِ بْنِ نُضَيْلَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَأَنَّ امْرَأَتَيْنِ كَانَتَا تَحْتَ رَجُلٍ مِنْ هُذَيْلٍ فَرَمَتْ إِحْدَاهُمَا الْأُخْرَى بِعَمُودِ فُسْطَاطٍ فَأَسْقَطَتْ فَاخْتَصَمَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا كَيْفَ نَدِي مَنْ لَا صَاحَ وَلَا اسْتَهَلَّ وَلَا شَرِبَ وَلَا أَكَلْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسَجْعٌ كَسَجْعِ الْأَعْرَابِ فَقَضَى بِالْغُرَّةِ عَلَى عَاقِلَةِ الْمَرْأَةِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] telah menceritakan kepada kami [Abdullah] dari [Syu'bah] dari [Manshur] dari [Ibrahim] dari ['Ubaid bin Nudhailah] dari [Al Mughirah bin Syu'bah] bahwa dua orang wanita isteri seorang laki-laki dari Hudzail, salah seorang dari mereka melempar wanita yang lain dengan tiang kemah, sehingga menyebabkan kandungannya gugur. Kemudian mereka menghadapkan permasalahan tersebut kepada Nabi shallallahu 'alaihi wasallam, mereka berkata; \"Bagaimana kami menanggung denda orang yang tidak berteriak dan menangis, tidak minum dan tidak makan? Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah ini sajak seperti sajak orang-orang badui?\" lalu beliau memutuskan denda berupa seorang budak menjadi tanggungan 'ashabah wanita yang membunuh. "},"4528":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ قَالَ سَمِعْتُ إِبْرَاهِيمَ عَنْ عُبَيْدِ بْنِ نُضَيْلَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَأَنَّ رَجُلًا مِنْ هُذَيْلٍ كَانَ لَهُ امْرَأَتَانِ فَرَمَتْ إِحْدَاهُمَا الْأُخْرَى بِعَمُودِ الْفُسْطَاطِ فَأَسْقَطَتْ فَقِيلَ أَرَأَيْتَ مَنْ لَا أَكَلْ وَلَا شَرِبَ وَلَا صَاحَ فَاسْتَهَلَّ فَقَالَ أَسَجْعٌ كَسَجْعِ الْأَعْرَابِ فَقَضَى فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِغُرَّةٍ عَبْدٍ أَوْ أَمَةٍ وَجُعِلَتْ عَلَى عَاقِلَةِ الْمَرْأَةِأَرْسَلَهُ الْأَعْمَشُ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Syu'bah] dari [Manshur], dia berkata; \"Saya mendengar [Ibrahim] dari ['Ubaid bin Nudhailah] dari [Al Mughirah bin Syu'bah] bahwa seorang laki-laki dari Hudzail memiliki dua orang isteri, kemudian salah seorang dari mereka melempar yang lainnya dengan tiang kemah, sehingga ia menggugurkan kandungannya. Kemudian dikatakan; \"Bagaimana pendapatmu mengenai orang yang tidak makan, tidak minum, tidak berteriak dan tidak menangis?\" Kemudian beliau bersabda: \"Apakah ini sajak seperti sajak orang-orang badui?\" lalu Rasulullah shallallahu 'alaihi wasallam memutuskan untuk membayar denda berupa seorang budak dan dibebankan kepada 'ashabah wanita yang membunuh. Hadits tersebut dimursalkan oleh Al A'masy. "},"4529":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا مُصْعَبٌ قَالَ حَدَّثَنَا دَاوُدُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ قَالَضَرَبَتْ امْرَأَةٌ ضَرَّتَهَا بِحَجَرٍ وَهِيَ حُبْلَى فَقَتَلَتْهَا فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا فِي بَطْنِهَا غُرَّةً وَجَعَلَ عَقْلَهَا عَلَى عَصَبَتِهَا فَقَالُوا نُغَرَّمُ مَنْ لَا شَرِبَ وَلَا أَكَلْ وَلَا اسْتَهَلَّ فَمِثْلُ ذَلِكَ يُطَلَّ فَقَالَ أَسَجْعٌ كَسَجْعِ الْأَعْرَابِ هُوَ مَا أَقُولُ لَكُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Mush'ab] telah menceritakan kepada kami [Daud] dari [Al A'masy] dari [Ibrahim], dia berkata; seorang wanita telah memukul madunya yang sedang hamil dengan batu hingga membunuhnya, kemudian Rasulullah shallallahu 'alaihi wasallam menetapkan denda untuk janin yang dikandungnya berupa seorang budak, dan membebankan dendanya kepada 'ashabah wanita yang membunuh. Kemudian mereka berkata; \"Apakah kami menanggung denda orang yang tidak makan, tidak minum, dan tidak menangis? Hal seperti itu adalah sesuatu yang dibatalkan.\" Kemudian beliau bersabda: \"Apakah ini sajak seperti sajak orang-orang badui? Keputusannya adalah apa yang saya katakan.\" "},"4530":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا عَمْرٌو عَنْ أَسْبَاطَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَتْ امْرَأَتَانِ جَارَتَانِ كَانَ بَيْنَهُمَا صَخَبٌ فَرَمَتْ إِحْدَاهُمَا الْأُخْرَى بِحَجَرٍ فَأَسْقَطَتْ غُلَامًا قَدْ نَبَتَ شَعْرُهُ مَيْتًا وَمَاتَتْ الْمَرْأَةُ فَقَضَى عَلَى الْعَاقِلَةِ الدِّيَةَ فَقَالَ عَمُّهَا إِنَّهَا قَدْ أَسْقَطَتْ يَا رَسُولَ اللَّهِ غُلَامًا قَدْ نَبَتَ شَعْرُهُ فَقَالَ أَبُو الْقَاتِلَةِ إِنَّهُ كَاذِبٌ إِنَّهُ وَاللَّهِ مَا اسْتَهَلَّ وَلَا شَرِبَ وَلَا أَكَلْ فَمِثْلُهُ يُطَلَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسَجْعٌ كَسَجْعِ الْجَاهِلِيَّةِ وَكِهَانَتِهَا إِنَّ فِي الصَّبِيِّ غُرَّةً قَالَ ابْنُ عَبَّاسٍ كَانَتْ إِحْدَاهُمَا مُلَيْكَةَ وَالْأُخْرَى أُمَّ غَطِيفٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] telah menceritakan kepada kami ['Amru] dari [Asbath] dari [Simak] dari [Ikrimah] dari [Ibn Abbas], dia berkata; ada dua orang wanita yang bertetangga, diantara keduanya terjadi percecokan lalu salah seorang dari mereka melempar yang lainnya dengan batu hingga menggugurkan anaknya yang telah tumbuh rambutnya, dan wanita itupun mati, lalu ditetapkan atas 'ashabah agar membayar diyat, pamannya berkata; \"Sesungguhnya dia telah mengugurkan seorang anak yang telah tumbuh rambutnya wahai Rasulullah.\" Lalu ayah wanita yang membunuh berkata; \"Dia berdusta, sungguh demi Allah, anak itu tidak menangis, tidak makan dan tidak minum. Maka hal seperti ini adalah sesuatu yang dibatalkan.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah ini sebuah sajak seperti sajak orang-orang Jahiliyah dan perdukunannya? Sesungguhnya denda untuk seorang bayi berupa seorang budak, \" Ibnu Abbas berkata; \"Salah satunya bernama Mulaikah dan yang lainnya adalah Ummi Ghathif.\""},"4531":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ قَالَ حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا يَقُولُكَتَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى كُلِّ بَطْنٍ عُقُولَةً وَلَا يَحِلُّ لِمَوْلًى أَنْ يَتَوَلَّى مُسْلِمًا بِغَيْرِ إِذْنِهِ","id":"Telah mengabarkan kepada kami [Al Abbas bin Abdul 'Azhim] telah menceritakan kepada kami [Adh Dhahhak bin Makhlad] dari [Ibnu Juraij], dia berkata; telah menceritakan kepadaku [Abu Az Zubair] bahwa dia mendengar [Jabir] berkata; \"Rasulullah shallallahu 'alaihi wasallam menetapkan diyat atas setiap perut dan tidak halal bagi seorang tuan untuk menisbatkan seorang muslim sebagai budaknya yang telah dimerdekakan tanpa seizinnya.\""},"4532":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ وَمُحَمَّدُ بْنُ مُصَفَّى قَالَا حَدَّثَنَا الْوَلِيدُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَطَبَّبَ وَلَمْ يُعْلَمْ مِنْهُ طِبٌّ قَبْلَ ذَلِكَ فَهُوَ ضَامِنٌأَخْبَرَنِي مَحْمُودُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا الْوَلِيدُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ جَدِّهِ مِثْلَهُ سَوَاءً","id":"Telah mengabarkan kepadaku ['Amru bin Utsman] dan [Muhammad bin Mushaffa], mereka berkata; telah menceritakan kepada kami [Al Walid] dari [Ibnu Juraij] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakekknya], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang mengobati dan dia tidak mengetahui ilmunya sebelum itu maka dia yang bertanggung jawab.\" Telah menceritakan kepadaku [Mahmud bin Khalid] telah menceritakan kepadaku [Al Walid] dari [Ibn Juraij] dari [Amru bin Syu'aib] dari [kakekknya] sama seperti itu."},"4533":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ أَبْجَرَ عَنْ إِيَادِ بْنِ لَقِيطٍ عَنْ أَبِي رِمْثَةَ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ أَبِي فَقَالَ مَنْ هَذَا مَعَكَ قَالَ ابْنِي أَشْهَدُ بِهِ قَالَ أَمَا إِنَّكَ لَا تَجْنِي عَلَيْهِ وَلَا يَجْنِي عَلَيْكَ","id":"Telah mengabarkan kepadaku [Harun bin Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku [Abdul Malik bin Abjar] dari [Iyad bin Laqith] dari [Abu Rimtsah], dia berkata; \"Saya bersama ayahku datang kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Siapa ini yang bersamamu?\" ayahku berkata; \"Anakku, saya bersaksi dengannya.\" Beliau bersabda: \"Sesungguhnya dia tidak dihukum karena kejahatanmu dan engkau tidak dihukum karena kejahatannya.\""},"4534":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا بِشْرُ بْنُ السَّرِيِّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَشْعَثَ عَنْ الْأَسْوَدِ بْنِ هِلَالٍ عَنْ ثَعْلَبَةَ بْنِ زَهْدَمٍ الْيَرْبُوعِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فِي أُنَاسٍ مِنْ الْأَنْصَارِ فَقَالُوا يَا رَسُولَ اللَّهِ هَؤُلَاءِ بَنُو ثَعْلَبَةَ بْنِ يَرْبُوعٍ قَتَلُوا فُلَانًا فِي الْجَاهِلِيَّةِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَتَفَ بِصَوْتِهِ أَلَا لَا تَجْنِي نَفْسٌ عَلَى الْأُخْرَى","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Bisyr bin As Sari] telah menceritakan kepada kami [Sufyan] dari [Asy'ats] dari [Al Aswad bin Hilal] dari [Tsa'labah bin Zahdam Al Yarbu'i], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam berkhutbah diantara orang-orang Anshar, kemudian mereka berkata; \"Wahai Rasulullah mereka adalah Bani Tsa'labah bin Yarbu', mereka membunuh fulan pada masa Jahiliyah.\" Lalu Nabi shallallahu 'alaihi wasallam berbisik: \"Ketahuilah sebuah jiwa tidak dihukum karena kejahatan jiwa yang lain.\""},"4535":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ عَنْ سُفْيَانَ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ الْأَسْوَدِ بْنِ هِلَالٍ عَنْ ثَعْلَبَةَ بْنِ زَهْدَمٍ قَالَانْتَهَى قَوْمٌ مِنْ بَنِي ثَعْلَبَةَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْطُبُ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ هَؤُلَاءِ بَنُو ثَعْلَبَةَ بْنِ يَرْبُوعٍ قَتَلُوا فُلَانًا رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَجْنِي نَفْسٌ عَلَى أُخْرَى","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] dari [Sufyan] dari [Asy'ats bin Abu Asy Asya'tsa`] dari [Al Aswad bin Hilal] dari [Tsa'labah bin Zahdam] beberapa orang dari Bani Tsa'labah datang kepada Nabi shallallahu 'alaihi wasallam yang sedang berkhutbah, kemudian seseorang berkata; \"Wahai Rasulullah, orang-orang Bani Tsa'labah bin Yarbu' telah membunuh Fulan dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sebuah jiwa tidak dihukum karena kejahatan jiwa yang lain.\""},"4536":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ قَالَ سَمِعْتُ الْأَسْوَدَ بْنَ هِلَالٍ يُحَدِّثُ عَنْ رَجُلٍ مِنْ بَنِي ثَعْلَبَةَ بْنِ يَرْبُوعٍأَنَّ نَاسًا مِنْ بَنِي ثَعْلَبَةَ أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ هَؤُلَاءِ بَنُو ثَعْلَبَةَ بْنِ يَرْبُوعٍ قَتَلُوا فُلَانًا رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَجْنِي نَفْسٌ عَلَى أُخْرَى","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Syu'bah] dari [Asy'ats bin Abu Asy Sya' tsa`], saya mendengar [Al Aswad bin Hilal] bercerita dari [seseorang dari Bani Tsa'labah bin Yarbu'] bahwa beberapa orang dari Bani Tsa'labah mendatangi Nabi shallallahu 'alaihi wasallam, kemudian seorang laki-laki berkata; \"Wahai Rasulullah, mereka adalah Bani Tsa'labah bin Yarbu', mereka telah membunuh seseorang dari sahabat Nabi shallallahu 'alaihi wasallam. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sebuah jiwa tidak dihukum karena kejahatan jiwa yang lain.\""},"4537":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا أَبُو عَتَّابٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْأَشْعَثِ بْنِ سُلَيْمٍ عَنْ الْأَسْوَدِ بْنِ هِلَالٍ وَكَانَ قَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ رَجُلٍ مِنْ بَنِي ثَعْلَبَةَ بْنِ يَرْبُوعٍأَنَّ نَاسًا مِنْ بَنِي ثَعْلَبَةَ أَصَابُوا رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَجُلٌ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رَسُولَ اللَّهِ هَؤُلَاءِ بَنُو ثَعْلَبَةَ قَتَلَتْ فُلَانًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَجْنِي نَفْسٌ عَلَى أُخْرَىقَالَ شُعْبَةُ أَيْ لَا يُؤْخَذُ أَحَدٌ بِأَحَدٍ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Abu Daud] telah menceritakan kepada kami [Abu 'Attab] telah menceritakan kepada kami [Syu'bah] dari [Al Asy'ats bin Sulaim] dari [Al Aswad bin Hilal] dan dia telah mengetahui Nabi shallallahu 'alaihi wasallam, dari [seseorang dari Bani Tsa'labah bin Yarbu'] bahwa beberapa orang dari Bani Tsa'labah membunuh seorang sahabat Nabi shallallahu 'alaihi wasallam, kemudian seorang laki-laki dari kalangan sahabat Rasulullah shallallahu 'alaihi wasallam berkata; \"Wahai Rasulullah, mereka adalah Bani Tsa'labah, mereka telah membunuh Fulan.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebuah jiwa tidak dihukum karena kejahatan jiwa yang lain.\" Syu'bah berkata; \"Yaitu tidak dihukum seseorang karena orang lain.\" Wallahu 'alam. "},"4538":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَشْعَثِ بْنِ سُلَيْمٍ عَنْ أَبِيهِ عَنْ رَجُلٍ مِنْ بَنِي ثَعْلَبَةَ بْنِ يَرْبُوعٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَكَلَّمُ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ هَؤُلَاءِ بَنُو ثَعْلَبَةَ بْنِ يَرْبُوعٍ الَّذِينَ أَصَابُوا فُلَانًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَعْنِي لَا تَجْنِي نَفْسٌ عَلَى نَفْسٍ","id":"Telah mengabarkan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Al Asy'ats bin Sulaim] dari [ayahnya] dari [seseorang dari Bani Tsa'labah bin Yarbu'], dia berkata; \"Saya datang menemui Nabi shallallahu 'alaihi wasallam ketika beliau sedang berbicara. Kemudian seseorang berkata; \"Wahai Rasulullah, mereka adalah Bani Tsa'labah bin Yarbu' yang telah membunuh Fulan. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak, sebuah jiwa tidak dihukum karena kejahatan jiwa yang lain.\""},"4539":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ فِي حَدِيثِهِ عَنْ أَبِي الْأَحْوَصِ عَنْ أَشْعَثَ عَنْ أَبِيهِ عَنْ رَجُلٍ مِنْ بَنِي يَرْبُوعٍ قَالَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُكَلِّمُ النَّاسَ فَقَامَ إِلَيْهِ نَاسٌ فَقَالُوا يَا رَسُولَ اللَّهِ هَؤُلَاءِ بَنُو فُلَانٍ الَّذِينَ قَتَلُوا فُلَانًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَجْنِي نَفْسٌ عَلَى أُخْرَى","id":"Telah menceritakan kepada kami [Hannad bin As Sari] dalam haditsnya dari [Abu Al Ahwash] dari [Al Asy'ats] dari [ayahnya] dari [seorang laki-laki dari Bani Yarbu'], dia berkata; \"Saya datang menemui Nabi shallallahu 'alaihi wasallam ketika beliau sedang berbicara dengan orang-orang, kemudian beberapa orang menemui beliau dan berkata; \"Wahai Rasulullah, mereka adalah Bani Fulan yang telah membunuh Fulan. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebuah jiwa tidak dihukum karena kejahatan jiwa yang lain.\""},"4540":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ عِيسَى قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى قَالَ أَنْبَأَنَا يَزِيدُ وَهُوَ ابْنُ زِيَادِ بْنِ أَبِي الْجَعْدِ عَنْ جَامِعِ بْنِ شَدَّادٍ عَنْ طَارِقٍ الْمُحَارِبِيِّأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ هَؤُلَاءِ بَنُو ثَعْلَبَةَ الَّذِينَ قَتَلُوا فُلَانًا فِي الْجَاهِلِيَّةِ فَخُذْ لَنَا بِثَأْرِنَا فَرَفَعَ يَدَيْهِ حَتَّى رَأَيْتُ بَيَاضَ إِبْطَيْهِ وَهُوَ يَقُولُ لَا تَجْنِي أُمٌّ عَلَى وَلَدٍ مَرَّتَيْنِ","id":"Telah mengabarkan kepada kami [Yusuf bin Isa] telah menceritakan kepada kami [Al Fadhl bin Musa] telah menceritakan kepada kami [Yazid yaitu Ibnu Ziyad bin Abu Al Ja'di] dari [Jami' bin Syaddad] dari [Thariq Al Muharibi] bahwa seseorang berkata; \"Wahai Rasulullah, mereka adalah Bani Tsa'labah yang membunuh Fulan pada masa Jahiliyah, maka lakukanlah pembalasan untuk kami, lalu beliau mengangkat tangan beliau hingga terlihat putih ketiaknya, beliau bersabda: \"Tidaklah seorang anak dihukum karena kejahatan ibunya, \" sebanyak dua kali."},"4541":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ بْنِ مُحَمَّدٍ قَالَ أَنْبَأَنَا ابْنُ عَائِذٍ قَالَ حَدَّثَنَا الْهَيْثَمُ بْنُ حُمَيْدٍ قَالَ أَخْبَرَنِي الْعَلَاءُ وَهُوَ ابْنُ الْحَارِثِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي الْعَيْنِ الْعَوْرَاءِ السَّادَّةِ لِمَكَانِهَا إِذَا طُمِسَتْ بِثُلُثِ دِيَتِهَا وَفِي الْيَدِ الشَّلَّاءِ إِذَا قُطِعَتْ بِثُلُثِ دِيَتِهَا وَفِي السِّنِّ السَّوْدَاءِ إِذَا نُزِعَتْ بِثُلُثِ دِيَتِهَا","id":"Telah mengabarkan kepada kami [Ahmad bin Ibrahim bin Muhammad] telah menceritakan kepada kami [Ibnu 'Aidz] telah menceritakan kepada kami [Al Haitsam bin Humaid] telah menceritakan kepadaku [Al 'Ala` yaitu Ibnu Al Harits] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam menetapkan diyat untuk mata yang cacat sebelah apabila tidak bisa melihat dengan sepertiga diyatnya, dan untuk tangan yang lumpuh jika terpotong dengan sepertiga diyatnya, pada gigi hitam apabila terlepas dengan sepertiga diyatnya."},"4542":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مُعَاوِيَةَ قَالَ حَدَّثَنَا عَبَّادٌ عَنْ حُسَيْنٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْأَسْنَانِ خَمْسٌ مِنْ الْإِبِلِ","id":"Telah mengabarkan kepada kami [Muhammad bin Mu'awiyah] telah menceritakan kepada kami ['Abbad] dari [Husain] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Diyat untuk gigi adalah lima ekor unta.\""},"4543":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا حَفْصُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ مَطَرٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَسْنَانُ سَوَاءٌ خَمْسًا خَمْسًا","id":"Telah mengabarkan kepada kami [Al Husain bin Manshur] telah menceritakan kepada kami [Hafsh bin Abdur Rahman] telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Mathar] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Gigi diyatnya sama, yaitu lima, lima.\""},"4544":{"ar":"أَخْبَرَنَا أَبُو الْأَشْعَثِ قَالَ حَدَّثَنَا خَالِدٌ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ مَسْرُوقِ بْنِ أَوْسٍ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْأَصَابِعِ عَشْرٌ عَشْرٌ","id":"Telah mengabarkan kepada kami [Abu Al Asy'ats] telah menceritakan kepada kami [Khalid] dari [Sa'id] dari [Qatadah] dari [Masruq bin Aus] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Diyat jari-jari adalah sepuluh, sepuluh.\""},"4545":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ غَالِبٍ التَّمَّارِ عَنْ مَسْرُوقِ بْنِ أَوْسٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَصَابِعُ سَوَاءٌ عَشْرًا","id":"Telah mengabarkan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Ghalib At Tammar] dari [Masruq bin Aus] dari [Abu Musa Al Asy'ari] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jari-jari diyatnya sama, yaitu sepuluh.\""},"4546":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا حَفْصٌ وَهُوَ ابْنُ عَبْدِ الرَّحْمَنِ الْبَلْخِيُّ عَنْ سَعِيدٍ عَنْ غَالِبٍ التَّمَّارِ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ مَسْرُوقِ بْنِ أَوْسٍ عَنْ أَبِي مُوسَى قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْأَصَابِعَ سَوَاءٌ عَشْرًا عَشْرًا مِنْ الْإِبِلِ","id":"Telah mengabarkan kepada kami [Al Husain bin Manshur] telah menceritakan kepada kami [Hafsh yaitu Ibnu Abdur Rahman Al Balkhi] dari [Sa'id] dari [Ghalib At Tammar] dari [Humaid bin Hilal] dari [Masruq bin Aus] dari [Abu Musa], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam menetapkan bahwa diyat untuk jari-jari adalah sama, yaitu sepuluh unta, sepuluh unta.\""},"4547":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِأَنَّهُ لَمَّا وُجِدَ الْكِتَابُ الَّذِي عِنْدَ آلِ عَمْرِو بْنِ حَزْمٍ الَّذِي ذَكَرُوا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ لَهُمْ وَجَدُوا فِيهِ وَفِيمَا هُنَالِكَ مِنْ الْأَصَابِعِ عَشْرًا عَشْرًا","id":"Telah mengabarkan kepada kami [Al Husain bin Manshur] telah menceritakan kepada kami [Abdullah bin Numair] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sa'id bin Al Musayyab] bahwa tatkala ditemukan catatan yang ada pada keluarga 'Amru bin Hazm yang mereka sebutkan bahwa catatan tersebut ditulis oleh Rasulullah shallallahu 'alaihi wasallam untuk mereka, mereka dapatkan isinya dan di antara isinya adalah diyat untuk jari-jari adalah sepuluh sepuluh."},"4548":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي قَتَادَةُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَذِهِ وَهَذِهِ سَوَاءٌ يَعْنِي الْخِنْصَرَ وَالْإِبْهَامَ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Ini dan ini adalah sama.\" yaitu jari kelingking dan ibu jari."},"4549":{"ar":"أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفَهَذِهِ وَهَذِهِ سَوَاءٌ الْإِبْهَامُ وَالْخِنْصَرُ","id":"Telah mengabarkan kepada kami [Nashr bin Ali] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] ['Ikrimah] dari [Ibnu 'Abbas], dia berkata; \"Ini dan ini adalah sama (diyatnya) \", yaitu ibu jari dan jari kelingking."},"4550":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَالْأَصَابِعُ عَشْرٌ عَشْرٌ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari ['Ikrimah] dari [Ibnu 'Abbas], dia berkata; \"Jari-jari diyatnya adalah sepuluh-sepuluh.\""},"4551":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ أَنَّ أَبَاهُ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَلَمَّا افْتَتَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ قَالَ فِي خُطْبَتِهِ وَفِي الْأَصَابِعِ عَشْرٌ عَشْرٌ","id":"Telah menceritakan kepada kami [Isma'il bin Mas'ud] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Husain Al Mu'allim] dari ['Amru bin Syu'aib] bahwa [ayahnya] telah menceritakan kepadanya dari [Abdullah bin 'Amru], dia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam membuka Mekkah beliau bersabda dalam khutbahnya: \"Diyat untuk jari-jari adalah sepuluh-sepuluh.\""},"4552":{"ar":"أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ الْهَيْثَمِ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا هَمَّامٌ قَالَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ وَابْنُ جُرَيْجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي خُطْبَتِهِ وَهُوَ مُسْنِدٌ ظَهْرَهُ إِلَى الْكَعْبَةِ الْأَصَابِعُ سَوَاءٌ","id":"Telah mengabarkan kepadaku [Abdullah bin Al Haitsam] telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Husain Al Mu'allim] dan [Ibnu Juraij] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Nabi shallallahu 'alaihi wasallam bersabda dalam khutbahnya seraya menyandarkan punggungnya ke ka'bah: \"Jari-jari adalah sama.\""},"4553":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ أَنَّ أَبَاهُ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَلَمَّا افْتَتَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ قَالَ فِي خُطْبَتِهِ وَفِي الْمَوَاضِحِ خَمْسٌ خَمْسٌ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Husain Al Mu'allim] dari ['Amru bin Syu'aib] bahwa [ayahnya] telah menceritakan kepadanya dari [Abdullah bin 'Amru], dia berkata; \"Tatkala Rasulullah shallallahu 'alaihi wasallam membuka Mekkah beliau bersabda dalam khutbahnya: \"Untuk luka-luka yang menampakkan tulang diyatnya lima, lima.\""},"4554":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا الْحَكَمُ بْنُ مُوسَى قَالَ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ سُلَيْمَانَ بْنِ دَاوُدَ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَى أَهْلِ الْيَمَنِ كِتَابًا فِيهِ الْفَرَائِضُ وَالسُّنَنُ وَالدِّيَاتُ وَبَعَثَ بِهِ مَعَ عَمْرِو بْنِ حَزْمٍ فَقُرِئَتْ عَلَى أَهْلِ الْيَمَنِ هَذِهِ نُسْخَتُهَا مِنْ مُحَمَّدٍ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى شُرَحْبِيلَ بْنِ عَبْدِ كُلَالٍ وَنُعَيْمِ بْنِ عَبْدِ كُلَالٍ وَالْحَارِثِ بْنِ عَبْدِ كُلَالٍ قَيْلِ ذِيِ رُعَيْنٍ وَمَعَافِرَ وَهَمْدَانَ أَمَّا بَعْدُ وَكَانَ فِي كِتَابِهِ أَنَّ مَنْ اعْتَبَطَ مُؤْمِنًا قَتْلًا عَنْ بَيِّنَةٍ فَإِنَّهُ قَوَدٌ إِلَّا أَنْ يَرْضَى أَوْلِيَاءُ الْمَقْتُولِ وَأَنَّ فِي النَّفْسِ الدِّيَةَ مِائَةً مِنْ الْإِبِلِ وَفِي الْأَنْفِ إِذَا أُوعِبَ جَدْعُهُ الدِّيَةُ وَفِي اللِّسَانِ الدِّيَةُ وَفِي الشَّفَتَيْنِ الدِّيَةُ وَفِي الْبَيْضَتَيْنِ الدِّيَةُ وَفِي الذَّكَرِ الدِّيَةُ وَفِي الصُّلْبِ الدِّيَةُ وَفِي الْعَيْنَيْنِ الدِّيَةُ وَفِي الرِّجْلِ الْوَاحِدَةِ نِصْفُ الدِّيَةِ وَفِي الْمَأْمُومَةِ ثُلُثُ الدِّيَةِ وَفِي الْجَائِفَةِ ثُلُثُ الدِّيَةِ وَفِي الْمُنَقِّلَةِ خَمْسَ عَشْرَةَ مِنْ الْإِبِلِ وَفِي كُلِّ أُصْبُعٍ مِنْ أَصَابِعِ الْيَدِ وَالرِّجْلِ عَشْرٌ مِنْ الْإِبِلِ وَفِي السِّنِّ خَمْسٌ مِنْ الْإِبِلِ وَفِي الْمُوضِحَةِ خَمْسٌ مِنْ الْإِبِلِ وَأَنَّ الرَّجُلَ يُقْتَلُ بِالْمَرْأَةِ وَعَلَى أَهْلِ الذَّهَبِ أَلْفُ دِينَارٍخَالَفَهُ مُحَمَّدُ بْنُ بَكَّارِ بْنِ بِلَالٍ","id":"Telah mengabarkan kepada kami ['Amru bin Manshur] telah menceritakan kepada kami [Al Hakam bin Musa] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Sulaiman bin Daud] telah menceritakan kepadaku [Az Zuhri] dari [Abu Bakar bin Muhammad bin 'Amru bin Hazm] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam menulis surat kepada penduduk Yaman yang berisi tentang berbagai kewajiban, sunnah-sunnah, dan diyat. Beliau mengutus 'Amru bin Hazm untuk mengantar surat tersebut. Kemudian surat tersebut dibacakan di hadapan penduduk Yaman. Inilah naskahnya; \"Dari Muhammad, Nabi shallallahu 'alaihi wasallam, kepada Syurahbil bin Abdu Kulal dan Nu'aim bin Abdu Kulal, serta Al Harits bin Abdu Kulal Qail Dzu ru'ain, Ma'afir, dan Hamdan; adapun selanjutnya.... Dan di antara isi surat tersebut adalah bahwa, \"Barang siapa membunuh seorang mukmin secara lalim dengan adanya bukti maka ia mendapatkan balasan, kecuali apabila para wali orang yang dibunuh merasa rela. Untuk sebuah nyawa satu diyat yaitu seratus ekor unta, hidung apabila dipotong semuanya adalah satu diyat, untuk lidah satu diyat, untuk dua bibir satu diyat, dua buah pelir satu diyat, penis satu diyat, tulang belakang satu diyat, dua mata satu diyat, satu kaki setengah diyat, luka yang sampai kepada otak sepertiga diyat, luka dalam sepertiga diyat, tulang retak dan bergeser lima belas unta, dan untuk setiap jari tangan dan kaki sepuluh unta, untuk gigi lima unta, untuk luka yang menampakkan tulang lima unta. Dan seseorang dibunuh akibat membunuh seorang wanita, bagi pemilik emas diyatnya adalah seribu dinar.\" Muhammad bin Bakkar bin Bilal menyelisihi hal tersebut. "},"4555":{"ar":"أَخْبَرَنَا الْهَيْثَمُ بْنُ مَرْوَانَ بْنِ الْهَيْثَمِ بْنِ عِمْرَانَ الْعَنْسِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بَكَّارِ بْنِ بِلَالٍ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ أَرْقَمَ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَى أَهْلِ الْيَمَنِ بِكِتَابٍ فِيهِ الْفَرَائِضُ وَالسُّنَنُ وَالدِّيَاتُ وَبَعَثَ بِهِ مَعَ عَمْرِو بْنِ حَزْمٍ فَقُرِئَ عَلَى أَهْلِ الْيَمَنِ هَذِهِ نُسْخَتُهُ فَذَكَرَ مِثْلَهُ إِلَّا أَنَّهُ قَالَ وَفِي الْعَيْنِ الْوَاحِدَةِ نِصْفُ الدِّيَةِ وَفِي الْيَدِ الْوَاحِدَةِ نِصْفُ الدِّيَةِ وَفِي الرِّجْلِ الْوَاحِدَةِ نِصْفُ الدِّيَةِقَالَ أَبُو عَبْد الرَّحْمَنِ وَهَذَا أَشْبَهُ بِالصَّوَابِ وَاللَّهُ أَعْلَمُ وَسُلَيْمَانُ بْنُ أَرْقَمَ مَتْرُوكُ الْحَدِيثِ وَقَدْ رَوَى هَذَا الْحَدِيثَ يُونُسُ عَنْ الزُّهْرِيِّ مُرْسَلًا","id":"Telah mengabarkan kepada kami [Al Haitsam bin Marwan bin Al Haitsam bin Imran Al 'Ansi] telah menceritakan kepada kami [Muhammad bin Bakkar bin Bilal] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Sulaiman bin Arqam] telah menceritakan kepadaku [Az Zuhri] dari [Abu Bakar bin Muhammad bin 'Amru bin Hazm] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam menulis surat kepada pendudukYaman yang isinya berbagai kewajiban, sunnah-sunnah dan diyat. Beliau mengirimnya bersama 'Amru bin Hazm, kemudian dibacakan kepada penduduk Yaman, inilah naskahnya, beliau menyebutkan seperti itu hanya saja beliau bersabda: \"Untuk satu mata setengah diyat, satu tangan setengah diyat, dan satu kaki setengah diyat.\" Abu Abdur Rahman berkata; \"Ini lebih mendekati kebenaran. Wallahu a'lam. Sulaiman bin Arqam adalah orang yang ditinggalkan haditsnya, dan hadits ini telah diriwayatkan oleh Yunus dari Az Zuhri secara mursal.\""},"4556":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ قَالَقَرَأْتُ كِتَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي كَتَبَ لِعَمْرِو بْنِ حَزْمٍ حِينَ بَعَثَهُ عَلَى نَجْرَانَ وَكَانَ الْكِتَابُ عِنْدَ أَبِي بَكْرِ بْنِ حَزْمٍ فَكَتَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا بَيَانٌ مِنْ اللَّهِ وَرَسُولِهِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا أَوْفُوا بِالْعُقُودِ وَكَتَبَ الْآيَاتِ مِنْهَا حَتَّى بَلَغَ إِنَّ اللَّهَ سَرِيعُ الْحِسَابِ }ثُمَّ كَتَبَ هَذَا كِتَابُ الْجِرَاحِ فِي النَّفْسِ مِائَةٌ مِنْ الْإِبِلِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ahmad bin 'Amru bin As Sarh] telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab], dia berkata; \"Saya membaca surat Rasulullah shallallahu 'alaihi wasallam yang beliau tulis untuk 'Amru bin Hazm ketika beliau mengutusnya ke Najran, dan surat tersebut ada pada Abu Bakar bin Hazm. Rasulullah shallallahu 'alaihi wasallam menulis: \"Ini adalah penjelasan dari Allah dan RasulNya, Hai orang-orang yang beriman, penuhilah aqad-aqad itu.....\" beliau menulis beberapa ayat hingga sampai pada firmanNya: \"Sesungguhnya Allah amat cepat hisabNya.\" Kemudian beliau menulis: \"Ini adalah catatan mengenai hal luka, untuk sebuah nyawa seratus unta....\" seperti itu.\""},"4557":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ الْوَاحِدِ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا سَعِيدٌ وَهُوَ ابْنُ عَبْدِ الْعَزِيزِ عَنْ الزُّهْرِيِّ قَالَجَاءَنِي أَبُو بَكْرِ بْنُ حَزْمٍ بِكِتَابٍ فِي رُقْعَةٍ مِنْ أَدَمٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا بَيَانٌ مِنْ اللَّهِ وَرَسُولِهِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا أَوْفُوا بِالْعُقُودِ }فَتَلَا مِنْهَا آيَاتٍ ثُمَّ قَالَ فِي النَّفْسِ مِائَةٌ مِنْ الْإِبِلِ وَفِي الْعَيْنِ خَمْسُونَ وَفِي الْيَدِ خَمْسُونَ وَفِي الرِّجْلِ خَمْسُونَ وَفِي الْمَأْمُومَةِ ثُلُثُ الدِّيَةِ وَفِي الْجَائِفَةِ ثُلُثُ الدِّيَةِ وَفِي الْمُنَقِّلَةِ خَمْسَ عَشْرَةَ فَرِيضَةً وَفِي الْأَصَابِعِ عَشْرٌ عَشْرٌ وَفِي الْأَسْنَانِ خَمْسٌ خَمْسٌ وَفِي الْمُوضِحَةِ خَمْسٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdul Wahid] telah menceritakan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Sa'id yaitu Ibnu Abdul Aziz] dari [Az Zuhri], dia berkata; \"Telah datang kepadaku [Abu Bakar bin Hazm] membawa surat dalam secarik kulit, dari Rasulullah shallallahu 'alaihi wasallam: \"Ini adalah penjelasan dari Allah dan RasulNya, \"Hai orang-orang yang beriman, penuhilah aqad-aqad itu.....\" beliau membaca beberapa ayat kenudian bersabda; \"Untuk sebuah nyawa seratus unta, untuk mata lima puluh unta, untuk satu tangan lima puluh, satu kaki lima puluh, luka hingga ke otak sepertiga diyat, luka dalam sepertiga diyat, tulang retak dan bergeser lima belas unta, dan untuk jari-jari sepuluh-sepuluh, untuk gigi lima, lima, luka yang menampakkan tulang lima.\""},"4558":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ قَالَالْكِتَابُ الَّذِي كَتَبَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعَمْرِو بْنِ حَزْمٍ فِي الْعُقُولِ إِنَّ فِي النَّفْسِ مِائَةً مِنْ الْإِبِلِ وَفِي الْأَنْفِ إِذَا أُوعِيَ جَدْعًا مِائَةً مِنْ الْإِبِلِ وَفِي الْمَأْمُومَةِ ثُلُثُ النَّفْسِ وَفِي الْجَائِفَةِ مِثْلُهَا وَفِي الْيَدِ خَمْسُونَ وَفِي الْعَيْنِ خَمْسُونَ وَفِي الرِّجْلِ خَمْسُونَ وَفِي كُلِّ إِصْبَعٍ مِمَّا هُنَالِكَ عَشْرٌ مِنْ الْإِبِلِ وَفِي السِّنِّ خَمْسٌ وَفِي الْمُوضِحَةِ خَمْسٌ","id":"Telah mengabarkan kepada kami [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar dari [Ibnu Al Qasim] telah menceritakan kepadaku [Malik] dari [Abdullah bin Abu Bakar bin Muhammad bin 'Amru bin Hazm] dari [ayahnya], dia berkata; \"Surat yang ditulis Rasulullah shallallahu 'alaihi wasallam untuk 'Amru bin Hazm mengenai diyat adalah; sesungguhnya untuk nyawa seratus unta, hidung apabila dipotong semuanya seratus unta, luka yang sampai ke otak sepertiga, luka dalam seperti itu (sepertiga juga), dan untuk satu tangan lima puluh, satu mata lima puluh, satu kaki lima puluh, dan untuk setiap jari sepuluh unta, satu gigi lima dan untuk luka yang menampakkan tulang lima.\" "},"4559":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبَانُ قَالَ حَدَّثَنَا يَحْيَى عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ أَعْرَابِيًّا أَتَى بَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَلْقَمَ عَيْنَهُ خُصَاصَةَ الْبَابِ فَبَصُرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَوَخَّاهُ بِحَدِيدَةٍ أَوْ عُودٍ لِيَفْقَأَ عَيْنَهُ فَلَمَّا أَنْ بَصُرَ انْقَمَعَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّكَ لَوْ ثَبَتَّ لَفَقَأْتُ عَيْنَكَ","id":"Telah mengabarkan kepada kami ['Amru bin Manshur] telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Aban] telah menceritakan kepada kami [Yahya] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] bahwa seorang badui datang ke pintu Rasulullah shallallahu 'alaihi wasallam kemudian meletakkan matanya pada celah pintu, kemudian Rasulullah shallallahu 'alaihi wasallam melihatnya dan beliau menuju kepadanya dengan membawa besi atau kayu untuk mencongkel matanya, kemudian tatkala orang itu melihat maka ia menarik matanya. Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya jika engkau tidak bergerak sungguh saya akan mencongkel matamu.\""},"4560":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ أَنَّ سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّ أَخْبَرَهُأَنَّ رَجُلًا اطَّلَعَ مِنْ جُحْرٍ فِي بَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِدْرَى يَحُكُّ بِهَا رَأْسَهُ فَلَمَّا رَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ عَلِمْتُ أَنَّكَ تَنْظُرُنِي لَطَعَنْتُ بِهِ فِي عَيْنِكَ إِنَّمَا جُعِلَ الْإِذْنُ مِنْ أَجْلِ الْبَصَرِ","id":"Telah mengabarkan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] bahwa [Sahl bin Sa'd As Sa'idi] telah mengabarkan kepadanya bahwa seorang laki-laki mengintip dari lubang pintu Rasulullah shallallahu 'alaihi wasallam padahal Rasulullah shallallahu 'alaihi wasallam sedang membawa sisir untuk menggaruk kepalanya. Tatkala Rasulullah shallallahu 'alaihi wasallam melihatnya beliau bersabda: \"Jika saya mengetahui bahwa engkau melihatku, sungguh aku akan menusukkan ini ke matamu, sesungguhnya diperintahkan untuk meminta izin agar mata (tidak melihat siapa yang di dalam).\""},"4561":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اطَّلَعَ فِي بَيْتِ قَوْمٍ بِغَيْرِ إِذْنِهِمْ فَفَقَئُوا عَيْنَهُ فَلَا دِيَةَ لَهُ وَلَا قِصَاصَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [ayahku] dari [Qatadah] dari [An Nadhr bin Anas] dari [Basyir bin Nahik] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barang siapa yang mengintip ke rumah suatu kaum tanpa seizin mereka kemudian mereka mencongkel matanya maka tidak ada diyat baginya dan tidak ada pembalasan.\""},"4562":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ أَنَّ امْرَأً اطَّلَعَ عَلَيْكَ بِغَيْرِ إِذْنٍ فَخَذَفْتَهُ فَفَقَأْتَ عَيْنَهُ مَا كَانَ عَلَيْكَ حَرَجٌ وَقَالَ مَرَّةً أُخْرَى جُنَاحٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: 'Apabila seseorang mengintipmu tanpa izin kemudian engkau melemparnya dan mencungkil matanya maka engkau tidak mendapatkan dosa.\" Dan pada kali lain beliau mengatakan: \"Dosa.\""},"4563":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مُصْعَبٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّهُ كَانَ يُصَلِّي فَإِذَا بِابْنٍ لِمَرْوَانَ يَمُرُّ بَيْنَ يَدَيْهِ فَدَرَأَهُ فَلَمْ يَرْجِعْ فَضَرَبَهُ فَخَرَجَ الْغُلَامُ يَبْكِي حَتَّى أَتَى مَرْوَانَ فَأَخْبَرَهُ فَقَالَ مَرْوَانُ لِأَبِي سَعِيدٍ لِمَ ضَرَبْتَ ابْنَ أَخِيكَ قَالَ مَا ضَرَبْتُهُ إِنَّمَا ضَرَبْتُ الشَّيْطَانَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا كَانَ أَحَدُكُمْ فِي صَلَاةٍ فَأَرَادَ إِنْسَانٌ يَمُرُّ بَيْنَ يَدَيْهِ فَيَدْرَؤُهُ مَا اسْتَطَاعَ فَإِنْ أَبَى فَلْيُقَاتِلْهُ فَإِنَّهُ شَيْطَانٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Mush'ab] telah menceritakan kepada kami [Muhammad bin Al Mubarak] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Shafwan bin Sulaim] dari ['Atho` bin Yasar] dari [Abu Sa'id Al Khudri] bahwa dia pernah melakukan shalat kemudian tiba-tiba anak Marwan lewat di depannya, kemudian dia menghalanginya namun anak tersebut tidak mundur kemudian dia memukulnya. Lalu anak itu keluar dalam keadaan menangis hingga datang kepada Marwan, dan memberitahukan kepadanya. Lalu Marwan berkata kepada Abu Sa'id; \"Kenapa engkau memukul anak saudaraku?\" Dia berkata; \"Saya tidak memukulnya, sesungguhnya saya memukul syetan. Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seseorang diantara kalian melakukan shalat kemudian ada orang yang ingin lewat di hadapannya lalu ia mencegahnya semampunya, apabila orang tersebut mengabaikan maka hendaknya ia memeranginya karena itu adalah syetan.\""},"4564":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ لَفْظًا قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍقَالَ أَمَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبْزَى أَنْ أَسْأَلَ ابْنَ عَبَّاسٍ عَنْ هَاتَيْنِ الْآيَتَيْنِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }فَسَأَلْتُهُ فَقَالَ لَمْ يَنْسَخْهَا شَيْءٌ وَعَنْ هَذِهِ الْآيَةِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }قَالَ نَزَلَتْ فِي أَهْلِ الشِّرْكِ","id":"Telah menceritakan kepada kami Abu Abdur Rahman secara lafazh, dia berkata; telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Sa'id bin Jubair], dia berkata; \"Saya diperintahkan oleh Abdur Rahman bin Abza untuk bertanya kepada [Ibnu Abbas] mengenai dua ayat ini: Barang siapa yang membunuh seorang mukmin dengan sengaja maka balasannya adalah Neraka Jahannam. Maka dia berkata; \"Tidak ada sesuatupun yang menghapusnya. Dan mengenai ayat ini: Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar. Dia berkata; \"Ayat tersebut turun mengenai ahli syirik.\" "},"4565":{"ar":"أَخْبَرَنَا أَزْهَرُ بْنُ جَمِيلٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ بْنِ النَّعْمَانِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَاخْتَلَفَ أَهْلُ الْكُوفَةِ فِي هَذِهِ الْآيَةِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }فَرَحَلْتُ إِلَى ابْنِ عَبَّاسٍ فَسَأَلْتُهُ فَقَالَ نَزَلَتْ فِي آخِرِ مَا أُنْزِلَتْ وَمَا نَسَخَهَا شَيْءٌ","id":"Telah mengabarkan kepada kami [Azhar bin Jamil] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Syu'bah] dari [Al Mughirah bin An Na'man] dari [Sa'id bin Jubair], dia berkata; \"Penduduk Kufah berselisih mengenai ayat ini: Barang siapa yang membunuh seorang mukmin dengan sengaja.....Kemudian saya pergi menemui [Ibnu Abbas] dan bertanya kepadanya, kemudian dia berkata; \"Ayat tersebut diturunkan di akhir ayat yang diturunkan dan tidak ada sesuatupun yang menghapusnya.\""},"4566":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي الْقَاسِمُ بْنُ أَبِي بَزَّةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَقُلْتُ لِابْنِ عَبَّاسٍ هَلْ لِمَنْ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا مِنْ تَوْبَةٍ قَالَ لَا وَقَرَأْتُ عَلَيْهِ الْآيَةَ الَّتِي فِي الْفُرْقَانِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }قَالَ هَذِهِ آيَةٌ مَكِّيَّةٌ نَسَخَتْهَا آيَةٌ مَدَنِيَّةٌ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }","id":"Telah mengabarkan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Ibnu Juraij] telah menceritakan kepadaku [Al Qasim bin Abu Bazzah] dari [Sa'id bin Jubair], dia berkata; \"Saya berkata kepada [Ibnu Abbas]; \"Apakah ada taubat bagi orang yang membunuh seorang mukmin secara sengaja?\" Dia berkata; \"Tidak.\" Dan saya membacakan kepadanya ayat yang ada dalam surat Al Furqan: Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar. Dia berkata; \"Ini adalah ayat Makkiyah dan dihapus oleh ayat Madaniyah. Yaitu: Barang siapa yang membunuh seorang mukmin dengan sengaja maka balasannya adalah Neraka Jahannam"},"4567":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمَّارٍ الدُّهْنِيِّ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِأَنَّ ابْنَ عَبَّاسٍ سُئِلَ عَمَّنْ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا ثُمَّ تَابَ وَآمَنَ وَعَمِلَ صَالِحًا ثُمَّ اهْتَدَى فَقَالَ ابْنُ عَبَّاسٍ وَأَنَّى لَهُ التَّوْبَةُ سَمِعْتُ نَبِيَّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَجِيءُ مُتَعَلِّقًا بِالْقَاتِلِ تَشْخَبُ أَوْدَاجُهُ دَمًا يَقُولُ سَلْ هَذَا فِيمَ قَتَلَنِي ثُمَّ قَالَ وَاللَّهِ لَقَدْ أَنْزَلَهَا وَمَا نَسَخَهَا","id":"Telah mengabarkan kepada kami [Qutaibah] telah menceritakan kepada kami [Sufyan] dari ['Ammar Ad Duhni] dari [Salim bin Abu Al Ja'd] bahwa [Ibnu Abbas] ditanya mengenai orang yang membunuh orang mukmin dengan sengaja kemudian bertaubat, beriman dan melakukan amal Shalih kemudian mendapatkan petunjuk. Maka Ibnu Abbas berkata; Terlambat baginya taubat, Saya mendengar Nabi kalian shallallahu 'alaihi wasallam bersabda: \"Ia akan datang bergantung kepada orang yang membunuh sedang urat lehernya bercucuran darah, dia berkata; \"Tanyakan kepada orang ini, kenapa dia membunuhku.\" Kemudian dia berkata; \"Demi Allah, sungguh Dia telah menurunkannya dan tidak menghapusnya.\""},"4568":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا النَّضْرُ بْنُ شُمَيْلٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرٍ قَالَ سَمِعْتُ أَنَسًا يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْكَبَائِرُ الشِّرْكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ وَقَتْلُ النَّفْسِ وَقَوْلُ الزُّورِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [An Nadhr bin Syumail] telah menceritakan kepada kami [Syu'bah] dari ['Ubaidullah bin Abu Bakar], dia berkata; \"Saya mendengar [Anas] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda:... Disebutkan dari jalur lain: Telah menceritakan kepada kami [Muhammad bin Abdul A'la] telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Ubaidullah bin Abu Bakar] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dosa-dosa besar adalah; mensekutukan Allah, durhaka kepada kedua orang tua, membunuh jiwa, dan perkataan palsu.\""},"4569":{"ar":"أَخْبَرَنَا عَبْدَةُ بْنُ عَبْدِ الرَّحِيمِ قَالَ أَنْبَأَنَا ابْنُ شُمَيْلٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَنْبَأَنَا فِرَاسٌ قَالَ سَمِعْتُ الشَّعْبِيَّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْكَبَائِرُ الْإِشْرَاكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ وَقَتْلُ النَّفْسِ وَالْيَمِينُ الْغَمُوسُ","id":"Telah mengabarkan kepada kami ['Abdah bin Abdur Rahim] telah menceritakan kepada kami [Ibnu Syumail] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Firas], dia berkata; \"Saya mendengar [Asy Sya'bi] dari [Abdullah bin 'Amru] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: 'Dosa-dosa besar adalah: mensekutukan Allah, durhaka kepada kedua orang tua, membunuh jiwa, dan sumpah palsu.\""},"4570":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَ حَدَّثَنَا إِسْحَقُ الْأَزْرَقُ عَنْ الْفُضَيْلِ بْنِ غَزْوَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزْنِي الْعَبْدُ حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَشْرَبُ الْخَمْرَ حِينَ يَشْرَبُهَا وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلَا يَقْتُلُ وَهُوَ مُؤْمِنٌ","id":"Telah mengabarkan kepada kami [Abdur Rahman bin Muhammad bin Sallam] telah menceritakan kepada kami [Ishaq Al Azraq] dari [Al Fudhail bin Ghazwan] dari [Ikrimah] dari [Ibnu Abbas], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba berzina ketika dia berzina sementara dirinya dalam keadaan beriman, dan tidaklah ia minum Khamr ketika dia meminumnya sedang dia dalam keadaan beriman, tidaklah dia mencuri sedang dia dalam keadaan beriman dan tidaklah ia membunuh ketika dia dalam keadaan beriman.\""},"4571":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ اللَّيْثِ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ الْقَعْقَاعِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ السَّارِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلَا يَشْرَبُ الْخَمْرَ حِينَ يَشْرَبُهَا وَهُوَ مُؤْمِنٌ وَلَا يَنْتَهِبُ نُهْبَةً ذَاتَ شَرَفٍ يَرْفَعُ النَّاسُ إِلَيْهَا أَبْصَارَهُمْ وَهُوَ مُؤْمِنٌ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] telah menceritakan kepada kami [Syu'bah bin Al Laits] telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Al Qa'qa'] dari [Abu Shalih] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah pezina itu berzina ketika dia dalam keadaan beriman, dan tidaklah pencuri itu mencuri ketika dia dalam keadaan beriman, tidaklah dia meminum khamr ketika meminumnya sedangkan dia dalam keadaan beriman, dan tidaklah dia merampas suatu rampasan yang berharga dan menjadi daya tarik manusia ketika dia dalam keadaan beriman.\""},"4572":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ ح وَأَنْبَأَنَا أَحْمَدُ بْنُ سَيَّارٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَحْمَدُ فِي حَدِيثِهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلَا يَشْرَبُ الْخَمْرَ حِينَ يَشْرَبُ وَهُوَ مُؤْمِنٌ ثُمَّ التَّوْبَةُ مَعْرُوضَةٌ بَعْدُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Syu'bah] dari [Sulaiman]. Disebutkan dari jalur lain: Telah menceritakan kepada kami [Ahmad bin Sayyar] telah menceritakan kepada kami [Abdullah bin Utsman] dari [Abu Hamzah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam... dan Ahmad berkata di dalam haditsnya; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah pezina itu berzina ketika dia dalam keadaan beriman, dan tidaklah pencuri itu mencuri ketika dia dalam keadaan beriman, tidaklah dia meminum khamr ketika meminumnya sedangkan dia dalam keadaan beriman, kemudian taubah terbentang setelah itu.\" "},"4573":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى الْمَرْوَزِيُّ أَبُو عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ عَنْ أَبِي حَمْزَةَ عَنْ يَزِيدَ وَهُوَ ابْنُ أَبِي زِيَادٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَلَا يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلَا يَشْرَبُ الْخَمْرَ وَهُوَ مُؤْمِنٌ وَذَكَرَ رَابِعَةً فَنَسِيتُهَا فَإِذَا فَعَلَ ذَلِكَ خَلَعَ رِبْقَةَ الْإِسْلَامِ مِنْ عُنُقِهِ فَإِنْ تَابَ تَابَ اللَّهُ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya Al Marwazi Abu Ali] telah menceritakan kepada kami [Abdullah bin Utsman] dari [Abu Hamzah] dari [Yazid yaitu Ibnu Abu Ziyad] dari [Abu Shalih] dari [Abu Hurairah], dia berkata \"Tidaklah pezina itu berzina ketika dia dalam keadaan beriman, dan tidaklah pencuri itu mencuri ketika dia dalam keadaan beriman, tidaklah dia meminum khamr ketika meminumnya sedangkan dia dalam keadaan beriman, kemudian beliau menyebutkan yang keempat tetapi saya lupa.\"Apabila dia melakukan hal tersebut berarti dia telah melepas tali Islam dari lehernya, kemudian apabila dia bertaubat maka Allah menerima taubatnya.\""},"4574":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ الْمُخَرَّمِيُّ قَالَ حَدَّثَنَا أ��بُو مُعَاوِيَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ ح وَأَنْبَأَنَا أَحْمَدُ بْنُ حَرْبٍ عَنْ أَبِي مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ اللَّهُ السَّارِقَ يَسْرِقُ الْبَيْضَةَ فَتُقْطَعُ يَدُهُ وَيَسْرِقُ الْحَبْلَ فَتُقْطَعُ يَدُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak Al Mukharrami] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy]. Disebutkan dalam jalur lain: Telah menceritakan kepada kami [Ahmad bin Harb] dari [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] radliallahu 'anhu, dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah melaknat pencuri yang mencuri telur hingga tangannya dipotong dan mencuri tali hingga tangannya dipotong.\""},"4575":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ قَالَ حَدَّثَنِي صَفْوَانُ بْنُ عَمْرٍو قَالَ حَدَّثَنِي أَزْهَرُ بْنُ عَبْدِ اللَّهِ الْحَرَازِيُّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍأَنَّهُ رَفَعَ إِلَيْهِ نَفَرٌ مِنْ الْكَلَاعِيِّينَ أَنَّ حَاكَةً سَرَقُوا مَتَاعًا فَحَبَسَهُمْ أَيَّامًا ثُمَّ خَلَّى سَبِيلَهُمْ فَأَتَوْهُ فَقَالُوا خَلَّيْتَ سَبِيلَ هَؤُلَاءِ بِلَا امْتِحَانٍ وَلَا ضَرْبٍ فَقَالَ النُّعْمَانُ مَا شِئْتُمْ إِنْ شِئْتُمْ أَضْرِبْهُمْ فَإِنْ أَخْرَجَ اللَّهُ مَتَاعَكُمْ فَذَاكَ وَإِلَّا أَخَذْتُ مِنْ ظُهُورِكُمْ مِثْلَهُ قَالُوا هَذَا حُكْمُكَ قَالَ هَذَا حُكْمُ اللَّهِ عَزَّ وَجَلَّ وَرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Baqiyah bin Al Walid] telah menceritakan kepadaku [Shafwan bin 'Amru] telah menceritakan kepadaku [Azhar bin Abdullah Al Harazi] dari [An Nu'man bin Basyir] bahwa beberapa orang Kala' (kabilah dari Yaman) mengadu kepadanya bahwa orang-orang Hakah mencuri harta. Lalu dia memenjarakan mereka beberapa hari kemudian membebaskanya, mereka (orang-orang Kala') menemuinya dan berkata engkau membebaskannya tanpa engkau uji atau engkau pukul? lalu Nu'man berkata; terserah kalian, jika kalian mau maka aku akan memukul mereka, jika saja Allah mengembalikan harta kalian maka itulah milik kalian namun jika tidak aku akan melakukan seperti yang aku lakukan pada mereka, mereka berkata; \"Inikah hukummu?\" Dia berkata; \"Ini adalah hukum Allah Azza wa jalla dan RasulNya shallallahu 'alaihi wasallam.\""},"4576":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ أَخْبَرَنِي ابْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَبَسَ نَاسًا فِي تُهْمَةٍ","id":"Telah mengabarkan kepada kami [Abdur Rahman bin Muhammad bin Sallam] telah menceritakan kepada kami [Abu Usamah], ia berkata; telah menceritakan kepadaku [Ibnu Al Mubarak] dari [Ma'mar] dari [Bahz bin Hakim] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam memenjarakan beberapa orang Karena sebuah tuduhan."},"4577":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ سَعِيدِ بْنِ مَسْرُوقٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَبَسَ رَجُلًا فِي تُهْمَةٍ ثُمَّ خَلَّى سَبِيلَهُ","id":"Telah mengabarkan kepada kami [Ali bin Sa'id bin Masruq] telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Ma'mar] dari [Bahz bin Hakim] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam memenjarakan seseorang karena sebuah tuduhan kemudian melepaskannya."},"4578":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَبِي الْمُنْذِرِ مَوْلَى أَبِي ذَرٍّ عَنْ أَبِي أُمَيَّةَ الْمَخْزُومِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِلِصٍّ اعْتَرَفَ اعْتِرَافًا وَلَمْ يُوجَدْ مَعَهُ مَتَاعٌ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا إِخَالُكَ سَرَقْتَ قَالَ بَلَى قَالَ اذْهَبُوا بِهِ فَاقْطَعُوهُ ثُمَّ جِيئُوا بِهِ فَقَطَعُوهُ ثُمَّ جَاءُوا بِهِ فَقَالَ لَهُ قُلْ أَسْتَغْفِرُ اللَّهَ وَأَتُوبُ إِلَيْهِ فَقَالَ أَسْتَغْفِرُ اللَّهَ وَأَتُوبُ إِلَيْهِ قَالَ اللَّهُمَّ تُبْ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Hammad bin Salamah] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Abu Al Mundzir], budak Abu Dzar yang sudah dimerdekakan, dari [Abu Umayyah Al Makhzumi] bahwa dihadapkan kepada Rasulullah shallallahu 'alaihi wasallam seorang pencuri yang memberikan sebuah pengakuan, padahal tidak didapatkan barang bersamanya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Saya kira engkau tidak mencuri.\" Kemudian orang tersebut mengatakan; \"Benar (saya mencuri). Beliau bersabda: \"Bawalah orang ini dan potonglah tangannya.\" Kemudian mereka memotongnya lalu dihadapkan kembali kepada beliau. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Katakanlah, saya meminta ampun kepada Allah dan bertaubat kepadaNya.\" Maka orang tersebut mengatakan; \"Saya meminta ampun kepada Allah dan bertaubat kepadaNya.\" Beliau bersabda: \"Ya Allah, terimalah taubatnya.\""},"4579":{"ar":"أَخْبَرَنَا هِلَالُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ عَطَاءٍ عَنْ صَفْوَانَ بْنِ أُمَيَّةَأَنَّ رَجُلًا سَرَقَ بُرْدَةً لَهُ فَرَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِقَطْعِهِ فَقَالَ يَا رَسُولَ اللَّهِ قَدْ تَجَاوَزْتُ عَنْهُ فَقَالَ أَبَا وَهْبٍ أَفَلَا كَانَ قَبْلَ أَنْ تَأْتِيَنَا بِهِ فَقَطَعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Hilal bin Al 'Ala`] telah menceritakan kepadaku [ayahku] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Sa'id] dari [Qatadah] dari ['Atho`] dari [Shafwan bin Umayyah] bahwa seorang laki-laki telah mencuri selendangnya, kemudian dia melaporkannya kepada Nabi shallallahu 'alaihi wasallam lalu beliau memerintahkannya untuk memotong tangannya. Kemudian Shafwan berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam saya telah memaafkannya.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Abu Wahb, Kenapa engkau tidak mengatakannya sebelum engkau datang kepada kami?\" kemudian Rasulullah shallallahu 'alaihi wasallam memotong tangannya. "},"4580":{"ar":"أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ أَحْمَدَ بْنِ مُحَمَّدِ بْنِ حَنْبَلٍ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ عَطَاءٍ عَنْ طَارِقِ بْنِ مُرَقَّعٍ عَنْ صَفْوَانَ بْنِ أُمَيَّةَأَنَّ رَجُلًا سَرَقَ بُرْدَةً فَرَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِقَطْعِهِ فَقَالَ يَا رَسُولَ اللَّهِ قَدْ تَجَاوَزْتُ عَنْهُ قَالَ فَلَوْلَا كَانَ هَذَا قَبْلَ أَنْ تَأْتِيَنِي بِهِ يَا أَبَا وَهْبٍ فَقَطَعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepadaku [Abdullah bin Ahmad bin Muhammad bin Hanbal] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari ['Atho`] dari [Thariq bin Muraqqa'] dari [Shafwan bin Umayyah] bahwa seorang laki-laki telah mencuri selendangnya, kemudian dia melaporkannya kepada Nabi shallallahu 'alaihi wasallam lalu beliau memerintahkan agar dipotong tangannya. Lalu Shafwan berkata; \"Wahai Rasulullah, saya telah memaafkannya.\" Beliau bersabda: \"Andaikan hal ini terjadi sebelum engkau membawanya kepadaku wahai Abu Wahb?\" Kemudian Rasulullah memotong tangannya. "},"4581":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ نُعَيْمٍ قَالَ أَنْبَأَنَا حِبَّانُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي عَطَاءُ بْنُ أَبِي رَبَاحٍأَنَّ رَجُلًا سَرَقَ ثَوْبًا فَأُتِيَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِقَطْعِهِ فَقَالَ الرَّجُلُ يَا رَسُولَ اللَّهِ هُوَ لَهُ قَالَ فَهَلَّا قَبْلَ الْآنَ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim bin Nu'aim] telah menceritakan kepada kami [Hibban] telah menceritakan kepada kami [Abdullah] dari [Al Auza'i] telah menceritakan kepadaku ['Atho`bin Abu Rabah] bahwa seorang laki-laki mencuri pakaian, lalu dia dihadapkan kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau memerintahkan untuk memotong tangannya. Seorang laki-laki berkata; \"Wahai Rasulullah, itu adalah miliknya, beliau bersabda: \" Kenapa kamu tidak mengatakannya sebelum ini.\""},"4582":{"ar":"أَخْبَرَنِي هِلَالُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا حُسَيْنٌ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ هُوَ ابْنُ أَبِي بَشِيرٍ قَالَ حَدَّثَنِي عِكْرِمَةُ عَنْ صَفْوَانَ بْنِ أُمَيَّةَأَنَّهُ طَافَ بِالْبَيْتِ وَصَلَّى ثُمَّ لَفَّ رِدَاءً لَهُ مِنْ بُرْدٍ فَوَضَعَهُ تَحْتَ رَأْسِهِ فَنَامَ فَأَتَاهُ لِصٌّ فَاسْتَلَّهُ مِنْ تَحْتِ رَأْسِهِ فَأَخَذَهُ فَأَتَى بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ هَذَا سَرَقَ رِدَائِي فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسَرَقْتَ رِدَاءَ هَذَا قَالَ نَعَمْ قَالَ اذْهَبَا بِهِ فَاقْطَعَا يَدَهُ قَالَ صَفْوَانُ مَا كُنْتُ أُرِيدُ أَنْ تُقْطَعَ يَدُهُ فِي رِدَائِي فَقَالَ لَهُ فَلَوْ مَا قَبْلَ هَذَاخَالَفَهُ أَشْعَثُ بْنُ سَوَّارٍ","id":"Telah mengabarkan kepadaku [Hilal bin Al 'Ala`] telah menceritakan kepada kami [Husain] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abdul Malik yaitu Ibnu Abu Basyir] telah menceritakan kepadaku [Ikrimah] dari [Shafwan bin Umayyah] bahwa dia melakukan Thawaf di Ka'bah dan melakukan shalat kemudian melipat selendangnya dan meletakkannya di bawah kepala kemudian tidur. Lalu datanglah seorang pencuri kepadanya dan mengambil selendang tersebut dari bawah kepalanya. Shafwan menangkapnya dan membawanya kepada Nabi shallallahu 'alaihi wasallam. Dia berkata; \"Orang ini telah mencuri selendangku. Kemudian Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Apakah engkau mencuri selendang ini?\" orang tersebut mengatakan; \"Ya.\" Beliau bersabda: \"Pergilah bawalah orang ini pergi dan potonglah tangannya.\" Shafwan berkata; \"Saya tidak menginginkan tangannya dipotong karena selendangku.\" Kemudian beliau bersabda: \"Seandainya engkau katakan sebelum ini.\" Asy'ats bin Sawwar menyelisihi hal ini. "},"4583":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ هِشَامٍ يَعْنِي ابْنَ أَبِي خِيَرَةَ قَالَ حَدَّثَنَا الْفَضْلُ يَعْنِي ابْنَ الْعَلَاءِ الْكُوفِيَّ قَالَ حَدَّثَنَا أَشْعَثُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ صَفْوَانُ نَائِمًا فِي الْمَسْجِدِ وَرِدَاؤُهُ تَحْتَهُ فَسُرِقَ فَقَامَ وَقَدْ ذَهَبَ الرَّجُلُ فَأَدْرَكَهُ فَأَخَذَهُ فَجَاءَ بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِقَطْعِهِ قَالَ صَفْوَانُ يَا رَسُولَ اللَّهِ مَا بَلَغَ رِدَائِي أَنْ يُقْطَعَ فِيهِ رَجُلٌ قَالَ هَلَّا كَانَ هَذَا قَبْلَ أَنْ تَأْتِيَنَا بِهِقَالَ أَبُو عَبْد الرَّحْمَنِ أَشْعَثُ ضَعِيفٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Hisyam yaitu Ibnu Abu Khiyarah] telah menceritakan kepada kami [Al Fadhl yaitu Ibnu Al 'Ala` Al Kufi] telah menceritakan kepada kami [Asy'ats] dari [Ikrimah] dari [Ibnu Abbas], dia berkata; \"Shafwan pernah tidur di masjid sedang selendangnya berada di bawahnya kemudian selendang terebut dicuri. Dia kemudian bangun tetapi orang yang mencuri telah pergi. Lalu dia mengejarnya dan menangkapnya serta membawanya kepada Nabi shallallahu 'alaihi wasallam. Lalu beliau memerintahkannya agar dipotong tangannya. Shafwan berkata; \"Wahai Rasulullah, selendangku tidaklah sampai membuat orang tersebut harus dipotong tangannya.\" Maka beliau bersabda: \"Kenapa ini tidak terjadi sebelum engkau membawanya kepadaku?\" Abu Abdur Rahman berkata; Asy'ats adalah lemah. "},"4584":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا عَمْرٌو عَنْ أَسْبَاطٍ عَنْ سِمَاكٍ عَنْ حُمَيْدٍ ابْنِ أُخْتِ صَفْوَانَ عَنْ صَفْوَانَ بْنِ أُمَيَّةَ قَالَكُنْتُ نَائِمًا فِي الْمَسْجِدِ عَلَى خَمِيصَةٍ لِي ثَمَنُهَا ثَلَاثُونَ دِرْهَمًا فَجَاءَ رَجُلٌ فَاخْتَلَسَهَا مِنِّي فَأُخِذَ الرَّجُلُ فَأُتِيَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِهِ لِيُقْطَعَ فَأَتَيْتُهُ فَقُلْتُ أَتَقْطَعُهُ مِنْ أَجْلِ ثَلَاثِينَ دِرْهَمًا أَنَا أَبِيعُهُ وَأُنْسِئُهُ ثَمَنَهَا قَالَ فَهَلَّا كَانَ هَذَا قَبْلَ أَنْ تَأْتِيَنِي بِهِ","id":"Telah mengabarkan kepadaku [Ahmad bin Utsman bin Hakim] telah menceritakan kepada kami ['Amru] dari [Asbath] dari [Simak] dari [Humaid] anak saudara wanita Shafwan dari [Shafwan bin Umayyah], dia berkata; \"Saya pernah tidur di masjid di atas bajuku yang harganya tiga puluh dirham, kemudian datang seorang laki-laki dan mencurinya dariku. Lalu orang tersebut ditangkap dan dibawa kepada Nabi shallallahu 'alaihi wasallam. Beliau memerintahkan agar tangannya dipotong, Lalu saya mendatangi beliau seraya berkata; \"Apakah Tuan akan memotongnya karena tiga puluh dirham? saya menjualnya dan menghutangkan harganya. Beliau bersabda: \"Kenapa hal ini tidak terjadi (kau katakana) sebelum engkau membawanya kepadaku?\""},"4585":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنَا أَسَدُ بْنُ مُوسَى قَالَ حَدَّثَنَا وَذَكَرَ حَمَّادُ بْنُ سَلَمَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ صَفْوَانَ بْنِ أُمَيَّةَأَنَّهُ سُرِقَتْ خَمِيصَتُهُ مِنْ تَحْتِ رَأْسِهِ وَهُوَ نَائِمٌ فِي مَسْجِدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَ اللِّصَّ فَجَاءَ بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِقَطْعِهِ فَقَالَ صَفْوَانُ أَتَقْطَعُهُ قَالَ فَهَلَّا قَبْلَ أَنْ تَأْتِيَنِي بِهِ تَرَكْتَهُ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdullah bin Abdur Rahim], dia berkata; telah menceritakan kepada kami [Asad bin Musa], dia berkata; telah menceritakan dan menyebutkan kepada kami [Hammad bin Salamah] dari ['Amr bin Dinar] dari [Thawus] dari [Shafwan bin Umayyah] bahwa pakaiannya dicuri dari kepalanya ketika dia sedang tidur di masjid Nabi shallallahu 'alaihi wasallam. Kemudian dia menangkap pencuri tersebut dan membawanya kepada Nabi shallallahu 'alaihi wasallam, lalu beliau memerintahkan agar dipotong tangannya. Kemudian Shafwan berkata; \"Apakah Tuan akan memotong tangannya?\" Beliau bersabda: \"Tidakkah engkau membiarkannya sebelum engkau membawanya kepadaku?\" "},"4586":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ هَاشِمٍ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَعَافَوْا الْحُدُودَ قَبْلَ أَنْ تَأْتُونِي بِهِ فَمَا أَتَانِي مِنْ حَدٍّ فَقَدْ وَجَبَ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Hasyim], dia berkata; telah menceritakan kepada kami [Al Walid], dia berkata; telah menceritakan kepada kami [Ibnu Juraij] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Saling memaafkanlah kalian dari hukuman sebelum kalian mendatangiku karena hukuman yang telah sampai kepadaku wajib dilaksanakan.\""},"4587":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ امْرَأَةً مَخْزُومِيَّةً كَانَتْ تَسْتَعِيرُ الْمَتَاعَ فَتَجْحَدُهُ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَطْعِ يَدِهَا","id":"Telah mengkhabarkan kepada kami [Mahmud bin Ghailan], dia berkata; telah menceritakan kepada kami [Abdur Razzaq], dia berkata; telah memberitakan kepada kami [Ma'mar] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar radliallahu 'anhuma] bahwa seorang wanita dari Bani Makhzum meminjam barang, lalu dia mengingkarinya, kemudian Nabi shallallahu 'alaihi wasallam memerintahkan untuk memotong tangannya."},"4588":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَتْ امْرَأَةٌ مَخْزُومِيَّةٌ تَسْتَعِيرُ مَتَاعًا عَلَى أَلْسِنَةِ جَارَاتِهَا وَتَجْحَدُهُ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَطْعِ يَدِهَا","id":"Telah mengkhabarkan kepada kami [Ishaq bin Ibrahim], dia berkata; telah memberitakan kepada kami [Abdur Razzaq], dia berkata; telah memberitakan kepada kami [Ma'mar] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar radliallahu 'anhuma], dia berkata; \"Ada seorang wanita Makhzum yang meminjam barang melalui lisan beberapa wanita tetangganya, lalu dia mengingkarinya. Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan agar tangannya dipotong.\" "},"4589":{"ar":"أَخْبَرَنَا عُثْمَانُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي الْحَسَنُ بْنُ حَمَّادٍ قَالَ حَدَّثَنَا عَمْرُو بْنُ هَاشِمٍ الْجَنْبِيُّ أَبُو مَالِكٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ امْرَأَةً كَانَتْ تَسْتَعِيرُ الْحُلِيَّ لِلنَّاسِ ثُمَّ تُمْسِكُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِتَتُبْ هَذِهِ الْمَرْأَةُ إِلَى اللَّهِ وَرَسُولِهِ وَتَرُدَّ مَا تَأْخُذُ عَلَى الْقَوْمِ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُمْ يَا بِلَالُ فَخُذْ بِيَدِهَا فَاقْطَعْهَا","id":"Telah mengkhabarkan kepada kami [Utsman bin Abdullah], dia berkata; telah menceritakan kepadaku [Al Hasan bin Hammad], dia berkata; telah menceritakan kepada kami ['Amr bin Hasyim Al Janbi Abu Malik] dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar radliallahu 'anhuma] bahwa ada seorang wanita meminjam perhiasan milik orang kemudian ia menahannya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita ini hendaknya bertaubat kepada Allah dan RasulNya serta mengembalikan apa yang telah dia ambil dari orang-orang tersebut.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berdirilah wahai Bilal ambil tangannya lalu potonglah.\""},"4590":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْدَانَ بْنِ عِيسَى قَالَ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ قَالَ حَدَّثَنَا مَعْقِلٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ امْرَأَةً مِنْ بَنِي مَخْزُومٍ سَرَقَتْ فَأُتِيَ بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَاذَتْ بِأُمِّ سَلَمَةَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كَانَتْ فَاطِمَةَ بِنْتَ مُحَمَّدٍ لَقَطَعْتُ يَدَهَا فَقُطِعَتْ يَدُهَا","id":"Telah mengkhabarkan kepada kami [Muhammad bin Ma'dan bin Isa], dia berkata; telah menceritakan kepada kami [Al Hasan bin Al A'yan], dia berkata; telah menceritakan kepada kami [Ma'qil] dari [Abu Az Zubair] dari [Jabir] bahwa seorang wanita dari Bani Makhzum mencuri, kemudian dihadapkan kepada Nabi shallallahu 'alaihi wasallam. Kemudian dia meminta perlindungan kepada Ummu Salamah. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya dia adalah Fathimah binti Muhammad niscaya akan saya potong tangannya.\" Kemudian tangan wanita tersebut dipotong. "},"4591":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِأَنَّ امْرَأَةً مِنْ بَنِي مَخْزُومٍ اسْتَعَارَتْ حُلِيًّا عَلَى لِسَانِ أُنَاسٍ فَجَحَدَتْهَا فَأَمَرَ بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُطِعَتْأَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا هَمَّامٌ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ دَاوُدَ بْنِ أَبِي عَاصِمٍ أَنَّ سَعِيدَ بْنَ الْمُسَيَّبِ حَدَّثَهُ نَحْوَهُ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Al Mutsanna], dia berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam], dia berkata; telah menceritakan kepada kami [ayahku] dari [Qatadah] dari [Sa'id bin Yazid] dari [Sa'id bin Al Musayyab] bahwa seorang wanita dari Bani Makhzum meminjam perhiasan melalui lisan orang-orang, kemudian dia mengingkarinya. Lalu Nabi shallallahu 'alaihi wasallam memerintahkan untuk memotong tangannya. Telah mengkhabarkan kepada kami [Muhammad bin Al Mutsanna], dia berkata; telah menceritakan kepada kami [Abdus Shamad], dia berkata; telah menceritakan kepada kami [Hammam], dia berkata; telah menceritakan kepada kami [Qatadah] dari [Dawud bin Abu 'Ashim] bahwa [Sa'id bin Al Musayyab] bercerita kepadanya semisal itu."},"4592":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ قَالَكَانَتْ مَخْزُومِيَّةٌ تَسْتَعِيرُ مَتَاعًا وَتَجْحَدُهُ فَرُفِعَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكُلِّمَ فِيهَا فَقَالَ لَوْ كَانَتْ فَاطِمَةَ لَقَطَعْتُ يَدَهَاقِيلَ لِسُفْيَانَ مَنْ ذَكَرَهُ قَالَ أَيُّوبُ بْنُ مُوسَى عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ إِنْ شَاءَ اللَّهُ تَعَالَى","id":"Telah mengkhabarkan kepada kami [Ishaq bin Ibrahim], dia berkata; telah memberitakan kepada kami [Sufyan], ia berkata; \"Ada seorang wanita Makhzum yang meminjam barang dan dia mengingkarinya. Kemudian dia dilaporkan kepada Rasulullah shallallahu 'alaihi wasallam dan dibicarakan mengenai wanita tersebut. Kemudian beliau bersabda: \"Sendainya dia adalah Fathimah niscaya saya potong tangannya.\" Dikatakan kepada Sufyan; 'Siapakah yang menyebutkannya?\" Dia berkata; \" [Ayyub bin Musa] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] insya Allah Ta'ala.\" "},"4593":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ امْرَأَةً سَرَقَتْ فَأُتِيَ بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا مَنْ يَجْتَرِئُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا أَنْ يَكُونَ أُسَامَةَ فَكَلَّمُوا أُسَامَةَ فَكَلَّمَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أُسَامَةُ إِنَّمَا هَلَكَتْ بَنُو إِسْرَائِيلَ حِينَ كَانُوا إِذَا أَصَابَ الشَّرِيفُ فِيهِمْ الْحَدَّ تَرَكُوهُ وَلَمْ يُقِيمُوا عَلَيْهِ وَإِذَا أَصَابَ الْوَضِيعُ أَقَامُوا عَلَيْهِ لَوْ كَانَتْ فَاطِمَةَ بِنْتَ مُحَمَّدٍ لَقَطَعْتُهَا","id":"Telah mengkhabarkan kepada kami [Muhammad bin Manshur], dia berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub bin Musa] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] bahwa ada seorang wanita yang mencuri kemudian dia dihadapkan kepada Nabi shallallahu 'alaihi wasallam, kemudian mereka berkata; \"Tidak ada orang yang berani berbicara kepada Rasulullah shallallahu 'alaihi wasallam kecuali Usamah. Kemudian mereka berbicara kepada Usamah. Maka Usamahpun berbicara kepada beliau. Nabi shallallahu 'alaihi wasallam kemudian bersabda: \"Wahai Usamah, sesungguhnya orang-orang Bani Israil binasa ketika orang mulia di antara mereka terkena hukuman had, mereka membiarkannya dan tidak menegakkan hukuman kepadanya, dan apabila hukuman tersebut mengenai orang yang rendah maka mereka menegakkan hukuman atasnya. Seandainya dia adalah Fathimah binti Muhammad niscaya saya akan memotong tangannya.\""},"4594":{"ar":"أَخْبَرَنَا رِزْقُ اللَّهِ بْنُ مُوسَى قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَارِقٍ فَقَطَعَهُ قَالُوا مَا كُنَّا نُرِيدُ أَنْ يَبْلُغَ مِنْهُ هَذَا قَالَ لَوْ كَانَتْ فَاطِمَةَ لَقَطَعْتُهَا","id":"Telah mengkhabarkan kepada kami [Rizqullah bin Musa], dia berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub bin Musa] dari [Az Zuhri] dari ['Urwah] dari [Aisyah], dia berkata; Telah dihadapkan seorang pencuri kepada Nabi shallallahu 'alaihi wasallam kemudian beliau memotong tangannya. Mereka mengatakan; \"Kami tidak ingin hal ini terjadi padanya.\" Beliau bersabda: \"Seandainya dia adalah Fathimah niscaya saya akan memotong tangannya.\""},"4595":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ سَعِيدِ بْنِ مَسْرُوقٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ امْرَأَةً سَرَقَتْ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا مَا نُكَلِّمُهُ فِيهَا مَا مِنْ أَحَدٍ يُكَلِّمُهُ إِلَّا حِبُّهُ أُسَامَةُ فَكَلَّمَهُ فَقَالَ يَا أُسَامَةُ إِنَّ بَنِي إِسْرَائِيلَ هَلَكُوا بِمِثْلِ هَذَا كَانَ إِذَا سَرَقَ فِيهِمْ الشَّرِيفُ تَرَكُوهُ وَإِنْ سَرَقَ فِيهِمْ الدُّونُ قَطَعُوهُ وَإِنَّهَا لَوْ كَانَتْ فَاطِمَةَ بِنْتَ مُحَمَّدٍ لَقَطَعْتُهَا","id":"Telah mengkhabarkan kepada kami [Ali bin Sa'id bin Masruq], dia berkata; telah menceritakan kepada kami [Yahya bin Zakariya bin Abu Zaidah] dari [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] bahwa pada zaman Rasulullah shallallahu 'alaihi wasallam ada seorang wanita yang mencuri, kemudian orang-orang berkata; \"Kami tidak akan berbicara kepada beliau mengenainya, tidak ada seorangpun yang bias berbicara kepada beliau kecuali orang yang dicintai beliau yaitu Usamah. Kemudian Usamah berbicara kepada beliau. Beliau bersabda: \"Wahai Usamah, sesungguhnya Bani Israil binasa karena kejadian seperti ini. Apabila ada orang mulia di antara mereka mencuri maka mereka membiarkannya tapi apabila ada orang rendah di antara mereka mencuri, mereka memotong tangannya. Sesungguhnya apabila dia adalah Fathimah binti Muhammad niscaya saya potong tangannya.\""},"4596":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ شُعَيْبٍ قَالَ أَخْبَرَنِي أَبِي عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْاسْتَعَارَتْ امْرَأَةٌ عَلَى أَلْسِنَةِ أُنَاسٍ يُعْرَفُونَ وَهِيَ لَا تُعْرَفُ حُلِيًّا فَبَاعَتْهُ وَأَخَذَتْ ثَمَنَهُ فَأُتِيَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَعَى أَهْلُهَا إِلَى أُسَامَةَ بْنِ زَيْدٍ فَكَلَّمَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُكَلِّمُهُ ثُمَّ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَشْفَعُ إِلَيَّ فِي حَدٍّ مِنْ حُدُودِ اللَّهِ فَقَالَ أُسَامَةُ اسْتَغْفِرْ لِي يَا رَسُولَ اللَّهِ ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشِيَّتَئِذٍ فَأَثْنَى عَلَى اللَّهِ عَزَّ وَجَلَّ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّمَا هَلَكَ النَّاسُ قَبْلَكُمْ أَنَّهُمْ كَانُوا إِذَا سَرَقَ الشَّرِيفُ فِيهِمْ تَرَكُوهُ وَإِذَا سَرَقَ الضَّعِيفُ فِيهِمْ أَقَامُوا عَلَيْهِ الْحَدَّ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَوْ أَنَّ فَاطِمَةَ بِنْتَ مُحَمَّدٍ سَرَقَتْ لَقَطَعْتُ يَدَهَا ثُمَّ قَطَعَ تِلْكَ الْمَرْأَةَ","id":"Telah mengkhabarkan kepada kami [Imran bin Bakkar], dia berkata; telah menceritakan kepada kami [Bisyr bin Syu'aib], dia berkata; telah mengkhabarkan kepadaku [ayahku] dari [Az Zuhri] dari ['Urwah] dari [Aisyah], dia berkata; \"Seorang wanita meminjam perhiasan melalui lisan orang-orang yang dikenal sedang dia tidak dikenal. Lalu dia jual perhiasan tersebut dan ia ambil uangnya. Kemudian dia dihadapkan kepada Rasulullah shallallahu 'alaihi was sallam. Lalu keluarganya berusaha menemui Usamah bin Zaid. Usamah kemudian berbicara kepada Rasulullah shallallahu 'alaihi was sallam tentang wanita tersebut. Maka meronalah wajah Rasulullah shallallahu 'alaihi was sallam sementara Usamah berbicara. Kemudian Rasulullah shallallahu 'alaihi was sallam bersabda; \"Apakah kamu hendak meminta syafa'at (keringanan) kepadaku atas hokum yang ditetapkan Allah?\" Usamah berkata; \"Mohonkanlah ampunan untukku, wahai Rasul Allah.\" Sontak Rasulullah shallallahu 'alaihi was sallam berdiri lalu memuji pada Alloh 'azza wajalla dengan pujian yang menjadi hakNya kemudian bersabda, \"Amma ba'du, Sesungguhnya orang-orang sebelum kalian binasa karena apabila ada orang yang mulia di antara mereka mencuri mereka membiarkannya, sedang apabila orang yang lemah di antara mereka mencuri mereka tegakkan had (hukuman) atasnya. Demi Dzat yang jiwa Muhammad ada di tanganNya, seandainya Fathimah binti Muhammad mencuri niscaya aku potong tangannya.\" Lalu dipotonglah tangan wanita tersebut."},"4597":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ قُرَيْشًا أَهَمَّهُمْ شَأْنُ الْمَخْزُومِيَّةِ الَّتِي سَرَقَتْ فَقَالُوا مَنْ يُكَلِّمُ فِيهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا وَمَنْ يَجْتَرِئُ عَلَيْهِ إِلَّا أُسَامَةُ بْنُ زَيْدٍ حِبُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَلَّمَهُ أُسَامَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَشْفَعُ فِي حَدٍّ مِنْ حُدُودِ اللَّهِ ثُمَّ قَامَ فَخَطَبَ فَقَالَ إِنَّمَا هَلَكَ الَّذِينَ قَبْلَكُمْ أَنَّهُمْ كَانُوا إِذَا سَرَقَ فِيهِمْ الشَّرِيفُ تَرَكُوهُ وَإِذَا سَرَقَ فِيهِمْ الضَّعِيفُ أَقَامُوا عَلَيْهِ الْحَدَّ وَايْمُ اللَّهِ لَوْ أَنَّ فَاطِمَةَ بِنْتَ مُحَمَّدٍ سَرَقَتْ لَقَطَعْتُ يَدَهَا","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] bahwa orang-orang Quraisy disibukkan oleh perkara wanita Makhzum yang mencuri, kemudian mereka berkata; \"Siapakah yang akan berbicara kepada Rasulullah shallallahu 'alaihi wasallam?\" Orang-orang berkata; \"Tidak ada yang berani kecuali Usamah bin Zaid, orang yang dicintai Rasulullah shallallahu 'alaihi wasallam.\" Kemudian Usamah berbicara kepada beliau. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah engkau akan memberikan pertolongan dalam perkara had di antara had-had Allah?\" kemudian beliau berdiri lalu berkhutbah, beliau bersabda: \"Sesungguhnya orang-orang sebelum kalian binasa karena apabila terdapat orang mulia di antara mereka yang mencuri maka mereka membiarkannya sedang apabila terdapat orang yang lemah di antara mereka mencuri maka mereka menegakkan hukuman atasnya. Demi Allah apabila Fathimah binti Muhammad mencuri niscaya saya potong tangannya.\" "},"4598":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا أَبُو الْجَوَّابِ قَالَ حَدَّثَنَا عَمَّارُ بْنُ رُزَيْقٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ مُحَمَّدِ بْنِ مُسْلِمٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْسَرَقَتْ امْرَأَةٌ مِنْ قُرَيْشٍ مِنْ بَنِي مَخْزُومٍ فَأُتِيَ بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا مَنْ يُكَلِّمُهُ فِيهَا قَالُوا أُسَامَةُ بْنُ زَيْدٍ فَأَتَاهُ فَكَلَّمَهُ فَزَبَرَهُ وَقَالَ إِنَّ بَنِي إِسْرَائِيلَ كَانُوا إِذَا سَرَقَ فِيهِمْ الشَّرِيفُ تَرَكُوهُ وَإِذَا سَرَقَ الْوَضِيعُ قَطَعُوهُ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ أَنَّ فَاطِمَةَ بِنْتَ مُحَمَّدٍ سَرَقَتْ لَقَطَعْتُهَا","id":"Telah mengkhabarkan kepada kami [Abu Bakar bin Ishaq], dia berkata; telah menceritakan kepada kami [Abu Al Jawwab], dia berkata; telah menceritakan kepada kami ['Ammar bin Ruzaiq] dari [Muhammad bin Abdur Rahman bin Abu Laila] dari [Isma'il bin Umayyah] dari [Muhammad bin Muslim] dari ['Urwah] dari [Aisyah], dia berkata; \"Ada seorang wanita dari suku Quraisy dari Bani Makhzum mencuri lalu dihadapkan kepada Nabi shallallahu 'alaihi wasallam, kemudian mereka berkata; \"Siapakah yang berbicara kepada beliau mengenainya? Yang lainnya mengatakan; \"Usamah bin Zaid.\" Kemudian Usamah datang dan berbicara kepada beliau. Kemudian beliau menghardiknya seraya bersabda: \"Sesungguhnya Bani Isroil, apabila ada orang mulia di antara mereka mencuri maka mereka membiarkannya sedang apabila ada orang yang rendah di antara mereka mencuri, mereka menegakkan hukuman atasnya. Demi Allah, apabila Fathimah binti Muhammad mencuri niscaya saya potong tangannya.\" "},"4599":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ جَبَلَةَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى بْنِ أَعْيَنَ قَالَ حَدَّثَنَا أَبِي عَنْ إِسْحَقَ بْنِ رَاشِدٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ قُرَيْشًا أَهَمَّهُمْ شَأْنُ الْمَخْزُومِيَّةِ الَّتِي سَرَقَتْ فَقَالُوا مَنْ يُكَلِّمُ فِيهَا قَالُوا مَنْ يَجْتَرِئُ عَلَيْهِ إِلَّا أُسَامَةُ بْنُ زَيْدٍ حِبُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَلَّمَهُ أُسَامَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا هَلَكَ الَّذِينَ مَنْ قَبْلِكُمْ أَنَّهُمْ كَانُوا إِذَا سَرَقَ فِيهِمْ الشَّرِيفُ تَرَكُوهُ وَإِذَا سَرَقَ فِيهِمْ الضَّعِيفُ أَقَامُوا عَلَيْهِ الْحَدَّ وَايْمُ اللَّهِ لَوْ سَرَقَتْ فَاطِمَةُ بِنْتُ مُحَمَّدٍ لَقَطَعْتُ يَدَهَا","id":"Telah mengkhabarkan kepada kami [Muhammad bin Jabalah], dia berkata; telah menceritakan kepada kami [Muhammad bin Musa bin A'yan], ia berkata; telah menceritakan kepada kami [ayahku] dari [Ishaq bin Rasyid] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] bahwa orang-orang Quraisy disibukkan oleh perkara wanita Makhzum yang mencuri, kemudian mereka berkata; \"Siapakah yang akan berbicara kepada Rasulullah shallallahu 'alaihi wasallam?\" Orang-orang yang lain mengatakan; \"Tidak ada yang berani kecuali Usamah bin Zaid orang yang dicintai Rasulullah shallallahu 'alaihi wasallam.\" Kemudian Usamah berbicara kepada beliau. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya orang-orang sebelum kalian binasa karena apabila terdapat orang mulia di antara mereka yang mencuri maka mereka membiarkannya sedang apabila terdapat orang yang lemah di antara mereka mencuri maka mereka menegakkan hukuman atasnya. Demi Allah, apabila Fathimah binti Muhammad mencuri niscaya saya potong tangannya.\""},"4600":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَنَّ عُرْوَةَ بْنَ الزُّبَيْرِ أَخْبَرَهُ عَنْ عَائِشَةَأَنَّ امْرَأَةً سَرَقَتْ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ الْفَتْحِ فَأُتِيَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَلَّمَهُ فِيهَا أُسَامَةُ بْنُ زَيْدٍ فَلَمَّا كَلَّمَهُ تَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَشْفَعُ فِي حَدٍّ مِنْ حُدُودِ اللَّهِ فَقَالَ لَهُ أُسَامَةُ اسْتَغْفِرْ لِي يَا رَسُولَ اللَّهِ فَلَمَّا كَانَ الْعَشِيُّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَثْنَى عَلَى اللَّهِ عَزَّ وَجَلَّ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ إِنَّمَا هَلَكَ النَّاسُ قَبْلَكُمْ أَنَّهُمْ كَانُوا إِذَا سَرَقَ فِيهِمْ الشَّرِيفُ تَرَكُوهُ وَإِذَا سَرَقَ فِيهِمْ الضَّعِيفُ أَقَامُوا عَلَيْهِ الْحَدَّ ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ أَنَّ فَاطِمَةَ بِنْتَ مُحَمَّدٍ سَرَقَتْ قَطَعْتُ يَدَهَا","id":"Telah mengkhabarkan kepada kami [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Wahb], dia berkata; telah mengkhabarkan kepadaku [Yunus] dari [Ibnu Syihab] bahwa [Urwah bin Az Zubair] telah mengkhabarkan kepadanya dari [Aisyah] bahwa seorang wanita mencuri pada zaman Rasulullah shallallahu 'alaihi wasallam pada saat terjadi perang penaklukan Mekkah. Kemudian dia dihadapkan kepada Rasulullah shallallahu 'alaihi wasallam. Lalu Usamah bin Zaid berbicara kepada beliau mengenai wanita tersebut. Setelah Usamah berbicara wajah Rasulullah shallallahu 'alaihi wasallam berubah dan beliau bersabda: \"Apakah kamu akan memberikan pertolongan dalam permasalahan hukuman di antara hukuman-hukuman Allah?\" Usamah berkata; \"Mintakanlah ampunan untukku wahai Rasulullah!\" Kemudian setelah sore hari Rasulullah shallallahu 'alaihi wasallam berdiri kemudian memuji Allah 'azza wajalla dengan pujian yang menjadi hakNya kemudian bersabda: \"Sesungguhnya orang-orang sebelum kalian binasa karena apabila ada orang mulia di antara mereka yang mencuri maka mereka membiarkannya sedang apabila ada orang yang lemah di antara mereka mencuri maka mereka menegakkan hukuman atasnya. Demi Allah, apabila Fathimah binti Muhammad mencuri niscaya saya potong tangannya.\""},"4601":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِأَنَّ امْرَأَةً سَرَقَتْ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ الْفَتْحِ مُرْسَلٌ فَفَزِعَ قَوْمُهَا إِلَى أُسَامَةَ بْنِ زَيْدٍ يَسْتَشْفِعُونَهُ قَالَ عُرْوَةُ فَلَمَّا كَلَّمَهُ أُسَامَةُ فِيهَا تَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتُكَلِّمُنِي فِي حَدٍّ مِنْ حُدُودِ اللَّهِ قَالَ أُسَامَةُ اسْتَغْفِرْ لِي يَا رَسُولَ اللَّهِ فَلَمَّا كَانَ الْعَشِيُّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطِيبًا فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّمَا هَلَكَ النَّاسُ قَبْلَكُمْ أَنَّهُمْ كَانُوا إِذَا سَرَقَ فِيهِمْ الشَّرِيفُ تَرَكُوهُ وَإِذَا سَرَقَ فِيهِمْ الضَّعِيفُ أَقَامُوا عَلَيْهِ الْحَدَّ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَوْ أَنَّ فَاطِمَةَ بِنْتَ مُحَمَّدٍ سَرَقَتْ لَقَطَعْتُ يَدَهَا ثُمَّ أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِ تِلْكَ الْمَرْأَةِ فَقُطِعَتْ فَحَسُنَتْ تَوْبَتُهَا بَعْدَ ذَلِكَقَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا وَكَانَتْ تَأْتِينِي بَعْدَ ذَلِكَ فَأَرْفَعُ حَاجَتَهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengkhabarkan kepada kami [Suwaid], dia berkata; telah memberitakan kepada kami [Abdullah] dari [Yunus] dari [Az Zuhri], dia berkata; telah mengkhabarkan kepadaku ['Urwah bin Az Zubair] bahwa seorang wanita pada zaman Rasulullah shallallahu 'alaihi wasallam mencuri pada saat terjadi perang Penaklukan Mekkah, Kemudian kaumnya datang kepada Usamah bin Zaid meminta pertolongan kepadanya. Urwah berkata; \"Kemudian tatkala Usamah berbicara kepadanya mengenai wanita tersebut wajah Rasulullah shallallahu 'alaihi wasallam berubah dan beliau bersabda: \"Apakah engkau mengajakku bicara mengenai hukuman di antara hukuman-hukuman Allah?\" Usamah berkata; \"Mintakanlah ampunan untukku wahai Rasulullah! Kemudian tatkala sore hari Rasulullah shallallahu 'alaihi wasallam berdiri dan berkhutbah, beliau memuji Allah dengan pujian yang menjadi hakNya. Kemudian beliau bersabda: \"Adapun selanjutnya, sesungguhnya orang-orang sebelum kalian binasa karena apabila ada orang mulia diantara mereka yang mencuri maka mereka membiarkannya dan apabila ada orang lemah di antara mereka yang mencuri maka mereka menegakkan hukuman kepadanya. Demi Dzat, yang jiwa Muhammad ada di tanganNya, seandainya Fathimah binti Muhammad mencuri niscaya saya potong tangannya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan agar tangan wanita tersebut dipotong. Kemudian setelah itu dia memperbaiki taubatnya. [Aisyah radliallahu 'anha] berkata; \"Setelah itu dia datang kepadaku dan saya laporkan keperluannya kepada Rasulullah shallallahu 'alaihi wasallam.\" "},"4602":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عِيسَى بْنِ يَزِيدَ قَالَ حَدَّثَنِي جَرِيرُ بْنُ يَزِيدَ أَنَّهُ سَمِعَ أَبَا زُرْعَةَ بْنَ عَمْرِو بْنِ جَرِيرٍ يُحَدِّثُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدٌّ يُعْمَلُ فِي الْأَرْضِ خَيْرٌ لِأَهْلِ الْأَرْضِ مِنْ أَنْ يُمْطَرُوا ثَلَاثِينَ صَبَاحًا","id":"Telah mengkhabarkan kepada kami [Suwaid bin Nashr], dia berkata; telah memberitakan kepada kami [Abdullah] dari [Isa bin Yazid], dia berkata; telah menceritakan kepadaku [Jarir bin Yazid] bahwa dia mendengar [Abu Zur'ah bin 'Amr bin Jarir] menceritakan bahwa dia mendengar [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hukuman yang dilakukan di dunia lebih baik bagi penduduk bumi daripada mereka dihujani selama tiga puluh hari setiap pagi.\""},"4603":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ أَنْبَأَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا يُونُسُ بْنُ عُبَيْدٍ عَنْ جَرِيرِ بْنِ يَزِيدَ عَنْ أَبِي زُرْعَةَ قَالَ قَالَ أَبُو هُرَيْرَةَإِقَامَةُ حَدٍّ بِأَرْضٍ خَيْرٌ لِأَهْلِهَا مِنْ مَطَرِ أَرْبَعِينَ لَيْلَةً","id":"Telah mengkhabarkan kepada kami ['Amr bin Zurarah], dia berkata; telah memberitakan kepada kami [Isma'il], dia berkata; telah menceritakan kepada kami [Yunus bin 'Ubaid] dari [Jarir bin Yazid] dari [Abu Zur'ah], dia berkata; [Abu Hurairah] berkata; \"Menegakkan hukuman di bumi lebih baik bagi penduduknya daripada hujan selama empat puluh malam.\""},"4604":{"ar":"أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَخْلَدٌ قَالَ حَدَّثَنَا حَنْظَلَةُ قَالَ سَمِعْتُ نَافِعًا قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُقَطَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مِجَنٍّ قِيمَتُهُ خَمْسَةُ دَرَاهِمَ كَذَا قَالَ","id":"Telah mengkhabarkan kepada kami [Abdul Hamid bin Muhammad], dia berkata; telah menceritakan kepada kami [Makhlad], dia berkata; telah menceritakan kepada kami [Hanzhalah], dia berkata; \"Saya mendengar [Nafi'] berkata; \"Saya mendengar [Abdullah bin Umar] berkata; \"Rasulullah shallallahu 'alaihi wasallam memotong tangan pencuri tameng yang harganya lima dirham.\" Begitulah ia berkata. "},"4605":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنَا حَنْظَلَةُ أَنَّ نَافِعًا حَدَّثَهُمْ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَقَطَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مِجَنٍّ ثَمَنُهُ ثَلَاثَةُ دَرَاهِمَقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا الصَّوَابُ","id":"Telah mengkhabarkan kepada kami [Yunus bin Abdul A'la], dia berkata; telah menceritakan kepada kami [Ibnu Wahb], dia berkata; telah menceritakan kepada kami [Hanzhalah] bahwa [Nafi'] menceritakan kepada mereka bahwa [Abdullah bin Umar] berkata; \"Rasulullah shallallahu 'alaihi wasallam memotong tangan karena mencuri tameng yang harganya tiga dirham.\" Abu Abdur Rahman berkata; \"Ini adalah yang benar.\" "},"4606":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطَعَ فِي مِجَنٍّ ثَمَنُهُ ثَلَاثَةُ دَرَاهِمَ","id":"Telah mengkhabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam memotong tangan pencuri tameng yang harganya tiga dirham. "},"4607":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي إِسْمَعِيلُ بْنُ أُمَيَّةَ أَنَّ نَافِعًا حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطَعَ يَدَ سَارِقٍ سَرَقَ تُرْسًا مِنْ صُفَّةِ النِّسَاءِ ثَمَنُهُ ثَلَاثَةُ دَرَاهِمَ","id":"Telah mengkhabarkan kepada kami [Yusuf bin Sa'id], dia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij], dia berkata; telah menceritakan kepadaku [Isma'il bin Umayyah] bahwa [Nafi'] telah bercerita kepadanya bahwa [Abdullah bin Umar] telah menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam memotong tangan pencuri yang pencuri tameng dari rak kaum wanita yang harganya tiga dirham."},"4608":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ سُفْيَانَ عَنْ أَيُّوبَ وَإِسْمَعِيلُ بْنُ أُمَيَّةَ وَعَبْدُ اللَّهِ وَمُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطَعَ فِي مِجَنٍّ قِيمَتُهُ ثَلَاثَةُ دَرَاهِمَ","id":"Telah mengkhabarkan kepadaku [Muhammad bin Isma'il bin Ibrahim], dia berkata; telah menceritakan kepada kami [Abu Nu'aim] dari [Sufyan] dari [Ayyub] dan [Isma'il bin Umayyah] dan [Abdullah] serta [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam memotong tangan pencuri tameng yang harganya tiga dirham. "},"4609":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الصَّبَّاحِ قَالَ حَدَّثَنَا أَبُو عَلِيٍّ الْحَنَفِيُّ قَالَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطَعَ فِي مِجَنٍّقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ","id":"Telah mengkhabarkan kepada kami [Abdullah bin Ash Shabbah], dia berkata; telah menceritakan kepada kami [Abu Ali Al Hanafi], dia berkata; telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam memotong tangan pencuri tameng. Abu Abdurrahman berkata; \"Hadits ini salah.\""},"4610":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْوَلِيدِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَطَعَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فِي مِجَنٍّ قِيمَتُهُ خَمْسَةُ دَرَاهِمَهَذَا الصَّوَابُ","id":"Telah mengkhabarkan kepada kami [Ahmad bin Nashr], dia berkata; telah menceritakan kepada kami [Abdullah bin Al Walid], dia berkata; telah menceritakan kepada kami [Sufyan] dari [Syu'bah] dari [Qatadah] dari [Anas], dia berkata; Abu Bakar radliallahu 'anhu memotong tangan pencuri tameng yang harganya lima dirham. Ini adalah yang benar."},"4611":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ أَبِي دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسًا يَقُولُسَرَقَ رَجُلٌ مِجَنًّا عَلَى عَهْدِ أَبِي بَكْرٍ فَقُوِّمَ خَمْسَةَ دَرَاهِمَ فَقُطِعَ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Abu Daud], dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah], dia berkata; \"Saya mendengar [Anas] berkata; \"Seorang laki-laki mencuri tameng pada zaman Abu Bakar, lalu barang tersebut dinilai seharga lima dirham. Maka dipotonglah tangan pencuri tersebut.\""},"4612":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ حَفْصِ بْنِ حَسَّانَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاقَطَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رُبْعِ دِينَارٍ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami [Ja'far bin Sulaiman] dari [Hafsh bin Hassan] dari [Az Zuhri] dari ['Urwah] dari [Aisyah radliallahu 'anha]; \"Rasulullah shallallahu 'alaihi wasallam memotong tangan pencuri barang yang harganya empat dinar.\""},"4613":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ أَنْبَأَنَا حِبَّانُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ قَالَ قَالَتْ عَمْرَةُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُقْطَعُ يَدُ السَّارِقِ فِي رُبْعِ دِينَارٍ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Hatim], dia berkata; telah memberitakan kepada kami [Hibban bin Musa], dia berkata; telah menceritakan kepada kami [Abdullah] dari [Yunus] dari [Az Zuhri], dia berkata; telah berkata ['Amrah] dari [Aisyah radliallahu 'anha] dari Rasulullah shallallahu 'alaihi wasallam; dipotong tangan pencuri barang senilai seperempat dinar."},"4614":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ وَعَمْرَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُقْطَعُ يَدُ السَّارِقِ فِي رُبْعِ دِينَارٍ فَصَاعِدًا","id":"Telah berkata [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dari ['Urwah] dan ['Amrah] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dipotong tangan pencuri yang mencuri barang senilai seperempat dinar ke atas.\""},"4615":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ عَنْ سَعِيدٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عَمْرَةَ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُقْطَعُ يَدُ السَّارِقِ فِي رُبْعِ دِينَارٍ فَصَاعِدًا","id":"Telah mengkhabarkan kepada kami [Al Hasan bin Muhammad], dia berkata; telah menceritakan kepada kami [Abdul Wahhab] dari [Sa'id] dari [Ma'mar] dari [Az Zuhri] dari ['Amrah] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dipotong tangan pencuri yang mencuri barang senilai seperempat dinar ke atas.\""},"4616":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مَعْمَرٍ عَنْ ابْنِ شِهَابٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْتُقْطَعُ الْيَدُ فِي رُبْعِ دِينَارٍ فَصَاعِدًا","id":"Telah mengkhabarkan kepada kami [Suwaid bin Nashr], dia berkata; telah memberitakan kepada kami [Abdullah] dari [Ma'mar] dari [Ibnu Syihab] dari ['Amrah] dari [Aisyah], dia berkata; \"Dipotong tangan pencuri sesuatu seharga seperempat dinar ke atas.\" "},"4617":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَقُتَيْبَةُ بْنُ سَعِيدٍ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُتَيْبَةُ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْطَعُ فِي رُبْعِ دِينَارٍ فَصَاعِدًا","id":"Telah mengkhabarkan kepada kami [Ishaq bin Ibrahim] dan [Qutaibah bin Sa'id] dari [Sufyan] dari [Az Zuhri] dari ['Amrah] dari [Aisyah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam berkata, Qutaibah berkata; \"Nabi shallallahu 'alaihi wasallam memotong tangan pencuri barang seharga seperempat dinar ke atas.\""},"4618":{"ar":"أَخْبَرَنِي يَزِيدُ بْنُ مُحَمَّدِ بْنِ فُضَيْلٍ قَالَ أَنْبَأَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبَانُ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُقْطَعُ يَدُ السَّارِقِ فِي رُبْعِ دِينَارٍ فَصَاعِدًا","id":"Telah mengkhabarkan kepadaku [Yazid bin Muhammad bin Fudhail], dia berkata; telah memberitakan kepada kami [Muslim bin Ibrahim], dia berkata; telah menceritakan kepada kami [Aban], dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Amrah] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Dipotong tangan pencuri sesuatu seharga seperempat dinar ke atas.\""},"4619":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ أَنَّهَا سَمِعَتْ عَائِشَةَ تَقُولُيُقْطَعُ فِي رُبْعِ دِينَارٍ فَصَاعِدًاقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا الصَّوَابُ مِنْ حَدِيثِ يَحْيَى","id":"Telah mengkhabarkan kepada kami [Suwaid bin Nashr], dia berkata; telah memberitakan kepada kami [Abdullah] dari [Yahya bin Sa'id] dari ['Amrah] bahwa dia mendengar [Aisyah] berkata; \"Dipotong tangan pencuri sesuatu seharga seperempat dinar ke atas.\" Abu Abdur Rahman berkata; \"Ini adalah yang benar dari hadits Yahya.\""},"4620":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْالْقَطْعُ فِي رُبْعِ دِينَارٍ فَصَاعِدًا","id":"Telah mengkhabarkan kepada kami [Muhammad bin Al 'Ala`], dia berkata; telah menceritakan kepada kami [Ibnu Idris] dari [Yahya bin Sa'id] dari ['Amrah] dari [Aisyah], dia berkata; \"(Hukum) memotong tangan adalah pada seperempat dinar ke atas.\""},"4621":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْمَا طَالَ عَلَيَّ وَلَا نَسِيتُ الْقَطْعُ فِي رُبْعِ دِينَارٍ فَصَاعِدًا","id":"[Al Haris bin Miskin] berkata dengan membacakan riwayat dan saya mendengar, dari [Ibnu Al Qasim], dia berkata; telah menceritakan kepadaku [Malik] dari [Yahya bin Sa'd] dari ['Amrah] dari [Aisyah], dia berkata; \"Tidaklah terlalu lama (waktu berselang) bagiku dan saya pun tidak lupa (bahwa hukum) memotong tangan adalah pada seperempat dinar ke atas.\""},"4622":{"ar":"أَخْبَرَنَا أَبُو صَالِحٍ مُحَمَّدُ بْنُ زُنْبُورٍ قَالَ حَدَّثَنَا ابْنُ أَبِي حَازِمٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يُقْطَعُ السَّارِقُ إِلَّا فِي رُبْعِ دِينَارٍ فَصَاعِدًاأَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ سَلْمَانَ عَنْ ابْنِ الْهَادِ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ حَزْمٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ الْأَوَّلِ","id":"Telah mengkhabarkan kepada kami [Abu Shalih Muhammad bin Zunbur], dia berkata; telah menceritakan kepada kami [Ibnu Abu Hazim] dari [Yazid bin Abdullah] dari [Abu Bakar bin Muhammad] dari ['Amrah] dari [Aisyah] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak dipotong tangan orang yang mencuri kecuali pada seperempat dinar ke atas.\" Telah mengkhabarkan kepada kami [Ahmad bin 'Amr bin As Sarh], dia berkata; telah menceritakan kepada kami [Ibnu Wahb], dia berkata; telah memberitakan kepadaku [Abdur Rahman bin Salman] dari [Ibnu Al Had] dari [Abu Bakar bin Muhammad bin Hazm] dari ['Amrah] dari [Aisyah] dari Rasulullah shallallahu 'alaihi wasallam seperti yang pertama. "},"4623":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي الرِّجَالِ عَنْ أَبِيهِ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقْطَعُ يَدُ السَّارِقِ فِي ثَمَنِ الْمِجَنِّ وَثَمَنُ الْمِجَنِّ رُبْعُ دِينَارٍ","id":"Telah mengkhabarkan kepadaku [Ibrahim bin Ya'qub], dia berkata; telah menceritakan kepada kami [Abdullah bin Yusuf], dia berkata; telah menceritakan kepada kami [Abdur Rahman bin Muhammad bin Abdur Rahman bin Abu Ar Rijal] dari [ayahnya] dari ['Amrah] dari [Aisyah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dipotong tangan orang yang mencuri sesuatu seharga tameng sedangkan harga tameng adalah seperempat dinar.\""},"4624":{"ar":"أَخْبَرَنِي يَحْيَى بْنُ دُرُسْتَ قَالَ حَدَّثَنَا أَبُو إِسْمَعِيلَ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ أَنَّ مُحَمَّدَ بْنَ عَبْدِ الرَّحْمَنِ حَدَّثَهُ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْطَعُ الْيَدَ فِي رُبْعِ دِينَارٍ فَصَاعِدًا","id":"Telah mengkhabarkan kepada kami [Yahya bin Durust], dia berkata; telah menceritakan kepada kami [Abu Isma'il], dia berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] bahwa [Muhammad bin Abdur Rahman] telah menceritakan kepadanya dari ['Amrah] dari [Aisyah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memotong tangan pencuri sesuatu seharga seperempat dinar ke atas.\" "},"4625":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا حُسَيْنٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ ثُمَّ ذَكَرَ كَلِمَةً مَعْنَاهَا عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقْطَعُ الْيَدُ إِلَّا فِي رُبْعِ دِينَارٍ","id":"Telah mengkhabarkan kepada kami [Humaid bin Mas'adah], dia berkata; telah menceritakan kepada kami [Abdul Warits], dia berkata; telah menceritakan kepada kami [Husain] dari [Yahya bin Abu Katsir] dari [Muhammad bin Abdur Rahman] kemudian dia menyebutkan satu kalimat yang maknanya adalah dari ['Amrah] dari [Aisyah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak dipotong tangan kecuali pada seperempat dinar.\""},"4626":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ أَنَّ بُكَيْرَ بْنَ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ حَدَّثَهُ أَنَّ سُلَيْمَانَ بْنَ يَسَارٍ حَدَّثَهُ أَنَّ عَمْرَةَ ابْنَةَ عَبْدِ الرَّحْمَنِ حَدَّثَتْهُ أَنَّهَا سَمِعَتْ عَائِشَةَ تَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقْطَعُ يَدُ السَّارِقِ فِيمَا دُونَ الْمِجَنِّقِيلَ لِعَائِشَةَ مَا ثَمَنُ الْمِجَنِّ قَالَتْ رُبْعُ دِينَارٍ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'd bin Ibrahim bin Sa'd], dia berkata; telah menceritakan kepada kami [pamanku], dia berkata; telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] dari [Yazid bin Abu Habib] bahwa [Bukair bin Abdullah bin Al Asyaj] telah menceritakan kepadanya bahwa [Sulaiman bin Yasar] telah menceritakan kepadanya bahwa ['Amrah], puteri dari Abdur Rahman telah menceritakan kepadanya bahwa dia mendengar [Aisyah] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak dipotong tangan pencuri sesuatu yang kurang dari harga tameng.\" Ditanyakan kepada Aisyah; \"Berapakah harta tameng?\" Dia berkata; \"Seperempat dinar.\""},"4627":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي مَخْرَمَةُ عَنْ أَبِيهِ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُقْطَعُ يَدُ السَّارِقِ إِلَّا فِي رُبْعِ دِينَارٍ فَصَاعِدًا","id":"Telah mengkhabarkan kepadaku [Ahmad bin 'Amr bin As Sarh], dia berkata; telah menceritakan kepada kami [Ibnu Wahb], dia berkata; telah mengkhabarkan kepadaku [Makhramah] dari [ayahnya] dari [Sulaiman bin Yasar] dari ['Amrah] dari [Aisyah] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak dipotong tangan orang yang mencuri keculi pada sesuatu seharga seperempat dinar ke atas.\""},"4628":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ إِسْحَقَ قَالَ حَدَّثَنِي قُدَامَةُ بْنُ مُحَمَّدٍ قَالَ أَخْبَرَنِي مَخْرَمَةُ بْنُ بُكَيْرٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ عُثْمَانَ بْنَ أَبِي الْوَلِيدِ يَقُولُ سَمِعْتُ عُرْوَةَ بْنَ الزُّبَيْرِ يَقُولُكَانَتْ عَائِشَةُ تُحَدِّثُ عَنْ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا تُقْطَعُ الْيَدُ إِلَّا فِي الْمِجَنِّ أَوْ ثَمَنِهِوَزَعَمَ أَنَّ عُرْوَةَ قَالَ الْمِجَنُّ أَرْبَعَةُ دَرَاهِمَ","id":"Telah mengkhabarkan kepada kami [Abu Bakar bin Ishaq], dia berkata; telah menceritakan kepadaku [Qudamah bin Muhammad], dia berkata; telah mengkhabarkan kepadaku [Makhramah bin Bukair] dari [ayahnya], dia berkata; saya mendengar [Utsman bin Abu Al Walid] berkata; saya mendengar ['Urwah bin Az Zubair] berkata; [Aisyah] menceritakan dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Tidak dipotong tangan kecuali mencuri tameng atau yang seharga dengannya.\" Utsman mengira bahwa Urwah berkata; \"Harga tameng adalah empat dirham.\""},"4629":{"ar":"قَالَ وَسَمِعْتُ سُلَيْمَانَ بْنَ يَسَارٍ يَزْعُمُ أَنَّهُ سَمِعَ عَمْرَةَ تَقُولُ سَمِعْتُ عَائِشَةَ تُحَدِّثُأَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُقْطَعُ الْيَدُ إِلَّا فِي رُبْعِ دِينَارٍ فَمَا فَوْقَهُ","id":"(Masih dari jalur periwayatan yang sama dengan hadits sebelumnya), [Bukair] berkata; saya mendengar [Sulaiman bin Yasar] mengaku bahwa dia mendengar ['Amrah] berkata; saya mendengar [Aisyah] menceritakan bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak dipotong tangan kecuali mencuri sesuatu seharga seperempat dinar dan yang di atasnya.\""},"4630":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ عَبْدِ اللَّهِ الدَّانَاجِ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ قَالَلَا تُقْطَعُ الْخَمْسُ إِلَّا فِي الْخَمْسِقَالَ هَمَّامٌ فَلَقِيتُ عَبْدَ اللَّهِ الدَّانَاجَ فَحَدَّثَنِي عَنْ سُلَيْمَانَ بْنِ يَسَارٍ قَالَ لَا تُقْطَعُ الْخَمْسُ إِلَّا فِي الْخَمْسِ","id":"Telah mengkhabarkan kepada kami ['Amr bin Ali], dia berkata; telah menceritakan kepada kami [Abdur Rahman bin Mahdi], dia berkata; telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Abdullah Ad Danaj] dari [Sulaiman bin Yasar], dia berkata; \"Tidak dipotong lima hal kecuali pada lima hal.\" [Hammam] berkata; \"Lalu aku bertemu dengan [Abdullah Ad Danih], dia berkata kepadaku; dari [Sulaiman bin Yasar], ia berkata; \"Tidak dipotong lima hal kecuali pada lima hal.\""},"4631":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ عِيسَى عَنْ الشَّعْبِيِّ عَنْ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَ��َّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطَعَ فِي قِيمَةِ خَمْسَةِ دَرَاهِمَ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Al Mutsanna], dia berkata; telah menceritakan kepada kami [Abdur Rahman] dari [Sufyan] dari [Isa] dari [Asy Sya'bi] dari [Abdullah] bahwa Nabi shallallahu 'alaihi wasallam memotong tangan pencuri barang seharga lima dirham."},"4632":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ الْأَخْنَسِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي كَمْ تُقْطَعُ الْيَدُ قَالَ لَا تُقْطَعُ الْيَدُ فِي ثَمَرٍ مُعَلَّقٍ فَإِذَا ضَمَّهُ الْجَرِينُ قُطِعَتْ فِي ثَمَنِ الْمِجَنِّ وَلَا تُقْطَعُ فِي حَرِيسَةِ الْجَبَلِ فَإِذَا آوَى الْمُرَاحَ قُطِعَتْ فِي ثَمَنِ الْمِجَنِّ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari ['Ubaidullah bin Al Akhnas] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam ditanya mengenai berapa harga barang yang menyebabkan tangan dipotong? Beliau bersabda: \"Tidak dipotong tangan karena buah yang menggantung di pohon kemudian apabila telah terkumpul dalam tempat pengeringan maka tangan orang yang mencurinya dipotong apabila mencapai harga tameng, dan tidak dipotong karena mengambil kambing yang di gembala di gunung, kemudian apabila kambing tersebut telah memasuki kandangnya maka tangan yang mengambilnya dipotong apabila mencapai harga tameng.\" "},"4633":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سُئِلَ عَنْ الثَّمَرِ الْمُعَلَّقِ فَقَالَ مَا أَصَابَ مِنْ ذِي حَاجَةٍ غَيْرَ مُتَّخِذٍ خُبْنَةً فَلَا شَيْءَ عَلَيْهِ وَمَنْ خَرَجَ بِشَيْءٍ مِنْهُ فَعَلَيْهِ غَرَامَةُ مِثْلَيْهِ وَالْعُقُوبَةُ وَمَنْ سَرَقَ شَيْئًا مِنْهُ بَعْدَ أَنْ يُؤْوِيَهُ الْجَرِينُ فَبَلَغَ ثَمَنَ الْمِجَنِّ فَعَلَيْهِ الْقَطْعُ وَمَنْ سَرَقَ دُونَ ذَلِكَ فَعَلَيْهِ غَرَامَةُ مِثْلَيْهِ وَالْعُقُوبَةُ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya yaitu Abdullah bin 'Amr] dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau ditanya mengenai buah yang menggantung di pohon. Beliau bersabda: \"Orang yang mengambilnya karena sangat membutuhkan dan tidak mengambilnya di dalam lipatan kain, maka tidak ada hukuman atasnya. Dan barang siapa yang keluar membawa sebagian darinya (yang ada dalam lipatan kain) maka dia wajib membayar denda dua kalinya, serta mendapat hukuman. Dan barang siapa yang mencuri sebagian darinya setelah terkumpul dalam tempat pengeringan dan mencapai harga tameng maka tangannya dipotong, dan barang siapa yang mencuri kurang dari itu maka dia berkewajiban membayar denda dua kalinya, dan mendapatkan hukuman.\" "},"4634":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ وَهِشَامُ بْنُ سَعْدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَجُلًا مِنْ مُزَيْنَةَ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ كَيْفَ تَرَى فِي حَرِيسَةِ الْجَبَلِ فَقَالَ هِيَ وَمِثْلُهَا وَالنَّكَالُ وَلَيْسَ فِي شَيْءٍ مِنْ الْمَاشِيَةِ قَطْعٌ إِلَّا فِيمَا آوَاهُ الْمُرَاحُ فَبَلَغَ ثَمَنَ الْمِجَنِّ فَفِيهِ قَطْعُ الْيَدِ وَمَا لَمْ يَبْلُغْ ثَمَنَ الْمِجَنِّ فَفِيهِ غَرَامَةُ مِثْلَيْهِ وَجَلَدَاتُ نَكَالٍ قَالَ يَا رَسُولَ اللَّهِ كَيْفَ تَرَى فِي الثَّمَرِ الْمُعَلَّقِ قَالَ هُوَ وَمِثْلُهُ مَعَهُ وَالنَّكَالُ وَلَيْسَ فِي شَيْءٍ مِنْ الثَّمَرِ الْمُعَلَّقِ قَطْعٌ إِلَّا فِيمَا آوَاهُ الْجَرِينُ فَمَا أُخِذَ مِنْ الْجَرِينِ فَبَلَغَ ثَمَنَ الْمِجَنِّ فَفِيهِ الْقَطْعُ وَمَا لَمْ يَبْلُغْ ثَمَنَ الْمِجَنِّ فَفِيهِ غَرَامَةُ مِثْلَيْهِ وَجَلَدَاتُ نَكَالٍ","id":"Telah berkata; [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Wahb], dia berkata; telah mengkhabarkan kepadaku ['Amr bin Al Harits] dan [Hisyam bin Sa'd] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya yaitu Abdullah bin 'Amr] bahwa seorang laki-laki dari Muzainah datang kepada Rasulullah shallallahu 'alaihi wasallam lalu berkata; \"Wahai Rasulullah, bagaimana pendapat Tuan mengenai kambing yang di gembala di gunung?\" Beliau bersabda: \"Hewan itu dan yang semisalnya mengakibatkan hukuman, dan tidak ada sesuatupun dari hewan ternak yang menyebabkan tangan dipotong kecuali yang telah berada dalam kandangnya dan mencapai harga tameng maka padanya tangan dipotong. Dan yang belum mencapai harga tameng maka padanya terdapat denda dua kali yang semisalnya serta hukuman cambuk.\" Orang tersebut berkata; \"Wahai Rasulullah, bagaimana pendapat Tuan mengenai buah yang menggantung di pohon?\" Beliau bersabda: \"Buah tersebut dan yang semisalnya mengakibatkan hukuman dan tidak ada pemotongan tangan karena mengambil sebagian buah yang tergantung dalam pohon kecuali apabila telah terkumpul pada tempat pengeringan, maka yang terambil dari tempat pengeringan dan mencapai harga tameng padanya terdapat pemotongan tangan dan yang belum mencapai harga tameng padanya terdapat denda serta hukuman cambuk.\""},"4635":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ خَالِدِ بْنِ خَلِيٍّ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا سَلَمَةُ يَعْنِي ابْنَ عَبْدِ الْمَلِكِ الْعَوْصِيَّ عَنْ الْحَسَنِ وَهُوَ ابْنُ صَالِحٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدِ بْنِ أَبِي بَكْرٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Khalid bin Khalli], dia berkata; telah menceritakan kepada kami [ayahku], dia berkata; telah menceritakan kepada kami [Salamah yaitu Ibnu Abdul Malik Al 'Aushi] dari [Al Hasan yaitu Ibnu Shalih] dari [Yahya bin Sa'id] dari [Al Qasim bin Muhammad bin Abu Bakar] dari [Rafi' bin Khadij], dia berkata; \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada pemotongan tangan pada buah dan mayang kurma.\""},"4636":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ سَمِعْتُ يَحْيَى بْنَ سَعِيدٍ الْقَطَّانَ يَقُولُ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍ","id":"Telah mengkhabarkan kepada kami ['Amr bin Ali], dia berkata; saya mendengar [Yahya bin Sa'id Al Qaththan] berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Rafi' bin Khadij], dia berkata; \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada pemotongan tangan pada buah dan mayang kurma.\""},"4637":{"ar":"أَخْبَرَنِي يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍ","id":"Telah mengkhabarkan kepadaku [Yahya bin Habib bin 'Arabi], dia berkata; telah menceritakan kepada kami [Hammad] dari [Yahya] dari [Muhammad bin Yahya bin Habban] dari [Rafi' bin Khadij], dia berkata; \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada pemotongan tangan pada buah dan mayang kurma.\""},"4638":{"ar":"أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَخْلَدٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ رَافِعِ بْنِ خَدِيجٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍ","id":"Telah mengkhabarkan kepada kami [Abdul Hamid bin Muhammad], dia berkata; telah menceritakan kepada kami [Makhlad], dia berkata; telah menceritakan kepada kami [Sufyan] dari [Yahya] dari [Muhammad bin Yahya bin Habban] dari [Rafi' bin Khadij] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada pemotongan tangan pada buah dan mayang kurma.\""},"4639":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ سُفْيَانَ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim], dia berkata; telah menceritakan kepada kami [Abu Nu'aim] dari [Sufyan] dari [Yahya] dari [Muhammad bin Yahya bin Habban] dari [Rafi' bin Khadij], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada pemotongan tangan pada buah dan mayang kurma.\""},"4640":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ عَمِّهِ أَنَّ رَافِعَ بْنَ خَدِيجٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍ وَالْكَثَرُ الْجُمَّارُ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami [Al Laits] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [pamannya] bahwa [Rafi' bin Khadij] berkata; \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada pemotongan tangan pada buah dan mayang kurma.\""},"4641":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ مَيْمُونٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ أَبِي مَيْمُونٍ عَنْ رَافِعِ بْنِ خَدِيجٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ أَبُو مَيْمُونٍ لَا أَعْرِفُهُ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Ali bin Maimun], dia berkata; telah menceritakan kepada kami [Sa'id bin Manshur], dia berkata; telah menceritakan kepada kami [Abdul 'Aziz bin Muhammad] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Abu Maimun] dari [Rafi' bin Khadij] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada pemotongan tangan pada buah dan mayang kurma.\" Abu Abdur Rahman berkata; \"Ini adalah salah, saya tidak mengenal Abu Maimun.\" "},"4642":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ رَجُلٍ مِنْ قَوْمِهِ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍ","id":"Telah mengkhabarkan kepada kami [Al Husain bin Manshur], dia berkata; telah menceritakan kepada kami [Abu Salamah], dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [seorang laki-laki] dari kaumnya dari [Rafi' bin Khadij], dia berkata; \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada pemotongan tangan pada buah dan mayang kurma.\""},"4643":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الصَّمَدِ بْنِ عَلِيٍّ عَنْ مَخْلَدٍ عَنْ سُفْيَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ عَلَى خَائِنٍ وَلَا مُنْتَهِبٍ وَلَا مُخْتَلِسٍ قَطْعٌلَمْ يَسْمَعْهُ سُفْيَانُ مِنْ أَبِي الزُّبَيْرِ","id":"Telah mengkhabarkan kepada kami [Abdullah bin Abdush Shamad bin Ali] dari [Makhlad] dari [Sufyan] dari [Abu Az Zubair] dari [Jabir] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada pemotongan tangan pada orang yahg berkhianat, merampas dan menggelapkan harta.\" Sufyan belum mendengar dari Abu Az Zubair. "},"4644":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ عَنْ سُفْيَانَ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ عَلَى خَائِنٍ وَلَا مُنْتَهِبٍ وَلَا مُخْتَلِسٍ قَطْعٌوَلَمْ يَسْمَعْهُ أَيْضًا ابْنُ جُرَيْجٍ مِنْ أَبِي الزُّبَيْرِ","id":"Telah mengkhabarkan kepada kami [Mahmud bin Ghailan], dia berkata; telah menceritakan kepada kami [Abu Daud Al Hafari] dari [Sufyan] dari [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada pemotongan tangan atas orang yahg berkhianat, merampas dan menggelapkan harta.\" Ibnu Juraij juga belum mendengar dari Abu Az Zubair. "},"4645":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ سَلْمٍ الْمَصَاحِفِيُّ الْبَلْخِيُّ قَالَ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ أَنْبَأَنَا يُوسُفُ عَنْ الْحَارِثِ بْنِ حَاطِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِلِصٍّ فَقَالَ اقْتُلُوهُ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّمَا سَرَقَ فَقَالَ اقْتُلُوهُ قَالُوا يَا رَسُولَ اللَّهِ إِنَّمَا سَرَقَ قَالَ اقْطَعُوا يَدَهُ قَالَ ثُمَّ سَرَقَ فَقُطِعَتْ رِجْلُهُ ثُمَّ سَرَقَ عَلَى عَهْدِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ حَتَّى قُطِعَتْ قَوَائِمُهُ كُلُّهَا ثُمَّ سَرَقَ أَيْضًا الْخَامِسَةَ فَقَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَ بِهَذَا حِينَ قَالَ اقْتُلُوهُ ثُمَّ دَفَعَهُ إِلَى فِتْيَةٍ مِنْ قُرَيْشٍ لِيَقْتُلُوهُ مِنْهُمْ عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ وَكَانَ يُحِبُّ الْإِمَارَةَ فَقَالَ أَمِّرُونِي عَلَيْكُمْ فَأَمَّرُوهُ عَلَيْهِمْ فَكَانَ إِذَا ضَرَبَ ضَرَبُوهُ حَتَّى قَتَلُوهُ","id":"Telah mengkhabarkan kepada kami [Sulaiman bin Salm Al Mashahifi Al Balkhi], dia berkata; telah menceritakan kepada kami [An Nadhr bin Syumail], dia berkata; telah menceritakan kepada kami [Hammad], dia berkata; telah memberitakan kepada kami [Yusuf] dari [Harits bin Hathib] bahwa dihadapkan seorang pencuri kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Bunuhlah dia, \" Para sahabat berkata; \"Wahai Rasulullah, dia hanya mencuri.\" Beliau bersabda: \"Bunuhlah dia, \" Para sahabat berkata; \"Wahai Rasulullah; dia hanya mencuri.\" Beliau bersabda: \"Potonglah tangannya.\" Harits bin Hathib berkata; Kemudian dia mencuri lagi maka dipotonglah kakinya. Lalu pada masa Abu Bakar radliallahu 'anhu dia mencuri lagi hingga dipotonglah semua pergelangannya. Tapi dia masih mencuri lagi hingga yang kelima kalinya, maka berkatalah Abu Bakar radliallahu 'anhu; \"Rasulullah shallallahu 'alaihi wasallam lebih mengetahui mengenai hal ini ketika beliau bersabda; \"Bunuhlah dia\". Lalu dia menyerahkannya kepada beberapa orang pemuda Quraisy agar mereka membunuhnya. Di antara mereka adalah Abdullah bin Az Zubair, dia adalah seorang yang senang menjadi pemimpin. Dia berkata; \"Angkatlah aku sebagai pemimpin kalian!\" Lalu mereka mengangkatnya sebagai pemimpin, jika dia memukul maka mereka (pun ikut) memukulnya hingga mereka membunuhnya (pencuri tersebut).\" "},"4646":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عَقِيلٍ قَالَ حَدَّثَنَا جَدِّي قَالَ حَدَّثَنَا مُصْعَبُ بْنُ ثَابِتٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَجِيءَ بِسَارِقٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اقْتُلُوهُ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّمَا سَرَقَ قَالَ اقْطَعُوهُ فَقُطِعَ ثُمَّ جِيءَ بِهِ الثَّانِيَةَ فَقَالَ اقْتُلُوهُ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّمَا سَرَقَ قَالَ اقْطَعُوهُ فَقُطِعَ فَأُتِيَ بِهِ الثَّالِثَةَ فَقَالَ اقْتُلُوهُ قَالُوا يَا رَسُولَ اللَّهِ إِنَّمَا سَرَقَ فَقَالَ اقْطَعُوهُ ثُمَّ أُتِيَ بِهِ الرَّابِعَةَ فَقَالَ اقْتُلُوهُ قَالُوا يَا رَسُولَ اللَّهِ إِنَّمَا سَرَقَ قَالَ اقْطَعُوهُ فَأُتِيَ بِهِ الْخَامِسَةَ قَالَ اقْتُلُوهُ قَالَ جَابِرٌ فَانْطَلَقْنَا بِهِ إِلَى مِرْبَد النَّعَمِ وَحَمَلْنَاهُ فَاسْتَلْقَى عَلَى ظَهْرِهِ ثُمَّ كَشَّرَ بِيَدَيْهِ وَرِجْلَيْهِ فَانْصَدَعَتْ الْإِبِلُ ثُمَّ حَمَلُوا عَلَيْهِ الثَّانِيَةَ فَفَعَلَ مِثْلَ ذَلِكَ ثُمَّ حَمَلُوا عَلَيْهِ الثَّالِثَةَ فَرَمَيْنَاهُ بِالْحِجَارَةِ فَقَتَلْنَاهُ ثُمَّ أَلْقَيْنَاهُ فِي بِئْرٍ ثُمَّ رَمَيْنَا عَلَيْهِ بِالْحِجَارَةِقَالَ أَبُو عَبْد الرَّحْمَنِ وَهَذَا حَدِيثٌ مُنْكَرٌ وَمُصْعَبُ بْنُ ثَابِتٍ لَيْسَ بِالْقَوِيِّ فِي الْحَدِيثِ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdullah bin 'Ubaid bin 'Aqil], dia berkata; telah menceritakan kepada kami [kakekku], dia berkata; telah menceritakan kepada kami [Mush'ab bin Tsabit] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah], dia berkata; \"Dihadapkan seorang pencuri kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Bunuhlah dia.\" Para sahabat berkata; \"Wahai Rasulullah; dia hanya mencuri.\" Beliau bersabda: \"Potonglah tangannya.\" Lalu dipotonglah tangannya. Kemudian dia dihadapkan lagi untuk yang kedua kalinya, beliau bersabda: \"Bunuhlah dia.\" Para sahabat berkata; \"Wahai Rasulullah, dia hanya mencuri.\" Beliau bersabda: \"Potonglah.\" Lalu dipotonglah tangannya. Lalu dia dihadapkan untuk yang ketiga kalinya, beliau bersabda: \"Bunuhlah dia.\" Para sahabat berkata; \"Wahai Rasulullah; dia hanya mencuri.\" Beliau bersabda: \"Potonglah, \" Lalu dia dihadapkan lagi untuk yang keempat kalinya, beliau bersabda: \"Bunuhlah dia.\" Para sahabat berkata; \"Wahai Rasulullah, dia hanya mencuri, beliau bersabda: \"Potonglah.\" Lalu untuk yang kelima kalinya ia dihadapkan kembali, beliau bersabda: \"Bunuhlah dia.\" Jabir berkata; \"Lalu kami membawanya ke kandang unta, dan dia terbaring di atas punggung unta tersebut, lalu dia bergerak meronta dengan tangan dan kakinya sehingga unta tersebut naik. Untuk kedua kalinya mereka menaikkannya, dia pun melakukan hal yang sama. Kemudian mereka membawanya untuk yang ketiga kalinya. Kami melemparinya dengan batu hingga membunuhnya, Lalu kami buangnya kesumur, kami melemparinya dengan batu.\" Abu Abdur Rahman berkata; \"Ini adalah hadits mungkar. Mush'ab bin Tsabit adalah orang yang tidak kuat dalam hadits, wallahu Ta'ala a'lam.\""},"4647":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنِي بَقِيَّةُ قَالَ حَدَّثَنِي نَافِعُ بْنُ يَزِيدَ قَالَ حَدَّثَنِي حَيْوَةُ بْنُ شُرَيْحٍ عَنْ عَيَّاشِ بْنِ عَبَّاسٍ عَنْ جُنَادَةَ بْنِ أَبِي أُمَيَّةَ قَالَ سَمِعْتُ بُسْرَ بْنَ أَبِي أَرْطَاةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُقْطَعُ الْأَيْدِي فِي السَّفَرِ","id":"Telah mengkhabarkan kepada kami ['Amr bin Utsman], dia berkata; telah menceritakan kepadaku [Baqiyah], dia berkata; telah menceritakan kepadaku [Nafi' bin Yazid], dia berkata; telah menceritakan kepadaku [Haiwah bin Syuraih] dari ['Ayyasy bin Abbas] dari [Junadah bin Abu Umayyah], dia berkata; saya mendengar [Busr bin Abu Arthah], dia berkata; \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak dipotong tangan ketika dalam safar.\""},"4648":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ مُدْرِكٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عُمَرَ وَهُوَ ابْنُ أَبِي سَلَمَةَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَرَقَ الْعَبْدُ فَبِعْهُ وَلَوْ بِنَشٍّقَالَ أَبُو عَبْد الرَّحْمَنِ عُمَرُ بْنُ أَبِي سَلَمَةَ لَيْسَ بِالْقَوِيِّ فِي الْحَدِيثِ","id":"Telah mengkhabarkan kepada kami [Al Hasan bin Mudrik], dia berkata; telah menceritakan kepada kami [Yahya bin Hammad], dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Umar yaitu Ibnu Abu Salamah] dari [ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \" Jika seorang budak mencuri maka juallah dia walau dengan duapuluh dirham, \" Abu Abdur Rahman berkata; \"Umar bin Abu Salamah adalah orang yang tidak kuat dalam hal hadits.\""},"4649":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَطِيَّةَ أَنَّهُ أَخْبَرَهُ قَالَكُنْتُ فِي سَبْيِ قُرَيْظَةَ وَكَانَ يُنْظَرُ فَمَنْ خَرَجَ شِعْرَتُهُ قُتِلَ وَمَنْ لَمْ تَخْرُجْ اسْتُحْيِيَ وَلَمْ يُقْتَلْ","id":"Telah mengkhabarkan kepada kami [Isma'il bin Mas'ud], dia berkata; telah menceritakan kepada kami [Khalid], dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik bin 'Umair] dari ['Athiyah] bahwa dia telah mengkhabarkan kepadanya, dia berkata; \"Saya pernah berada di antara tawanan orang-orang Quraizhah. Mereka melihat orang yang telah keluar bulu kelaminnya dibunuh sedang yang belum keluar bulu kelaminnya dibiarkan hidup, tidak dibunuh.\""},"4650":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ أَبِي بَكْرِ بْنِ عَلِيٍّ عَنْ الْحَجَّاجِ عَنْ مَكْحُولٍ عَنْ ابْنِ مُحَيْرِيزٍ قَالَسَأَلْتُ فَضَالَةَ بْنَ عُبَيْدٍ عَنْ تَعْلِيقِ يَدِ السَّارِقِ فِي عُنُقِهِ قَالَ سُنَّةٌ قَطَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَ سَارِقٍ وَعَلَّقَ يَدَهُ فِي عُنُقِهِ","id":"Telah mengkhabarkan kepada kami [Suwaid bin Nashr], dia berkata; telah memberitakan kepada kami [Abdullah] dari [Abu Bakar bin Ali] dari [Al Hajjaj] dari [Makhul] dari [Ibnu Muhairiz], dia berkata; \"Saya bertanya kepada [Fadhalah bin 'Ubaid] mengenai penggantungan tangan pencuri di lehernya. Dia berkata; \"Sunnah. Rasulullah shallallahu 'alaihi wasallam memotong tangan pencuri dan menggantungkannya di lehernya.\" "},"4651":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنِي عُمَرُ بْنُ عَلِيٍّ الْمُقَدَّمِيُّ قَالَ حَدَّثَنَا الْحَجَّاجُ عَنْ مَكْحُولٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُحَيْرِيزٍ قَالَ قُلْتُ لِفَضَالَةَ بْنِ عُبَيْدٍأَرَأَيْتَ تَعْلِيقَ الْيَدِ فِي عُنُقِ السَّارِقِ مِنْ السُّنَّةِ هُوَ قَالَ نَعَمْ أُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَارِقٍ فَقَطَعَ يَدَهُ وَعَلَّقَهُ فِي عُنُقِهِقَالَ أَبُو عَبْد الرَّحْمَنِ الْحَجَّاجُ بْنُ أَرْطَاةَ ضَعِيفٌ وَلَا يُحْتَجُّ بِحَدِيثِهِ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Basysyar], dia berkata; telah menceritakan kepadaku [Umar bin Ali Al Muqaddami], dia berkata; telah menceritakan kepada kami [Al Hajjaj] dari [Makhul] dari [Abdur Rahman bin Muhairiz], dia berkata; \"Saya berkata kepada [Fadhalah bin 'Ubaid]; \"Bagaimana pendapatmu mengenai penggantungan tangan pada leher pencuri, apakah hal itu termasuk sunnah?\" Dia berkata; \"Ya. Pernah dihadapkan seorang pencuri kepada Rasulullah shallallahu 'alaihi wasallam kemudian beliau memotong tangannya dan menggantungkannya di lehernya.\" Abu Abdur Rahman berkata; \"Al Hajjaj bin Arthah adalah orang yang lemah dan haditsnya tidak dijadikan sebagai hujjah.\" "},"4652":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا حَسَّانُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا الْمُفَضَّلُ بْنُ فَضَالَةَ عَنْ يُونُسَ بْنِ يَزِيدَ قَالَ سَمِعْتُ سَعْدَ بْنَ إِبْرَاهِيمَ يُحَدِّثُ عَنْ الْمِسْوَرِ بْنِ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُغَرَّمُ صَاحِبُ سَرِقَةٍ إِذَا أُقِيمَ عَلَيْهِ الْحَدُّقَالَ أَبُو عَبْد الرَّحْمَنِ وَهَذَا مُرْسَلٌ وَلَيْسَ بِثَابِتٍ","id":"Telah mengkhabarkan kepada kami ['Amr bin Manshur], dia berkata; telah menceritakan kepada kami [Hassan bin Abdullah], dia berkata; telah menceritakan kepada kami [Al Mufadhdhal bin Fadhalah] dari [Yunus bin Yazid], dia berkata; \"Saya mendengar [Sa'd bin Ibrahim] menceritakan dari [Al Miswar bin Ibrahim] dari [Abdur Rahman bin 'Auf] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang pemilik harta curian itu dihutangi jika telah ditegakkan hukuman atasnya.\" Abu Abdur Rahman berkata; \"Hadits ini mursal dan tidak kuat.\""},"4653":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ أَحْمَدُ بْنُ شُعَيْبٍ مِنْ لَفْظِهِ قَالَ أَنْبَأَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ الْإِيمَانُ بِاللَّهِ وَرَسُولِهِ","id":"Telah mengkhabarkan kepada kami Abu Abdur Rahman Ahmad bin Syu'aib dari lafazhnya, dia berkata; telah memberitakan kepada kami ['Amr bin Ali], dia berkata; telah menceritakan kepada kami [Abdur Rahman], dia berkata; telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam ditanya; \"Amalan apakah yang paling utama?\" Beliau bersabda: \"Beriman kepada Allah dan RasulNya.\""},"4654":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي سُلَيْمَانَ عَنْ عَلِيٍّ الْأَزْدِيِّ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ حُبْشِيٍّ الْخَثْعَمِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ الْأَعْمَالِ أَفْضَلُ فَقَالَ إِيمَانٌ لَا شَكَّ فِيهِ وَجِهَادٌ لَا غُلُولَ فِيهِ وَحَجَّةٌ مَبْرُورَةٌ","id":"Telah mengkhabarkan kepada kami [Harun bin Abdullah], dia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij], dia berkata; telah menceritakan kepada kami [Utsman bin Abu Sulaiman] dari [Ali Al Azdi] dari ['Ubaid bin Umair] dari [Abdullah bin Hubsyi Al Khats'ami] bahwa Nabi shallallahu 'alaihi wasallam ditanya; \"Amalan apakah yang lebih utama?\" Beliau bersabda: \"Keimanan yang tidak ada keragua padanya dan jihad yang tidak ada pencurian hasil rampasan padanya, serta haji yang mabrur.\" "},"4655":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ طَلْقِ بْنِ حَبِيبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثٌ مَنْ كُنَّ فِيهِ وَجَدَ بِهِنَّ حَلَاوَةَ الْإِيمَانِ وَطَعْمَهُ أَنْ يَكُونَ اللَّهُ عَزَّ وَجَلَّ وَرَسُولُهُ أَحَبَّ إِلَيْهِ مِمَّا سِوَاهُمَا وَأَنْ يُحِبَّ فِي اللَّهِ وَأَنْ يَبْغُضَ فِي اللَّهِ وَأَنْ تُوقَدَ نَارٌ عَظِيمَةٌ فَيَقَعَ فِيهَا أَحَبَّ إِلَيْهِ مِنْ أَنْ يُشْرِكَ بِاللَّهِ شَيْئًا","id":"Telah mengkhabarkan kepada kami [Ishaq bin Ibrahim], dia berkata; telah memberitakan kepada kami [Jarir] dari [Manshur] dari [Thalq bin Habib] dari [Anas bin Malik], dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga perkara yang apabila ada pada diri seseorang niscaya dengannya dia akan mendapatkan manis dan lezatnya keimanan, yaitu; Allah 'azza wajalla dan RasulNya lebih dia cintai daripada selainnya, mencintai dan membenci karena Allah, dan dinyalakannya api yang besar kemudian dia terjatuh ke dalamnya lebih dia senangi daripada mensekutukan Allah dengan sesuatu.\""},"4656":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ شُعْبَةَ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثٌ مَنْ كُنَّ فِيهِ وَجَدَ حَلَاوَةَ الْإِيمَانِ مَنْ أَحَبَّ الْمَرْءَ لَا يُحِبُّهُ إِلَّا لِلَّهِ عَزَّ وَجَلَّ وَمَنْ كَانَ اللَّهُ عَزَّ وَجَلَّ وَرَسُولُهُ أَحَبَّ إِلَيْهِ مِمَّا سِوَاهُمَا وَمَنْ كَانَ أَنْ يُقْذَفَ فِي النَّارِ أَحَبَّ إِلَيْهِ مِنْ أَنْ يَرْجِعَ إِلَى الْكُفْرِ بَعْدَ أَنْ أَنْقَذَهُ اللَّهُ مِنْهُ","id":"Telah mengkhabarkan kepada kami [Suwaid bin Nashr], dia berkata; telah menceritakan kepada kami [Abdullah] dari [Syu'bah] dari [Qatadah], dia berkata; \"Saya mendengar [Anas bin Malik] radliallahu 'anhu menceritakan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"\"Tiga perkara yang apabila ada pada diri seseorang niscaya dia akan mendapatkan manisnya keimanan, yaitu; orang yang mencintai seseorang di mana tidaklah dia mencintainya kecuali karena Allah 'azza wajalla, orang yang lebih mencintai Allah dan RasulNya daripada selain mereka berdua, dan orang yang lebih suka dicampakkan ke dalam Neraka daripada kembali kepada kekafiran setelah Allah menyelamatkannya darinya.\""},"4657":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ حُمَيْدٍ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثٌ مَنْ كُنَّ فِيهِ وَجَدَ بِهِنَّ حَلَاوَةَ الْإِسْلَامِ مَنْ كَانَ اللَّهُ وَرَسُولُهُ أَحَبَّ إِلَيْهِ مِمَّا سِوَاهُمَا وَمَنْ أَحَبَّ الْمَرْءَ لَا يُحِبُّهُ إِلَّا لِلَّهِ وَمَنْ يَكْرَهُ أَنْ يَرْجِعَ إِلَى الْكُفْرِ كَمَا يَكْرَهُ أَنْ يُلْقَى فِي النَّارِ","id":"Telah mengkhabarkan kepada kami [Ali bin Hujr], dia berkata; telah menceritakan kepada kami [Isma'il] dari [Humaid] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tiga perkara yang apabila ada pada diri seseorang niscaya dia akan mendapatkan manisnya Islam, yaitu; orang yang lebih mencintai Allah dan RasulNya daripada selain mereka berdua, orang yang mencintai seseorang karena Allah, dan orang yang tidak senang kembali kepada kekafiran sebagaimana ia membenci untuk dicampakkan ke dalam Neraka.\""},"4658":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ قَالَ أَنْبَأَنَا كَهْمَسُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ يَحْيَى بْنِ يَعْمَرَ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَ حَدَّثَنِي عُمَرُ بْنُ الْخَطَّابِ قَالَبَيْنَمَا نَحْنُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ إِذْ طَلَعَ عَلَيْنَا رَجُلٌ شَدِيدُ بَيَاضِ الثِّيَابِ شَدِيدُ سَوَادِ الشَّعَرِ لَا يُرَى عَلَيْهِ أَثَرُ السَّفَرِ وَلَا يَعْرِفُهُ مِنَّا أَحَدٌ حَتَّى جَلَسَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْنَدَ رُكْبَتَيْهِ إِلَى رُكْبَتَيْهِ وَوَضَعَ كَفَّيْهِ عَلَى فَخِذَيْهِ ثُمَّ قَالَ يَا مُحَمَّدُ أَخْبِرْنِي عَنْ الْإِسْلَامِ قَالَ أَنْ تَشْهَدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَتُقِيمَ الصَّلَاةَ وَتُؤْتِيَ الزَّكَاةَ وَتَصُومَ رَمَضَانَ وَتَحُجَّ الْبَيْتَ إِنْ اسْتَطَعْتَ إِلَيْهِ سَبِيلًا قَالَ صَدَقْتَ فَعَجِبْنَا إِلَيْهِ يَسْأَلُهُ وَيُصَدِّقُهُ ثُمَّ قَالَ أَخْبِرْنِي عَنْ الْإِيمَانِ قَالَ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ وَالْيَوْمِ الْآخِرِ وَالْقَدَرِ كُلِّهِ خَيْرِهِ وَشَرِّهِ قَالَ صَدَقْتَ قَالَ فَأَخْبِرْنِي عَنْ الْإِحْسَانِ قَالَ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنْ لَمْ تَكُنْ تَرَاهُ فَإِنَّهُ يَرَاكَ قَالَ فَأَخْبِرْنِي عَنْ السَّاعَةِ قَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ بِهَا مِنْ السَّائِلِ قَالَ فَأَخْبِرْنِي عَنْ أَمَارَاتِهَا قَالَ أَنْ تَلِدَ الْأَمَةُ رَبَّتَهَا وَأَنْ تَرَى الْحُفَاةَ الْعُرَاةَ الْعَالَةَ رِعَاءَ الشَّاءِ يَتَطَاوَلُونَ فِي الْبُنْيَانِ قَالَ عُمَرُ فَلَبِثْتُ ثَلَاثًا ثُمَّ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عُمَرُ هَلْ تَدْرِي مَنْ السَّائِلُ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّهُ جِبْرِيلُ عَلَيْهِ السَّلَام أَتَاكُمْ لِيُعَلِّمَكُمْ أَمْرَ دِينِكُمْ","id":"Telah mengkhabarkan kepada kami [Ishaq bin Ibrahim], dia berkata; telah menceritakan kepada kami [An Nadhr bin Syumail], dia berkata; telah memberitakan kepada kami [Kahmas bin Al Hasan], dia berkata; telah menceritakan kepada kami [Abdullah bin Buraidah] dari [Yahya bin Ya'mar] bahwa [Abdullah bin Umar] berkata; telah menceritakan kepadaku [Umar bin Al Khathab], dia berkata; \"Pada suatu hari ketika kami bersama Rasulullah shallallahu 'alaihi wasallam tiba-tiba muncul di hadapan kami orang yang sangat putih pakaiannya, hitam rambutnya, tidak terlihat padanya bekas bepergian, dan tidak ada seorangpun di antara kami yang mengenalnya, hingga ia duduk di hadapan Rasulullah shallallahu 'alaihi wasallam dan menyandarkan lututnya kepada lutut beliau dan meletakkan kedua telapak tangannya pada kedua paha beliau kemudian berkata; \"Wahai Muhammad, beritahukan kepadaku mengenai Islam\". Beliau bersabda: \"Engkau bersaksi bahwa tidak ada Tuhan yang berhak disembah kecuali Allah, dan Muhammad adalah utusan Allah, engkau mendirikan shalat, membayar zakat, berpuasa Ramadhan dan melakukan haji ke Ka'bah apabila mampu pergi ke sana.\" Orang tersebut berkata; \"Tuan benar\". Maka kami pun heran kepadanya, dia bertanya dan dia pula yang membenarkannya. Kemudian dia berkata; \"Beritahukan kepadaku mengenai iman!\" Beliau bersabda: \"Engkau beriman kepada Allah, para MalaikatNya, kitab-kitabNya, para rasulNya dan Hari Akhir serta seluruh takdir yang baik dan yang buruk.\" Dia berkata; \"Tuan benar\". Dia berkata; \"Beritahukan kepadaku mengenai ihsan!\" Beliau bersabda: \"Ihsan adalah engkau menyembah Allah seolah-olah engkau melihatNya dan apabila engkau tidak melihatNya maka sesungguhnya Dia melihatmu.\" Dia berkata; \"Beritahukan kepadaku mengenai Hari Kiamat!\" Beliau bersabda: \"Orang yang ditanya tidaklah lebih mengetahui daripada yang bertanya.\" Dia berkata; \"Beritahukan kepadaku mengenai tanda-tandanya!\" Beliau bersabda: \"Jika ada budak wanita yang melahirkan tuannya, dan engkau melihat orang yang tidak beralas kaki, telanjang dan tidak berkhitan serta menggembalakan kambing saling berlomba meninggikan bangunan.\" Tiga hari kemudian beliau bertanya kepadaku: \"Wahai Umar, apakah engkau mengetahui siapakah yang bertanya?\" saya menjawab; \"Allah dan RasulNya lebih mengetahui.\" Beliau bersabda: \"Sesungguhnya dia adalah Jibril 'alaihissalam, datang kepada kalian hendak mengajarkan kepada kalian perkara agama kalian.\" "},"4659":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ عَنْ جَرِيرٍ عَنْ أَبِي فَرْوَةَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ وَأَبِي ذَرٍّ قَالَاكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْلِسُ بَيْنَ ظَهْرَانَيْ أَصْحَابِهِ فَيَجِيءُ الْغَرِيبُ فَلَا يَدْرِي أَيُّهُمْ هُوَ حَتَّى يَسْأَلَ فَطَلَبْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَجْعَلَ لَهُ مَجْلِسًا يَعْرِفُهُ الْغَرِيبُ إِذَا أَتَاهُ فَبَنَيْنَا لَهُ دُكَّانًا مِنْ طِينٍ كَانَ يَجْلِسُ عَلَيْهِ وَإِنَّا لَجُلُوسٌ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَجْلِسِهِ إِذْ أَقْبَلَ رَجُلٌ أَحْسَنُ النَّاسِ وَجْهًا وَأَطْيَبُ النَّاسِ رِيحًا كَأَنَّ ثِيَابَهُ لَمْ يَمَسَّهَا دَنَسٌ حَتَّى سَلَّمَ فِي طَرَفِ الْبِسَاطِ فَقَالَ السَّلَامُ عَلَيْكَ يَا مُحَمَّدُ فَرَدَّ عَلَيْهِ السَّلَامُ قَالَ أَدْنُو يَا مُحَمَّدُ قَالَ ادْنُهْ فَمَا زَالَ يَقُولُ أَدْنُو مِرَارًا وَيَقُولُ لَهُ ادْنُ حَتَّى وَضَعَ يَدَهُ عَلَى رُكْبَتَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا مُحَمَّدُ أَخْبِرْنِي مَا الْإِسْلَامُ قَالَ الْإِسْلَامُ أَنْ تَعْبُدَ اللَّهَ وَلَا تُشْرِكَ بِهِ شَيْئًا وَتُقِيمَ الصَّلَاةَ وَتُؤْتِيَ الزَّكَاةَ وَتَحُجَّ الْبَيْتَ وَتَصُومَ رَمَضَانَ قَالَ إِذَا فَعَلْتُ ذَلِكَ فَقَدْ أَسْلَمْتُ قَالَ نَعَمْ قَالَ صَدَقْتَ فَلَمَّا سَمِعْنَا قَوْلَ الرَّجُلِ صَدَقْتَ أَنْكَرْنَاهُ قَالَ يَا مُحَمَّدُ أَخْبِرْنِي مَا الْإِيمَانُ قَالَ الْإِيمَانُ بِاللَّهِ وَمَلَائِكَتِهِ وَالْكِتَابِ وَالنَّبِيِّينَ وَتُؤْمِنُ بِالْقَدَرِ قَالَ فَإِذَا فَعَلْتُ ذَلِكَ فَقَدْ آمَنْتُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ قَالَ صَدَقْتَ قَالَ يَا مُحَمَّدُ أَخْبِرْنِي مَا الْإِحْسَانُ قَالَ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنْ لَمْ تَكُنْ تَرَاهُ فَإِنَّهُ يَرَاكَ قَالَ صَدَقْتَ قَالَ يَا مُحَمَّدُ أَخْبِرْنِي مَتَى السَّاعَةُ قَالَ فَنَكَسَ فَلَمْ يُجِبْهُ شَيْئًا ثُمَّ أ��عَادَ فَلَمْ يُجِبْهُ شَيْئًا ثُمَّ أَعَادَ فَلَمْ يُجِبْهُ شَيْئًا وَرَفَعَ رَأْسَهُ فَقَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنْ السَّائِلِ وَلَكِنْ لَهَا عَلَامَاتٌ تُعْرَفُ بِهَا إِذَا رَأَيْتَ الرِّعَاءَ الْبُهُمَ يَتَطَاوَلُونَ فِي الْبُنْيَانِ وَرَأَيْتَ الْحُفَاةَ الْعُرَاةَ مُلُوكَ الْأَرْضِ وَرَأَيْتَ الْمَرْأَةَ تَلِدُ رَبَّهَا خَمْسٌ لَا يَعْلَمُهَا إِلَّا اللَّهُ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ إِلَى قَوْلِهِ إِنَّ اللَّهَ عَلِيمٌ خَبِيرٌ }ثُمَّ قَالَ لَا وَالَّذِي بَعَثَ مُحَمَّدًا بِالْحَقِّ هُدًى وَبَشِيرًا مَا كُنْتُ بِأَعْلَمَ بِهِ مِنْ رَجُلٍ مِنْكُمْ وَإِنَّهُ لَجِبْرِيلُ عَلَيْهِ السَّلَام نَزَلَ فِي صُورَةِ دِحْيَةَ الْكَلْبِيِّ","id":"Telah bercerita kepada kami [Muhammad bin Qudamah] dari [Jarir] dari [Abu Farwah] dari [Abu Zur'ah] dari [Abu Hurairah] dan [Abu Dzar], mereka berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah duduk di antara para sahabat beliau. Kemudian datanglah orang asing dan ia tidak tahu yang manakah Rasulullah shallallahu 'alaihi wasallam hingga ia bertanya. Kemudian kami meminta (izin) kepada Rasulullah shallallahu 'alaihi wasallam untuk membuatkan beliau tempat duduk sehingga beliau bisa diketahui oleh orang asing apabila hendak menemui beliau. Kemudian kami membuatkan tempat duduk yang panjang untuk beliau dari tanah liat. Ketika kami tengah duduk, sedang Rasulullah shallallahu 'alaihi wasallam berada di tempat duduk beliau, tiba-tiba datanglah seorang laki-laki yang sangat elok wajahnya dan sangat harum baunya seolah-olah bajunya tidak pernah terkena kotoran, hingga dia memberikan salam di tepi permadani, dia berkata; \"As Salaamu 'alaika wahai Muhammad! Lalu beliau membalas salamnya. Dia berkata; \"Apakah aku boleh mendekat wahai Muhammad? Beliau bersabda: \"Mendekatlah.\" Ia terus berkata; \"Apakah aku boleh mendekat?\", beberapa kali. Dan beliau bersabda kepadanya: \"Mendekatlah.\" Hingga orang tersebut meletakkan tangannya pada kedua lutut Rasulullah shallallahu 'alaihi wasallam. Dia berkata; \"Wahai Muhammad, beritahukan kepadaku apakah Islam itu?\" Beliau bersabda: \"Islam adalah engkau menyembah Allah dan tidak mensekutukanNya dengan sesuatu, mendirikan shalat, membayar zakat, melakukan haji ke Baitulloh dan melakukan puasa Ramadhan.\" dia berkata; \"Apakah apabila aku melakukannya maka aku telah masuk Islam?\" Beliau menjawab: \"Ya.\" dia berkata; Tuan benar. Tatkala kami mendengar perkataan; engkau benar, dari orang tersebut;, maka kami pun menjadi bingung terhadapnya. Dia berkata; \"Wahai Muhammad, beritahukan kepadaku apakah iman itu!\" Beliau bersabda: \"Beriman kepada Allah, MalaikatNya, kitab-kitabNya, dan para nabi serta beriman kepada tagdir.\" Dia berkata; \"Apakah apabila saya melakukan hal tersebut maka aku telah beriman?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"ya.\" Dia berkata; Tuan benar.\" Dia berkata; \"Beritahukan kepadaku apa itu ihsan?\" Beliau bersabda: \"Engkau beribadah kepada Allah, seolah-olah engkau melihatNya dan apabila engkau tidak melihatNya maka sesungguhnya Dia melihatmu\". Dia berkata; \"Tuan benar.\" Dia berkata; \"Wahai Muhammad, beritahukan kepadaku kapankah Hari Kiamat tiba?\" Beliau menundukkan kepala dan tidak menjawab sedikitpun, kemudian orang tersebut mengulang pertanyaan dan beliau tidak menjawab sedikitpun. Lalu beliau mengangkat kepalanya seraya bersabda: \"Orang yang ditanya tidaklah lebih tahu daripada yang bertanya. Akan tetapi ia memiliki tanda-tanda yang dengannya Hari Kiamat tersebut diketahui. Yaitu apabila engkau melihat para penggembala hewan ternak yang berlomba-lomba meninggikan bangunan dan engkau lihat orang-orang yang tidak beralas kaki dan telanjang sebagai para pemilik tanah, dan engkau melihat wanita yang melahirkan tuannya. Itulah lima tanda yang tidak diketahui kecuali oleh Allah. Sesungguhnya Allah memiliki ilmu mengenai Hari Kiamat hingga firman Allah: Sesungguhnya Allah Maha Mengetahui lagi Maha Mengenal. Kemudian beliau bersabda: \"Demi Dzat yang mengutus Muhammad dengan kebenaran sebagai pemberi petunjuk dan kabar gembira, tidaklah aku lebih mengetahui dari salah seorang dari kalian. Sesungguhnya ia adalah Jibril 'alaihissalam yang turun dalam bentuk Dahjah Al Kalbi.\" "},"4660":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ ثَوْرٍ قَالَ مَعْمَرٌ وَأَخْبَرَنِي الزُّهْرِيُّ عَنْ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِ قَالَأَعْطَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رِجَالًا وَلَمْ يُعْطِ رَجُلًا مِنْهُمْ شَيْئًا قَالَ سَعْدٌ يَا رَسُولَ اللَّهِ أَعْطَيْتَ فُلَانًا وَفُلَانًا وَلَمْ تُعْطِ فُلَانًا شَيْئًا وَهُوَ مُؤْمِنٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ مُسْلِمٌ حَتَّى أَعَادَهَا سَعْدٌ ثَلَاثًا وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَوْ مُسْلِمٌ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأُعْطِي رِجَالًا وَأَدَعُ مَنْ هُوَ أَحَبُّ إِلَيَّ مِنْهُمْ لَا أُعْطِيهِ شَيْئًا مَخَافَةَ أَنْ يُكَبُّوا فِي النَّارِ عَلَى وُجُوهِهِمْ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdul A'la], dia berkata; telah menceritakan kepada kami [Muhammad yaitu Ibnu Tsaur], berkata [Ma'mar] dan telah mengkhabarkan kepadaku [Az Zuhri] dari ['Amir bin Sa'd bin Abu Waqqash] dari [ayahnya], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah memberi kepada beberapa orang dan tidak memberi kepada seorang saja dari mereka sedikitpun. Sa'd bertanya; \"Wahai Rasulullah shallallahu 'alaihi wasallam, Tuan memberi kepada Fulan sedangkan Fulan (yang satunya) tidak Tuan beri sedikitpun, padahal dia adalah seorang mukmin.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Ataukah ia seorang muslim?\" hingga Sa'd mengulang tiga kali dan Nabi shallallahu 'alaihi wasallam bersabda: \"Ataukah ia seorang muslim?\" kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saya memberi beberapa orang dan meninggalkan orang yang lebih saya cintai daripada mereka, saya tidak memberinya sedikitpun karena khawatir mereka akan diseret ke dalam Neraka di atas wajah mereka.\""},"4661":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنَا سَلَّامُ بْنُ أَبِي مُطِيعٍ قَالَ سَمِعْتُ مَعْمَرًا عَنْ الزُّهْرِيِّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ سَعْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَسَمَ قَسْمًا فَأَعْطَى نَاسًا وَمَنَعَ آخَرِينَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَعْطَيْتَ فُلَانًا وَمَنَعْتَ فُلَانًا وَهُوَ مُؤْمِنٌ قَالَ لَا تَقُلْ مُؤْمِنٌ وَقُلْ مُسْلِمٌقَالَ ابْنُ شِهَابٍ{ قَالَتْ الْأَعْرَابُ آمَنَّا }","id":"Telah mengkhabarkan kepada kami ['Amr bin Manshur], ia berkata; telah menceritakan kepada kami [Hisyam bin Abdul Malik], ia berkata; telah menceritakan kepada kami [Sallam bin Abu Muthi'], ia berkata; \"Saya mendengar [Ma'mar] dari [Az Zuhri] dari ['Amir bin Sa'd] dari [Sa'd] bahwa Rasulullah shallallahu 'alaihi wasallam membagikan suatu pembagian, beliau memberi beberapa orang namun tidak memberi beberapa orang lainnya. Lalu saya bertanya; \"Wahai Rasulullah, engkau memberi Fulan dan menahan dari Fulan, padahal dia adalah seorang mukmin.\" Maka beliau bersabda: \"Janganlah engkau mengatakan; mukmin, katakanlah; muslim.\" Ibnu Syihab berkata; Orang-orang Arab Badui itu berkata: \"Kami telah beriman.\""},"4662":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ عَمْرٍو عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ بِشْرِ بْنِ سُحَيْمٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُ أَنْ يُنَادِيَ أَيَّامَ التَّشْرِيقِ أَنَّهُ لَا يَدْخُلُ الْجَنَّةَ إِلَّا مُؤْمِنٌ وَهِيَ أَيَّامُ أَكْلٍ وَشُرْبٍ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami [Hammad] dari ['Amr] dari [Nafi' bin Jubair bin Muth'im] dari [Bisyr bin Suhaim] bahwa Nabi shallallahu 'alaihi wasallam memerintahkannya agar menyeru pada hari-hari Tasyriq; bahwa tidak akan masuk Surga kecuali orang mukmin. Hari-hari itu adalah hari-hari makan dan minum. "},"4663":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُسْلِمُ مَنْ سَلِمَ النَّاسُ مِنْ لِسَانِهِ وَيَدِهِ وَالْمُؤْمِنُ مَنْ أَمِنَهُ النَّاسُ عَلَى دِمَائِهِمْ وَأَمْوَالِهِمْ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Al Qa'qa' bin Hakim] dari [Abu Shaleh] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang muslim adalah orang yang seluruh manusia selamat dari lidah dan tangannya, sedangkan seorang mukmin adalah orang yang seluruh manusia merasa aman darah dan harta mereka dari (gangguan) nya.\" "},"4664":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ إِسْمَعِيلَ عَنْ عَامِرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْمُسْلِمُ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ وَالْمُهَاجِرُ مَنْ هَجَرَ مَا نَهَى اللَّهُ عَنْهُ","id":"Telah mengkhabarkan kepada kami ['Amr bin Ali], dia berkata; telah menceritakan kepada kami [Yahya] dari [Isma'il] dari ['Amir] dari [Abdullah bin 'Amr], dia berkata; \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang muslim adalah orang yang seluruh kaum muslimin merasa selamat dari lidah dan tangannya, dan orang yang berhijrah adalah orang yang meninggalkan apa yang Allah larang.\""},"4665":{"ar":"أَخْبَرَنَا حَفْصُ بْنُ عُمَرَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَنْصُورِ بْنِ سَعْدٍ عَنْ مَيْمُونِ بْنِ سِيَاهٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى صَلَاتَنَا وَاسْتَقْبَلَ قِبْلَتَنَا وَأَكَلَ ذَبِيحَتَنَا فَذَلِكُمْ الْمُسْلِمُ","id":"Telah mengkhabarkan kepada kami [Hafsh bin Umar], ia berkata; telah menceritakan kepada kami [Abdur Rahman bin Mahdi] dari [Manshur bin Sa'd] dari [Maimun bin Siyah] dari [Anas], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa melakukan shalat (seperti) shalat kami dan menghadap ke Kiblat kami, serta makan sembelihan kami maka dia adalah orang muslim.\""},"4666":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ الْمُعَلَّى بْنِ يَزِيدَ قَالَ حَدَّثَنَا صَفْوَانُ بْنُ صَالِحٍ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ حَدَّثَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَسْلَمَ الْعَبْدُ فَحَسُنَ إِسْلَامُهُ كَتَبَ اللَّهُ لَهُ كُلَّ حَسَنَةٍ كَانَ أَزْلَفَهَا وَمُحِيَتْ عَنْهُ كُلُّ سَيِّئَةٍ كَانَ أَزْلَفَهَا ثُمَّ كَانَ بَعْدَ ذَلِكَ الْقِصَاصُ الْحَسَنَةُ بِعَشْرَةِ أَمْثَالِهَا إِلَى سَبْعِ مِائَةِ ضِعْفٍ وَالسَّيِّئَةُ بِمِثْلِهَا إِلَّا أَنْ يَتَجَاوَزَ اللَّهُ عَزَّ وَجَلَّ عَنْهَا","id":"Telah mengkhabarkan kepadaku [Ahmad bin Al Mua'lla bin Yazid], dia berkata; telah menceritakan kepada kami [Shafwan bin Shaleh], dia berkata; telah menceritakan kepada kami [Al Walid], dia berkata; telah menceritakan kepada kami [Malik] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [Abu Sa'id Al Khudri], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang hamba masuk Islam lalu memperbaiki keIslamannya maka Allah akan menuliskan untuknya setiap kebaikan yang dia lakukan, dan dihapus setiap keburukan yang dia lakukan kemudian setelah itu (setiap) kebaikan dibalas dengan sepuluh hingga tujuhratus kali lipat, sedangkan keburukan akan dibalas dengan semisalnya kecuali jika Allah Azza wa jalla memaafkannya.\""},"4667":{"ar":"أَخْبَرَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْأُمَوِيُّ عَنْ أَبِيهِ قَالَ حَدَّثَنَا أَبُو بُرْدَةَ وَهَوَ بُرَيْدُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقُلْنَا يَا رَسُولَ اللَّهِ أَيُّ الْإِسْلَامِ أَفْضَلُ قَالَ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ","id":"Telah mengkhabarkan kepada kami [Sa'id bin Yahya bin Sa'id Al Umawi] dari [ayahnya], dia berkata; telah menceritakan kepada kami [Abu Burdah yaitu Buraid bin Abdullah bin Abu Burdah] dari [Abu Burdah] dari [Abu Musa], dia berkata; \"Kami bertanya; \"Wahai Rasulullah (amalan) Islam yang manakah yang paling utama?\" Beliau bersabda: \"Orang yang seluruh kaum muslimin selamat dari lisan dan tangannya.\""},"4668":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَجُلًا سَأَ��َ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْإِسْلَامِ خَيْرٌ قَالَ تُطْعِمُ الطَّعَامَ وَتَقْرَأُ السَّلَامَ عَلَى مَنْ عَرَفْتَ وَمَنْ لَمْ تَعْرِفْ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari [Abdullah bin 'Amr] bahwa seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam; (Amalan) Islam manakah yang paling baik?\" Beliau bersabda: \"Engkau memberi makan dan mengucapkan salam kepada orang yang engkau kenal dan yang tidak engkau kenal.\""},"4669":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَمَّارٍ قَالَ حَدَّثَنَا الْمُعَافَى يَعْنِي ابْنَ عِمْرَانَ عَنْ حَنْظَلَةَ بْنِ أَبِي سُفْيَانَ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا قَالَ لَهُ أَلَا تَغْزُو قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بُنِيَ الْإِسْلَامُ عَلَى خَمْسٍ شَهَادَةِ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَإِقَامِ الصَّلَاةِ وَإِيتَاءِ الزَّكَاةِ وَالْحَجِّ وَصِيَامِ رَمَضَانَ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdullah bin 'Ammar], dia berkata; telah menceritakan kepada kami [Al Mu'afa yaitu Ibnu Imran] dari [Hanzhalah bin Abu Sufyan] dari [Ikrimah bin Khalid] dari [Ibnu Umar] bahwa seorang laki-laki berkata kepadanya; Kenapa kamu tidak berperang?\" Ibnu Umar menjawab; \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Islam terbangun atas lima perkara, yaitu; bersaksi bahwa tidak ada Tuhan yang berhak disembah kecuali Allah, mendirikan shalat, membayar zakat, melakukan haji, dan berpuasa Ramadhan.\" "},"4670":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَجْلِسٍ فَقَالَ تُبَايِعُونِي عَلَى أَنْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا قَرَأَ عَلَيْهِمْ الْآيَةَ فَمَنْ وَفَّى مِنْكُمْ فَأَجْرُهُ عَلَى اللَّهِ وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَسَتَرَهُ اللَّهُ عَزَّ وَجَلَّ فَهُوَ إِلَى اللَّهِ إِنْ شَاءَ عَذَّبَهُ وَإِنْ شَاءَ غَفَرَ لَهُ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Idris Al Khaulani] dari ['Ubadah bin Ash Shamit], dia berkata; \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu majelis, kemudian beliau bersabda: \"Apakah kalian akan membaiatku untuk tidak mensekutukan Allah dengan sesuatupun, tidak mencuri, dan tidak berzina?\" Lalu beliau membaca sebuah ayat.\"Barang siapa di antara kalian yang menepatinya maka pahalanya di sisi Allah, dan barang siapa yang melakukan sebagian darinya maka Allah 'azza wajalla pasti menutupi (kekurangan) nya. Lalu (hukuman bagi) dia kembali kepada Allah, jika Allah menghendaki Dia akan mengadzabnya dan jika Allah menghendaki Dia akan mengampuninya.\" "},"4671":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ نُعَيْمٍ قَالَ أَنْبَأَنَا حِبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَشْهَدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَإِذَا شَهِدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَاسْتَقْبَلُوا قِبْلَتَنَا وَأَكَلُوا ذَبِيحَتَنَا وَصَلَّوْا صَلَاتَنَا فَقَدْ حَرُمَتْ عَلَيْنَا دِمَاؤُهُمْ وَأَمْوَالُهُمْ إِلَّا بِحَقِّهَا لَهُمْ مَا لِلْمُسْلِمِينَ وَعَلَيْهِمْ مَا عَلَيْهِمْ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Hatim bin Nu'aim], dia berkata; telah memberitakan kepada kami [Hibban], dia berkata; telah memberitakan kepada kami [Abdullah] dari [Humaid Ath Thawil] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya diperintahkan untuk memerangi manusia hingga mereka bersaksi bahwa tidak ada Tuhan yang berhak disembah kecuali Allah dan Muhammad adalah Rasulullah, apabila mereka telah bersaksi bahwa tidak ada Tuhan yang berhak disembah kecuali Allah dan Muhammad adalah Rasulullah, menghadap ke kiblat kita, memakan sembelihan kita, dan melakukan shalat (seperti) sholat kita maka sungguh telah diharamkan atas kita darah dan harta mereka, kecuali dengan haknya. Bagi mereka apa yang menjadi hak kaum muslimin dan atas mereka apa yang menjadi kewajiban kaum muslimin.\" "},"4672":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا أَبُو عَامِرٍ قَالَ حَدَّثَنَا سُلَيْمَانُ وَهُوَ ابْنُ بِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْإِيمَانُ بِضْعٌ وَسَبْعُونَ شُعْبَةً وَالْحَيَاءُ شُعْبَةٌ مِنْ الْإِيمَانِ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak], dia berkata; telah menceritakan kepada kami [Abu 'Amir], dia berkata; telah menceritakan kepada kami [Sulaiman yaitu Ibnu Bilal] dari [Abdullah bin Dinar] dari [Abu Shaleh] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Iman itu ada tujuh puluh sekian cabang, dan rasa malu adalah salah satu cabang dari keimanan.\""},"4673":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ عَنْ سُفْيَانَ قَالَ و حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سُهَيْلٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْإِيمَانُ بِضْعٌ وَسَبْعُونَ شُعْبَةً أَفْضَلُهَا لَا إِلَهَ إِلَّا اللَّهُ وَأَوْضَعُهَا إِمَاطَةُ الْأَذَى عَنْ الطَّرِيقِ وَالْحَيَاءُ شُعْبَةٌ مِنْ الْإِيمَانِ","id":"Telah mengkhabarkan kepada kami [Ahmad bin Sulaiman], dia berkata; telah menceritakan kepada kami [Abu Daud] dari [Sufyan], dia berkata; telah menceritakan kepada kami [Abu Nu'aim], dia berkata; telah menceritakan kepada kami [Sufyan] dari [Suhail] dari [Abdullah bin Dinar] dari [Abu Shaleh] dari [Abu Hurairah], dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Iman itu ada tujuh puluh sekian cabang yang paling utama adalah persaksian bahwa tidak ada Tuhan yang berhak disembah kecuali Allah dan yang paling rendah adalah menyingkirkan gangguan dari jalan. Dan rasa malu adalah salah satu cabang dari keimanan.\""},"4674":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ عَنْ ابْنِ عَجْلَانَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحَيَاءُ شُعْبَةٌ مِنْ الْإِيمَانِ","id":"Telah mengkhabarkan kepada kami [Yahya bin Habib bin Arabi], dia berkata; telah menceritakan kepada kami [Khalid yaitu Ibnu Al Harits] dari [Ibnu 'Ajlan] dari [Abdullah bin Dinar] dari [Abu Shaleh] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Rasa malu adalah salah satu cabang dari keimanan.\""},"4675":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ وَعَمْرُو بْنُ عَلِيٍّ عَنْ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي عَمَّارٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُلِئَ عَمَّارٌ إِيمَانًا إِلَى مُشَاشِهِ","id":"Telah mengkhabarkan kepada kami [Ishaq bin Manshur] dan ['Amr bin Ali] dari [Abdur Rahman], dia berkata; telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abu 'Ammar] dari ['Amr bin Syurahbil] dari [salah seorang sahabat Nabi shallallahu 'alaihi wasallam], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \" Ammar (Orang yang teguh imannya) (hatinya) dipenuhi dengan keimanan hingga tulang pokoknya.\""},"4676":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ قَالَ قَالَ أَبُو سَعِيدٍسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ رَأَى مُنْكَرًا فَلْيُغَيِّرْهُ بِيَدِهِ فَإِنْ لَمْ يَسْتَطِعْ فَبِلِسَانِهِ فَإِنْ لَمْ يَسْتَطِعْ فَبِقَلْبِهِ وَذَلِكَ أَضْعَفُ الْإِيمَانِ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Basysyar], dia berkata; telah menceritakan kepada kami [Abdur Rahman], dia berkata; telah menceritakan kepada kami [Sufyan] dari [Qais bin Muslim] dari [Thariq bin Syihab], dia berkata; [Abu Sa'id] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabada: \"Barang siapa yang melihat kemungkaran maka hendaknya ia mengubahnya dengan tangannya dan apabila ia tidak mampu maka dengan lidahnya dan apabila tidak mampu maka dengan hatinya dan yang demikian itu adalah selemah-lemah iman.\""},"4677":{"ar":"حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَخْلَدٌ قَالَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ قَالَ قَالَ أَبُو سَعِيدٍ الْخُدْرِيُّسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ رَأَى مُنْكَرًا فَغَيَّرَهُ بِيَدِهِ فَقَدْ بَرِئَ وَمَنْ لَمْ يَسْتَطِعْ أَنْ يُغَيِّرَهُ بِيَدِهِ فَغَيَّرَهُ بِلِسَانِهِ فَقَدْ بَرِئَ وَمَنْ لَمْ يَسْتَطِعْ أَنْ يُغَيِّرَهُ بِلِسَانِهِ فَغَيَّرَهُ بِقَلْبِهِ فَقَدْ بَرِئَ وَذَلِكَ أَضْعَفُ الْإِيمَانِ","id":"Telah mengkhabarkan kepada kami [Abdul Hamid bin Muhammad], dia berkata; telah menceritakan kepada kami [Makhlad], dia berkata; telah menceritakan kepada kami [Malik bin Mighwal] dari [Qais bin Muslim] dari [Thariq bin Syihab], dia berkata; [Abu Sa'id Al Khudri] berkata; \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang melihat kemungkaran kemudian ia merubahnya dengan tangannya maka sungguh ia telah berlepas diri dari kemungkaran tersebut, dan orang yang tidak mampu untuk mengubahnya dengan tangannya kemudian mengubahnya dengan lisannya maka sungguh ia telah berlepas diri, dan barang siapa yang tidak mampu untuk mengubahnya dengan lisannya kemudian ia mengubahnya dengan hatinya maka sungguh ia telah berlepas diri, dan hal itu adalah selemah-lemah iman.\""},"4678":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مُجَادَلَةُ أَحَدِكُمْ فِي الْحَقِّ يَكُونُ لَهُ فِي الدُّنْيَا بِأَشَدَّ مُجَادَلَةً مِنْ الْمُؤْمِنِينَ لِرَبِّهِمْ فِي إِخْوَانِهِمْ الَّذِينَ أُدْخِلُوا النَّارَ قَالَ يَقُولُونَ رَبَّنَا إِخْوَانُنَا كَانُوا يُصَلُّونَ مَعَنَا وَيَصُومُونَ مَعَنَا وَيَحُجُّونَ مَعَنَا فَأَدْخَلْتَهُمْ النَّارَ قَالَ فَيَقُولُ اذْهَبُوا فَأَخْرِجُوا مَنْ عَرَفْتُمْ مِنْهُمْ قَالَ فَيَأْتُونَهُمْ فَيَعْرِفُونَهُمْ بِصُوَرِهِمْ فَمِنْهُمْ مَنْ أَخَذَتْهُ النَّارُ إِلَى أَنْصَافِ سَاقَيْهِ وَمِنْهُمْ مَنْ أَخَذَتْهُ إِلَى كَعْبَيْهِ فَيُخْرِجُونَهُمْ فَيَقُولُونَ رَبَّنَا قَدْ أَخْرَجْنَا مَنْ أَمَرْتَنَا قَالَ وَيَقُولُ أَخْرِجُوا مَنْ كَانَ فِي قَلْبِهِ وَزْنُ دِينَارٍ مِنْ الْإِيمَانِ ثُمَّ قَالَ مَنْ كَانَ فِي قَلْبِهِ وَزْنُ نِصْفِ دِينَارٍ حَتَّى يَقُولَ مَنْ كَانَ فِي قَلْبِهِ وَزْنُ ذَرَّةٍقَالَ أَبُو سَعِيدٍ فَمَنْ لَمْ يُصَدِّقْ فَلْيَقْرَأْ هَذِهِ الْآيَةَ{ إِنَّ اللَّهَ لَا يَغْفِرُ أَنْ يُشْرَكَ بِهِ وَيَغْفِرُ مَا دُونَ ذَلِكَ لِمَنْ يَشَاءُ إِلَى عَظِيمًا }","id":"Telah mengkhabarkan kepada kami [Muhammad bin Rafi'], dia berkata; telah menceritakan kepada kami [Abdur Razzaq], dia berkata; telah memberitakan kepada kami [Ma'mar] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [Abu Sa'id Al Khudri] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perdebatan salah seorang di antara kalian tentang haqnya di dunia, tidaklah lebih dahsyat daripada perdebatan kaum mukminin kepada Tuhan mereka tentang saudara-saudara mereka yang dimasukkan ke Neraka, beliau bersabda: \"Mereka berkata; \"Wahai Tuhan kami, dahulu saudara-saudara kami sholat bersama kami, berpuasa bersama kami dan berhaji bersama kami namun Engkau memasukkan mereka ke Neraka, beliau bersabda: \" Allah berfirman; \"Pergilah, lalu keluarkanlah siapa yang kalian kenal di antara mereka.\" Beliau bersabda: \"Lalu mereka mendatangi mereka dan mengenali mereka dengan bentuk mereka, di antara mereka ada yang terbakar hingga setengah betisnya, di antara mereka ada yang terbakar hingga mata kakinya, lalu mereka mengeluarkannya seraya berkata; \"Wahai Tahun kami, kami telah mengeluarkan orang yang Engkau perintahkan.\" Beliau bersabda: \"Lalu Allah berfirman; \"Keluarkan siapa saja yang di hatinya terdapat keimanan seberat satu dinar.\" lalu Dia berfirman lagi; \"Siapa yang di hatinya terdapat keimanan seberat setengah dinar.\" Hingga Dia mengatakan; \"Siapa yang di hatinya terdapat keimanan seberat biji Dzarroh (atom).\" Abu Sa'id berkata; \"Barang siapa yang tidak percaya maka hendaknya ia membaca ayat ini: \"Sesungguhnya Allah tidak akan mengampuni dosa syirik, dan Dia mengampuni segala dosa yang selain dari (syirik) itu, bagi siapa yang dikehendaki-Nya. Barangsiapa yang mempersekutukan Allah, maka sungguh ia telah berbuat dosa yang besar.\""},"4679":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي أَبُو أُمَامَةَ بْنُ سَهْلٍ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَا أَنَا نَائِمٌ رَأَيْتُ النَّاسَ يُعْرَضُونَ عَلَيَّ وَعَلَيْهِمْ قُمُصٌ مِنْهَا مَا يَبْلُغُ الثُّدِيَّ وَمِنْهَا مَا يَبْلُغُ دُونَ ذَلِكَ وَعُرِضَ عَلَيَّ عُمَرُ بْنُ الْخَطَّابِ وَعَلَيْهِ قَمِيصٌ يَجُرُّهُ قَالَ فَمَاذَا أَوَّلْتَ ذَلِكَ يَا رَسُولَ اللَّهِ قَالَ الدِّينَ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Yahya bin Abdullah], dia berkata; telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd], dia berkata; telah menceritakan kepada kami [ayahku] dari [Shalih bin Kaisan] dari [Ibnu Syihab], dia berkata; telah menceritakan kepadaku [Abu Umamah bin Sahl] bahwa dia mendengar [Abu Sa'id Al Khudri] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika saya sedang tidur, saya melihat orang-orang diperlihatkan kepadaku. Di antara mereka ada yang memakai pakaian hingga payudara mereka dan ada pula yang kurang dari itu. Dan ditampakkan kepadaku Umar bin Al Khathab, dia memakai baju yang dia seret. Abu Sa'id berkata; apa yang Tuan tafsirkan (dari pakaian tersebut), wahai Rasulullah?\" Beliau bersabda: \"Agama.\""},"4680":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ قَالَ حَدَّثَنَا أَبُو عُمَيْسٍ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ قَالَجَاءَ رَجُلٌ مِنْ الْيَهُودِ إِلَى عُمَرَ بْنِ الْخَطَّابِ فَقَالَ يَا أَمِيرَ الْمُؤْمِنِينَ آيَةٌ فِي كِتَابِكُمْ تَقْرَءُونَهَا لَوْ عَلَيْنَا مَعْشَرَ الْيَهُودِ نَزَلَتْ لَاتَّخَذْنَا ذَلِكَ الْيَوْمَ عِيدًا قَالَ أَيُّ آيَةٍ قَالَ{ الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ وَأَتْمَمْتُ عَلَيْكُمْ نِعْمَتِي وَرَضِيتُ لَكُمْ الْإِسْلَامَ دِينًا }فَقَالَ عُمَرُ إِنِّي لَأَعْلَمُ الْمَكَانَ الَّذِي نَزَلَتْ فِيهِ وَالْيَوْمَ الَّذِي نَزَلَتْ فِيهِ نَزَلَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي عَرَفَاتٍ فِي يَوْمِ جُمُعَةٍ","id":"Telah mengkhabarkan kepada kami [Abu Daud], dia berkata; telah menceritakan kepada kami [Ja'far bin 'Aun], dia berkata; telah menceritakan kepada kami [Abu 'Umais] dari [Qais bin Muslim] dari [Thariq bin Syihab], dia berkata; \"Telah datang seorang laki-laki Yahudi kepada Umar bin Al Khathab lalu berkata; \"Wahai Amirul mukminin, terdapat satu ayat dalam kitab kalian yang kalian baca, seandainya turun kepada kami orang-orang Yahudi niscaya kami menjadikan hari tersebut sebagai Hari Raya. Ayat apakah itu?\" [Umar] berkata; \"Pada hari ini telah Kusempurnakan untuk kamu agamamu, dan telah Ku-cukupkan kepadamu nikmat-Ku, dan telah Aku ridhai Islam itu jadi agama bagimu. Kemudian Umar berkata; \"Sungguh aku mengetahui tempat turunnya ayat tersebut, dan harinya. Ayat tersebut turun kepada kepada Rasulullah shallallahu 'alaihi wasallam di 'Arafah pada hari Jum'at.\" "},"4681":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا بِشْرٌ يَعْنِي ابْنَ الْمُفَضَّلِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ أَنَّهُ سَمِعَ أَنَسًا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى أَكُونَ أَحَبَّ إِلَيْهِ مِنْ وَلَدِهِ وَوَالِدِهِ وَالنَّاسِ أَجْمَعِينَ","id":"Telah mengkhabarkan kepada kami [Humaid bin Mas'adah], dia berkata; telah menceritakan kepada kami [Bisyr yaitu Ibnu Al Mufadhdhal], dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] bahwa ia mendengar [Anas] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah sempurna keimanan salah seorang di antara kalian hingga aku lebih dia cintai daripada anaknya, orang tuannya dan seluruh umat manusia.\""},"4682":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ عَبْدِ الْعَزِيزِ ح وَأَنْبَأَنَا عِمْرَانُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى أَكُونَ أَحَبَّ إِلَيْهِ مِنْ مَالِهِ وَأَهْلِهِ وَالنَّاسِ أَجْمَعِينَ","id":"Telah mengkhabarkan kepada kami [Al Husain bin Huraits], dia berkata; telah memberitakan kepada kami [Isma'il] dari [Abdul Aziz], telah menceritakan dan memberitakan kepada kami [Imran bin Musa], dia berkata; telah menceritakan kepada kami [Abdul Warits], dia berkata; telah menceritakan kepada kami [Abdul Aziz] dari [Anas], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"\"Tidaklah sempurna keimanan salah seorang di antara kalian hingga aku lebih dia cintai daripada hartanya, keluarganya dan seluruh umat manusia.\""},"4683":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا شُعَيْبٌ قَالَ حَدَّثَنَا أَبُو الزِّنَادِ مِمَّا حَدَّثَهُ عَبْدُ الرَّحْمَنِ بْنُ هُرْمُزَ مِمَّا ذُكِرَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يُحَدِّثُ بِهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى أَكُونَ أَحَبَّ إِلَيْهِ مِنْ وَلَدِهِ وَوَالِدِهِ","id":"Telah mengkhabarkan kepada kami [Imran bin Bakkar], dia berkata; telah menceritakan kepada kami [Ali bin 'Ayyasy], dia berkata; telah menceritakan kepada kami [Syu'aib], dia berkata; telah menceritakan kepada kami [Abu Az Zinad], berdasarkan apa yang diceritakan oleh [Abdur Rahman bin Hurmuz] di antara yang dia sebutkan adalah bahwa dia mendengar [Abu Hurairah] bercerita kepadanya dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Demi Dzat yang jiwaku ada di tanganNya; tidaklah sempurna keimanan salah seorang di antara kalian hingga aku lebih ia cintai daripada anak dan orang tuanya\""},"4684":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا النَّضْرُ قَالَ حَدَّثَنَا شُعْبَةُ ح وَأَنْبَأَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا بِشْرٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسًا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ حُمَيْدُ بْنُ مَسْعَدَةَ فِي حَدِيثِهِ إِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى يُحِبَّ لِأَخِيهِ مَا يُحِبُّ لِنَفْسِهِ","id":"Telah mengkhabarkan kepada kami [Ishaq bin Ibrahim], dia berkata; telah menceritakan kepada kami [An Nadhr], dia berkata; telah menceritakan kepada kami [Syu'bah], telah menceritakan dan memberitakan kepada kami [Humaid bin Mas'adah], dia berkata; telah menceritakan kepada kami [Bisyr], dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah], dia berkata; \"Saya mendengar [Anas] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda:.... Dan Humaid bin Mas'adah berkata dalam haditsnya; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah sempurna keimanan salah seorang di antara kalian hingga ia mencintai bagi saudaranya sebagaimana apa yang ia cintai bagi dirinya sendiri.\""},"4685":{"ar":"أَخْبَرَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ حُسَيْنٍ وَهُوَ الْمُعَلِّمُ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى يُحِبَّ لِأَخِيهِ مَا يُحِبُّ لِنَفْسِهِ مِنْ الْخَيْرِ","id":"Telah mengkhabarkan kepada kami [Musa bin Abdur Rahman], dia berkata; telah menceritakan kepada kami [Abu Usamah] dari [Husain yaitu Al Mua'allim] dari [Qatadah] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwa Muhammad ada di tanganNya, tidaklah sempurna keimanan salah seorang di antara kalian hingga ia mencintai kebaikan bagi saudaranya sebagaimana ia mencintai kebaikan bagi dirinya sendiri.\""},"4686":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ عِيسَى قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى قَالَ أَنْبَأَنَا الْأَعْمَشُ عَنْ عَدِيٍّ عَنْ زِرٍّ قَالَ قَالَ عَلِيٌّإِنَّهُ لَعَهْدُ النَّبِيِّ الْأُمِّيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيَّ أَنَّهُ لَا يُحِبُّكَ إِلَّا مُؤْمِنٌ وَلَا يَبْغُضُكَ إِلَّا مُنَافِقٌ","id":"Telah mengkhabarkan kepada kami [Yusuf bin Isa], dia berkata; telah memberitakan kepada kami [Al Fadhl bin Musa], dia berkata; telah memberitakan kepada kami [Al A'masy] dari ['Adi] dari [Zirr], dia berkata; [Ali] berkata; \"Sesungguhnya ini adalah wasiat yang telah diwasiatkan Nabi yang buta huruf shallallahu 'alaihi wasallam kepadaku: \"Sesungguhnya tidak ada yang mencintaimu kecuali orang mukmin dan tidak ada yang membencimu kecuali orang munafik.\""},"4687":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ عَنْ شُعْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ جَبْرٍ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حُبُّ الْأَنْصَارِ آيَةُ الْإِيمَانِ وَبُغْضُ الْأَنْصَارِ آيَةُ النِّفَاقِ","id":"Telah mengkhabarkan kepada kami [Isma'il bin Mas'ud], dia berkata; telah menceritakan kepada kami [Khalid yaitu Ibnu Al Harits] dari [Syu'bah] dari [Abdullah bin Abdullah bin Jabr] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Mencintai orang-orang Anshar adalah tanda keimanan dan membenci orang-orang Anshar adalah tanda kemunafikan.\""},"4688":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرْبَعَةٌ مَنْ كُنَّ فِيهِ كَانَ مُنَافِقًا أَوْ كَانَتْ فِيهِ خَصْلَةٌ مِنْ الْأَرْبَعِ كَانَتْ فِيهِ خَصْلَةٌ مِنْ النِّفَاقِ حَتَّى يَدَعَهَا إِذَا حَدَّثَ كَذَبَ وَإِذَا وَعَدَ أَخْلَفَ وَإِذَا عَاهَدَ غَدَرَ وَإِذَا خَاصَمَ فَجَرَ","id":"Telah mengkhabarkan kepada kami [Bisyr bin Khalid], dia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Abdullah bin Murrah] dari [Masruq] dari [Abdullah bin 'Amr] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Empat hal, barang siapa yang keempat hal tersebut terdapat padanya maka dia adalah seorang munafik, atau padanya terdapat satu sifat dari empat sifat tersebut maka padanya terdapat sifat kemunafikan hingga dia meninggalkannya, yaitu; apabila dia berbicara dia berdusta, apabila berjanji dia mengingkarinya, apabila mengadakan perjanjian maka ia mengkhianati, dan apabila berselisih maka ia melampaui batas.\""},"4689":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا أَبُو سُهَيْلٍ نَافِعُ بْنُ مَالِكِ بْنِ أَبِي عَامِرٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ آيَةُ النِّفَاقِ ثَلَاثٌ إِذَا حَدَّثَ كَذَبَ وَإِذَا وَعَدَ أَخْلَفَ ��َإِذَا اؤْتُمِنَ خَانَ","id":"Telah mengkhabarkan kepada kami [Ali bin Hujr], dia berkata; telah menceritakan kepada kami [Isma'il], dia berkata; telah menceritakan kepada kami [Abu Suhail Nafi' bin Malik bin Abu 'Amir] dari [ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tanda orang munafik itu ada tiga, yaitu; apabila berbicara dia berdusta, apabila berjanji dia mengingkari dan apabila dipercaya dia mengkhianati.\" "},"4690":{"ar":"أَخْبَرَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ زِرِّ بْنِ حُبَيْشٍ عَنْ عَلِيٍّ قَالَعَهِدَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا يُحِبُّنِي إِلَّا مُؤْمِنٌ وَلَا يَبْغُضُنِي إِلَّا مُنَافِقٌ","id":"Telah mengkhabarkan kepada kami [Washil bin Abdul A'la], dia berkata; telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari ['Adi bin Tsabit] dari [Zirr bin Hubaisy] dari [Ali], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam telah berwasiat kepadaku bahwa tidak ada yang mencintaiku kecuali orang mukmin dan tidak ada yang membenciku kecuali orang munafik.\""},"4691":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَحْيَى بْنِ الْحَارِثِ قَالَ حَدَّثَنَا الْمُعَافَى قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا مَنْصُورُ بْنُ الْمُعْتَمِرِ عَنْ أَبِي وَائِلٍ قَالَ قَالَ عَبْدُ اللَّهِثَلَاثٌ مَنْ كُنَّ فِيهِ فَهُوَ مُنَافِقٌ إِذَا حَدَّثَ كَذَبَ وَإِذَا اؤْتُمِنَ خَانَ وَإِذَا وَعَدَ أَخْلَفَ فَمَنْ كَانَتْ فِيهِ وَاحِدَةٌ مِنْهُنَّ لَمْ تَزَلْ فِيهِ خَصْلَةٌ مِنْ النِّفَاقِ حَتَّى يَتْرُكَهَا","id":"Telah mengkhabarkan kepada kami ['Amr bin Yahya bin Al Harits], dia berkata; telah menceritakan kepada kami [Al Mu'afa], dia berkata; telah menceritakan kepada kami [Zuhair], dia berkata; telah menceritakan kepada kami [Manshur bin Al Mu'tamir] dari [Abu Wail], dia berkata; [Abdullah] berkata; \"Tiga hal yang barang siapa ketiganya ada padanya maka ia adalah orang munafik yaitu; jika berbicara dusta, jika dipercaya khianat, dan jika berjanji mengingkari. Maka barangsiapa pada dirinya terdapat salah satu di antara ketiga hal tersebut niscaya pada dirinya akan selalu ada bagian dari sifat kemunafikan hingga ia meninggalkannya.\""},"4692":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ شَهْرَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang melakukan shalat malam pada bulan Ramadhan Karena keimanan dan mengharapkan pahala maka diampuni dosanya yang telah lalu.\""},"4693":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ ح وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengkhabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] serta [Al Harits bin Miskin] yang membacakan riwayat sedang saya mendengar, dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Humaid bin Abdur Rahman] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barang siapa melakukan shalat malam pada Bulan Ramadhan karena keimanan dan mengharapkan pahala maka diampuni dosanya yang telah lalu.\""},"4694":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ قَالَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ وَحُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Isma'il], dia berkata; telah menceritakan kepada kami [Abdullah bin Muhammad bin Asma`], dia berkata; telah menceritakan kepada kami [Juwairiyah] dari [Malik] dari [Az Zuhri], telah mengkhabarkan kepadaku [Abu Salamah bin Abdur Rahman] dan [Humaid bin Abdur Rahman] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barang siapa melakukan shalat malam pada Bulan Ramadhan karena keimanan dan mengharapkan pahala maka diampuni dosanya yang telah lalu.\" "},"4695":{"ar":"حَدَّثَنَا أَبُو الْأَشْعَثِ قَالَ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَنْ قَامَ لَيْلَةَ الْقَدْرِ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengkhabarkan kepada kami [Abu Al Asy'ats], dia berkata; telah menceritakan kepada kami [Khalid yaitu Ibnu Al Harits], dia berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abu Katsir] dari [Abu Salamah bin Abdur Rahman], dia berkata; telah bercerita kepadaku [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda; \"Barang siapa melakukan shalat malam pada Bulan Ramadhan karena keimanan dan mengharapkan pahala maka diampuni dosanya yang telah lalu dan barang siapa melakukan shalat malam pada lailatul qadr karena keimanan dan mengharapkan pahala maka diampuni dosanya yang telah lalu.\""},"4696":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ قَالَ حَدَّثَنِي أَبُو سُهَيْلٍ عَنْ أَبِيهِ أَنَّهُ سَمِعَ طَلْحَةَ بْنَ عُبَيْدِ اللَّهِ يَقُولُجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَهْلِ نَجْدٍ ثَائِرَ الرَّأْسِ يُسْمَعُ دَوِيُّ صَوْتِهِ وَلَا يُفْهَمُ مَا يَقُولُ حَتَّى دَنَا فَإِذَا هُوَ يَسْأَلُ عَنْ الْإِسْلَامِ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسُ صَلَوَاتٍ فِي الْيَوْمِ وَاللَّيْلَةِ قَالَ هَلْ عَلَيَّ غَيْرُهُنَّ قَالَ لَا إِلَّا أَنْ تَطَوَّعَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصِيَامُ شَهْرِ رَمَضَانَ قَالَ هَلْ عَلَيَّ غَيْرُهُ قَالَ لَا إِلَّا أَنْ تَطَوَّعَ وَذَكَرَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الزَّكَاةَ فَقَالَ هَلْ عَلَيَّ غَيْرُهَا قَالَ لَا إِلَّا أَنْ تَطَوَّعَ فَأَدْبَرَ الرَّجُلُ وَهُوَ يَقُولُ لَا أَزِيدُ عَلَى هَذَا وَلَا أَنْقُصُ مِنْهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْلَحَ إِنْ صَدَقَ","id":"Telah mengkhabarkan kepada kami [Muhammad bin salamah], dia berkata; telah menceritakan kepada kami [Ibnu Al Qasim] dari [Malik], dia berkata; telah menceritakan kepadaku [Abu Suhail] dari [ayahnya] bahwa ia mendengar [Thalhah bin 'Ubaidullah] berkata; \"Telah datang seorang laki-laki dari penduduk Nejd kepada Rasulullah shallallahu 'alaihi wasallam dengan rambut acak-acakan. Gema suaranya terdengar, namun (maksud) dari apa yang dikatakannya tidak bisa difahami kecuali setelah dia mendekat. Ternyata dia bertanya mengenai Islam, maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Lima shalat dalam sehari semalam.\" Dia berkata; \"Apakah ada kewajiban lain atasku?\" Beliau bersabda: \"Tidak kecuali engkau melakukan (sholat) sunnah.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"dan puasa pada Bulan Ramadhan.\" Orang tersebut berkata; \"Apakah ada kewajiban bagiku lagi selainnya?\" Beliau bersabda: \"Tidak kecuali engkau melakukan (puasa) sunnah.\" Dan Rasulullah shallallahu 'alaihi wasallam menyebutkan kepadanya zakat, kemudian orang tersebut berkata; \"Apakah ada kewajiban atasku selain itu?\" Beliau bersabda: \"Tidak kecuali engkau melakukan (zakat) sunnah (Shodaqoh/infaq).\" Kemudian orang tersebut berpaling seraya berkata; \"Aku tidak akan menambah hal ini dan tidak akan menguranginya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dia akan beruntung apabila jujur.\""},"4697":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدٍ عَنْ عَطَاءِ بْنِ مِينَاءَ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ان��تَدَبَ اللَّهُ لِمَنْ يَخْرُجُ فِي سَبِيلِهِ لَا يُخْرِجُهُ إِلَّا الْإِيمَانُ بِي وَالْجِهَادُ فِي سَبِيلِي أَنَّهُ ضَامِنٌ حَتَّى أُدْخِلَهُ الْجَنَّةَ بِأَيِّهِمَا كَانَ إِمَّا بِقَتْلٍ وَإِمَّا وَفَاةٍ أَوْ أَنْ يَرُدَّهُ إِلَى مَسْكَنِهِ الَّذِي خَرَجَ مِنْهُ يَنَالُ مَا نَالَ مِنْ أَجْرٍ أَوْ غَنِيمَةٍ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami [Al Laits] dari [Sa'id] dari ['Atho`bin Mina`], dia telah mendengar [Abu Hurairah] berkata; \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah menjamin bagi orang yang keluar di jalanNya dan tidak ada yang menggerakkannya untuk keluar kecuali karena keimanan(nya) kepadaKu dan (ingin) berjihad di jalanKu, bahwa dia terjamin hingga Aku memasukkannya ke dalam Surga, dengan apapun dari dua hal, baik karena terbunuh ataupun karena meninggal dunia atau Allah akan mengembalikannya ke tempat tinggalnya yang darinya ia keluar, dan mendapatkan apa yang ia dapatkan berupa pahala dan harta rampasan perang.\" "},"4698":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَضَمَّنَ اللَّهُ عَزَّ وَجَلَّ لِمَنْ خَرَجَ فِي سَبِيلِهِ لَا يُخْرِجُهُ إِلَّا الْجِهَادُ فِي سَبِيلِي وَإِيمَانٌ بِي وَتَصْدِيقٌ بِرُسُلِي فَهُوَ ضَامِنٌ أَنْ أُدْخِلَهُ الْجَنَّةَ أَوْ أُرْجِعَهُ إِلَى مَسْكَنِهِ الَّذِي خَرَجَ مِنْهُ نَالَ مَا نَالَ مِنْ أَجْرٍ أَوْ غَنِيمَةٍ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Qudamah], dia berkata; telah menceritakan kepada kami [Jarir] dari ['Umarah bin Al Qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah 'azza wajalla menjamin bagi orang yang keluar di jalanNya tidak ada yang mengeluarkannya kecuali berjihad di jalanKu serta beriman kepadaKu dan membenarkan rasulKu, maka ia terjamin untuk Aku masukkan ke dalam Surga, atau mengembalikannya ke tempatnya yang darinya ia keluar, dan mendapatkan apa yang ia dapatkan berupa pahala dan rampasan perang.\" "},"4699":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبَّادٌ وَهُوَ ابْنُ عَبَّادٍ عَنْ أَبِي جَمْرَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَدِمَ وَفْدُ عَبْدِ الْقَيْسِ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا إِنَّا هَذَا الْحَيَّ مِنْ رَبِيعَةَ وَلَسْنَا نَصِلُ إِلَيْكَ إِلَّا فِي الشَّهْرِ الْحَرَامِ فَمُرْنَا بِشَيْءٍ نَأْخُذُهُ عَنْكَ وَنَدْعُو إِلَيْهِ مَنْ وَرَاءَنَا فَقَالَ آمُرُكُمْ بِأَرْبَعٍ وَأَنْهَاكُمْ عَنْ أَرْبَعٍ الْإِيمَانُ بِاللَّهِ ثُمَّ فَسَّرَهَا لَهُمْ شَهَادَةُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ وَإِقَامُ الصَّلَاةِ وَإِيتَاءُ الزَّكَاةِ وَأَنْ تُؤَدُّوا إِلَيَّ خُمُسَ مَا غَنِمْتُمْ وَأَنْهَاكُمْ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُقَيَّرِ وَالْمُزَفَّتِ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami ['Abbad yaitu Ibnu 'Abbad] dari [Abu Jamrah] dari [Ibnu Abbas], dia berkata; \"Telah datang utusan Abdul Qais kepada Rasulullah shallallahu 'alaihi wasallam, mereka berkata; \"Sesungguhnya kami ini adalah penduduk kampung dari Rabi'ah dan kami tidak akan sampai kepadamu kecuali pada Bulan Haram maka perintahkan sesuatu kepada kami yang akan kami ambil darimu dan kami serukan hal itu kepada orang-orang yang ada di belakang kami.\" Kemudian beliau bersabda: \"Aku perintahkan kalian dengan empat perkara dan aku melarang kalian dari empat perkara, yaitu; beriman kepada Allah, kemudian beliau menafsirkan maksudnya kepada mereka yaitu bersaksi bahwa tidak ada Tuhan yang berhak disembah melainkan Allah dan aku adalah Rasulullah, menegakkan shalat dan memberikan zakat, serta memberikan kepadaku seperlima dari harta rampasan perang yang kalian dapatkan, dan aku melarang kalian dari labu kering yang dijadikan sebagai bejana, hantam (bejana yang dilapisi minyak), muqayyar (bejana yang dilapisi dengan aspal), dan Muzaffat (bejana yang dicat dengan tir).\" "},"4700":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَ حَدَّثَنَا إِسْحَقُ يَعْنِي ابْنَ يُوسُفَ بْنِ الْأَزْرَقِ عَنْ عَوْفٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اتَّبَعَ جَنَازَةَ مُسْلِمٍ إِيمَانًا وَاحْتِسَابًا فَصَلَّى عَلَيْهِ ثُمَّ انْتَظَرَ حَتَّى يُوضَعَ فِي قَبْرِهِ كَانَ لَهُ قِيرَاطَانِ أَحَدُهُمَا مِثْلُ أُحُدٍ وَمَنْ صَلَّى عَلَيْهِ ثُمَّ رَجَعَ كَانَ لَهُ قِيرَاطٌ","id":"Telah mengkhabarkan kepada kami [Abdur Rahman bin Muhammad bin sallam], dia berkata; telah menceritakan kepada kami [Ishaq yaitu Ibnu Yusuf bin Al Azraq] dari ['Auf] dari [Muhammad bin Sirin] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barang siapa yang mengikuti jenazah seorang muslim karena keimanan dan mengharapkan pahala, lalu dia menshalatkannya, kemudian menunggu hingga disemayamkan dalam kuburnya, maka baginya pahala dua qirath, salah satunya seperti Gunung Uhud. Dan barang siapa yang menshalatkannya kemudian dia kembali (pulang) maka baginya pahala satu qirath.\" "},"4701":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ ح وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ أَخْبَرَنِي مَالِكٌ وَاللَّفْظُ لَهُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ عَلَى رَجُلٍ يَعِظُ أَخَاهُ فِي الْحَيَاءِ فَقَالَ دَعْهُ فَإِنَّ الْحَيَاءَ مِنْ الْإِيمَانِ","id":"Telah mengkhabarkan kepada kami [Harun bin Abdullah], dia berkata; telah menceritakan kepada kami [Ma'n], dia berkata; telah menceritakan kepada kami [Malik] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar dari [Ibnu Al Qasim], telah mengkhabarkan kepadaku [Malik] dan lafazhnya adalah lafazh dia, dari [Ibnu Syihab] dari [Salim] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam melewati seorang laki-laki yang memberikan nasehat kepada saudaranya mengenai rasa malu. Maka beliau bersabda: \"TInggalkanlah dia, sesungguhnya rasa malu itu sebagian dari keimanan.\""},"4702":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ نَافِعٍ قَالَ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ مَعْنِ بْنِ مُحَمَّدٍ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذَا الدِّينَ يُسْرٌ وَلَنْ يُشَادَّ الدِّينَ أَحَدٌ إِلَّا غَلَبَهُ فَسَدِّدُوا وَقَارِبُوا وَأَبْشِرُوا وَيَسِّرُوا وَاسْتَعِينُوا بِالْغَدْوَةِ وَالرَّوْحَةِ وَشَيْءٍ مِنْ الدَّلْجَةِ","id":"Telah mengkhabarkan kepada kami [Abu Bakar bin Nafi'], dia berkata; telah menceritakan kepada kami [Umar bin Ali] dari [Ma'n bin Muhammad] dari [Sa'id] dari [Abu Hurairah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya agama ini mudah dan tidak ada seorangpun yang bersikap keras terhadap agama melainkan dia akan terkalahkan, maka bersikaplah lurus, dan bersikaplah sederhana, berilah kabar gembira, berilah kemudahan, dan mintalah pertolongan pada saat pagi hari dan sore hari dan sedikit dari waktu malam.\""},"4703":{"ar":"أَخْبَرَنَا شُعَيْبُ بْنُ يُوسُفَ عَنْ يَحْيَى وَهُوَ ابْنُ سَعِيدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَعِنْدَهَا امْرَأَةٌ فَقَالَ مَنْ هَذِهِ قَالَتْ فُلَانَةُ لَا تَنَامُ تَذْكُرُ مِنْ صَلَاتِهَا فَقَالَ مَهْ عَلَيْكُمْ مِنْ الْعَمَلِ مَا تُطِيقُونَ فَوَاللَّهِ لَا يَمَلُّ اللَّهُ عَزَّ وَجَلَّ حَتَّى تَمَلُّوا وَكَانَ أَحَبَّ الدِّينِ إِلَيْهِ مَا دَامَ عَلَيْهِ صَاحِبُهُ","id":"Telah mengkhabarkan kepada kami [Syu'aib bin Yusuf] dari [Yahya yaitu Ibnu Sa'id] dari [Hisyam bin 'Urwah], telah mengkhabarkan kepadaku [ayahku] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam menemuinya sementara di sisinya terdapat seorang wanita, kemudian beliau bertanya: \"Siapakah wanita ini?\" Aisyah berkata; \"Fulanah, ia tidak tidur.\" Aisyah menyebutkan mengenai shalatnya. Kemudian beliau bersabda: \"Tahanlah, hendaknya kalian melakukan apa yang kalian mampu. Demi Allah, Allah tidak akan merasa bosan hingga kalian merasa bosan. Dan (ibadah) yang paling Allah cintai dari agama ini adalah yang dilakukan oleh pelakunya secara terus menerus.\" "},"4704":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ ح وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَا حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوشِكُ أَنْ يَكُونَ خَيْرَ مَالِ مُسْلِمٍ غَنَمٌ يَتَّبِعُ بِهَا شَعَفَ الْجِبَالِ وَمَوَاقِعَ الْقَطْرِ يَفِرُّ بِدِينِهِ مِنْ الْفِتَنِ","id":"Telah mengkhabarkan kepada kami [Harun bin Abdullah], dia berkata; telah menceritakan kepada kami [Ma'n] dan [Al Harits bin Miskin] dengan membacakan riwayat sedangkan saya mendengar dari [Ibnu Al Qasim] mereka berkata; telah menceritakan kepada kami [Malik] dari [Abdur Rahman bin Abdullah bin Abdur Rahman bin Abu Sha'sha'ah] dari [ayahnya] dari [Abu Sa'id Al Khudri], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sudah dekat zaman di mana harta seorang muslim yang paling baik adalah kambing, dengannya dia menuju puncak gunung dan tempat turunnya hujan, dia lari membawa agamanya dari berbagai fitnah.\" "},"4705":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا يَعْقُوبُ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الْمُنَافِقِ كَمَثَلِ الشَّاةِ الْعَائِرَةِ بَيْنَ الْغَنَمَيْنِ تَعِيرُ فِي هَذِهِ مَرَّةً وَفِي هَذِهِ مَرَّةً لَا تَدْرِي أَيَّهَا تَتْبَعُ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami [Ya'qub] dari [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Permisalan orang munafik adalah seperti kambing yang bingung di antara dua kambing, terkadang dia pergi kepada kambing yang ini dan terkadang pergi kepada kambing yang ini, dia tidak tahu manakah yang akan dia ikuti.\" "},"4706":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ أَبَا مُوسَى الْأَشْعَرِيَّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُؤْمِنِ الَّذِي يَقْرَأُ الْقُرْآنَ مَثَلُ الْأُتْرُجَّةِ طَعْمُهَا طَيِّبٌ وَرِيحُهَا طَيِّبٌ وَمَثَلُ الْمُؤْمِنِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ كَمَثَلِ التَّمْرَةِ طَعْمُهَا طَيِّبٌ وَلَا رِيحَ لَهَا وَمَثَلُ الْمُنَافِقِ الَّذِي يَقْرَأُ الْقُرْآنَ كَمَثَلِ الرَّيْحَانَةِ رِيحُهَا طَيِّبٌ وَطَعْمُهَا مُرٌّ وَمَثَلُ الْمُنَافِقِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ كَمَثَلِ الْحَنْظَلَةِ طَعْمُهَا مُرٌّ وَلَا رِيحَ لَهَا","id":"Telah mengkhabarkan kepada kami ['Amr bin Ali], dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'], dia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas bin Malik] bahwa [Abu Musa Al Asy'ari] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan seorang mukmin yang membaca Al Qur`an adalah seperti buah Utrujah, rasanya enak dan baunya wangi. Sedang permisalan seorang mukmin yang tidak membaca Al Qur`an adalah seperti buah kurma, rasanya enak dan tidak berbau. Permisalan orang munafik yang membaca Al Qur`an adalah seperti tumbuhan Raihanah, baunya harum dan rasanya pahit. Dan permisalan orang munafik yang tidak membaca Al Qur`an adalah seperti Hanzhalah (sejenis labu), rasanya pahit dan tidak berbau.\" "},"4707":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى يُحِبَّ لِأَخِيهِ مَا يُحِبُّ لِنَفْسِهِقَالَ الْقَاضِي يَعْنِي ابْنَ الْكَسَّارِ سَمِعْتُ عَبْدَ الصَّمَدِ الْبُخَارِيَّ يَقُولُ حَفْصُ بْنُ عُمَرَ الَّذِي يَرْوِي عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ لَا أَعْرِفُهُ إِلَّا أَنْ يَكُونَ سَقَطَ الْوَاوُ مِنْ حَفْصِ بْنِ عَمْرٍو الرَّبَالِيِّ الْمَشْهُورُ بِالرِّوَايَةِ عَنْ الْبَصْرِيِّينَ وَهُوَ ثِقَةٌ ذَكَرَهُ فِي هَذَا الْخَبَرِ فِي حَدِيثِ مَنْصُورِ بْنِ سَعْدٍ فِي بَابِ صِفَةِ الْمُسْلِمِ سَمِعْتُهُ يَقُولُ لَا أَعْلَمُ رَوَى حَدِيثَ أَنَسِ بْنِ مَالِكٍ الْمَرْفُوعَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ بِزِيَادَةِ قَوْلِهِ وَاسْتَقْبَلُوا قِبْلَتَنَا وَأَكَلُوا ذَبِيحَتَنَا وَصَلَّوْا صَلَاتَنَا عَنْ حُمَيْدٍ الطَّوِيلِ إِلَّا عَبْدَ اللَّهِ بْنَ الْمُبَارَكِ وَيَحْيَى بْنَ أَيُّوبَ الْبَصْرِيَّ وَهُوَ فِي هَذَا الْجُزْءِ فِي بَابِ مَا يُقَاتِلُ النَّاسَ","id":"Telah mengkhabarkan kepada kami [Suwaid bin Nashr], dia berkata; telah memberitakan kepada kami [Abdullah] dari [Syu'bah] dari [Qatadah] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak sempurna keimanan salah seorang di antara kalian hingga dia mencintai bagi saudaranya apa yang ia cintai bagi dirinya sendiri.\" Al Qadhi yaitu Ibnu Al Kassar berkata; \"Saya mendengar Abdush Shamad Al Bukhari berkata; Hafsh bin Umar lah yang meriwayatkan dari Abdur Rahman bin Mahdi saya tidak mengenalnya, kecuali jika huruf wawunya dihilangkan dari (nama) Hafsh bin ' 'Amru Ar Rabali yang dikenal meriwayatkan dari orang-orang Bashrah, ia adalah orang yang tsiqah. Ia menyebutkan mengenai kabar ini dalam hadits Manshur bin Sa'd pada Bab sifat seorang muslim, saya mendengarnya berkata; \"Saya tidak mengetahui ada yang meriwayatkan hadits Anas bin Malik yang marfu' yaitu: \"Saya diperintahkan untukmemerangi manusia... dengan tambahan: menghadap kiblat kami, memakan sembelihan kami dan melakukan shalat seperti shalat kami dari Humaid Ath Thawil selain Abdullah bin Al Mubarak dan Yahya bin Ayyub Al Bashri dan hadits ini dalam juz ini, dalam bab 'apa yang memerangi manusia'. "},"4708":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا وَكِيعٌ قَالَ حَدَّثَنَا زَكَرِيَّا بْنُ أَبِي زَائِدَةَ عَنْ مُصْعَبِ بْنِ شَيْبَةَ عَنْ طَلْقِ بْنِ حَبِيبٍ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشْرَةٌ مِنْ الْفِطْرَةِ قَصُّ الشَّارِبِ وَقَصُّ الْأَظْفَارِ وَغَسْلُ الْبَرَاجِمِ وَإِعْفَاءُ اللِّحْيَةِ وَالسِّوَاكُ وَالِاسْتِنْشَاقُ وَنَتْفُ الْإِبْطِ وَحَلْقُ الْعَانَةِ وَانْتِقَاصُ الْمَاءِقَالَ مُصْعَبٌ وَنَسِيتُ الْعَاشِرَةَ إِلَّا أَنْ تَكُونَ الْمَضْمَضَةَ","id":"Telah mengkhabarkan kepada kami [Ishaq bin Ibrahim], dia berkata; telah memberitakan kepada kami [Waki'], dia berkata; telah menceritakan kepada kami [Zakariya bin Abu Zaidah] dari [Mush'ab bin Syaibah] dari [Thalq bin Habib] dari [Abdullah bin Az Zubair] dari [Aisyah] dari Rasulullah shallallahu 'alaihi wasallam: \"Sepuluh perkara yang termasuk fithrah yaitu; memotong kumis, memotong kuku, mencuci ruas-ruas jari, memanjangkan jenggot, menggosok gigi, memasukkan air ke hidung ketika berwudhu, mencabut bulu ketiak, mencukur bulu kemaluan, beristinja` menggunakan air.\" Mush'ab berkata; \"Saya lupa yang ke sepuluh, kecuali berkumur-kumur.\" "},"4709":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ عَنْ أَبِيهِ قَالَ سَمِعْتُ طَلْقًايَذْكُرُ عَشْرَةً مِنْ الْفِطْرَةِ السِّوَاكَ وَقَصَّ الشَّارِبِ وَتَقْلِيمَ الْأَظْفَارِ وَغَسْلَ الْبَرَاجِمِ وَحَلْقَ الْعَانَةِ وَالِاسْتِنْشَاقَ وَأَنَا شَكَكْتُ فِي الْمَضْمَضَةِ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdul A'la], dia berkata; telah menceritakan kepada kami [Al Mu'tamir] dari [ayahnya], dia berkata; \"Saya mendengar [Thalq] menyebutkan sepuluh hal yang termasuk fithroh yaitu menggosok gigi, memotong kumis, memotong kuku, mencuci ruas-ruas jari, mencukur bulu kemaluan, memasuk air ke hidung, dan aku ragu mengenai berkumur.\""},"4710":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ طَلْقِ بْنِ حَبِيبٍ قَالَعَشْرَةٌ مِنْ السُّنَّةِ السِّوَاكُ وَقَصُّ الشَّارِبِ وَالْمَضْمَضَةُ وَالِاسْتِنْشَاقُ وَتَوْفِيرُ اللِّحْيَةِ وَقَصُّ الْأَظْفَارِ وَنَتْفُ الْإِبْطِ وَالْخِتَانُ وَحَلْقُ الْعَانَةِ وَغَسْلُ الدُّبُرِقَالَ أَبُو عَبْد الرَّحْمَنِ وَحَدِيثُ سُلَيْمَانَ التَّيْمِيِّ وَجَعْفَرِ بْنِ إِيَاسٍ أَشْبَهُ بِالصَّوَابِ مِنْ حَدِيثِ مُصْعَبِ بْنِ شَيْبَةَ وَمُصْعَبٌ مُنْكَرُ الْحَدِيثِ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Thalq bin Habib], dia berkata; \"Sepuluh perkara yang termasuk perkara sunnah yaitu; menggosok gigi, memotong kumis, berkumur-kumur, memasukkan air ke hidung, memanjangkan jenggot, memotong kuku, mencabut bulu ketiak, berkhitan, mencukur bulu kemaluan, dan mencuci dubur.\" Abu Abdur Rahman berkata; \"Sedangkan hadits Salman At Taimi dan Ja'far bin Iyas lebih dekat dengan kebenaran daripada hadits Mush'ab bin Syaibah. Mush'ab adalah orang yang haditsnya mungkar.\" "},"4711":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ بِشْرٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَقَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسٌ مِنْ الْفِطْرَةِ الْخِتَانُ وَحَلْقُ الْعَانَةِ وَنَتْفُ الضَّبْعِ وَتَقْلِيمُ الظُّفْرِ وَتَقْصِيرُ الشَّارِبِوَقَفَهُ مَالِكٌ","id":"Telah mengkhabarkan kepada kami [Humaid bin Mas'adah] dari [Bisyr], dia berkata; telah menceritakan kepada kami [Abdur Rahman bin Ishaq] dari [Sa'id Al Maqburi] dari [Abu Hurairah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lima perkara termasuk dari fithrah yaitu; khitan, mencukur bulu kemaluan, mencabut bulu ketiak, memotong kuku, memendekkan kumis.\" Hadits tersebut diwaqafkan oleh Malik. "},"4712":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَخَمْسٌ مِنْ الْفِطْرَةِ تَقْلِيمُ الْأَظْفَارِ وَقَصُّ الشَّارِبِ وَنَتْفُ الْإِبْطِ وَحَلْقُ الْعَانَةِ وَالْخِتَانُ","id":"Telah mengkhabarkan kepada kami [Qutaibah] dari [Malik] dari [Al Maqburi] dari [Abu Hurairah], dia berkata; \"Lima perkara termasuk dari fithrah, yaitu; memotong kuku, menggunting kumis, mencabut bulu ketiak, mencukur bulu kemaluan, serta berkhitan.\" "},"4713":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَلْقَمَةَ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَحْفُوا الشَّوَارِبَ وَأَعْفُوا اللِّحَى","id":"Telah mengkhabarkan kepada kami [Muhammad bin Basysyar], dia berkata; telah menceritakan kepada kami [Abdur Rahman], dia berkata; telah menceritakan kepada kami [Sufyan] dari [Abdur Rahman bin ' Alqamah] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Pendekkan kumis dan panjangkan jenggot.\""},"4714":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي عَلْقَمَةَ قَالَ سَمِعْتُ ابْنَ عُمَرَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْفُوا اللِّحَى وَأَحْفُوا الشَّوَارِبَ","id":"Telah mengkhabarkan kepada kami ['Amr bin Ali], dia berkata; telah menceritakan kepada kami [Abdur Rahman], dia berkata; telah menceritakan kepada kami [Sufyan], dia berkata; telah menceritakan kepada kami [Abdur Rahman bin Abu 'Alqamah], dia berkata; \"Saya mendengar [Ibnu Umar] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Panjangkan jenggot dan pendekkan kumis.\""},"4715":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ يُوسُفَ بْنَ صُهَيْبٍ يُحَدِّثُ عَنْ حَبِيبِ بْنِ يَسَارٍ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ لَمْ يَأْخُذْ شَارِبَهُ فَلَيْسَ مِنَّا","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdul A'la], dia berkata; telah menceritakan kepada kami [Al Mu'tamir], dia berkata; \"Saya mendengar [Yusuf bin Shuhaib] bercerita dari [Habib bin Yasar] dari [Zaid bin Arqam], dia berkata; \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang tidak memendekkan kumisnya maka ia bukan dari golongan kami.\""},"4716":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى صَبِيًّا حَلَقَ بَعْضَ رَأْسِهِ وَتَرَكَ بَعْضًا فَنَهَى عَنْ ذَلِكَ وَقَالَ احْلِقُوهُ كُلَّهُ أَوْ اتْرُكُوهُ كُلَّهُ","id":"Telah mengkhabarkan kepada kami [Ishaq bin Ibrahim] telah memberitakan kepada kami [Abdur Razzaq], dia berkata; telah memberitakan kepada kami [Ma'mar] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam melihat seorang anak mencukur sebagian kepalanya dan meninggalkan sebagian yang lainnya, kemudian beliau melarang dari hal tersebut dan bersabda: \"Cukurlah semuanya, atau biarkan semuanya.\""},"4717":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مُوسَى الْحَرَشِيُّ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ خِلَاسٍ عَنْ عَلِيٍّنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَحْلِقَ الْمَرْأَةُ رَأْسَهَا","id":"Telah mengkhabarkan kepada kami [Muhammad bin Musa Al Harasyi], dia berkata; telah menceritakan kepada kami [Abu Daud], dia berkata; telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Khilas] dari [Ali] bahwa Rasulullah shallallahu 'alaihi wasallam melarang wanita mencukur rambutnya."},"4718":{"ar":"أَخْبَرَنِي عِمْرَانُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ أَبِي الرِّجَالِ عَنْ عُمَرَ بْنِ نَافِعٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَهَانِي اللَّهُ عَزَّ وَجَلَّ عَنْ الْقَزَعِ","id":"Telah mengkhabarkan kepada kami [Imran bin Yazid], dia berkata; telah menceritakan kepada kami [Abdur Rahman bin Muhammad bin Abu Ar Rijal] dari [Umar bin Nafi'] dari [ayahnya] dari [Abdullah bin Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \" Allah 'azza wajalla melarangku dari mencukur sebagian rambut kepala.\""},"4719":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ عَنْ سُفْيَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْقَزَعِقَالَ أَبُو عَبْد الرَّحْمَنِ حَدِيثُ يَحْيَى بْنِ سَعِيدٍ وَمُحَمَّدِ بْنِ بِشْرٍ أَوْلَى بِالصَّوَابِ","id":"Telah mengkhabarkan kepada kami [Ahmad bin Sulaiman], dia berkata; telah menceritakan kepada kami [Abu Daud] dari [Sufyan] dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma, dia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang dari mencukur sebagian rambut kepala. Abu Abdur Rahman berkata; \"Hadits Yahya bin Sa'id dan Muhammad Bisyr lebih benar.\" "},"4720":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا سُفْيَانُ أَخُو قَبِيصَةَ وَمُعَاوِيَةُ بْنُ هِشَامٍ قَالَا حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا عَاصِمُ بْنُ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلِي شَعْرٌ فَقَالَ ذُبَابٌ فَظَنَنْتُ أَنَّهُ يَعْنِينِي فَأَخَذْتُ مِنْ شَعْرِي ثُمَّ أَتَيْتُهُ فَقَالَ لِي لَمْ أَعْنِكَ وَهَذَا أَحْسَنُ","id":"Telah mengkhabarkan kepada kami [Mahmud bin Ghailan], dia berkata; telah menceritakan kepada kami [Sufyan saudara Qabishah] dan [Mu'awiyah bin Hisyam] mereka berkata; telah menceritakan kepada kami [Sufyan], dia berkata; telah menceritakan kepada kami ['Ashim bin Kulaib] dari [ayahnya] dari [Wail bin Hujr], dia berkata; \"Saya menemui Nabi shallallahu 'alaihi wasallam sedangkan saya memiliki rambut (panjang), lalu beliau bersabda: \" lalat\" Saya mengira bahwa yang beliau maksudkan adalah saya lalu saya memotongnya dan menemui beliau, beliau bersabda kepadaku: \"Aku tidak memaksudkan dirimu tapi ini lebih baik.\""},"4721":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ أَنَسٍ قَالَكَانَ شَعْرُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَعْرًا رَجْلًا لَيْسَ بِالْجَعْدِ وَلَا بِالسَّبْطِ بَيْنَ أُذُنَيْهِ وَعَاتِقِهِ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Al Mutsanna], dia berkata; telah menceritakan kepada kami [Wahb bin Jarir], dia berkata; telah menceritakan kepada kami [ayahku], dia berkata; \"Saya mendengar [Qatadah] bercerita dari [Anas], dia berkata; \"Rambut Nabi shallallahu 'alaihi wasallam adalah rambut yang tidak keriting dan tidak pula lurus, (terurai) di antara kedua telinga dan pundak beliau.\" "},"4722":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ دَاوُدَ الْأَوْدِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ الْحِمْيَرِيِّ قَالَلَقِيتُ رَجُلًا صَحِبَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا صَحِبَهُ أَبُو هُرَيْرَةَ أَرْبَعَ سِنِينَ قَالَ نَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَمْتَشِطَ أَحَدُنَا كُلَّ يَوْمٍ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami [Abu Awanah] dari [Daud Al Audi] dari [Humaid bin Abdur Rahman Al Himyari], dia berkata; \"Saya bertemu dengan [seorang laki-laki] yang pernah menyertai Nabi shallallahu 'alaihi wasallam sebagaimana Abu Hurairah menyertai beliau selama empat tahun, dia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang kami untuk menyisir rambut setiap hari.\""},"4723":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّرَجُّلِ إِلَّا غِبًّا","id":"Telah mengkhabarkan kepada kami [Ali bin Hujr], dia berkata; telah menceritakan kepada kami [Isa bin Yunus] dari [Hisyam bin Hassan] dari [Al Hasan] dari [Abdullah bin Mughaffal], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang dari menyisir kecuali berselang hari.\"."},"4724":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ التَّرَجُّلِ إِلَّا غِبًّا","id":"Telah mengkhabarkan kepada kami [Muhammad bin Basyar], dia berkata; telah menceritakan kepada kami [Abu Daud], dia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Qatadah] dari [Al Hasan] bahwa Nabi shallallahu 'alaihi wasallam melarang dari menyisir rambut kecuali berselang hari."},"4725":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا بِشْرٌ عَنْ يُونُسَ عَنْ الْحَسَنِ وَمُحَمَّدٍ قَالَاالتَّرَجُّلُ غِبٌّ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami [Bisyr] dari [Yunus] dari [Al Hasan] dan [Muhammad], mereka berkata; \"Menyisir itu berselang hari.\""},"4726":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ عَنْ كَهْمَسٍ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَكَانَ رَجُلٌ مِنْ أَصْحَابِ النَّبِيّ�� صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامِلًا بِمِصْرَ فَأَتَاهُ رَجُلٌ مِنْ أَصْحَابِهِ فَإِذَا هُوَ شَعِثُ الرَّأْسِ مُشْعَانٌّ قَالَ مَا لِي أَرَاكَ مُشْعَانًّا وَأَنْتَ أَمِيرٌ قَالَ كَانَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَانَا عَنْ الْإِرْفَاهِ قُلْنَا وَمَا الْإِرْفَاهُ قَالَ التَّرَجُّلُ كُلَّ يَوْمٍ","id":"Telah mengkhabarkan kepada kami [Isma'il bin Mas'ud], dia berkata; telah menceritakan kepada kami [Khalid bin Al Harits] dari [Kahmas] dari [Abdullah bin Syaqiq], dia berkata; \"Terdapat seorang sahabat Nabi shallallahu 'alaihi wasallam yang menjadi gubernur di Mesir, kemudian dia didatangi oleh seseorang dari sahabatnya yang mendapatinya berambut acak-acakan tidak teratur. Orang tersebut berkata; \"Kenapa kulihat rambutmu tidak teratur sedangkan engkau adalah seorang pemimpin?\" [Dia] berkata; \"Dahulu Nabi shallallahu 'alaihi wasallam melarang kami dari irfah. Kami bertanya; \"Irfah itu apa?\" Beliau bersabda; \"Menyisir setiap hari.\" "},"4727":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ مُحَمَّدِ بْنِ بِشْرٍ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ التَّيَامُنَ يَأْخُذُ بِيَمِينِهِ وَيُعْطِي بِيَمِينِهِ وَيُحِبُّ التَّيَمُّنَ فِي جَمِيعِ أُمُورِهِ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Ma'mar], dia berkata; telah menceritakan kepada kami [Abu 'Ashim] dari [Muhammad bin Bisyr] dari [Asy'ats bin Abu Asy Asy'tsa`] dari [Al Aswad bin Yazid] dari [Aisyah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam suka memulai sesuatu dengan yang kanan, beliau mengambil dengan tangan kanan, memberi dengan tangan kanan, dan suka memulai dengan yang kanan dalam segala perkara.\""},"4728":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَمَّارٍ قَالَ حَدَّثَنَا الْمُعَافَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَمَا رَأَيْتُ أَحَدًا أَحْسَنَ فِي حُلَّةٍ حَمْرَاءَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجُمَّتُهُ تَضْرِبُ مَنْكِبَيْهِ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdullah bin 'Ammar], dia berkata; telah menceritakan kepada kami [Al Mu'afa] dari [Israil] dari [Abu Ishaq] dari [Al Bara`], dia berkata; \"Saya tidak melihat seseorang yang lebih baik ketika memakai pakaian merah daripada Rasulullah shallallahu 'alaihi wasallam dan rambut beliau menyentuh kedua pundak beliau.\" "},"4729":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَكَانَ شَعْرُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَنْصَافِ أُذُنَيْهِ","id":"Telah mengkhabarkan kepada kami [Ishaq bin Ibrahim], dia berkata; telah memberitakan kepada kami [Abdur Razzaq], dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Tsabit] dari [Anas], dia berkata; \"Rambut Rasulullah shallallahu 'alaihi wasallam sampai pertengahan kedua telinga beliau.\" "},"4730":{"ar":"أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَخْلَدٌ قَالَ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ أَبِيهِ قَالَ حَدَّثَنِي الْبَرَاءُ قَالَمَا رَأَيْتُ رَجُلًا أَحْسَنَ فِي حُلَّةٍ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَرَأَيْتُ لَهُ لِمَّةً تَضْرِبُ قَرِيبًا مِنْ مَنْكِبَيْهِ","id":"Telah mengkhabarkan kepada kami [Abdul Hamid bin Muhammad], dia berkata; telah menceritakan kepada kami [Makhlad], dia berkata; telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [ayahnya], dia berkata; telah menceritakan kepadaku [Al Bara`], dia berkata; \"Saya tidak melihat seseorang yang lebih baik ketika memakai pakaian merah daripada Rasulullah shallallahu 'alaihi wasallam.\" Dia juga berkata; \"Saya juga melihat rambut beliau hampir menyentuh kedua pundak beliau.\""},"4731":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ إِسْمَعِيلَ بْنِ سُلَيْمَانَ قَالَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ الْأَعْمَشِ عَنْ أَبِي إِسْحَقَ عَنْ هُبَيْرَةَ بْنِ يَرِيمَ قَالَقَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ عَلَى قِرَاءَةِ مَنْ تَأْمُرُونِّي أَقْرَأُ لَقَدْ قَرَأْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِضْعًا وَسَبْعِينَ سُورَةً وَإِنَّ زَيْدًا لَصَاحِبُ ذُؤَابَتَيْنِ يَلْعَبُ مَعَ الصِّبْيَانِ","id":"Telah mengkhabarkan kepada kami [Al Hasan bin Isma'il bin Sulaiman], dia berkata; telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Al A'masy] dari [Abu Ishaq] dari [Hubairah bin Yarim], dia berkata; [Abdullah bin Mas'ud] berkata; berdasarkan bacaan siapakah kalian memerintahkanku membaca? Sungguh aku telah membaca Al Quran atas (petunjuk) Rasulullah shallallahu 'alaihi wasallam sebanyak tujuh puluh surat lebih, sedangkan Zaid ketika itu adalah orang yang memiliki dua jambul yang tengah bermain bersama anak-anak.\""},"4732":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو شِهَابٍ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي وَائِلٍ قَالَخَطَبَنَا ابْنُ مَسْعُودٍ فَقَالَ كَيْفَ تَأْمُرُونِّي أَقْرَأُ عَلَى قِرَاءَةِ زَيْدِ بْنِ ثَابِتٍ بَعْدَ مَا قَرَأْتُ مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِضْعًا وَسَبْعِينَ سُورَةً وَإِنَّ زَيْدًا مَعَ الْغِلْمَانِ لَهُ ذُؤَابَتَانِ","id":"Telah mengkhabarkan kepadaku, [Ibrahim bin Ya'qub], dia berkata; telah menceritakan kepada kami [Sa'id bin Sulaiman], dia berkata; telah menceritakan kepada kami [Abu Syihab], dia berkata; telah menceritakan kepada kami [Al A'masy] dari [Abu Wail], dia berkata; [Ibnu Mas'ud] berkhutbah kepada kami, dia berkata; \"Bagaimana kalian memerintahkanku untuk membaca berdasarkan bacaan Zaid bin Tsabit setelah aku membaca dari mulut Rasulullah shallallahu 'alaihi wasallam sebanyak tujuh puluh sekian surat? Sedangkan Zaid bersama beberapa orang anak dan dia memiliki dua jambul.\" "},"4733":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْمُسْتَمِرِّ الْعُرُوقِيُّ قَالَ حَدَّثَنَا الصَّلْتُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا غَسَّانُ بْنُ الْأَغَرِّ بْنِ حُصَيْنٍ النَّهْشَلِيُّ قَالَ حَدَّثَنِي عَمِّي زِيَادُ بْنُ الْحُصَيْنِ عَنْ أَبِيهِ قَالَلَمَّا قَدِمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْنُ مِنِّي فَدَنَا مِنْهُ فَوَضَعَ يَدَهُ عَلَى ذُؤَابَتِهِ ثُمَّ أَجْرَى يَدَهُ وَسَمَّتَ عَلَيْهِ وَدَعَا لَهُ","id":"Telah mengkhabarkan kepada kami [Ibrahim bin Al Mustamir Al 'Uruqi], dia berkata; telah menceritakan kepada kami [Ash Shalt bin Muhammad], dia berkata; telah menceritakan kepada kami [Ghassan bin Al Agharr bin Hushain An Nahsyali], dia berkata; telah menceritakan kepadaku [pamanku yaitu Ziyad bin Al Hushain] dari [ayahnya], dia berkata; \"Tatkala Nabi shallallahu 'alaihi wasallam tiba di Madinah Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Mendekatlah kepadaku.\" Kemudian dia mendekat kepada beliau kemudian beliau meletakkan tangannya pada rambutnya yang dijalin dan menggerakkan tangannya serta mendoakan keberkahan untuknya.\""},"4734":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا قَاسِمٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلِي جُمَّةٌ قَالَ ذُبَابٌ وَظَنَنْتُ أَنَّهُ يَعْنِينِي فَانْطَلَقْتُ فَأَخَذْتُ مِنْ شَعْرِي فَقَالَ إِنِّي لَمْ أَعْنِكَ وَهَذَا أَحْسَنُ","id":"Telah mengkhabarkan kepada kami [Ahmad bin Harb], dia berkata; telah menceritakan kepada kami [Qasim], dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Ashim bin Kulaib] dari [ayahnya] dari [Wail bin Hujr], dia berkata; \"Saya datang kepada Nabi shallallahu 'alaihi wasallam sedang saya mempunyai rambut yang mejuntai ke bahu, beliau bersabda: \"Lalat.\" Saya mengira bahwa yang beliau maksudkan adalah saya, lalu saya pergi dan memotongnya kemudian beliau bersabda kepadaku: \"Aku tidak memaksudkan dirimu tapi ini lebih baik.\""},"4735":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ وَذَكَرَ آخَرَ قَبْلَهُ عَنْ عَيَّاشِ بْنِ عَبَّاسٍ الْقِتْبَانِيِّ أَنَّ شُيَيْمَ بْنَ بَيْتَانَ حَدَّثَهُ أَنَّهُ سَمِعَ رُوَيْفِعَ بْنَ ثَابِتٍ يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا رُوَيْفِعُ لَعَلَّ الْحَيَاةَ سَتَطُولُ بِكَ بَعْدِي فَأَخْبِرْ النَّاسَ أَنَّهُ مَنْ عَقَدَ لِحْيَتَهُ أَوْ تَقَلَّدَ وَتَرًا أَوْ اسْتَنْجَى بِرَجِيعِ دَابَّةٍ أَوْ عَظْمٍ فَإِنَّ مُحَمَّدًا بَرِيءٌ مِنْهُ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Salamah], dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari [Haiwah bin Syuraih] dan dia menyebutkan orang lain sebelumnya dari ['Ayyasy bin Abbas Al Qitbani] bahwa [Syuyaim bin Baitan] telah menceritakan kepadanya bahwa ia mendengar [Ruwaifi' bin Tsabit] berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Ruwaifi' semoga umurmu panjang sepeninggalku, maka khabarkan kepada orang-orang bahwa barang siapa yang mengikat jenggotnya atau mengalungkan tali busur atau beristinja` menggunakan kotoran binatang, atau tulang maka sesungguhnya Muhammad berlepas diri darinya.\""},"4736":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ عَبْدِ الْعَزِيزِ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ نَتْفِ الشَّيْبِ","id":"Telah mengkhabarkan kepada kami [Qutaibah] dari [Abdul Aziz] dari ['Umarah bin Ghaziyyah] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam melarang mencabut uban."},"4737":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ قَالَ أَبُو سَلَمَةَ إِنَّ أَبَا هُرَيْرَةَ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَخْبَرَهُ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْيَهُودُ وَالنَّصَارَى لَا تَصْبُغُ فَخَالِفُوهُمْأَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah mengkhabarkan kepada kami ['Ubaidullah bin Sa'd bin Ibrahim], dia berkata; telah menceritakan kepada kami [pamanku], dia berkata; telah menceritakan kepada kami [ayahku] dari [Shaleh] dari [Ibnu Syihab], dia berkata; [Abu Salamah] berkata; \"Sesungguhnya [Abu Hurairah] berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam.... Dan telah mengkhabarkan kepada kami [Yunus bin Abdul A'la], dia berkata; telah memberitakan kepada kami [Ibnu Wahb], dia berkata; telah mengkhabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Abu Salamah bin Abdur Rahman], telah dikhabarkan kepadanya dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang Yahudi dan Nashrani tidak menyemir rambut, maka selisihilah mereka.\" Telah mengkhabarkan kepada kami [Ishaq bin Ibrahim], dia berkata; telah memberitakan kepada kami [Abdur Rozaq], dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam seperti itu."},"4738":{"ar":"أَخْبَرَنِي الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْيَهُودَ وَالنَّصَارَى لَا تَصْبُغُ فَخَالِفُوا عَلَيْهِمْ فَاصْبُغُوا","id":"Telah mengkhabarkan kepadaku [Al Husain bin Huraits], dia berkata; telah memberitakan kepada kami [Al Fadhl bin Musa] dari [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang-orang Yahudi dan Nashrani tidak menyemir rambut, maka selisihilah mereka, dan semirlah rambut kalian.\""},"4739":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ خَشْرَمٍ قَالَ حَدَّثَنَا عِيسَى وَهُوَ ابْنُ يُونُسَ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ سُلَيْمَانَ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْيَهُودَ وَالنَّصَارَى لَا تَصْبُغُ فَخَالِفُوهُمْ","id":"Telah mengkhabarkan kepada kami [Ali bin Khasyram], dia berkata; telah menceritakan kepada kami [Isa yaitu Ibnu Yunus] dari [Al Auza'i] dari [Az Zuhri] dari [Sulaiman] dan [Abu Salamah bin Abdur Rahman] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya orang-orang Yahudi dan Nasrani tidak menyemir rambut maka selisihilah mereka.\""},"4740":{"ar":"أَخْبَرَنِي عُثْمَانُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ جَنَابٍ قَالَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيِّرُوا الشَّيْبَ وَلَا تَشَبَّهُوا بِالْيَهُودِ","id":"Telah mengkhabarkan kepadaku [Utsman bin Abdullah], dia berkata; telah menceritakan kepada kami [Ahmad bin Janab], dia berkata; telah menceritakan kepada kami [Isa bin Yunus] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Ibnu Umar], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ubahlah uban kalian dan janganlah kalian meniru orang-orang Yahudi.\""},"4741":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَخْلَدِ بْنِ الْحُسَيْنِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ كُنَاسَةَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ عُثْمَانَ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ الزُّبَيْرِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيِّرُوا الشَّيْبَ وَلَا تَشَبَّهُوا بِالْيَهُودِوَكِلَاهُمَا غَيْرُ مَحْفُوظٍ","id":"Telah mengkhabarkan kepada kami [Humaid bin Makhlad bin Al Husain], dia berkata; telah menceritakan kepada kami [Muhammad bin Kunasah], dia berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Utsman bin 'Urwah] dari [ayahnya] dari [Az Zubair], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ubahlah uban kalian dan janganlah kalian meniru orang-orang Yahudi.\" Keduanya tidak terjaga."},"4742":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ عُبَيْدِ اللَّهِ الْحَلَبِيُّ عَنْ عُبَيْدِ اللَّهِ وَهُوَ ابْنُ عَمْرٍو عَنْ عَبْدِ الْكَرِيمِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَفَعَهُ أَنَّهُ قَالَقَوْمٌ يَخْضِبُونَ بِهَذَا السَّوَادِ آخِرَ الزَّمَانِ كَحَوَاصِلِ الْحَمَامِ لَا يَرِيحُونَ رَائِحَةَ الْجَنَّةِ","id":"Telah mengkhabarkan kepada kami [Abdur Rahman bin 'Ubaidullah Al Halabi] dari ['Ubaidullah yaitu Ibnu Amr] dari [Abdul Karim] dari [Sa'id bin Jubair] dari [Ibnu Abbas], dan dia memarfu'kannya bahwa dia berkata; \"Akan ada suatu kaum yang menyemir rambut dengan warna hitam pada akhir zaman seperti paruh-paruh burung merpati, mereka tidak akan mencium baunya Surga.\""},"4743":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَأُتِيَ بِأَبِي قُحَافَةَ يَوْمَ فَتْحِ مَكَّةَ وَرَأْسُهُ وَلِحْيَتُهُ كَالثَّغَامَةِ بَيَاضًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيِّرُوا هَذَا بِشَيْءٍ وَاجْتَنِبُوا السَّوَادَ","id":"Telah mengkhabarkan kepada kami [Yunus bin Abdul A'la], dia berkata; telah menceritakan kepada kami [Ibnu Wahb], dia berkata; telah mengkhabarkan kepadaku [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir], dia berkata; \"Pada saat penaklukan Mekkah Abu Quhafah datang dengan rambut dan jenggotnya yang putih seperti Tsaghamah, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ubahlah uban ini dengan sesuatu dan hindari warna hitam.\""},"4744":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ يَعْلَى قَالَ حَدَّثَنَا بِهِ أَبِي عَنْ غَيْلَانَ عَنْ أَبِي إِسْحَقَ عَنْ ابْنِ أَبِي لَيْلَى عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفْضَلُ مَا غَيَّرْتُمْ بِهِ الشَّمَطَ الْحِنَّاءُ وَالْكَتَمُ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Muslim], dia berkata; telah menceritakan kepada kami [Yahya bin Ya'la], dia berkata; [ayahku] telah menceritakannya kepada kami dari [Ghailan] dari [Abu Ishaq] dari [Ibnu Abu Laila] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesuatu yang paling utama yang kalian gunakan untuk mengubah rambut putih adalah inai dan katam.\""},"4745":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ الْأَجْلَحِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِي الْأَسْوَدِ الدِّيْلِيِّ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحْسَنَ مَا غَيَّرْتُمْ بِهِ الشَّيْبَ الْحِنَّاءُ وَالْكَتَمُ","id":"Telah mengkhabarkan kepada kami [Ya'qub bin Ibrahim], dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Al Ajlah] dari [Abdullah bin Buraidah] dari [Abu Al Aswad Ad Dili] dari [Abu Dzar], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sesuatu yang paling baik yang kalian gunakan untuk mengubah uban adalah inai dan katam.\""},"4746":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ أَشْعَثَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عِيسَى قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَخْبَرَنِي ابْنُ أَبِي لَيْلَى عَنْ الْأَجْلَحِ فَلَقِيتُ الْأَجْلَحَ فَحَدَّثَنِي عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِي الْأَسْوَدِ الدِّيْلِيِّ عَنْ أَبِي ذَرٍّ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ مِنْ أَحْسَنِ مَا غَيَّرْتُمْ بِهِ الشَّيْبَ الْحِنَّاءَ وَالْكَتَمَ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdur Rahman bin Asy'ats], dia berkata; telah menceritakan kepadaku [Muhammad bin Isa], dia berkata; telah menceritakan kepada kami [Husyaim], dia berkata; telah mengkhabarkan kepadaku [Ibnu Abu Laila] dari [Al Ajlah], kemudian saya bertemu dengan Al Ajlah lalu ia menceritakan kepadaku dari [Ibnu Buraidah] dari [Abu Al Aswad Ad Dili] dari [Abu Dzar], dia berkata; \"Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sesuatu sebaik-baik yang kalian gunakan untuk mengubah uban adalah inai dan katam.\" "},"4747":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْثَرٌ عَنْ الْأَجْلَحِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِي الْأَسْوَدِ الدِّيْلِيِّ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحْسَنَ مَا غَيَّرْتُمْ بِهِ الشَّيْبَ الْحِنَّاءُ وَالْكَتَمُخَالَفَهُ الْجُرَيْرِيُّ وَكَهْمَسٌ","id":"Telah mengkhabarkan kepada kami [Qutaibah], dia berkata; telah menceritakan kepada kami ['Abtsar] dari [Al Ajlah] dari [Abdullah bin Buraidah] dari [Abu Al Aswad Ad Dili] dari [Abu Dzar], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sebaik-baik apa yang kalian gunakan untuk mengubah uban adalah inai dan katam.\" Al Jurairi dan Kahmas menyelisihinya. "},"4748":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحْسَنَ مَا غَيَّرْتُمْ بِهِ الشَّيْبَ الْحِنَّاءُ وَالْكَتَمُ","id":"Telah mengkhabarkan kepada kami [Humaid bin Mas'adah], dia berkata; telah menceritakan kepada kami [Abdul Warits], dia berkata; telah menceritakan kepada kami [Al Jurairi] dari [Abdullah bin Buraidah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sebaik-baik apa yang kalian gunakan untuk mengubah uban adalah inai dan katam.\""},"4749":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ كَهْمَسًا يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ أَنَّهُ بَلَغَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَحْسَنَ مَا غَيَّرْتُمْ بِهِ الشَّيْبَ الْحِنَّاءُ وَالْكَتَمُ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdul A'la], dia berkata; telah menceritakan kepada kami [Al Mu'tamir], ia berkata; \"Saya mendengar [Kahmas] menceritakan dari [Abdullah bin Buraidah] bahwa telah sampai kepadanya kabar bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sebaik-baik apa yang kalian gunakan untuk mengubah uban adalah inai dan katam.\""},"4750":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ إِيَادِ بْنِ لَقِيطٍ عَنْ أَبِي رِمْثَةَ قَالَأَتَيْتُ أَنَا وَأَبِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ قَدْ لَطَخَ لِحْيَتَهُ بِالْحِنَّاءِ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Basysyar], dia berkata; telah menceritakan kepada kami [Abdur Rahman] dari [Sufyan] dari [Iyad bin Laqith] dari [Abu Rimtsah], dia berkata; \"Aku bersama ayahku menemui Nabi shallallahu 'alaihi wasallam ketika itu beliau melumuri jenggot beliau dengan inai.\""},"4751":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ إِيَادِ بْنِ لَقِيطٍ عَنْ أَبِي رِمْثَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَأَيْتُهُ قَدْ لَطَخَ لِحْيَتَهُ بِالصُّفْرَةِ","id":"Telah mengkhabarkan kepada kami ['Amr bin Ali], dia berkata; telah menceritakan kepada kami [Abdur Rahman] dari [Sufyan] dari [Iyad bin Laqith] dari [Abu Rimtsah], dia berkata; \"Saya datang menemui Nabi shallallahu 'alaihi wasallam dan melihat beliau telah melumuri jenggot beliau menggunakan warna kuning.\""},"4752":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا الدَّرَاوَرْدِيُّ عَنْ زَيْدِ بْنِ أَسْلَمَ قَالَرَأَيْتُ ابْنَ عُمَرَ يُصَفِّرُ لِحْيَتَهُ بِالْخَلُوقِ فَقُلْتُ يَا أَبَا عَبْدِ الرَّحْمَنِ إِنَّكَ تُصَفِّرُ لِحْيَتَكَ بِالْخَلُوقِ قَالَ إِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَفِّرُ بِهَا لِحْيَتَهُ وَلَمْ يَكُنْ شَيْءٌ مِنْ الصِّبْغِ أَحَبَّ إِلَيْهِ مِنْهَا وَلَقَدْ كَانَ يَصْبُغُ بِهَا ثِيَابَهُ كُلَّهَا حَتَّى عِمَامَتَهُقَالَ أَبُو عَبْد الرَّحْمَنِ وَهَذَا أَوْلَى بِالصَّوَابِ مِنْ حَدِيثِ قُتَيْبَةَ","id":"Telah mengkhabarkan kepada kami [Ya'qub bin Ibrahim], dia berkata; telah menceritakan kepada kami [Ad Darawardi] dari [Zaid bin Aslam], dia berkata; \"Saya melihat [Ibnu Umar] mewarnai kuning jenggotnya dengan menggunakan khaluq (kunyit yang dicampur dengan minyak wangi). Aku bertanya; \"Wahai Abu Abdur Rahman (Mengapa) kamu mewarnai kuning jenggotmu dengan menggunakan khaluq?\" Dia berkata; \"Sesungguhnya saya melihat Rasulullah shallallahu 'alaihi wasallam mewarnai kuning jenggot beliau dengan menggunakannya dan tidak ada pewarna yang lebih beliau sukai daripadanya. Beliau mencelup seluruh baju beliau dengan menggunakannya hingga sorban beliau.\" Abu Abdur Rahman berkata; \"Ini lebih benar daripada hadits Qutaibah.\" "},"4753":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّهُ سَأَلَهُ هَلْ خَضَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمْ يَبْلُغْ ذَلِكَ إِنَّمَا كَانَ شَيْءٌ فِي صُدْغَيْهِ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Al Mutsanna], dia berkata; telah menceritakan kepada kami [Abu Daud], dia berkata; telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas] bahwa dia pernah ditanya apakah Rasulullah shallallahu 'alaihi wasallam menyemir rambut beliau? Dia menjawab; \"Tidak sampai seperti itu, hanya sedikit pada rambut putih yang ada di kedua pelipis beliau.\""},"4754":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا الْمُثَنَّى يَعْنِي ابْنَ سَعِيدٍ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَكُنْ يَخْضِبُ إِنَّمَا كَانَ الشَّمَطُ عِنْدَ الْعَنْفَقَةِ يَسِيرًا وَفِي الصُّدْغَيْنِ يَسِيرًا وَفِي الرَّأْسِ يَسِيرًا","id":"Telah mengkhabarkan kepada kami [Muhammad bin Al Mutsanna], dia berkata; telah menceritakan kepada kami [Abdush Shamad], dia berkata; telah menceritakan kepada kami [Al Mutsanna yaitu Ibnu Sa'id], dia berkata; telah menceritakan kepada kami [Qatadah] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam tidak menyemir, kecuali hanya pada sedikit uban yang ada di bawah bibir, di kedua pelipis serta di kepala beliau."},"4755":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ الرُّكَيْنَ يُحَدِّثُ عَنْ الْقَاسِمِ بْنِ حَسَّانَ عَنْ عَمِّهِ عَبْدِ الرَّحْمَنِ بْنِ حَرْمَلَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَكْرَهُ عَشْرَ خِصَالٍ الصُّفْرَةَ يَعْنِي الْخَلُوقَ وَتَغْيِيرَ الشَّيْبِ وَجَرَّ الْإِزَارِ وَالتَّخَتُّمَ بِالذَّهَبِ وَالضَّرْبَ بِالْكِعَابِ وَالتَّبَرُّجَ بِالزِّينَةِ لِغَيْرِ مَحَلِّهَا وَالرُّقَى إِلَّا بِالْمُعَوِّذَاتِ وَتَعْلِيقَ التَّمَائِمِ وَعَزْلَ الْمَاءِ بِغَيْرِ مَحَلِّهِ وَإِفْسَادَ الصَّبِيِّ غَيْرَ مُحَرِّمِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Al Mu'tamir] ia berkata; Aku mendengar [Ar Rukain] menceritakan dari [Al Qasim bin Hassan] dari pamannya ['Abdurrahman bin Harmalah] dari [Abdullah bin Mas'ud] berkata, \"Nabi Allah shallallahu 'alaihi wasallam membenci sepuluh hal; warna kuning -yakni Khaluq (wewangian yang mempunyai warna kuning) -, mewarnai uban, memanjangkan sarung, memakai cincin emas, permainan dadu, berhias bukan tanpa tempatnya, jampi, menggantungkan jimat, membuang air (mani) bukan pada tempatnya (kemaluan) dan merusak anak kecil (menggauli isteri yang masih menyusu).\""},"4756":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا الْمُعَلَّى بْنُ أَسَدٍ قَالَ حَدَّثَنَا مُطِيعُ بْنُ مَيْمُونٍ حَدَّثَتْنَا صَفِيَّةُ بِنْتُ عِصْمَةَ عَنْ عَائِشَةَأَنَّ امْرَأَةً مَدَّتْ يَدَهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكِتَابٍ فَقَبَضَ يَدَهُ فَقَالَتْ يَا رَسُولَ اللَّهِ مَدَدْتُ يَدِي إِلَيْكَ بِكِتَابٍ فَلَمْ تَأْخُذْهُ فَقَالَ إِنِّي لَمْ أَدْرِ أَيَدُ امْرَأَةٍ هِيَ أَوْ رَجُلٍ قَالَتْ بَلْ يَدُ امْرَأَةٍ قَالَ لَوْ كُنْتِ امْرَأَةً لَغَيَّرْتِ أَظْفَارَكِ بِالْحِنَّاءِ","id":"Telah menceritakan kepada kami [Amru bin Manshur] ia berkata; telah menceritakan kepada kami [Al Mu'alla bin Asad] ia berkata; telah menceritakan kepada kami [Muthi' bin Maimun] berkata, telah menceritakan kepada kami [Shafiyah binti Ishmah] dari ['Aisyah] berkata, \"Seorang wanita mengulurkan tangannya kepada Nabi shallallahu 'alaihi wasallam dengan sebuah kitab, wanita itu memegang tangan beliau seraya berkata, \"Wahai Rasulullah, aku ulurkan tanganku dengan sebuah kitab namun engkau tidak mengambilnya?! Beliau bersabda: \"Aku tidak tahu, apakah itu tangan seorang wanita atau tangan laki-laki.\" Wanita itu berkata, \"Itu tangan seorang wanita.\" Beliau bersabda: \"Sekiranya aku seorang wanita, sungguh kuku tanganku akan aku beri warna dengan pacar (inai).\""},"4757":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا أَبُو زَيْدٍ سَعِيدُ بْنُ الرَّبِيعِ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ قَالَ سَمِعْتُ كَرِيمَةَ قَالَتْسَمِعْتُ عَائِشَةَ سَأَلَتْهَا امْرَأَةٌ عَنْ الْخِضَابِ بِالْحِنَّاءِ قَالَتْ لَا بَأْسَ بِهِ وَلَكِنْ أَكْرَهُ هَذَا لِأَنَّ حِبِّي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَكْرَهُ رِيحَهُ تَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ibrahim bin Ya'qub] ia berkata; telah menceritakan kepada kami [Abu Zaid Sa'id bin Ar Rabi'] ia berkata; telah menceritakan kepada kami [Ali Ibnul Mubarak] ia berkata; Aku mendengar [Karimah] berkata; Aku mendengar ['Aisyah], Bahwasanya ia pernah ditanya oleh seorang perempuan tentang hukum mewarnai dengan pacar (inai), ia menjawab, \"Tidak apa-apa, hanya saja aku tidak menyukainya. Sebab kekasihku shallallahu 'alaihi wasallam tidak suka dengan baunya.\""},"4758":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ قَالَ حَدَّثَنَا أَبِي وَأَبُو الْأَسْوَدِ النَّضْرُ بْنُ عَبْدِ الْجَبَّارِ قَالَا حَدَّثَنَا الْمُفَضَّلُ بْنُ فَضَالَةَ عَنْ عَيَّاشِ بْنِ عَبَّاسٍ الْقِتْبَانِيِّ عَنْ أَبِي الْحُصَيْنِ الْهَيْثَمِ بْنِ شُفَيٍّ وَقَالَ أَبُو الْأَسْوَدِ شُفَيٌّ إِنَّهُ سَمِعَهُ يَقُولُخَرَجْتُ أَنَا وَصَاحِبٌ لِي يُسَمَّى أَبَا عَامِرٍ رَجُلٌ مِنْ الْمَعَافِرِ لِنُصَلِّيَ بِإِيلِيَاءَ وَكَانَ قَاصُّهُمْ رَجُلًا مِنْ الْأَزْدِ يُقَالُ لَهُ أَبُو رَيْحَانَةَ مِنْ الصَّحَابَةِ قَالَ أَبُو الْحُصَيْنِ فَسَبَقَنِي صَاحِبِي إِلَى الْمَسْجِدِ ثُمَّ أَدْرَكْتُهُ فَجَلَسْتُ إِلَى جَنْبِهِ فَقَالَ هَلْ أَدْرَكْتَ قَصَصَ أَبِي رَيْحَانَةَ فَقُلْتُ لَا فَقَالَ سَمِعْتُهُ يَقُولُ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عَشْرٍ عَنْ الْوَشْرِ وَالْوَشْمِ وَالنَّتْفِ وَعَنْ مُكَامَعَةِ الرَّجُلِ الرَّجُلَ بِغَيْرِ شِعَارٍ وَعَنْ مُكَامَعَةِ الْمَرْأَةِ الْمَرْأَةَ بِغَيْرِ شِعَارٍ وَأَنْ يَجْعَلَ الرَّجُلُ أَسْفَلَ ثِيَابِهِ حَرِيرًا مِثْلَ الْأَعَاجِمِ أَوْ يَجْعَلَ عَلَى مَنْكِبَيْهِ حَرِيرًا أَمْثَالَ الْأَعَاجِمِ وَعَنْ النُّهْبَى وَعَنْ رُكُوبِ النُّمُورِ وَلُبُوسِ الْخَوَاتِيمِ إِلَّا لِذِي سُلْطَانٍ","id":"Telah mengabarkan kepada kami ['Abdurrahman bin Abdullah bin Abdul Hakam] ia berkata; telah menceritakan kepada kami [Bapakku] dan [Abu Al Aswad An Nadlr bin Abdul Jabbar] keduanya berkata; telah menceritakan kepada kami [Al Mufadldlal bin Fadlalah] dari [Ayyasy bin Abbas Al Qitbani] dari [Abu Al Hushain Al Haitsam bin Syufay]. [Abu Al Aswad Syufay] berkata; sesungguhnya ia mendengarnya berkata, \"Aku dengan seorang temanku yang bernama Abu Amir, seorang laki-laki dari bani Al Ma'afir, keluar untuk shalat di Iliya. Dan yang biasa memberi mereka nasihat adalah seorang laki-laki dari Al Azdi yang bernama [Abu Raihanah], seorang sahabat Nabi. Abu Al Hushain berkata, \"Temanku itu mendahului aku datang ke masjid, kemudian aku menyusulnya dan duduk di sampingnya. Ia berkata, \"Apakah engkau pernah mendengar kisah Abu Raihanah?\" Aku menjawab, \"Belum.\" Ia (kawanku) kemudian berkata, \"Abu Raihanah mengatakan bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari sepuluh perkara; meratakan gigi, memakai tato, mencabut uban, dua orang lelaki yang tidur bareng tanpa kain yang membatasinya, dua orang wanita tidur bareng tanpa kain yang membatasinya, seorang laki-laki yang melapisi kain bajunya dengan sutera sebagaimana orang 'ajam (bukan arab) -atau ia mengatakan- meletakkan di atas pundaknya kain sutera seperti orang 'ajam, merampok, memakai kulit harimau dan memakai cincin kecuali penguasa.\""},"4759":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ عَنْ هِشَامٍ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَنَّ مُعَاوِيَةَ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الزُّورِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Khalid] dari [Hisyam] ia berkata; telah menceritakan kepada kami [Qatadah] dari [Sa'd Ibnul Musayyab] bahwa [Mu'awiyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari berdusta.\""},"4760":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي مَخْرَمَةُ بْنُ بُكَيْرٍ عَنْ أَبِيهِ عَنْ سَعِيدٍ الْمَقْبُرِيِّ قَالَرَأَيْتُ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَ عَلَى الْمِنْبَرِ وَمَعَهُ فِي يَدِهِ كُبَّةٌ مِنْ كُبَبِ النِّسَاءِ مِنْ شَعْرٍ فَقَالَ مَا بَالُ الْمُسْلِمَاتِ يَصْنَعْنَ مِثْلَ هَذَا إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَيُّمَا امْرَأَةٍ زَادَتْ فِي رَأْسِهَا شَعْرًا لَيْسَ مِنْهُ فَإِنَّهُ زُورٌ تَزِيدُ فِيهِ","id":"Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh] ia berkata; telah memberitakan kepada kami [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Makhramah bin Bukair] dari [bapaknya] dari [Sa'id Al Maqburi] ia berkata; Aku melihat [Mu'awiyah bin Abu Sufyan] di atas mimbar sementara di tangannya terdapat gulungan rambut wanita. Ia lalu berkata, \"Kenapa kaum Muslimah melakukan hal semacam ini! Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita mana saja yang menambahi rambut palsu pada kepalanya, sungguh itu adalah kedustaan yang ditambahkan padanya.\""},"4761":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ امْرَأَتِهِ فَاطِمَةَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَ","id":"Telah mengabarkan kepadaku [Muhammad bin Isma'il bin Ibrahim] ia berkata; telah menceritakan kepada kami [Abu An Nadlr] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Hisyam bin Urwah] dari isterinya [Fatimah] dari [Asma binti Abu Bakar] berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat wanita yang menyambung rambut dan wanita yang minta untuk disambungkan rambutnya.\""},"4762":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَ وَالْوَاشِمَةَ وَالْمُوتَشِمَةَأَرْسَلَهُ الْوَلِيدُ بْنُ أَبِي هِشَامٍ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Muhammad bin Bisyr] ia berkata; telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat wanita yang menyambung rambut dan yang minta disambung rambutnya, wanita yang bertato dan wanita yang minta ditato.\" Walid bin Abu Hisyam memursalkannya hadits ini."},"4763":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ قَالَ حَدَّثَنَا جُوَيْرِيَةُ بْنُ أَسْمَاءَ عَنْ الْوَلِيدِ بْنِ أَبِي هِشَامٍ عَنْ نَافِعٍ أَنَّهُ بَلَغَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَ وَالْوَاشِمَةَ وَالْمُسْتَوْشِمَةَ","id":"Telah mengabarkan kepada kami [Al Abbas bin Abdul Azhim] ia berkata; telah menceritakan kepada kami [Abdullah bin Muhammad bin Asma] ia berkata; telah menceritakan kepada kami [Juwairiah bin Asma] dari [Al Walid bin Abu Hisyam] dari [Nafi'], Bahwasanya telah sampai kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam melaknat wanita yang menyambung rambut dan yang minta disambung rambutnya, wanita yang bertato dan wanita yang minta ditato.\""},"4764":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ وَهْبٍ قَالَ حَدَّثَنَا مِسْكِينُ بْنُ بُكَيْرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ الْحَسَنِ بْنِ مُسْلِمٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ اللَّهُ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَأَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا خَلَفُ بْنُ مُوسَى قَالَ حَدَّثَنَا أَبِي عَنْ قَتَادَةَ عَنْ عَزْرَةَ عَنْ الْحَسَنِ الْعُرَنِيِّ عَنْ يَحْيَى بْنِ الْجَزَّارِ عَنْ مَسْرُوقٍ أَنَّ امْرَأَةً أَتَتْ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ فَقَالَتْ إِنِّي امْرَأَةٌ زَعْرَاءُ أَيَصْلُحُ أَنْ أَصِلَ فِي شَعْرِي فَقَالَ لَا قَالَتْ أَشَيْءٌ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَ��َلَّمَ أَوْ تَجِدُهُ فِي كِتَابِ اللَّهِ قَالَ لَا بَلْ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَجِدُهُ فِي كِتَابِ اللَّهِ وَسَاقَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Muhammad bin Wahb] ia berkata; telah menceritakan kepada kami [Miskin bin Bukair] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Amru bin Murrah] dari [Al Hasan bin Muslim] dari [Shafiah binti Syaibah] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat wanita yang menyambung rambut dan yang minta disambung rambutnya.\" Telah mengabarkan kepada kami [Amru bin Manshur] ia berkata; telah menceritakan kepada kami [Khalaf bin Musa] ia berkata; telah menceritakan kepada kami [Bapakku] dari [Qatadah] dari [Azrah] dari [Al Hasan Al 'Urani] dari [Yahya Ibnul Jazzar] dari [Masruq] ia berkata, \"Seorang wanita datang kepada [Abdullah bin Mas'ud] dan berkata, \"Aku adalah seorang wanita yang berambut tipis (rontok), apakah boleh jika aku menyambung rambutku?\" Abdullah bin Mas'ud menjawab, \"Tidak boleh.\" Wanita itu berkata lagi, \"Apakah itu sesuatu yang engkau dengar dari Rasulullah shallallahu 'alaihi wasallam, atau sesuatu yang engkau dapat dari Kitabullah?\" Abdullah bin Mas'ud menjawab, \"Bukan, tapi sesuatu yang kudengar dari Rasulullah shallallahu 'alaihi wasallam, dan dari apa yang aku temukan dalam Kitabullah, \" lalu ia menyebutkan sebagaimana dalam hadits tersebut.\""},"4765":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَاشِمَاتِ وَالْمُوتَشِمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِأَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ قَالَ قَالَ عَبْدُ اللَّهِ الْمُتَفَلِّجَاتِ وَسَاقَ الْحَدِيثَ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Muhammad bin Salam] ia berkata; telah menceritakan kepada kami [Abu Dawud Al Hafari] dari [Sufyan] dari [Manshur] dari [Ibrahim] dari [Alqamah] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat wanita pembuat tato, wanita yang ditato, wanita yang mencukur alis dan wanita yang merenggangkan gigi untuk kecantikan dengan merubah ciptaan Allah.\" Telah mengabarkan kepada kami [Ahmad bin Harb] ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] ia berkata, \" [Abdullah] berkata, \"Wanita-wanita yang merenggangkan gigi…lalu ia menyebutkan sebagaimana dalam hadits.\""},"4766":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا أَبَانُ بْنُ صَمْعَةَ عَنْ أُمِّهِ قَالَتْ سَمِعْتُ عَائِشَةَ تَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْوَاشِمَةِ وَالْمُسْتَوْشِمَةِ وَالْوَاصِلَةِ وَالْمُسْتَوْصِلَةِ وَالنَّامِصَةِ وَالْمُتَنَمِّصَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Khalid] ia berkata; telah menceritakan kepada kami [Aban bin Sham'ah] dari [Ibunya] ia berkata; Aku mendengar ['Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang wanita yang mentato dan wanita yang minta ditato, wanita yang menyambung rambut dan wanita yang minta untuk disambung rambutnya, serta wanita yang mencukur bulus alis dan wanita yang minta untuk dicukur bulu alisnya.\""},"4767":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ الْأَعْمَشِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُرَّةَ يُحَدِّثُ عَنْ الْحَارِثِ عَنْ عَبْدِ اللَّهِ قَالَآكِلُ الرِّبَا وَمُوكِلُهُ وَكَاتِبُهُ إِذَا عَلِمُوا ذَلِكَ وَالْوَاشِمَةُ وَالْمَوْشُومَةُ لِلْحُسْنِ وَلَاوِي الصَّدَقَةِ وَالْمُرْتَدُّ أَعْرَابِيًّا بَعْدَ الْهِجْرَةِ مَلْعُونُونَ عَلَى لِسَانِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] ia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Al A'masy] ia berkata; aku mendengar [Abdullah bin Murrah] menceritakan dari [Al Harits] dari [Abdullah] ia berkata, \"Pemakan riba, yang membawakannya dan yang menulisnya -jika mereka mengetahui-, wanita pentato, wanita yang minta ditato untuk tampil cantik, penolak zakat, dan orang badui yang murtad setelah hijrah, pada hari kiamat mereka akan dilaknat melalui lisan Muhammad shallallahu 'alaihi wasallam.\""},"4768":{"ar":"أَخْبَرَنِي زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا حُصَيْنٌ وَمُغِيرَةُ وَابْنُ عَوْنٍ عَنْ الشَّعْبِيِّ عَنْ الْحَارِثِ عَنْ عَلِيٍّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ آكِلَ الرِّبَا وَمُوكِلَهُ وَكَاتِبَهُ وَمَانِعَ الصَّدَقَةِ وَكَانَ يَنْهَى عَنْ النَّوْحِأَرْسَلَهُ ابْنُ عَوْنٍ وَعَطَاءُ بْنُ السَّائِبِ","id":"Telah mengabarkan kepadaku [Ziyad bin Ayyub] ia berkata; telah menceritakan kepada kami [Husyaim] ia berkata; telah memberitakan kepada kami [Hushain] dan [Mughirah] dan [Ibnu Aun] dari [Asy Sya'bi] dari [Al Harits] dari [Ali] berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat pemakan riba, yang membawakannya dan penulisnya, penolak zakat, dan beliau juga melarang dari niyahah (meratapi mayit).\" Ibnu Aun dan 'Atha bin As Sa`ib memursalkan hadits ini."},"4769":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ الشَّعْبِيِّ عَنْ الْحَارِثِ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آكِلَ الرِّبَا وَمُوكِلَهُ وَشَاهِدَهُ وَكَاتِبَهُ وَالْوَاشِمَةَ وَالْمُوتَشِمَةَ قَالَ إِلَّا مِنْ دَاءٍ فَقَالَ نَعَمْ وَالْحَالُّ وَالْمُحَلَّلُ لَهُ وَمَانِعُ الصَّدَقَةِ وَكَانَ يَنْهَى عَنْ النَّوْحِ وَلَمْ يَقُلْ لَعَنَ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] ia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] ia berkata; telah menceritakan kepada kami [Ibnu Aun] dari [Asy Sya'bi] dari [Al Harits] berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat para pemakan riba, yang membawakannya, yang menyaksikannya, dan yang menulisnya. Wanita pentato dan wanita yang minta ditato.\" Al Harits berkata, \"Kecuali karena penyakit?\" beliau bersabda: \"Benar, dan Al hallu, Al Muhalla lahu, dan penolak zakat.\" Beliau juga melarang dari An nauh (meratapi mayit), namun tidak melaknatnya.\""},"4770":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا خَلَفٌ يَعْنِي ابْنَ خَلِيفَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ الشَّعْبِيِّ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آكِلَ الرِّبَا وَمُوكِلَهُ وَشَاهِدَهُ وَكَاتِبَهُ وَالْوَاشِمَةَ وَالْمُوتَشِمَةَ وَنَهَى عَنْ النَّوْحِ وَلَمْ يَقُلْ لَعَنَ صَاحِبَ","id":"Telah menceritakan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Khalaf] -Ibnu Khalifah- dari ['Atha bin As Sa`ib] dari [Asy Sya'bi] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat para pemakan riba, yang membawakannya, yang menyaksikannya dan penulisnya. Wanita pentato dan wanita yang minta ditato. Dan beliau juga melarang dari An Nauh (meratapi mayit), namun tidak mengatakan, '(Semoga Allah) melaknat pelaku…'"},"4771":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ عُمَارَةَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَأُتِيَ عُمَرُ بِامْرَأَةٍ تَشِمُ فَقَالَ أَنْشُدُكُمْ بِاللَّهِ هَلْ سَمِعَ أَحَدٌ مِنْكُمْ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو هُرَيْرَةَ فَقُمْتُ فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ أَنَا سَمِعْتُهُ قَالَ فَمَا سَمِعْتَهُ قُلْتُ سَمِعْتُهُ يَقُولُ لَا تَشِمْنَ وَلَا تَسْتَوْشِمْنَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Jarir] dari [Umarah] dari [Abu Zur'ah] dari [Abu Hurairah] ia berkata, \"Seorang wanita yang bertato didatangkan kepada Umar, lalu ia berkata, \"Aku bersumpah kepada Allah atas kalian, adakah di antara kalian yang mendengar dari Rasulullah shallallahu 'alaihi wasallam (tentang tato)?\", Abu Hurairah berkata, \"Lalu aku berdiri dan berkata, \"Wahai Amirul mukminin, aku telah mendengarnya!\" Umar berkata, \"Apa yang engkau dengar?\" aku menjawab, \"Aku mendengar beliau bersabda: \"Janganlah seorang wanita itu bertato atau minta untuk ditato.\""},"4772":{"ar":"أَخْبَرَنَا أَبُو عَلِيٍّ مُحَمَّدُ بْنُ يَحْيَى الْمَرْوَزِيُّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ عَنْ أَبِي حَمْزَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ الْعُرْيَانِ بْنِ الْهَيْثَمِ عَنْ قَبِيصَةَ بْنِ جَابِرٍ عَنْ ابْنِ مَسْعُودٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْعَنُ الْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ وَالْمُوتَشِمَاتِ اللَّاتِي يُغَيِّرْنَ خَلْقَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Abu Ali Muhammad bin Yahya Al Marwazi] ia berkata; telah menceritakan kepada kami [Abdullah bin Utsman] dari [Abu Hamzah] dari [Abdul Malik bin Umair] dari [Al 'Uryan bin Al Haitsam] dari [Qabishah bin Jabir] dari [Ibnu Mas'ud] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam melaknat para wanita yang mencabut bulu alis, wanita yang merenggangkan gigi dan wanita yang minta ditato, mereka merubah ciptaan Allah 'azza wajalla.\""},"4773":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ الْعُرْيَانِ بْنِ الْهَيْثَمِ عَنْ قَبِيصَةَ بْنِ جَابِرٍ عَنْ عَبْدِ اللَّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْعَنُ الْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ وَالْمُوتَشِمَاتِ اللَّاتِي يُغَيِّرْنَ خَلْقَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] ia berkata; telah menceritakan kepada kami [Yahya bin Hammad] ia berkata; telah menceritakan kepada kami [Abu Awanah] dari [Abdul Malik bin Umair] dari [Al 'Uryan Al Haitsam] dari [Qabishah bin Jabir] dari [Abdullah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam melaknat para wanita yang mencabut bulu alis, wanita yang merenggangkan gigi, dan wanita yang membuat tato, mereka merubah ciptaan Allah 'azza wajalla.\""},"4774":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ بْنِ شَقِيقٍ قَالَ أَنْبَأَنَا الْحُسَيْنُ بْنُ وَاقِدٍ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ الْعُرْيَانِ بْنِ الْهَيْثَمِ عَنْ قَبِيصَةَ بْنِ جَابِرٍ عَنْ عَبْدِ اللَّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَعَنَ اللَّهُ الْمُتَنَمِّصَاتِ وَالْمُوتَشِمَاتِ وَالْمُتَفَلِّجَاتِ اللَّاتِي يُغَيِّرْنَ خَلْقَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub] ia berkata; telah menceritakan kepada kami [Ali Ibnul Hasan bin Syaqiq] ia berkata; telah memberitakan kepada kami [Al Husain bin Waqid] ia berkata; telah menceritakan kepada kami [Abdul Malik bin Umair] dari [Al 'Uryan Ibnul Haitsam] dari [Qabishah bin Jabir] dari [Abdullah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah melaknat para wanita yang mencabut bulu alis, wanita yang membuat tato, dan wanita yang merenggangkan gigi, mereka merubah ciptaan Allah 'azza wajalla.\""},"4775":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ حَدَّثَنَا حَبَّانُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ قَالَ حَدَّثَنِي عَيَّاشُ بْنُ عَبَّاسٍ الْقِتْبَانِيُّ عَنْ أَبِي الْحُصَيْنِ الْحِمْيَرِيِّ أَنَّهُ كَانَ هُوَ وَصَاحِبٌ لَهُ يَلْزَمَانِ أَبَا رَيْحَانَةَ يَتَعَلَّمَانِ مِنْهُ خَيْرًا قَالَ فَحَضَرَ صَاحِبِي يَوْمًا فَأَخْبَرَنِي صَاحِبِي أَنَّهُ سَمِعَ أَبَا رَيْحَانَةَ يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّمَ الْوَشْرَ وَالْوَشْمَ وَالنَّتْفَ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] ia berkata; telah menceritakan kepada kami [Habban] ia berkata; telah menceritakan kepada kami [Abdullah] dari [Haiwah bin Syuraih] ia berkata; telah menceritakan kepadaku [Ayyasy bin Abbas Al Qitbani] dari [Abu Al Hushain Al Himyari], Bahwasanya ia dan seorang temannya selalu duduk dalam majlis Abu Raihanah, mereka belajar kebaikan darinya.\" Abu Al Hushain berkata, \"Suatu hari [temanku] datang dan mengabarkan kepadaku bahwa ia pernah mendengar [Abu Raihanah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang mengikir gigi, membuat tato dan mencabut bulu alis.\""},"4776":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْحُصَيْنِ الْحِمْيَرِيِّ عَنْ أَبِي رَيْحَانَةَ قَالَبَلَغَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْوَشْرِ وَالْوَشْمِ","id":"Telah mengabarkan kepada kami [Ahmad bin Amru bin As Sarh] ia berkata; telah menceritakan kepada kami [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Al Hushain Al Himyari] dari [Abu Raihanah] ia berkata, \"Telah sampai kabar kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam melarang mengkikir gigi dan mencabut bulu alis.\""},"4777":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْحُصَيْنِ الْحِمْيَرِيِّ عَنْ أَبِي رَيْحَانَةَ قَالَبَلَغَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْوَشْرِ وَالْوَشْمِ","id":"Telah menceritakan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Al Hushain Al Himyari] dari [Abu Raihanah] ia berkata, \"Telah sampai kabar kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam melarang mengkikir gigi dan mencabut bulu alis.\""},"4778":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا دَاوُدُ وَهُوَ ابْنُ عَبْدِ الرَّحْمَنِ الْعَطَّارُ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ خَيْرِ أَكْحَالِكُمُ الْإِثْمِدَ إِنَّهُ يَجْلُو الْبَصَرَ وَيُنْبِتُ الشَّعَرَأَبُو عَبْد الرَّحْمَنِ عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ لَيِّنُ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Dawud] -yaitu Ibnu 'Abdurrahman Al 'Aththar- dari [Abdullah bin Utsman bin Khutsaim] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya celak terbaik untuk kalian pakai adalah Al Itsmid (batu celak), ia bisa membuat tajam pandangan mata dan menumbuhkan rambut.\" Abu 'Abdurrahman Abdullah bin Utsman bin Khutsaim adalah seorang yang lemah dalam masalah hadits."},"4779":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكٍ قَالَ سَمِعْتُ جَابِرَ بْنَ سَمُرَةَسُئِلَ عَنْ شَيْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ إِذَا ادَّهَنَ رَأْسَهُ لَمْ يُرَ مِنْهُ وَإِذَا لَمْ يُدَّهَنْ رُئِيَ مِنْهُ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] ia berkata; telah menceritakan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Simak] ia berkata; Aku mendengar [Jabir bin Abdullah] ditanya tentang uban Rasulullah shallallahu 'alaihi wasallam, ia menjawab, \"Jika beliau memakai minyak rambut maka ubannya tidak terlihat, jika tidak memakainya maka uban beliau terlihat.\""},"4780":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ مَيْمُونٍ قَالَ حَدَّثَنَا الْقَعْنَبِيُّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ زَيْدٍ عَنْ أَبِيهِ أَنَّ ابْنَ عُمَرَكَانَ يَصْبُغُ ثِيَابَهُ بِالزَّعْفَرَانِ فَقِيلَ لَهُ فَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْبُغُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ali bin Maimun] ia berkata; telah menceritakan kepada kami [Al Qa'nabi] ia berkata; telah menceritakan kepada kami [Abdullah bin Zaid] dari [Bapaknya] bahwa [Ibnu Umar] pernah mencelup kain bajunya dengan za'faran, ketika hal itu ditanyakan kepadanya, ia pun menjawab, \"Rasulullah shallallahu 'alaihi wasallam biasa melakukannya.\""},"4781":{"ar":"أَخْبَرَنَا أَبُو عُبَيْدَةَ بْنُ أَبِي السَّفَرِ عَنْ عَبْدِ الصَّمَدِ بْنِ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنَا بَكْرٌ الْمُزَلِّقُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَطَاءٍ الْهَاشِمِيُّ عَنْ مُحَمَّدِ بْنِ عَلِيٍّ قَالَ سَأَلْتُ عَائِشَةَأَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَطَيَّبُ قَالَتْ نَعَمْ بِذِكَارَةِ الطِّيبِ الْمِسْكِ وَالْعَنْبَرِ","id":"Telah mengabarkan kepada kami [Abu Ubaidah bin Abu As Safar] dari [Abdu Ash Shamad bin Abdul Warits] ia berkata; telah menceritakan kepada kami [Bakr Al Muzalliq] ia berkata; telah menceritakan kepada kami [Abdullah bin 'Atha Al Hasyimi] dari [Muhammad bin Ali] ia berkata, \"Aku pernah bertanya ['Aisyah], 'Apakah Rasulullah shallallahu 'alaihi wasallam memakai parfum, ia menjawab, \"Ya, dengan minyak wangi misk dan 'anbar.\""},"4782":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ يَعْنِي الْحَفَرِيَّ عَنْ سُفْيَانَ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ رَجُلٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طِيبُ الرِّجَالِ مَا ظَهَرَ رِيحُهُ وَخَفِيَ لَوْنُهُ وَطِيبُ النِّسَاءِ مَا ظَهَرَ لَوْنُهُ وَخَفِيَ رِيحُهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Abu Dawud] -yaitu Al Hafari- dari [Sufyan] dari [Al Jurairi] dari [Abu Nadlrah] dari [seorang laki-laki] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Parfum laki-laki itu baunya nampak sementara warnanya tidak, dan parfum wanita itu warnanya nampak sementara baunya tidak.\""},"4783":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ مَيْمُونٍ الرَّقِّيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ الْفِرْيَابِيُّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ الطَّفَاوِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ طِيبُ الرِّجَالِ مَا ظَهَرَ رِيحُهُ وَخَفِيَ لَوْنُهُ وَطِيبُ النِّسَاءِ مَا ظَهَرَ لَوْنُهُ وَخَفِيَ رِيحُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ali bin Maimun Ar Raqqi] ia berkata; telah menceritakan kepada kami [Muhammad bin Yusuf Al Firyani] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Al Jurairi] dari [Abu An Nadlrah] dari [Ath Thafawi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Parfum laki-laki itu baunya nampak sementara warnanya tidak, dan parfum wanita itu warnanya nampak sementara baunya tidak.\""},"4784":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَ حَدَّثَنَا شَبَابَةُ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ خُلَيْدِ بْنِ جَعْفَرٍ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ امْرَأَةً مِنْ بَنِي إِسْرَائِيلَ اتَّخَذَتْ خَاتِمًا مِنْ ذَهَبٍ وَحَشَتْهُ مِسْكًا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ أَطْيَبُ الطِّيبِ","id":"Telah mengabarkan kepada kami ['Abdurrahman bin Muhammad bin Sallam] ia berkata; telah menceritakan kepada kami [Syababah] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Khulaid bin Ja'far] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada seorang wanita bani Isra'il memaki cincin yang diolesi minyak wangi.\" Beliau melanjutkan: \"Dan itu adalah minyak yang paling bagus.\""},"4785":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عِمْرَانَ بْنِ ظَبْيَانَ عَنْ حُكَيْمِ بْنِ سَعْدٍ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهِ رَدْعٌ مِنْ خَلُوقٍ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ فَانْهَكْهُ ثُمَّ أَتَاهُ فَقَالَ اذْهَبْ فَانْهَكْهُ ثُمَّ أَتَاهُ فَقَالَ اذْهَبْ فَانْهَكْهُ ثُمَّ لَا تَعُدْ","id":"Telah menceritakan kepada kami [Muhammad bin Manshur] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Imran bin Zhabyan] dari [Hakim bin Sa'd] dari [Abu Hurairah] ia berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dengan mengenakan pakaian yang dilumuri wewangian berwarna kuning, Nabi shallallahu 'alaihi wasallam lalu bersabda kepadanya: \"Pergi dan lepaslah.\" Laki-laki itu datang kembali dan beliau bersabda: \"Pergi dan lepaslah.\" Laki-laki itu datang kembali dan beliau bersabda: \"Pergi dan lepaslah ia, dan jangan kembali.\""},"4786":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ قَالَ سَمِعْتُ أَبَا حَفْصِ بْنَ عَمْرٍو وَقَالَ عَلَى إِثْرِهِ يُحَدِّثُ عَنْ يَعْلَى بْنِ مُرَّةَأَنَّهُ مَرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُتَخَلِّقٌ فَقَالَ لَهُ هَلْ لَكَ امْرَأَةٌ قُلْتُ لَا قَالَ فَاغْسِلْهُ ثُمَّ اغْسِلْهُ ثُمَّ لَا تَعُدْ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata, telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari ['Atha bin As Sa`ib] ia berkata; Aku mendengar [Abu Hafsh bin Amru] -dia berkata setelahnya- ia menceritakan dari [Ya'la bin Murrah], bahwa ia pernah lewat di depan Nabi shallallahu 'alaihi wasallam sementara ia memakai wewangian yang berwarna, beliau lalu bertanya kepadanya: \"Apakah engkau mempunyai isteri?\" aku menjawab, \"Tidak.\" Beliau bersabda: \"Cucilah, kemudian cuci lagi dan jangan kamu ulangi.\""},"4787":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَطَاءٍ قَالَ سَمِعْتُ أَبَا حَفْصِ بْنَ عَمْرٍو عَنْ يَعْلَى بْنِ مُرَّةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْصَرَ رَجُلًا مُتَخَلِّقًا قَالَ اذْهَبْ فَاغْسِلْهُ ثُمَّ اغْسِلْهُ وَلَا تَعُدْأَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَطَاءٍ عَنْ ابْنِ عَمْرٍو عَنْ رَجُلٍ عَنْ يَعْلَى نَحْوَهُ خَالَفَهُ سُفْيَانُ رَوَاهُ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ عَبْدِ اللَّهِ بْنِ حَفْصٍ عَنْ يَعْلَى","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] ia berkata; telah menceritakan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Atha] ia berkata; Aku mendengar [Abu Hafsh bin Amru] dari [Ya'la bin Murrah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melihat seorang laki-laki yang memakai wewangian berwarna, maka beliau bersabda: \"Pergi dan cucilah, kemudian cuci lagi dan jangan engkau ulangi.\" Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] ia berkata; telah menceritakan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Atha] dari [Ibnu Amru] dari [Seorang laki-laki] dari [Ya'la] sebagaimana dalam hadits, tetapi riwayat itu berbeda dengan Sufyan, ia meriwayatkan dari 'Atha bin As Sa`ib dari Abdullah bin Hafsh dari Ya'la."},"4788":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ النَّضْرِ بْنِ مُسَاوِرٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ عَبْدِ اللَّهِ بْنِ حَفْصٍ عَنْ يَعْلَى بْنِ مُرَّةَ الثَّقَفِيِّ قَالَأَبْصَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِي رَدْعٌ مِنْ خَلُوقٍ قَالَ يَا يَعْلَى لَكَ امْرَأَةٌ قُلْتُ لَا قَالَ اغْسِلْهُ ثُمَّ لَا تَعُدْ ثُمَّ اغْسِلْهُ ثُمَّ لَا تَعُدْ ثُمَّ اغْسِلْهُ ثُمَّ لَا تَعُدْ قَالَ فَغَسَلْتُهُ ثُمَّ لَمْ أَعُدْ ثُمَّ غَسَلْتُهُ ثُمَّ لَمْ أَعُدْ ثُمَّ غَسَلْتُهُ ثُمَّ لَمْ أَعُدْ","id":"Telah mengabarkan kepada kami [Muhammad bin An Nadlr bin Musawir] ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Atha bin As Sa`ib] dari [Abdullah bin Hafsh] dari [Ya'la bin Murrah Ast Tsaqafi] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memperhatikan aku, sementara aku sedang mengenakan pakaian yang dilumuri wewangian yang berwarna. Beliau bersabda: \"Wahai Ya'la, apakah engkau mempunyai isteri?\" aku menjawab, \"Tidak.\" Beliau bersabda: \"Cucilah dan jangan engkau ulangi (melumuri dengan wewangian yang berwarna), kemudian cucilah dan jangan engkau ulangi, kemudian cucilah dan jangan engkau ulangi.\" Ya'la berkata, \"Lalu aku mencucinya dan tidak mengulangi, kemudian aku mencucinya dan tidak mengulangi, kemudian aku mencucinya dan tidak mengulangi.\""},"4789":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ يَعْقُوبَ الصَّبِيحِيُّ قَالَ حَدَّثَنَا ابْنُ مُوسَى يَعْنِي مُحَمَّدًا قَالَ أَخْبَرَنِي أَبِي عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ عَبْدِ اللَّهِ بْنِ حَفْصٍ عَنْ يَعْلَى قَالَمَرَرْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مُتَخَلِّقٌ فَقَالَ أَيْ يَعْلَى هَلْ لَكَ امْرَأَةٌ قُلْتُ لَا قَالَ اذْهَبْ فَاغْسِلْهُ ثُمَّ اغْسِلْهُ ثُمَّ اغْسِلْهُ ثُمَّ لَا تَعُدْ قَالَ فَذَهَبْتُ فَغَسَلْتُهُ ثُمَّ غَسَلْتُهُ ثُمَّ غَسَلْتُهُ ثُمَّ لَمْ أَعُدْ","id":"Telah mengabarkan kepada kami [Isma'il bin Ya'qub Ash Shabihi] ia berkata; telah menceritakan kepada kami [Ibnu Musa] -yaitu Muhammad- ia berkata; telah mengabarkan kepadaku [Bapakku] dari ['Atha bin As Sa`ib] dari [Abdullah bin Hafsh] dari [Ya'la] ia berkata, \"Aku lewat di depan Rasulullah shallallahu 'alaihi wasallam sementara aku mengenakan pakaian yang dilumuri wewangian yang berwarna. Beliau bersabda: \"Wahai Ya'la, apakah engkau mempunyai isteri?\" aku menjawab, \"Tidak.\" Beliau bersabda: \"Pergi dan cucilah, kemudian cucilah, kemudian cucilah dan jangan engkau ulangi.\" Ya'la berkata, \"Kemudian aku pergi dan mencucinya, kemudian aku mencuci dan mencucinya lagi, setelah itu aku tidak mengulanginya lagi.\""},"4790":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا ثَابِتٌ وَهُوَ ابْنُ عِمَارَةَ عَنْ غُنَيْمِ بْنِ قَيْسٍ عَنْ الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا امْرَأَةٍ اسْتَعْطَرَتْ فَمَرَّتْ عَلَى قَوْمٍ لِيَجِدُوا مِنْ رِيحِهَا فَهِيَ زَانِيَةٌ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] ia berkata; telah menceritakan kepada kami [Khalid] ia berkata; telah menceritakan kepada kami [Tsabit] -Yaitu Ibnu Umarah- dari [Ghunaim bin Qais] dari [Al Asy'ari] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita mana saja yang memakai minyak wangi kemudian melintas pada suatu kaum agar mereka mencium baunya, maka ia adalah pezina.\""},"4791":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ بْنِ عَلِيِّ بْنِ عَبْدِ اللَّهِ بْنِ الْعَبَّاسِ الْهَاشِمِيُّ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ قَالَ سَمِعْتُ صَفْوَانَ بْنَ سُلَيْمٍ وَلَمْ أَسْمَعْ مِنْ صَفْوَانَ غَيْرَهُ يُحَدِّثُ عَنْ رَجُلٍ ثِقَةٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَجَتْ الْمَرْأَةُ إِلَى الْمَسْجِدِ فَلْتَغْتَسِلْ مِنْ الطِّيبِ كَمَا تَغْتَسِلُ مِنْ الْجَنَابَةِ مُخْتَصَرٌ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il bin Ibrahim] ia berkata; telah menceritakan kepada kami [Sulaiman bin Dawud bin Ali bin Abdullah bin Al Abbas Al Hasyimi] ia berkata; telah menceritakan kepada kami [Ibrahim bin Sa'd] ia berkata; Aku mendengar [Shafwan bin Sulaim] -dan aku belum pernah mendengar dari Shafwan selain riwayat itu- menceritakan dari [seorang laki-laki yang terpercaya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang wanita ingin pergi ke masjid, maka hendaklah ia membersihkan wewangiannya layaknya ia mandi besar, \" secara ringkas."},"4792":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ هِشَامِ بْنِ عِيسَى الْبَغْدَادِيُّ قَالَ حَدَّثَنَا أَبُو عَلْقَمَةَ الْفَرْوِيُّ عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنِي يَزِيدُ بْنُ خُصَيْفَةَ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا امْرَأَةٍ أَصَابَتْ بَخُورًا فَلَا تَشْهَدْ مَعَنَا الْعِشَاءَ الْآخِرَةَقَالَ أَبُو عَبْد الرَّحْمَنِ لَا أَعْلَمُ أَحَدًا تَابَعَ يَزِيدَ بْنَ خُصَيْفَةَ عَنْ بُسْرِ بْنِ سَعِيدٍ عَلَى قَوْلِهِ عَنْ أَبِي هُرَيْرَةَ وَقَدْ خَالَفَهُ يَعْقُوبُ بْنُ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ رَوَاهُ عَنْ زَيْنَبَ الثَّقَفِيَّةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Hisyam bin Isa Al Baghdadi] ia berkata; telah menceritakan kepada kami [Abu Alqamah Al Farwi Abdullah bin Muhammad] ia berkata; telah menceritakan kepadaku [Yazid bin Khushaifah] dari [Busr bin Sa'id] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita mana saja yang memakai wewangian, maka janganlah ia ikut shalat isya yang akhir bersama kami.\" 'Abdurrahman berkata, \"Aku tidak mengetahui seorang pun yang menguatkan (riwayat) Yazid bin Khushaifah dari Busyr bin Sa'id, atas perkataannya dari Abu Hurairah. Ya'qub bin Abdullah bin Al Asyaj juga menyelisihinya, ia meriwayatkan dari Zainab Ats Tsaqafiah.\""},"4793":{"ar":"أَخْبَرَنِي هِلَالُ بْنُ الْعَلَاءِ بْنِ هِلَالٍ قَالَ حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ يَعْقُوبَ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا شَهِدَتْ إِحْدَاكُنَّ صَلَاةَ الْعِشَاءِ فَلَا تَمَسَّ طِيبًا","id":"Telah mengabarkan kepadaku [Hilal Ibnul 'Ala bin Hilal] ia berkata; telah menceritakan kepada kami [Mu'alla bin Asad] ia berkata; telah menceritakan kepada kami [Wuhaib] dari [Muhammad bin 'Ajlan] dari [Ya'qub bin Abdullah bin Al Asyaj] dari [Busr bin Sa'id] dari [Zainab] isteri Abdullah, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian ikut shalat isya, maka jangan memakai minyak wangi.\""},"4794":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ ابْنِ عَجْلَانَ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا شَهِدَتْ إِحْدَاكُنَّ الْعِشَاءَ فَلَا تَمَسَّ طِيبًاقَالَ أَبُو عَبْد الرَّحْمَنِ حَدِيثُ يَحْيَى وَجَرِيرٍ أَوْلَى بِالصَّوَابِ مِنْ حَدِيثِ وُهَيْبِ بْنِ خَالِدٍ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Jarir] dari [Ibnu 'Ajlan] dari [Bukair bin Abdullah bin Al Asyaj] dari [Busr bin Sa'id] dari [Zainab] isteri Abdullah, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian ikut shalat isya, maka jangan memakai minyak wangi.\" Hadits Yahya dan Jarir lebih utama (shahih) dari hadits Wuhaib bin Khalid. Waallahu 'alam."},"4795":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ سَعِيدِ بْنِ يَعْقُوبَ الْحِمْصِيُّ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْنَبَ الثَّقَفِيَّةِأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيَّتُكُنَّ خَرَجَتْ إِلَى الْمَسْجِدِ فَلَا تَقْرَبَنَّ طِيبًا","id":"Telah mengabarkan kepadaku [Ahmad bin Sa'id bin Ya'qub Al Himshi] ia berkata; telah menceritakan kepada kami [Utsman bin Sa'id] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Bukair bin Al Asyaj] dari [Busr bin Sa'id] dari [Zainab Ats Tsaqafi] berkata, \"Nabi Allah shallallahu 'alaihi wasallam bersabda: \"Siapapun dari kalian yang datang ke masjid, maka jangan sekali-kali memakai wewangian.\""},"4796":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ الْقُرَشِيِّ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ زَيْنَبَ الثَّقَفِيَّةِ امْرَأَةِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهَا أَنْ لَا تَمَسَّ الطِّيبَ إِذَا خَرَجَتْ إِلَى الْعِشَاءِ الْآخِرَةِ","id":"Telah mengabarkan kepada kami [Amru bin Ali] ia berkata; telah menceritakan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Muhammad bin Abdullah Al Qursyi] dari [Bukair bin Al Asyaj] dari [Zainab Ats Tsaqafi] -isteri Abdullah-, bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan kepadanya agar ia tidak memakai wewangian jika ingin pergi shalat isya yang akhir.\""},"4797":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا مَنْصُورُ بْنُ أَبِي مُزَاحِمٍ قَالَ أَنْبَأَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ هِشَامٍ عَنْ بُكَيْرٍ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْنَبَ الثَّقَفِيَّةِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا خَرَجَتْ الْمَرْأَةُ إِلَى الْعِشَاءِ الْآخِرَةِ فَلَا تَمَسَّ طِيبًا","id":"Telah mengabarkan kepada kami [Abu Bakr bin Ali] ia berkata; telah menceritakan kepada kami [Manshur bin Abu Muzahim] ia berkata; telah memberitakan kepada kami [Ibrahim bin Sa'd] dari [Bapaknya] dari [Muhammad bin Abdullah bin Amru bin Hisyam] dari [Bukair] dari [Busr bin Sa'id] dari [Zainab Ats Tsaqafi,] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang wanita ingin menghadiri shalat isya yang akhir, maka janganlah ia memakai wewangian.\""},"4798":{"ar":"أَخْبَرَنِي يُوسُفُ بْنُ سَعِيدٍ قَالَ بَلَغَنِي عَنْ حَجَّاجٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي زِيَادُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْنَبَ الثَّقَفِيَّةِ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا شَهِدَتْ إِحْدَاكُنَّ الصَّلَاةَ فَلَا تَمَسَّ طِيبًاقَالَ أَبُو عَبْد الرَّحْمَنِ وَهَذَا غَيْرُ مَحْفُوظٍ مِنْ حَدِيثِ الزُّهْرِيِّ","id":"Telah mengabarkan kepadaku [Yusuf bin Sa'id] ia berkata; telah sampai kepadaku dari [Hajjaj] dari [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Ziyad bin Sa'd] dari [Ibnu Syihab] dari [Busr bin Sa'id] dari [Zainab Ats Tsaqafi] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian ingin menghadiri shalat, maka janganlah memakai wewangian.\" 'Abdurrahman berkata, \"Hadits dari Az Zuhri ini tidak kuat.\""},"4799":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ أَبُو طَاهِرٍ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي مَخْرَمَةُ عَنْ أَبِيهِ عَنْ نَافِعٍ قَالَكَانَ ابْنُ عُمَرَ إِذَا اسْتَجْمَرَ اسْتَجْمَرَ بِالْأَلُوَّةِ غَيْرَ مُطَرَّاةٍ وَبِكَافُورٍ يَطْرَحُهُ مَعَ الْأَلُوَّةِ ثُمَّ قَالَ هَكَذَا كَانَ يَسْتَجْمِرُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ahmad bin Amru bin As Sarh Abu Thahir] ia berkata; telah memberitakan kepada kami [Ibnu Wahb] berkata; telah mengabarkan kepadaku [Makhramah] dari [Bapaknya] dari [Nafi'] ia berkata, \"Jika [Ibnu Umar] ingin menggunakan wewangian, ia memakai Al aluwwah (kayu wangi yang dibakar) tanpa campuran, terkadang juga memakai kapur yang dicampur dengan Al aluwwah. Lalu ia berkata, \"Beginilah kebiasaan Rasulullah shallallahu 'alaihi wasallam saat memakai minyak wangi.\""},"4800":{"ar":"أَخْبَرَنَا وَهْبُ بْنُ بَيَانٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَنْبَأَنَا عَمْرُو بْنُ الْحَارِثِ أَنَّ أَبَا عُشَّانَةَ هُوَ الْمَعَافِرِيُّ حَدَّثَهُ أَنَّهُ سَمِعَ عُقْبَةَ بْنَ عَامِرٍ يُخْبِرُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَمْنَعُ أَهْلَهُ الْحِلْيَةَ وَالْحَرِيرَ وَيَقُولُ إِنْ كُنْتُمْ تُحِبُّونَ حِلْيَةَ الْجَنَّةِ وَحَرِيرَهَا فَلَا تَلْبَسُوهَا فِي الدُّنْيَا","id":"Telah mengabarkan kepada kami [Wahb bin Bayan] ia berkata; telah menceritakan kepada kami [Ibnu Wahb] ia berkata; telah memberitakan kepada kami [Amru bin Al Harits] bahwa [Abu Usyanah] -yakni Al Ma'arifi- menceritakan kepadanya, bahwa ia mendengar [Uqbah bin Amir] mengabarkan, bahwa Rasulullah shallallahu 'alaihi wasallam melarang saudaranya memakai perhiasan dan sutera. Beliau bersabda: \"Jika kalian ingin mengenakan perhiasan surga dan kain suteranya, maka janganlah kalian memakainya di dunia.\""},"4801":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ رِبْعِيٍّ عَنْ امْرَأَتِهِ عَنْ أُخْتِ حُذَيْفَةَ قَالَتْخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مَعْشَرَ النِّسَاءِ أَمَا لَكُنَّ فِي الْفِضَّةِ مَا تَحَلَّيْنَ أَمَا إِنَّهُ لَيْسَ مِنْ امْرَأَةٍ تَحَلَّتْ ذَهَبًا تُظْهِرُهُ إِلَّا عُذِّبَتْ بِهِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] ia berkata; telah menceritakan kepada kami [Jarir] dari [Manshur]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Muhammad bin Basysyar] ia berkata; telah menceritakan kepada kami ['Abdurrahman] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Rib'i] dari [Isterinya] dari [saudara perempuan Hudzaifah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkhutbah di hadapan kami: \"Wahai kaum wanita, tidakkah kalian itu memakai perhiasan perak, sesungguhnya tidak ada seorang perempuan yang memakai perhiasan emas kemudian ditampakkan (di depan orang laki-laki) kecuali wanita itu akan di siksa oleh Allah karenanya.\""},"4802":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ مَنْصُورًا يُحَدِّثُ عَنْ رِبْعِيٍّ عَنْ امْرَأَتِهِ عَنْ أُخْتِ حُذَيْفَةَ قَالَتْخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مَعْشَرَ النِّسَاءِ أَمَا لَكُنَّ فِي الْفِضَّةِ مَا تَحَلَّيْنَ أَمَا إِنَّهُ لَيْسَ مِنْكُنَّ امْرَأَةٌ تُحَلَّى ذَهَبًا تُظْهِرُهُ إِلَّا عُذِّبَتْ بِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Al Mu'tamir] ia berkata; Aku mendengar [Manshur] menceritakan dari [Rib'i] dari [Isterinya] dari [Saudara perempuan Hudzaifah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkhutbah di hadapan kami: \"Wahai kaum wanita, tidakkah kalian itu memakai perhiasan perak, sesungguhnya tidak ada seorang perempuan yang memakai perhiasan emas kemudian ditampakkan (di depan orang laki-laki) kecuali wanita itu akan di siksa oleh Allah karenanya.\""},"4803":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي مَحْمُودُ بْنُ عَمْرٍو أَنَّ أَسْمَاءَ بِنْتَ يَزِيدَ حَدَّثَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا امْرَأَةٍ تَحَلَّتْ يَعْنِي بِقِلَادَةٍ مِنْ ذَهَبٍ جُعِلَ فِي عُنُقِهَا مِثْلُهَا مِنْ النَّارِ وَأَيُّمَا امْرَأَةٍ جَعَلَتْ فِي أُذُنِهَا خُرْصًا مِنْ ذَهَبٍ جَعَلَ اللَّهُ عَزَّ وَجَلَّ فِي أُذُنِهَا مِثْلَهُ خُرْصًا مِنْ النَّارِ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] ia berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] ia berkata; telah menceritakan kepadaku [Bapakku] dari [Yahya bin Abu Katsir] ia berkata; telah menceritakan kepadaku [Mahmud bin Amru] bahwa [Asma binti Yazid] menceritakan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita mana saja yang berhias -yakni dengan kalung-, maka akan dibuatkan untuknya yang seperti itu pula dari api neraka. Dan wanita mana saja yang memasang pada telinganya anting dari emas, maka pada hari kiamat nanti Allah akan memasangkan pada telinganya anting dari api.\""},"4804":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي زَيْدٌ عَنْ أَبِي سَلَّامٍ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ أَنَّ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُ قَالَجَاءَتْ بِنْتُ هُبَيْرَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي يَدِهَا فَتَخٌ فَقَالَ كَذَا فِي كِتَابِ أَبِي أَيْ خَوَاتِيمُ ضِخَامٌ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضْرِبُ يَدَهَا فَدَخَلَتْ عَلَى فَاطِمَةَ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَشْكُو إِلَيْهَا الَّذِي صَنَعَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْتَزَعَتْ فَاطِمَةُ سِلْسِلَةً فِي عُنُقِهَا مِنْ ذَهَبٍ وَقَالَتْ هَذِهِ أَهْدَاهَا إِلَيَّ أَبُو حَسَنٍ فَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالسِّلْسِلَةُ فِي يَدِهَا فَقَالَ يَا فَاطِمَةُ أَيَغُرُّكِ أَنْ يَقُولَ النَّاسُ ابْنَةُ رَسُولِ اللَّهِ وَفِي يَدِهَا سِلْسِلَةٌ مِنْ نَارٍ ثُمَّ خَرَجَ وَلَمْ يَقْعُدْ فَأَرْسَلَتْ فَاطِمَةُ بِالسِّلْسِلَةِ إِلَى السُّوقِ فَبَاعَتْهَا وَاشْتَرَتْ بِثَمَنِهَا غُلَامًا وَقَالَ مَرَّةً عَبْدًا وَذَكَرَ كَلِمَةً مَعْنَاهَا فَأَعْتَقَتْهُ فَحُدِّثَ بِذَلِكَ فَقَالَ الْحَمْدُ لِلَّهِ الَّذِي أَنْجَى فَاطِمَةَ مِنْ النَّارِأَخْبَرَنَا سُلَيْمَانُ بْنُ سَلْمٍ الْبَلْخِيُّ قَالَ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَّامٍ عَنْ أَبِي أَسْمَاءَ عَنْ ثَوْبَانَ قَالَ جَاءَتْ بِنْتُ هُبَيْرَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي يَدِهَا فَتَخٌ مِنْ ذَهَبٍ أَيْ خَوَاتِيمُ ضِخَامٌ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] ia berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] ia berkata; telah menceritakan kepadaku [Bapakku] dari [Yahya bin Abu Katsir] ia berkata; telah menceritakan kepadaku [Zaid] dari [Abu Sallam] dari [Abu Asma Ar Rahabi] bahwa [Tsauban] mantan budak Rasulullah shallallahu 'alaihi wasallam, menceritakan kepadanya, ia berkata, \"Puteri Hubairah datang menemui Rasulullah shallallahu 'alaihi wasallam sementara pada tangannya terdapat Fatakh -Tsauban berkata, \"Demikianlah tertulis dalam buku bapakku, yaitu cincin besar- hingga Rasulullah shallallahu 'alaihi wasallam memukul tangannya. Kemudian ia datang menemui Fatimah, puteri Rasulullah shallallahu 'alaihi wasallam dan mengadukan tentang perbuatan Rasulullah shallallahu 'alaihi wasallam kepadanya. Fatimah pun melepaskan kalung emas yang ada di lehernya seraya berkata, \"Kalung ini hadiah dari Abu Hasan untukku.\" Setelah itu Rasulullah shallallahu 'alaihi wasallam masuk sementara kalung miliknya masih ada dalam tangan, beliau lalu bersabda: \"Wahai Fatimah, maukah jika orang-orang mengatakan, 'Puteri Rasulullah, namun di tangannya menggenggam kalung dari api! ' Setelah itu Rasulullah pergi dan tidak duduk dahulu, Fatimah lantas pergi ke pasar menjual kalung itu dan membeli seorang budak dari hasil penjualan kalung itu -sekali waktu Tsauban menyebutkan dengan lafadz 'budak', dan sekali waktu dengan lafadz yang semakna- lalu ia memerdekakannya. Ketika hal itu diceritakan kepada Rasulullah shallallahu 'alaihi wasallam, beliau pun bersabda: \"Segala puji bagi Allah yang telah menyelamatkan Fatimah dari neraka.\" Telah mengabarkan kepada kami [Sulaiman bin Salm Al Balkhi] ia berkata; telah menceritakan kepada kami [An Nadlr bin Syumail] ia berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salam] dari [Abu Asma] dari [Tsauban] ia berkata, \"Puteri Hubairah datang menemui Rasulullah shallallahu 'alaihi wasallam sementara di tangannya terdapat cincin dari emas… sebagaimana dalam hadits tersebut.\""},"4805":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ شَاهِينَ الْوَاسِطِيُّ قَالَ أَنْبَأَنَا خَالِدٌ عَنْ مُطَرِّفٍ ح وَأَنْبَأَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا أَسْبَاطٌ عَنْ مُطَرِّفٍ عَنْ أَبِي الْجَهْمِ عَنْ أَبِي زَيْدٍ عَنْ أَبِي هُرَيْرَةَ قَالَكُنْتُ قَاعِدًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَتْهُ امْرَأَةٌ فَقَالَتْ يَا رَسُولَ اللَّهِ سِوَارَيْنِ مِنْ ذَهَبٍ قَالَ سِوَارَانِ مِنْ نَارٍ قَالَتْ يَا رَسُولَ اللَّهِ طَوْقٌ مِنْ ذَهَبٍ قَالَ طَوْقٌ مِنْ نَارٍ قَالَتْ قُرْطَيْنِ مِنْ ذَهَبٍ قَالَ قُرْطَيْنِ مِنْ نَارٍ قَالَ وَكَانَ عَلَيْهِمَا سِوَارَانِ مِنْ ذَهَبٍ فَرَمَتْ بِهِمَا قَالَتْ يَا رَسُولَ اللَّهِ إِنَّ الْمَرْأَةَ إِذَا لَمْ تَتَزَيَّنْ لِزَوْجِهَا صَلِفَتْ عِنْدَهُ قَالَ مَا يَمْنَعُ إِحْدَاكُنَّ أَنْ تَصْنَعَ قُرْطَيْنِ مِنْ فِضَّةٍ ثُمَّ تُصَفِّرَهُ بِزَعْفَرَانٍ أَوْ بِعَبِيرٍاللَّفْظُ لِابْنِ حَرْبٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Hasyin Al Wasithi] ia berkata; telah memberitakan kepada kami [Khalid] dari [Mutharrif]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Ahmad bin Harb] ia berkata; telah menceritakan kepada kami [Asbath] dari [Mutharrif] dari [Abul Jahm] dari [Abu Zaid] dari [Abu Hurairah] ia berkata, \"Aku duduk di sisi Nabi shallallahu 'alaihi wasallam, lalu datanglah seorang wanita kepada beliau seraya berkata, \"Wahai Rasulullah, dua gelang dari emas.\" Beliau bersabda: \"Dua gelang dari api.\" Wanita itu berkata, \"Wahai Rasulullah, kalung dari emas?\" beliau bersabda: \"Kalung dari api.\" Wanita itu berkata, \"Wahai Rasulullah, dua anting dari emas?\" beliau bersabda: \"Dua anting dari api.\" Abu Hurairah berkata, \"Wanita itu mempunyai dua gelang emas, tetapi kemudian ia membuang keduanya. Ia berkata, \"Wahai Rasulullah, seorang wanita jika tidak berhias untuk suaminya maka ia akan jelek di sisinya!\" beliau bersabda: \"Apa yang menghalangi salah seorang dari kalian untuk mengenakan dua anting dari perak, lalu memberinya warna dengan za'faran, atau 'abir (parfum), \" namun dengan lafadz Ibnu Harb.\""},"4806":{"ar":"أَخْبَرَنِي الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ بَكْرٍ قَالَ حَدَّثَنِي أَبِي عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى عَلَيْهَا مَسَكَتَيْ ذَهَبٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُخْبِرُكِ بِمَا هُوَ أَحْسَنُ مِنْ هَذَا لَوْ نَزَعْتِ هَذَا وَجَعَلْتِ مَسَكَتَيْنِ مِنْ وَرِقٍ ثُمَّ صَفَّرْتِهِمَا بِزَعْفَرَانٍ كَانَتَا حَسَنَتَيْنِقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا غَيْرُ مَحْفُوظٍ وَاللَّهُ أَعْلَمُ","id":"Telah mengabarkan kepadaku [Ar Rabi' bin Sulaiman] ia berkata; telah menceritakan kepada kami [Ishaq bin Bukair] ia berkata; telah menceritakan kepadaku [Bapakku] dari [Amru Ibnul Harits] dari [Ibnu Syihab] dari [Urwah] dari ['Aisyah], bahwa Rasulullah shallallahu 'alaihi wasallam pernah melihatnya mengenakan dua gelang emas, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Maukah engkau aku kabari apa yang lebih baik dari hal ini, seandainya engkau lepas ini lalu engkau mengenakan dua gelang dari perak dan engkau olesi dengan za'faran maka itu lebih baik.\" Abu 'Abdurrahman berkata, \"Hadits ini tidak terjaga. Waallahu a'lam.\""},"4807":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي أَفْلَحَ الْهَمْدَانِيِّ عَنْ ابْنِ زُرَيْرٍ أَنَّهُ سَمِعَ عَلِيَّ بْنَ أَبِي طَالِبٍ يَقُولُإِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ حَرِيرًا فَجَعَلَهُ فِي يَمِينِهِ وَأَخَذَ ذَهَبًا فَجَعَلَهُ فِي شِمَالِهِ ثُمَّ قَالَ إِنَّ هَذَيْنِ حَرَامٌ عَلَى ذُكُورِ أُمَّتِي","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Aflah Al Hamdani] dari [Ibnu Zurair] Bahwasanya ia pernah mendengar [Ali bin Abu Thalib] berkata, \"Nabi shallallahu 'alaihi wasallam mengambil sutra kemudian meletakkan di sisi kanannya, dan mengambil emas lalu meletakkannya di kiri kirinya, kemudian bersabda: \"Sesungguhnya kedua benda ini haram untuk kaum laki-laki dari umatku.\""},"4808":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ ابْنِ أَبِي الصَّعْبَةِ عَنْ رَجُلٍ مَنْ هَمْدَانَ يُقَالُ لَهُ أَبُو صَالِحٍ عَنْ ابْنِ زُرَيْرٍ أَنَّهُ سَمِعَ عَلِيَّ بْنَ أَبِي طَالِبٍ يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ حَرِيرًا فَجَعَلَهُ فِي يَمِينِهِ وَأَخَذَ ذَهَبًا فَجَعَلَهُ فِي شِمَالِهِ ثُمَّ قَالَ إِنَّ هَذَيْنِ حَرَامٌ عَلَى ذُكُورِ أُمَّتِي","id":"Telah mengabarkan kepada kami [Isa bin Hammad] ia berkata; telah memberitakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Ibnu Abu Ash Sha'bah] dari seorang laki-laki dari Hamdan yang dipanggil [Abu Shalih] dari [Ibnu Zurair] Bahwasanya ia pernah mendengar [Ali bin Abu Thalib] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengambil sutera dan meletakkannya di sisi kanannya, lalu mengambil emas dan meletakkannya di sisi kirinya, kemudian beliau bersabda: \"Sesungguhnya kedua benda ini haram untuk kaum laki-laki dari umatku.\""},"4809":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ أَبِي الصَّعْبَةِ عَنْ أَبِي أَفْلَحَ الْهَمْدَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ زُرَيْرٍ الْغَافِقِيِّ قَالَ سَمِعْتُ عَلِيًّا يَقُولُأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَهَبًا بِيَمِينِهِ وَحَرِيرًا بِشِمَالِهِ فَقَالَ هَذَا حَرَامٌ عَلَى ذُكُورِ أُمَّتِي","id":"Telah mengabarkan kepada kami [Amru bin Ali] ia berkata; telah menceritakan kepada kami [Yazid bin Harun] ia berkata; telah memberitakan kepada kami [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Abdul Aziz bin Abu Ash Sha'bah] dari [Abu Aflah Al Hamdani] dari [Abdullah bin Zurair Al Ghafiqi] ia berkata, \"Aku mendengar [Ali] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengambil emas dengan tangan kanannya dan mengambil sutera dengan tangan kirinya, lalu beliau bersabda: \"Ini diharamkan untuk umatku yang laki-laki.\""},"4810":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ الْحُسَيْنِ الدِّرْهَمِيُّ قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ سَعِيدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ أَبِي مُوسَىأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُحِلَّ الذَّهَبُ وَالْحَرِيرُ لِإِنَاثِ أُمَّتِي وَحُرِّمَ عَلَى ذُكُورِهَا","id":"Telah mengabarkan kepada kami [Ali Ibnul Husain Ad Dirhami] ia berkata; telah menceritakan kepada kami [Abdul A'la] dari [Sa'id] dari [Ayyub] dari [Nafi'] dari [Sa'id bin Abu Hind] dari [Abu Musa], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Emas dan sutra dihalalkan bagi para wanita dari umatku dan diharamkan bagi para lelakinya.\""},"4811":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ قَزَعَةَ عَنْ سُفْيَانَ بْنِ حَبِيبٍ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ مُعَاوِيَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُبْسِ الْحَرِيرِ وَالذَّهَبِ إِلَّا مُقَطَّعًاخَالَفَهُ عَبْدُ الْوَهَّابِ رَوَاهُ عَنْ خَالِدٍ عَنْ مَيْمُونٍ عَنْ أَبِي قِلَابَةَ","id":"Telah mengabarkan kepada kami [Al Hasan bin Qaza'ah] dari [Sufyan bin Habib] dari [Khalid] dari [Abu Qilabah] dari [Mu'awiyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang mengenakan sutera dan emas kecuali sepotong kecil.\" Abdul Wahhab menyelisihi riwayat ini, ia meriwayatkannya dari Khalid, dari Maimun, dari Abu Qilabah."},"4812":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَبِي شَيْخٍ أَنَّهُ سَمِعَ مُعَاوِيَةَ وَعِنْدَهُ جَمْعٌ مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَأَتَعْلَمُونَ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُبْسِ الذَّهَبِ إِلَّا مُقَطَّعًا قَالُوا اللَّهُمَّ نَعَمْ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] ia berkata; telah menceritakan kepada kami [Ibnu Abu Adi] dari [Sa'id] dari [Qatadah] dari [Abu Syaikh] bahwa ia pernah mendengar [Mu'awiyah] -yang waktu itu ia sedang bersama beberapa sahabat- berkata, \"Tidakkah kalian tahu bahwa Nabi shallallahu 'alaihi wasallam telah melarang memakai emas kecuali sepotong kecil?\" mereka menjawab, \"Tentu.\""},"4813":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ أَنْبَأَنَا أَسْبَاطٌ عَنْ مُغِيرَةَ عَنْ مَطَرٍ عَنْ أَبِي شَيْخٍ قَالَبَيْنَمَا نَحْنُ مَعَ مُعَاوِيَةَ فِي بَعْضِ حَجَّاتِهِ إِذْ جَمَعَ رَهْطًا مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُمْ أَلَسْتُمْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُبْسِ الذَّهَبِ إِلَّا مُقَطَّعًا قَالُوا اللَّهُمَّ نَعَمْخَالَفَهُ يَحْيَى بْنُ أَبِي كَثِيرٍ عَلَى اخْتِلَافٍ بَيْنَ أَصْحَابِهِ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] ia berkata; telah memberitakan kepada kami [Asbath] dari [Mughirah] dari [Mathar] dari [Abu Syaikh] ia berkata, \"Ketika kami sedang bersama [Mu'awiyah] dalam salah satu perjalanan hajinya, ia mengumpulkan sejumlah sahabat Muhammad shallallahu 'alaihi wasallam, ia lalu berkata kepada mereka, \"Bukankah kamu telah mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang memakai emas kecuali potongan kecil?\" mereka menjawab, \"Tentu.\" Yahya bin Abu Katsir menyelisihinya berdasar pada perselisihan yang terjadi antara sahabatnya."},"4814":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا حَرْبُ بْنُ شَدَّادٍ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنِي أَبُو شَيْخٍ عَنْ أَخِيهِ حِمَّانَأَنَّ مُعَاوِيَةَ عَامَ حَجَّ جَمَعَ نَفَرًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْكَعْبَةِ فَقَالَ لَهُمْ أَنْشُدُكُمْ بِاللَّهِ هَلْ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُبُوسِ الذَّهَبِ قَالُوا نَعَمْ قَالَ وَأَنَا أَشْهَ��ُخَالَفَهُ الْأَوْزَاعِيُّ عَلَى اخْتِلَافِ أَصْحَابِهِ عَلَيْهِ فِيهِ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] ia berkata; telah menceritakan kepada kami [Abdu Ash Shamad] ia berkata; telah menceritakan kepada kami [Harb bin Syaddad] ia berkata; telah menceritakan kepada kami [Yahya] ia berkata; telah menceritakan kepadaku [Abu Syaikh] dari saudaranya [Himman] ia berkata, \"Saat tahun haji, [Mu'awiyah] mengumpulkan beberapa sahabat Rasulullah shallallahu 'alaihi wasallam di Ka'bah, ia lalu berkata kepada mereka, \"Aku bersumpah dengan nama Allah atas kalian semua, apakah Rasulullah shallallahu 'alaihi wasallam telah melarang memakai emas?\" mereka menjawab, \"Ya.\" Mu'awiyah lalu berkata, \"Aku juga bersaksi.\" Al Auza'I menyelisihinya atas dasar perselisihan yang terjadi antara dirinya dengan para sahabatnya berkenaan dengan hadits tersebut."},"4815":{"ar":"أَخْبَرَنِي شُعَيْبُ بْنُ شُعَيْبِ بْنِ إِسْحَقَ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا شُعَيْبٌ عَنْ الْأَوْزَاعِيِّ عَنْ حَدِيثِ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو شَيْخٍ قَالَ حَدَّثَنِي حِمَّانُ قَالَحَجَّ مُعَاوِيَةُ فَدَعَا نَفَرًا مِنْ الْأَنْصَارِ فِي الْكَعْبَةِ فَقَالَ أَنْشُدُكُمْ بِاللَّهِ أَلَمْ تَسْمَعُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ الذَّهَبِ قَالُوا نَعَمْ قَالَ وَأَنَا أَشْهَدُ","id":"Telah mengabarkan kepadaku [Syu'aib bin Syu'aib bin Ishaq] ia berkata; telah menceritakan kepada kami [Abdul Wahhab bin Sa'id] ia berkata; telah menceritakan kepada kami [Syu'aib] dari [Al Auza'i] dari hadits [Yahya bin Abu Katsir] ia berkata; telah menceritakan kepadaku [Abu Syaikh] ia berkata; telah menceritakan kepadaku [Himman] ia berkata, \"Selesai [Mu'awiyah] haji ia mengumpulkan beberapa orang Anshar di Ka'bah, ia lalu berkata, \"Aku bersumpah dengan nama Allah atas kalian, tidakkah kalian telah mendengar bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari memaki emas?\" mereka menjawab, \"Ya.\" Ia lalu berkata, \"Aku juga bersaksi.\""},"4816":{"ar":"أَخْبَرَنَا نُصَيْرُ بْنُ الْفَرَحِ قَالَ حَدَّثَنَا عُمَارَةُ بْنُ بِشْرٍ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو إِسْحَقَ قَالَ حَدَّثَنِي حِمَّانُ قَالَحَجَّ مُعَاوِيَةُ فَدَعَا نَفَرًا مِنْ الْأَنْصَارِ فِي الْكَعْبَةِ فَقَالَ أَنْشُدُكُمْ بِاللَّهِ أَلَمْ تَسْمَعُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الذَّهَبِ قَالُوا اللَّهُمَّ نَعَمْ قَالَ وَأَنَا أَشْهَدُ","id":"Telah mengabarkan kepada kami [Nushair Ibnul Farah] ia berkata; telah menceritakan kepada kami [Umarah bin Bisyr] dari [Al Auza'i] dari [Yahya bin Abu Katsir] ia berkata; telah menceritakan kepadaku [Abu Ishaq] ia berkata; telah menceritakan kepadaku [Himman] ia berkata, \"Selesai [Mu'awiyah] haji ia mengumpulkan beberapa orang Anshar di Ka'bah, ia lalu berkata, \"Aku bersumpah dengan nama Allah atas kalian, tidakkah kalian telah mendengar bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari memaki emas?\" mereka menjawab, \"Ya.\" Ia lalu berkata, \"Aku juga bersaksi.\""},"4817":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا حَبَّانُ قَالَ حَدَّثَنَا سَلْمُ بْنُ زُرَيْرٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ طَرَفَةَ عَنْ جَدِّهِ عَرْفَجَةَ بْنِ أَسْعَدَأَنَّهُ أُصِيبَ أَنْفُهُ يَوْمَ الْكُلَابِ فِي الْجَاهِلِيَّةِ فَاتَّخَذَ أَنْفًا مِنْ وَرِقٍ فَأَنْتَنَ عَلَيْهِ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَتَّخِذَ أَنْفًا مِنْ ذَهَبٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] ia berkata; telah menceritakan kepada kami [Habban] ia berkata; telah menceritakan kepada kami [Salm bin Zurair] ia berkata; telah menceritakan kepada kami ['Abdurrahman bin Tharafah] dari kakeknya ['Arfajah bin As'ad], bahwa hidungnya terluka saat terjadi perang Kulab pada masa Jahiliyah. Kemudian ia memakai hidung palsu dari perak, namun hal itu justru menimbulkan bau busuk. Maka Nabi shallallahu 'alaihi wasallam memerintahkan kepadanya untuk memakai hidung dari emas.\""},"4818":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ أَبِي الْأَشْهَبِ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ طَرَفَةَ عَنْ عَرْفَجَةَ بْنِ أَسْعَدَ بْنِ كُرَيْبٍ قَالَوَكَانَ جَدُّهُ قَالَ حَدَّثَنِي أَنَّهُ رَأَى جَدَّهُ أُصِيبَ أَنْفُهُ يَوْمَ الْكُلَابِ فِي الْجَاهِلِيَّةِ قَالَ فَاتَّخَذَ أَنْفًا مِنْ فِضَّةٍ فَأَنْتَنَ عَلَيْهِ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَتَّخِذَهُ مِنْ ذَهَبٍ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dari [Abu Al Asyhab] ia berkata; telah menceritakan kepadaku ['Abdurrahman bin Tharafah] dari ['Arfajah bin As'ad bin Kuraib] ia berkata; kakeknya berkata; telah menceritakan kepadaku, bahwasanya ia melihat hidung kakeknya terluka pada saat perang Kulab pada masa Jahiliyah. 'Arfajah berkata, \"Lalu ia memakai hidung dari perak, tetapi justru menimbulkan bau busuk. Maka Nabi shallallahu 'alaihi wasallam memerintahkan kepadanya untuk memakai hidung dari emas.\""},"4819":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ مُحَمَّدِ بْنِ كَثِيرٍ الْحَرَّانِيُّ قَالَ حَدَّثَنَا سَعِيدُ بْنُ حَفْصٍ قَالَ حَدَّثَنَا مُوسَى بْنُ أَعْيَنَ عَنْ عِيسَى بْنِ يُونُسَ عَنْ الضَّحَّاكِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَطَاءٍ الْخُرَاسَانِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَقَالَ عُمَرُ لِصُهَيْبٍ مَا لِي أَرَى عَلَيْكَ خَاتَمَ الذَّهَبِ قَالَ قَدْ رَآهُ مَنْ هُوَ خَيْرٌ مِنْكَ فَلَمْ يَعِبْهُ قَالَ مَنْ هُوَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin Muhammad bin Katsir Al Harrani] ia berkata; telah menceritakan kepada kami [Sa'id bin Hafsh] ia berkata; telah menceritakan kepada kami [Musa bin A'yun] dari [Isa bin Yunus] dari [Adl Dlahhak bin 'Abdurrahman] dari ['Atha Al Khurasani] dari [Sa'id Ibnul Musayyab] ia berkata, \"Umar berkata kepada [Shuhaib], \"Kenapa aku melihatmu memakai cincin emas?\" Shuhaib menjawab, \"Orang yang lebih baik darimu telah melihatnya, dan ia tidak mencelanya.\" Umar berkata, \"Siapa itu?\" Shuhaib menjawab, \"Rasulullah shallallahu 'alaihi wasallam.\""},"4820":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ هُبَيْرَةَ بْنِ يَرِيمَ قَالَ قَالَ عَلِيٌّنَهَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ خَاتَمِ الذَّهَبِ وَعَنْ الْقَسِّيِّ وَعَنْ الْمَيَاثِرِ الْحُمْرِ وَعَنْ الْجِعَةِ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Ahwash] dari [Abu Ishaq] dari [Hubairah bin Yarim] ia berkata, \" [Ali] berkata, \"Nabi shallallahu 'alaihi wasallam melarangku memakai cincin emas, Al Qasi (pakaian yang bersulam sutera), alas pelana yang terbuat dari sutera, dan Al Ji'ah (minuman dari perasan gandum).\""},"4821":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ آدَمَ عَنْ عَبْدِ الرَّحِيمِ عَنْ زَكَرِيَّا عَنْ أَبِي إِسْحَقَ عَنْ هُبَيْرَةَ عَنْ عَلِيٍّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ خَاتَمِ الذَّهَبِ وَعَنْ الْقَسِّيِّ وَعَنْ الْمَيَاثِرِ الْحُمْرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari ['Abdurrahim] dari [Zakariya] dari [Abu Ishaq] dari [Hubairah] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang untuk memakai cincin emas, Al Qasi (pakaian yang bersulam sutera), alas pelana yang terbuat dari sutera, dan Al Ji'ah (minuman dari perasan gandum).\""},"4822":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا عَمَّارُ بْنُ رُزَيْقٍ عَنْ أَبِي إِسْحَقَ عَنْ صَعْصَعَةَ بْنِ صُوحَانَ عَنْ عَلِيٍّ قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ حَلْقَةِ الذَّهَبِ وَالْقَسِّيِّ وَالْمِيثَرَةِ وَالْجِعَةِقَالَ أَبُو عَبْد الرَّحْمَنِ الَّذِي قَبْلَهُ أَشْبَهُ بِالصَّوَابِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Al Mubaral] ia berkata; telah menceritakan kepada kami [Yahya bin Adam] ia berkata; telah menceritakan kepada kami [Ammar bin Ruzaiq] dari [Abu Ishaq] dari [Sha'sha'ah bin Shuhan] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku memakai gelang emas, kain yang bersulam sutera, kain pelapis pelana yang terbuat dari sutera dan minuman yang terbuat dari perasan gandum.\" 'Abdurrahman berkata, \"Hadits sebelumnya lebih mendekati kebenaran.\""},"4823":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ أَنْبَأَنَا إِسْرَائِيلُ عَنْ إِسْمَعِيلَ بْنِ سُمَيْعٍ عَنْ مَالِكِ بْنِ عُمَيْرٍ عَنْ صَعْصَعَةَ بْنِ صُوحَانَ قَالَقُلْتُ لِعَلِيٍّ انْهَنَا عَمَّا نَهَاكَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَهَانِي عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَحَلْقَةِ الذَّهَبِ وَلُبْسِ الْحَرِيرِ وَالْقَسِّيِّ وَالْمِيثَرَةِ الْحَمْرَاءِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Ubaidullah bin Musa] ia berkata; telah memberitakan kepada kami [Israil] dari [Isma'il bin Sumai'] dari [Malik bin Umair] dari [Sha'sha'ah bin Shuhan] ia berkata, \"Aku berkata kepada Ali, \"Laranglah kami dengan (sesuatu) yang Rasulullah shallallahu 'alaihi wasallam pernah melarangmu untuk melakukannya!\" [Ali] berkata, \"Beliau melarang aku dari Ad Duba, Al Hantam, gelang emas, mengenakan sutera, kain yang bersulam sutera, dan kain pelapis pelana yang terbuat dari sutera.\" "},"4824":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ دُحَيْمٌ قَالَ حَدَّثَنَا مَرْوَانُ هُوَ ابْنُ مُعَاوِيَةَ قَالَ حَدَّثَنَا إِسْمَعِيلُ هُوَ ابْنُ سُمَيْعٍ الْحَنَفِيُّ عَنْ مَالِكِ بْنِ عُمَيْرٍ قَالَ جَاءَ صَعْصَعَةُ بْنُ صُوحَانَ إِلَى عَلِيٍّ فَقَالَانْهَنَا عَمَّا نَهَاكَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالنَّقِيرِ وَالْجِعَةِ وَنَهَانَا عَنْ حَلْقَةِ الذَّهَبِ وَلُبْسِ الْحَرِيرِ وَلُبْسِ الْقَسِّيِّ وَالْمِيثَرَةِ الْحَمْرَاءِ","id":"Telah mengabarkan kepada kami ['Abdurrahman bin Ibrahim Duhaim] ia berkata; telah menceritakan kepada kami [Marwan] -yaitu Ibnu Mu'awiyah- ia berkata; telah menceritakan kepada kami [Isma'il] -yaitu Ibnu Sumai' Al Hanafi- dari [Malik bin Umair] ia berkata, \" [Sha'sha'ah] datang menemui Ali dan berkata, \"Laranglah kami dengan (sesuatu) yang Rasulullah shallallahu 'alaihi wasallam pernah melarangmu untuk melakukannya!\" [Ali] berkata, \"Beliau melarang aku dari Ad Duba, Al Hantam, An Naqir, minuman yang terbuat dari perasan gandum, gelang emas, memakai sutera, dan pelapis pelana yang terbuat dari sutera.\" "},"4825":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا أَبُو عَلِيٍّ الْحَنَفِيُّ وَعُثْمَانُ بْنُ عُمَرَ قَالَ أَبُو عَلِيٍّ حَدَّثَنَا وَقَال عُثْمَانُ أَنْبَأَنَا دَاوُدُ بْنُ قَيْسٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ عَنْ عَلِيٍّ قَالَنَهَانِي حِبِّي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَلَاثٍ لَا أَقُولُ نَهَى النَّاسَ نَهَانِي عَنْ تَخَتُّمِ الذَّهَبِ وَعَنْ لُبْسِ الْقَسِّيِّ وَعَنْ الْمُعَصْفَرِ الْمُفَدَّمَةِ وَلَا أَقْرَأُ سَاجِدًا وَلَا رَاكِعًاتَابَعَهُ الضَّحَّاكُ بْنُ عُثْمَانَ","id":"Telah mengabarkan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Abu Ali Al Hanafi] dan [Utsman bin Umar]. Abu Ali berkata, telah menceritakan kepada kami. Utsman berkata, telah memberitakan kepada kami [Dawud bin Qais] dari [Ibrahim bin Abdullah bin Hunain] dari [Bapaknya] dari [Ibnu Abbas] dari [Ali] ia berkata, \"Kekasihku, Rasulullah shallallahu 'alaihi wasallam melarangku dari tiga hal -aku tidak mengatakan kalau beliau melarang manusia-, beliau melarangku dari memakai cincin emas, memakai pakaian yang bersulam sutera, melumuri pakaian dengan wewangian yang berwarna dan menyengat, dan agar aku tidak membaca? Al Qur'an saat sujud dan rukuk.\" Dan Adl Dlahhak bin Utsman menguatkannya."},"4826":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ دَاوُدَ الْمُنْكَدِرِيُّ قَالَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ الضَّحَّاكِ عَنْ إِبْرَاهِيمَ بْنِ حُنَيْنٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ عَلِيٍّ قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا أَقُولُ نَهَاكُمْ عَنْ تَخَتُّمِ الذَّهَبِ وَعَنْ لُبْسِ الْقَسِّيِّ وَعَنْ لُبْسِ الْمُفَدَّمِ وَالْمُعَصْفَرِ وَعَنْ الْقِرَاءَةِ رَاكِعًا","id":"Telah mengabarkan kepada kami [Al Hasan bin Dawud Al Munkadir] ia berkata; telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Adl Dlahhak] dari [Ibrahim bin Hunain] dari [Bapaknya] dari [Abdullah bin Abbas] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku -dan aku tidak mengatakan beliau melarang kalian- dari memakai cincin emas, memakai pakaian yang bersulam sutera, melumuri pakaian dengan wewangian yang menyengat dan berwarna kuning, serta membaca Al-Qur'an saat rukuk.\""},"4827":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ قَزَعَةَ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ عَلِيًّا يَقُولُنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا أَقُولُ نَهَاكُمْ عَنْ خَاتَمِ الذَّهَبِ وَعَنْ الْقَسِّيِّ وَالْمُعَصْفَرِ وَأَنْ لَا أَقْرَأَ وَأَنَا رَاكِعٌ","id":"Telah mengabarkan kepada kami [Al Hasan bin Qaza'ah] ia berkata; telah menceritakan kepada kami [Khalid Ibnul Harits] ia berkata; telah menceritakan kepada kami [Muhammad bin Amru] dari [Ibrahim bin Abdullah bin Hunain] dari [Bapaknya] ia berkata; Aku mendengar [Ali] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku -dan aku tidak mengatakan beliau melarang kalian- dari cincin emas, kain yang bersulam sutera, kain yang diselup dengan warna kuning dan agar aku tidak membaca Al-Qur'an saat rukuk.\""},"4828":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ مُحَمَّدِ بْنِ بَكَّارِ بْنِ بِلَالٍ عَنْ مُحَمَّدِ بْنِ عِيسَى وَهُوَ ابْنُ الْقَاسِمِ بْنِ سُمَيْعٍ قَالَ حَدَّثَنَا زَيْدُ بْنُ وَاقِدٍ عَنْ نَافِعٍ عَنْ إِبْرَاهِيمَ مَوْلَى عَلِيٍّ عَنْ عَلِيٍّ قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ تَخَتُّمِ الذَّهَبِ وَعَنْ الْمُعَصْفَرِ وَعَنْ لُبْسِ الْقَسِّيِّ وَعَنْ الْقِرَاءَةِ فِي الرُّكُوعِ","id":"Telah mengabarkan kepadaku [Harun bin Muhammad bin Bakkar bin Bilal] dari [Muhammad bin Isa] -yaitu Ibnu Al Qasim bin Sumai'- ia berkata; telah menceritakan kepada kami [Zaid bin Waqid] dari [Nafi'] dari [Ibrahim] mantan budak Ali, dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku dari memakai cincin emas, kain yang dicelup dengan warna kuning, kain yang bersulam sutera dan dari membaca Al-Qur'an saat rukuk.\""},"4829":{"ar":"أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْحَجَّاجِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ حُنَيْنٍ مَوْلَى ابْنِ عَبَّاسٍ أَنَّ عَلِيًّا قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُبْسِ الْقَسِّيِّ وَالْمُعَصْفَرِ وَعَنْ التَّخَتُّمِ بِالذَّهَبِ","id":"Telah mengabarkan kepadaku [Abu Bakr bin Ali] ia berkata; telah menceritakan kepada kami [Ibrahim Ibnul Hajjaj] ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Hunain] mantan budak Ibnu Abbas, bahwa [Ali] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku dari memakai kain yang bersulam sutera, kain yang dicelup dengan warna kuning dan memakai cincin emas.\""},"4830":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ عَنْ أَشْعَثَ عَنْ مُحَمَّدٍ عَنْ عَبِيدَةَ عَنْ عَلِيٍّ قَالَنَهَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْقَسِّيِّ وَالْحَرِيرِ وَخَاتَمِ الذَّهَبِ وَأَنْ أَقْرَأَ رَاكِعًاخَالَفَهُ هِشَامٌ وَلَمْ يَرْفَعْهُ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] ia berkata; telah menceritakan kepada kami [Hammad bin Mas'adah] dari [Asy'ats] dari [Muhammad] dari [Abidah] dari [Ali] ia berkata, \"Nabi shallallahu 'alaihi wasallam melarang dari memakai kain yang bersulam sutera, memakai sutera, memakai cincin emas, dan membaca? Al-Qur'an saat rukuk.\" Namun ia tidak memarfu'kan hadits ini."},"4831":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَنْبَأَنَا هِشَامٌ عَنْ مُحَمَّدٍ عَنْ عَبِيدَةَ عَنْ عَلِيٍّ قَالَنَهَى عَنْ مَيَاثِرِ الْأُرْجُوَانِ وَلُبْسِ الْقَسِّيِّ وَخَاتَمِ الذَّهَبِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Yazid] ia berkata; telah memberitakan kepada kami [Hisyam] dari [Muhammad] dari [Abidah] dari [Ali] ia berkata, \"Beliau melarang dari pelapis pelana yang terbuat dari sutera, memakai kain yang bersulam sutera dan memakai cincin emas.\""},"4832":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ أَخْبَرَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ عَبِيدَةَ قَالَنَهَى عَنْ مَيَاثِرِ الْأُرْجُوَانِ وَخَوَاتِيمِ الذَّهَبِ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Muhammad] dari [Abidah] ia berkata, \"Beliau melarang dari pelapis pelana yang terbuat dari sutera, memakai kain yang bersulam sutera dan memakai cincin emas.\""},"4833":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصٍ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا إِبْرَاهِيمُ عَنْ الْحَجَّاجِ هُوَ ابْنُ الْحَجَّاجِ عَنْ قَتَادَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُبَيْدٍ عَنْ بُشَيْرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ تَخَتُّمِ الذَّهَبِ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh] ia berkata; telah menceritakan kepada kami [Bapakku] ia berkata; telah menceritakan kepada kami [Ibrahim] dari [Al Hajjaj] -yaitu Ibnul Hajjaj- dari [Qatadah] dari [Abdul Ubaid] dari [Busyair bin Nahik] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku dari memakai cincin emas.\""},"4834":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ حَمَّادٍ الْمَعْنِيُّ الْبَصْرِيُّ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَبِي التَّيَّاحِ قَالَ حَدَّثَنَا حَفْصٌ اللَّيْثِيُّ قَالَ أَشْهَدُ عَلَى عِمْرَانَ أَنَّهُ حَدَّثَنَا قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُبْسِ الْحَرِيرِ وَعَنْ التَّخَتُّمِ بِالذَّهَبِ وَعَنْ الشُّرْبِ فِي الْحَنَاتِمِ","id":"Telah mengabarkan kepada kami [Yunus bin Hammad Al Ma'ni Al Bashri] ia berkata; telah menceritakan kepada kami [Abdul Warits] dari [Abu At Tayyah] ia berkata; telah menceritakan kepada kami [Hafsh Al Laitsi] ia berkata; Aku bersaksi atas [Imran] bahwa ia menceritakan kepada kami, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari memakai kain sutera, memakai cincin emas dan minum dengan menggunakan Al Hantam.\" "},"4835":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ بَكْرِ بْنِ سَوَادَةَ أَنَّ أَبَا النَّجِيبِ حَدَّثَهُ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ حَدَّثَهُأَنَّ رَجُلًا قَدِمَ مِنْ نَجْرَانَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ خَاتَمٌ مِنْ ذَهَبٍ فَأَعْرَضَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِنَّكَ جِئْتَنِي وَفِي يَدِكَ جَمْرَةٌ مِنْ نَارٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Amru bin As Sarh] ia berkata; telah memberitakan kepada kami [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Amru bin Al Harits] dari [Bakr bin Sawadah] bahwa [Abu An Najib] menceritakan kepadanya, bahwa [Abu Sa'id Al Khudri] menceritakan kepadanya, bahwa seorang laki-laki dari Najran datang menemui Rasulullah shallallahu 'alaihi wasallam, sementara ia mengenakan cincin dari emas. Rasulullah shallallahu 'alaihi wasallam kemudian berpaling darinya seraya bersabda: \"Engkau datang kepadaku sementara di tanganmu ada bara dari neraka.\""},"4836":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ مَنْصُورٍ عَنْ سَالِمٍ عَنْ رَجُلٍ حَدَّثَهُ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ رَجُلًا كَانَ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ خَاتَمٌ مِنْ ذَهَبٍ وَفِي يَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِخْصَرَةٌ أَوْ جَرِيدَةٌ فَضَرَبَ بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِصْبَعَهُ فَقَالَ الرَّجُلُ مَا لِي يَا رَسُولَ اللَّهِ قَالَ أَلَا تَطْرَحُ هَذَا الَّذِي فِي إِصْبَعِكَ فَأَخَذَهُ الرَّجُلُ فَرَمَى بِهِ فَرَآهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ فَقَالَ مَا فَعَلَ الْخَاتَمُ قَالَ رَمَيْتُ بِهِ قَالَ مَا بِهَذَا أَمَرْتُكَ إِنَّمَا أَمَرْتُكَ أَنْ تَبِيعَهُ فَتَسْتَعِينَ بِثَمَنِهِوَهَذَا حَدِيثٌ مُنْكَرٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Ubaidullah] ia berkata; telah menceritakan kepada kami [Israil] dari [Manshur] dari [Salim] dari [seorang laki-laki] dari [Al Bara bin Azib] ia berkata, \"Seorang laki-laki yang memakai cincin emas duduk di sisi Nabi shallallahu 'alaihi wasallam, sementara di tangan Rasulullah shallallahu 'alaihi wasallam terdapat tongkat kecil, atau pelepah kurma. Nabi shallallahu 'alaihi wasallam kemudian memukul jari lelaki itu dengan tongkatnya, laki-laki itu pun berkata, \"Ada apa denganku ya Rasulullah!\" beliau menjawab: \"Kenapa kamu tidak membuang sesuatu yang ada di jarimu ini?\" laki-laki itu lantas membuang cincinnya. Setelah kejadian itu Nabi shallallahu 'alaihi wasallam kembali melihat laki-laki tersebut, beliau pun bertanya: \"Apa yang dilakukan oleh cincin itu?\" laki-laki itu menjawab, \"Aku telah membuangnya.\" Beliau bersabda: \"Aku tidak menyuruhmu seperti itu, tapi aku ingin agar kamu menjualnya hingga engkau dapat memanfaatkan hasil penjualannya.\" Ini adalah hadits munkar."},"4837":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ النُّعْمَانِ بْنِ رَاشِدٍ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْصَرَ فِي يَدِهِ خَاتَمًا مِنْ ذَهَبٍ فَجَعَلَ يَقْرَعُهُ بِقَضِيبٍ مَعَهُ فَلَمَّا غَفَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلْقَاهُ قَالَ مَا أُرَانَا إِلَّا قَدْ أَوْجَعْنَاكَ وَأَغْرَمْنَاكَخَالَفَهُ يُونُسُ رَوَاهُ عَنْ الزُّهْرِيِّ عَنْ أَبِي إِدْرِيسَ مُرْسَلًا أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو إِدْرِيسَ الْخَوْلَانِيُّأَنَّ رَجُلًا مِمَّنْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَبِسَ خَاتِمًا مِنْ ذَهَبٍ نَحْوَهُ قَالَ أَبُو عَبْد الرَّحْمَنِ وَحَدِيثُ يُونُسَ أَوْلَى بِالصَّوَابِ مِنْ حَدِيثِ النُّعْمَانِ أَخْبَرَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ بْنِ مُحَمَّدٍ الْقُرَشِيُّ الدِّمَشْقِيُّ أَبُو عَبْدِ الْمَلِكِ قِرَاءَةً قَالَ حَدَّثَنَا ابْنُ عَائِذٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى عَلَى رَجُلٍ خَاتَمًا مِنْ ذَهَبٍ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Amru bin Manshur] ia berkata; telah menceritakan kepada kami [Affan] ia berkata; telah menceritakan kepada kami [Wuhaib] dari [An Nu'man bin Rasyid] dari [Az Zuhri] dari ['Atha bin Yazid] dari [Abu Tsa'labah Al Khusyani], bahwa Nabi shallallahu 'alaihi wasallam melihat cincin emas yang ada di tangannya, beliau lalu memukulnya dengan tongkat yang beliau bawa. Namun saat beliau lengah, ia pun membuang cincinnya. Beliau bersabda: \"Tidaklah cincin itu engkau perlihatkan kepada kami, kecuali kami akan membuatmu sakit, atau akan memaksamu untuk membuangnya.\" Riwayat ini diselisihi oleh Yunus, ia meriwayatkan dari Az Zhuri, dari Abu Idris secara mursal.\" Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh] ia berkata; telah menceritakan kepada kami [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] ia berkata; telah mengabarkan kepadaku [Abu Idris Al Khaulani] berkata, \"Seorang laki-laki -ia termasuk orang yang pernah berjumpa dengan Nabi shallallahu 'alaihi wasallam- memakai cincin emas sebagaimana dalam hadits tersebut.\" 'Abdurrahman berkata, \"Hadits Yunus ini lebih benar dari pada hadits An Nu'man.\" Telah mengabarkan kepada kami [Ahmad bin Ibrahim bin Muhammad Al Qurasyi Ad Dimasyqi Abu Abdul Malik] secara qira'ah. Ia berkata, \"Telah menceritakan kepada kami [Ibnu 'Aidz] ia berkata; telah menceritakan kepada kami [Yahya bin Hamzah] dari [Al Auza'i] dari [Az Zuhri] dari [Abu Idris Al Khaulani] bahwa Rasulullah shallallahu 'alaihi wasallam pernah melihat seorang laki-laki mengenakan cincin…sebagaimana dalam hadits tersebut.\""},"4838":{"ar":"أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ الْعُمَرِيُّ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي إِدْرِيسَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى فِي يَدِ رَجُلٍ خَاتَمَ ذَهَبٍ فَضَرَبَ إِصْبَعَهُ بِقَضِيبٍ كَانَ مَعَهُ حَتَّى رَمَى بِهِأَخْبَرَنِي أَبُو بَكْرٍ أَحْمَدُ بْنُ عَلِيٍّ الْمَرْوَزِيُّ قَالَ حَدَّثَنَا الْوَرْكَانِيُّ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلٌ قَالَ أَبُو عَبْد الرَّحْمَنِ وَالْمَرَاسِيلُ أَشْبَهُ بِالصَّوَابِ وَاللَّهُ سُبْحَانَهُ وَتَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepadaku [Abu Bakr bin Ali] ia berkata; telah menceritakan kepada kami [Abdul Aziz Al Umari] ia berkata; telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Abu Idris], bahwa Nabi shallallahu 'alaihi wasallam sebuah cincin melingkar pada jari seorang laki-laki hingga beliau memukul tangannya. Laki-laki itu pun membuang cincinnya.\" Telah mengabarkan kepadaku [Abu Bakr Ahmad bin Ali Al Marwazi] ia berkata; telah menceritakan kepada kami [Al Warkani] ia berkata; telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab], bahwa Rasulullah shallallahu 'alaihi wasallam…secara mursal.\" 'Abdurrahman berkata, \"Hadits-hadits mursal lebih mendekati kebenaran. Waallahu a'lam.\""},"4839":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُسْلِمٍ مِنْ أَهْلِ مَرْوَ أَبُو طَيْبَةَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ رَجُلًا جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ خَاتَمٌ مِنْ حَدِيدٍ فَقَالَ مَا لِي أَرَى عَلَيْكَ حِلْيَةَ أَهْلِ النَّارِ فَطَرَحَهُ ثُمَّ جَاءَهُ وَعَلَيْهِ خَاتَمٌ مِنْ شَبَهٍ فَقَالَ مَا لِي أَجِدُ مِنْكَ رِيحَ الْأَصْنَامِ فَطَرَحَهُ قَالَ يَا رَسُولَ اللَّهِ مِنْ أَيِّ شَيْءٍ أَتَّخِذُهُ قَالَ مِنْ وَرِقٍ وَلَا تُتِمَّهُ مِثْقَالًا","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Zaid Ibnul Hubab] ia berkata; telah menceritakan kepadaku [Abdullah bin Muslim] seorang dari keluarga Marwa Abu Thaibah, ia berkata; telah menceritakan kepada kami [Abdullah bin Buraidah] dari [Bapaknya] berkata, \"Seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam, sementara pada jarinya terdapat cincin dari besi. Beliau bersabda: \"Kenapa aku melihat perhiasan ahli neraka pada tanganmu?\" laki-laki itu pun membuang cincinnya, setelah itu ia datang kembali dan di tangannya terdapat cincin dari tembaga, beliau lalu bersabda: \"Kenapa aku mendapati bau berhala darimu?\" laki-laki itu lalu membuang cincinnya seraya berkata, \"Wahai Rasulullah, lalu aku harus memakai cincin dari apa?\" Beliau menjawab: \"Perak, dan jangan engkau genapkan (nilai cincin itu) menjadi satu mitsqal.\""},"4840":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ حَدَّثَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ خَاتَمًا مِنْ وَرِقٍ فَصُّهُ حَبَشِيٌّ وَنُقِشَ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِ","id":"Telah mengabarkan kepada kami [Al Abbas bin Abdul Azhim Al 'Anbari] ia berkata; telah menceritakan kepada kami [Utsman bin Umar] ia berkata; telah menceritakan kepada kami [Yunus] dari [Az Zuhri] dari [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam memakai cincin dari perak, mata cincinnya dari Habsyah dan diukir padanya 'Muhammad Rasulullah'.\""},"4841":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبَّادُ بْنُ مُوسَى قَالَ حَدَّثَنَا طَلْحَةُ بْنُ يَحْيَى قَالَ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمُ فِضَّةٍ يَتَخَتَّمُ بِهِ فِي يَمِينِهِ فَصُّهُ حَبَشِيٌّ يَجْعَلُ فَصَّهُ مِمَّا يَلِي كَفَّهُ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Ali] ia berkata; telah menceritakan kepada kami [Abbad bin Musa] ia berkata; telah menceritakan kepada kami [Thalhah bin Musa] ia berkata; telah mengabarkan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memiliki cincin perak yang dipakai pada tangan sebelah kanan, dan mata cincinnya dari Habasyah. Beliau menjadikan mata cincinnya (menghadap) pada telapak bagian dalam.\""},"4842":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ خَالِدِ بْنِ خَلِيٍّ الْحِمْصِيُّ وَكَانَ أَبُوهُ خَالِدٌ عَلَى قَضَاءِ حِمْصَ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا سَلَمَةُ وَهُوَ ابْنُ عَبْدِ الْمَلِكِ الْعَوْصِيُّ عَنْ الْحَسَنِ وَهُوَ ابْنُ صَالِحِ بْنِ حَيٍّ عَنْ عَاصِمٍ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ خَاتَمُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فِضَّةٍ وَكَانَ فَصُّهُ مِنْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Khalid bin Khali Al Himshi] -bapaknya, Khalid, adalah seorang hakim di Hish- ia berkata; telah menceritakan kepada kami [Bapakku] ia berkata; telah menceritakan kepada kami [Salamah] -dia adalah anak Abdul Malik Al 'Aushi- dari [Ibnu Shalih bin Hay] dari [Ashim] dari [Humaid Ath Thawil] dari [Anas bin Malik] ia berkata, \"Cincin Rasulullah shallallahu 'alaihi wasallam adalah perak, dan mata cincinnya juga terbuat darinya.\""},"4843":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أُمَيَّةُ بْنُ بِسْطَامَ قَالَ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ حُمَيْدًا عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ خَاتَمُهُ مِنْ وَرِقٍ فَصُّهُ مِنْهُ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Ali] ia berkata; telah menceritakan kepada kami [Umayyah bin Bistham] ia berkata; telah menceritakan kepada kami [Mu'tamir] ia berkata; Aku mendengar [Humaid] dari [Anas] berkata, \"Cincin Nabi shallallahu 'alaihi wasallam terbuat dari perak, dan mata cincinnya juga terbuat darinya.\""},"4844":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا مُوسَى بْنُ دَاوُدَ قَالَ حَدَّثَنَا زُهَيْرُ بْنُ مُعَاوِيَةَ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَكَانَ خَاتَمُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فِضَّةٍ فَصُّهُ مِنْهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Musa bin Dawud] ia berkata; telah menceritakan kepada kami [Zuhair bin Mu'awiyah] dari [Humaid] dari [Anas] ia berkata, \"Cincin Nabi shallallahu 'alaihi wasallam terbuat dari perak, dan mata cincinnya juga terbuat darinya.\""},"4845":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ بِشْرٍ وَهُوَ ابْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَأَرَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَكْتُبَ إِلَى الرُّومِ فَقَالُوا إِنَّهُمْ لَا يَقْرَءُونَ كِتَابًا إِلَّا مَخْتُومًا فَاتَّخَذَ خَاتَمًا مِنْ فِضَّةٍ كَأَنِّي أَنْظُرُ إِلَى بَيَاضِهِ فِي يَدِهِ وَنُقِشَ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Bisyr] -dia adalah Ibnul Mufadldlal- ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bermaksud menulis surat untuk Kaisar Romawi, para sahabat lalu berkata, \"Mereka tidak mau membaca surat kecuali ada stempel di dalamnya.\" Beliau kemudian mengambil cincin dari perak, dan seakan aku melihat putihnya cincin tersebut melingkar di tangan beliau, pada cincin tersebut bertuliskan 'Muhammad Rasulullah'.\""},"4846":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ أَبُو الْجَوْزَاءِ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَأَخَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْعِشَاءِ الْآخِرَةِ حَتَّى مَضَى شَطْرُ اللَّيْلِ ثُمَّ خَرَجَ فَصَلَّى بِنَا كَأَنِّي أَنْظُرُ إِلَى بَيَاضِ خَاتَمِهِ فِي يَدِهِ مِنْ فِضَّةٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Utsman Abu Al Jauza] ia berkata; telah menceritakan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Qurrah bin Khalid] dari [Qatadah] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengakhirkan shalat isya yang akhir hingga berlalu tengah malam. Kemudian beliau keluar dan shalat bersama kami, dan seakan aku melihat putihnya cincin perak yang melingkar di tangan beliau.\""},"4847":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ سُلَيْمَانَ هُوَ ابْنُ بِلَالٍ عَنْ شَرِيكٍ هُوَ ابْنُ أَبِي نَمِرٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِ عَنْ عَلِيٍّ قَالَ شَرِيكٌ وَأَخْبَرَنِي أَبُو سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَلْبَسُ خَاتَمَهُ فِي يَمِينِهِ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] ia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari [Sulaiman] -ia adalah Ibnu Bilal- dari [Syarik] -ia adalah Ibnu Abu Namir- dari [Ibrahim bin Abdullah bin Hunain] dari [Bapaknya] dari [Ali]. [Syarik] berkata; telah mengabarkan kepadaku [Abu Salamah] ia berkata, \"Nabi shallallahu 'alaihi wasallam memakai cincinnya di tangan sebelah kanan.\""},"4848":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ الْبَحْرَانِيُّ قَالَ حَدَّثَنَا حَبَّانُ بْنُ هِلَالٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ابْنِ أَبِي رَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَخَتَّمُ بِيَمِينِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar Al Bahrani] ia berkata; telah menceritakan kepada kami [Habban bin Bilal] ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Ibnu Abu Rafi'] dari [Abdullah bin Ja'far] berkata, \"Nabi shallallahu 'alaihi wasallam memakai cincin di tangan kanannya.\""},"4849":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ عَنْ أَبِي عَتَّابٍ سَهْلِ بْنِ حَمَّادٍ ح وَأَنْبَأَنَا أَبُو دَاوُدَ حَدَّثَنَا أَبُو عَتَّابٍ سَهْلِ بْنِ حَمَّادٍ قَالَ حَدَّثَنَا أَبُو مَكِينٍ قَالَ حَدَّثَنَا إِيَاسُ بْنُ الْحَارِثِ بْنِ الْمُعَيْقِيبِ عَنْ جَدِّهِ مُعَيْقِيبٍ أَنَّهُ قَالَكَانَ خَاتَمُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيدًا مَلْوِيًّا عَلَيْهِ فِضَّةٌ قَالَ وَرُبَّمَا كَانَ فِي يَدِي فَكَانَ مُعَيْقِيبٌ عَلَى خَاتَمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Amru bin Ali] dari [Abu Attab Sahl bin Hammad]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Abu Dawud] dari [Abu Attab Sahl bin Hammad] ia berkata; telah menceritakan kepada kami [Abu Makin] ia berkata; telah menceritakan kepada kami [Iyas Ibnul Harits bin Al Mu'aiqib] dari kakeknya [Mu'aiqib] bahwa ia berkata, \"Cincin Nabi shallallahu 'alaihi wasallam terbuat dari besi yang dilapisi perak.\" Perawi berkata, \"Mu'aiqib juga mengenakan seperti cincin Rasulullah shallallahu 'alaihi wasallam.\""},"4850":{"ar":"أَخْبَرَنِي عَلِيُّ بْنُ مُحَمَّدِ بْنِ عَلِيٍّ الْمَصِّيصِيُّ قَالَ حَدَّثَنَا دَاوُدُ بْنُ مَنْصُورٍ مِنْ أَهْلِ ثَغْرٍ ثِقَةٌ قَالَ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ بَكْرِ بْنِ سَوَادَةَ عَنْ أَبِي النَّجِيبِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَأَقْبَلَ رَجُلٌ مِنْ الْبَحْرَيْنِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ فَلَمْ يُرَدَّ عَلَيْهِ وَكَانَ فِي يَدِهِ خَاتَمٌ مِنْ ذَهَبٍ وَجُبَّةُ حَرِيرٍ فَأَلْقَاهُمَا ثُمَّ سَلَّمَ فَرَدَّ عَلَيْهِ السَّلَامَ ثُمَّ قَالَ يَا رَسُولَ اللَّهِ أَتَيْتُكَ آنِفًا فَأَعْرَضْتَ عَنِّي فَقَالَ إِنَّهُ كَانَ فِي يَدِكَ جَمْرَةٌ مِنْ نَارٍ قَالَ لَقَدْ جِئْتُ إِذًا بِجَمْرٍ كَثِيرٍ قَالَ إِنَّ مَا جِئْتَ بِهِ لَيْسَ بِأَجْزَأَ عَنَّا مِنْ حِجَارَةِ الْحَرَّةِ وَلَكِنَّهُ مَتَاعُ الْحَيَاةِ الدُّنْيَا قَالَ فَمَاذَا أَتَخَتَّمُ قَالَ حَلْقَةً مِنْ حَدِيدٍ أَوْ وَرِقٍ أَوْ صُفْرٍ","id":"Telah mengabarkan kepadaku [Ali bin Muhammad bin Ali Al Mashishi] ia berkata; telah menceritakan kepada kami [Dawud bin Manshur] seorang dari penduduk Tsaghr dan tsiqah, dari [Laits bin Sa'id] dari [Amru Ibnul Harits] dari [Bakr bin Sawadah] dari [Abu An Najib] dari [Abu Sa'id Al Khudri] ia berkata, \"Seorang laki-laki dari Bahrain menemui Nabi shallallahu 'alaihi wasallam, ia mengucapkan salam namun beliau tidak membalasnya. Laki-laki itu memakai cincin emas dan jubah dari sutera, ia kemudian membuang keduanya dan mengucapkan salam lagi seraya berkata, \"Wahai Rasulullah, tadi aku memandang ke arahmu namun engkau berpaling?! Beliau bersabda: \"Karena di tanganmu ada bara dari api neraka.\" Laki-laki itu berkata, \"Kalau begitu aku datang dengan membawa bara yang banyak!\" Beliau bersabda: \"Apa yang engkau bawa itu tidaklah lebih hina bagi kami dari bebatuan di Harrah, itu hanyalah perhiasan dunia.\" Laki-laki itu berkata, \"Lalu dengan apa aku harus memakai cincin?\" Beliau menjawab: \"Dari besi, atau perak, atau tembaga.\""},"4851":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ قَالَ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ قَالَ حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ اتَّخَذَ حَلْقَةً مِنْ فِضَّةٍ فَقَالَ مَنْ أَرَادَ أَنْ يَصُوغَ عَلَيْهِ فَلْيَفْعَلْ وَلَا تَنْقُشُوا عَلَى نَقْشِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] ia berkata; telah menceritakan kepada kami [Muhammad bin Abdullah Al Anshari] ia berkata; telah menceritakan kepada kami [Hisyam bin Hassan] ia berkata; telah menceritakan kepadaku [Abdul Aziz bin Shuhaib] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar dengan memakai cincin, lalu beliau bersabda: \"Barangsiapa ingin membuat cincin silahkan melakukannya, namun jangan mengukir pada ukirannya (jangan mengukir dengan nama 'Muhammad Rasulullah').\""},"4852":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ سُلَيْمَانُ بْنُ سَيْفٍ الْحَرَّانِيُّ قَالَ حَدَّثَنَا هَارُونُ بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَاتَّخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا وَنَقَشَ عَلَيْهِ نَقْشًا قَالَ إِنَّا قَدْ اتَّخَذْنَا خَاتَمًا وَنَقَشْنَا فِيهِ نَقْشًا فَلَا يَنْقُشْ أَحَدٌ عَلَى نَقْشِهِثُمَّ قَالَ أَنَسٌ فَكَأَنِّي أَنْظُرُ إِلَى وَبِيصِهِ فِي يَدِهِ","id":"Telah mengabarkan kepada kami [Abu Dawud Sulaiman bin Yusuf Al Harani] ia berkata; telah menceritakan kepada kami [Harun bin Isma'il] ia berkata; telah menceritakan kepada kami [Ali Ibnul Mubarak] ia berkata; telah menceritakan kepada kami [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memakai cincin dan memberinya ukiran.\" Beliau bersabda: \"Kami memakai cincin dan telah memberinya ukiran, maka janganlah seseorang mengukirnya seperti itu (ukiran 'Muhammad Rasulullah').\" Ali berkata, \"Seakan aku melihat putihnya cincin beliau yang berada di tangan.\""},"4853":{"ar":"أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى الْخُوَارِزْمِيُّ بِبَغْدَادَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا الْعَوَّامُ بْنُ حَوْشَبٍ عَنْ أَزْهَرَ بْنِ رَاشِدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسْتَضِيئُوا بِنَارِ الْمُشْرِكِينَ وَلَا تَنْقُشُوا عَلَى خَوَاتِيمِكُمْ عَرَبِيًّا","id":"Telah mengabarkan kepada kami [Mujahid bin Musa Al Khuwarizmi] di Baghdad, ia berkata; telah menceritakan kepada kami [Husyaim] ia berkata; telah memberitakan kepada kami [Al 'Awwam bin Hausyab] dari [Azhar bin Rasyid] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menggunakan api orang musyrikin sebagai penerangan (minta pendapat dari mereka), dan jangan engkau ukir cincinmu dengan bahasa arab (Muhammad Rasulullah).\""},"4854":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِي بُرْدَةَ قَالَ قَالَ عَلِيٌّقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَلِيٌّ سَلْ اللَّهَ الْهُدَى وَالسَّدَادَ وَنَهَانِي أَنْ أَجْعَلَ الْخَاتَمَ فِي هَذِهِ وَهَذِهِ وَأَشَارَ يَعْنِي بِالسَّبَّابَةِ وَالْوُسْطَى","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Ashim bin Kulaib] dari [Abu Burdah] ia berkata; [Ali] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: 'Wahai Ali, mintalah kepada Allah petunjuk dan kelurusan dalam berbicara kepada Allah.' Beliau juga melarangku memakai cincin pada jari yang ini dan ini.\" Ali berisyarat -yakni dengan jari telunjuk dan jari tengah-.\""},"4855":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِي بُرْدَةَ عَنْ عَلِيٍّ قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَاتَمِ فِي هَذِهِ وَهَذِهِ يَعْنِي السَّبَّابَةَ وَالْوُسْطَىوَاللَّفْظُ لِابْنِ الْمُثَنَّى","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] dan [Muhammad bin Basysyar] keduanya berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Sufyan] dari [Ashim bin Kulaib] dari [Abu Burdah] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku untuk memakai cincin di jari ini dan ini, yaitu jari telunjuk dan jari tengah.\" Ini adalah lafadz Ibnul Mutsanna."},"4856":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرٌ قَالَ حَدَّثَنَا عَاصِمُ بْنُ كُلَيْبٍ عَنْ أَبِي بُرْدَةَ عَنْ عَلِيٍّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْ اللَّهُمَّ اهْدِنِي وَسَدِّدْنِي وَنَهَانِي أَنْ أَضَعَ الْخَاتَمِ فِي هَذِهِ وَهَذِهِ وَأَشَارَ بِشْرٌ بِالسَّبَّابَةِ وَالْوُسْطَىقَالَ وَقَالَ عَاصِمٌ أَحَدُهُمَا","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] ia berkata; telah menceritakan kepada kami [Bisyr] ia berkata; telah menceritakan kepada kami [Ashim bin Kulaib] dari [Abu Burdah] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Ya Allah berilah aku petunjuk dan luruskanlah aku dalam berbicara.\" Dan beliau melarangku untuk meletakkan cincin di jari ini dan ini -Bisyr berisyarat pada jari telunjuk dan jari tengah-. Ia berkata, \"Ashim berpendapat dengan salah satu dari keduanya (antara jari telunjuk dan jari tengah).\""},"4857":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ عَنْ سَعِيدِ بْنِ عَامِرٍ عَنْ هَمَّامٍ عَنْ ابْنِ جُرَيْجٍ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَخَلَ الْخَلَاءَ نَزَعَ خَاتَمَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] dari [Sa'id bin Amir] dari [Hammam] dari [Ibnu Juraij] dari [Az Zuhri] dari [Anas] ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam masuk ke dalam WC, beliau melepas cincinnya.\" "},"4858":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ عُبَيْدَ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَاتَّخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا مِنْ ذَهَبٍ وَجَعَلَ فَصَّهُ مِنْ قِبَلِ كَفِّهِ فَاتَّخَذَ النَّاسُ خَوَاتِيمَ الذَّهَبِ فَأَلْقَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمَهُ وَقَالَ لَا أَلْبَسُهُ أَبَدًا وَأَلْقَى النَّاسُ خَوَاتِيمَهُمْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Al Mu'tamir] ia berkata; Aku mendengar [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memakai cincin dari emas dan menghadapkan mata cincinnya ke arah telapak tangan. Lalu orang-orang ikut memakai cincin hingga Rasulullah shallallahu 'alaihi wasallam pun membuang cincinnya. Beliau bersabda: \"Aku tidak akan memakainya untuk selama-lamanya.\" Orang-orang pun membuang cincin mereka."},"4859":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ خَاتَمًا مِنْ ذَهَبٍ وَجَعَلَ فَصَّهُ مِمَّا يَلِي كَفَّهُ فَاتَّخَذَ النَّاسُ خَوَاتِيمَ فَطَرَحَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ لَا أَلْبَسُهُ أَبَدًا","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] ia berkata; telah menceritakan kepada kami [Khalid] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam memakai cincin dari emas dan menghadapkan mata cincinnya ke arah telapak tangan, orang-orang lalu ikut memakai cincin hingga Nabi shallallahu 'alaihi wasallam pun membuang cincinnya. Beliau bersabda: \"Aku tidak akan memakai selamanya.\""},"4860":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَخَتَّمَ خَاتَمًا مِنْ ذَهَبٍ ثُمَّ طَرَحَهُ وَلَبِسَ خَاتَمًا مِنْ وَرِقٍ وَنَقَشَ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِ وَقَالَ لَا يَنْبَغِي لِأَحَدٍ أَنْ يَنْقُشَ عَلَى نَقْشِ خَاتَمِي هَذَا ثُمَّ جَعَلَ فَصَّهُ فِي بَطْنِ كَفِّهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub bin Musa] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Nabi shallallahu 'alaihi wasallam memakai cincin dari emas, kemudian beliau membuangnya dan memakai cincin dari perak. Beliau mengukirnya dengan 'Muhammad Rasulullah'. Beliau bersabda: \"Tidak sepantasnya seseorang membuat ukiran sebagaimana ukiranku.\" Kemudian beliau menghadapkan mata cincinnya ke arah telapak tangan.\""},"4861":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ الْمُغِيرَةِ بْنِ زِيَادٍ قَالَ حَدَّثَنَا نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَبِسَ خَاتَمًا مِنْ ذَهَبٍ ثَلَاثَةَ أَيَّامٍ فَلَمَّا رَآهُ أَصْحَابُهُ فَشَتْ خَوَاتِيمُ الذَّهَبِ فَرَمَى بِهِ فَلَا نَدْرِي مَا فَعَلَ ثُمَّ أَمَرَ بِخَاتَمٍ مِنْ فِضَّةٍ فَأَمَرَ أَنْ يُنْقَشَ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِ وَكَانَ فِي يَدِ رَسُولِ اللَّهِ حَتَّى مَاتَوَفِي يَدِ أَبِي بَكْرٍ حَتَّى مَاتَ وَفِي يَدِ عُمَرَ حَتَّى مَاتَ وَفِي يَدِ عُثْمَانَ سِتَّ سِنِينَ مِنْ عَمَلِهِ فَلَمَّا كَثُرَتْ عَلَيْهِ الْكُتُبُ دَفَعَهُ إِلَى رَجُلٍ مِنْ الْأَنْصَارِ فَكَانَ يَخْتِمُ بِهِ فَخَرَجَ الْأَنْصَارِيُّ إِلَى قَلِيبٍ لِعُثْمَانَ فَسَقَطَ فَالْتُمِسَ فَلَمْ يُوجَدْ فَأَمَرَ بِخَاتَمٍ مِثْلِهِ وَنَقَشَ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] ia berkata; telah menceritakan kepada kami [Abu Ahsim] dari [Al Mughirah bin Ziyad] ia berkata; telah menceritakan kepada kami [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah memakai cincin emas selama tiga hari, ketika para sahabatnya melihat, tersebarlah (orang memakai) cincin emas. Maka Rasulullah pun membuangnya, dan aku tidak tahu apa yang dilakukan oleh beliau. Kemudian beliau memerintahkan untuk membuat cincin dari perak dan memerintahkan untuk memberi ukiran 'Muhammad Rasulullah'. Cincin itu ada di tangan Rasulullah shallallahu 'alaihi wasallam hingga beliau wafat, kemudian beralih di tangan Abu Bakar hingga wafat, kemudian di tangan Umar hingga wafat, kemudian di tangan Utsman selama enam tahun masa pemerintahannya. Ketika banyak buku yang harus ia beri stempel, ia pun memberikan cincin itu kepada salah seorang sahabat Anshar untuk menstempel. Saat sahabat Anshar itu keluar ke sumur milik Utsman, cincin itu jatuh. Cincin itu kemudian dicari namun tidak ditemukan. Utsman kemudian memerintahkan untuk membuat cincin baru yang semisal dan memberi ukiran 'Muhammad Rasulullah'.\""},"4862":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ خَاتَمًا مِنْ ذَهَبٍ وَكَانَ فَصُّهُ فِي بَاطِنِ كَفِّهِ فَاتَّخَذَ النَّاسُ خَوَاتِيمَ مِنْ ذَهَبٍ فَطَرَحَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَرَحَ النَّاسُ خَوَاتِيمَهُمْ وَاتَّخَذَ خَاتَمًا مِنْ فِضَّةٍ فَكَانَ يَخْتِمُ بِهِ وَلَا يَلْبَسُهُ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Abu Awanah] dari [Abu Bisyr] dari [Nafi'] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam memakai cincin dari emas, dan mata cincinnya menghadap ke arah telapak tangannya. Lalu orang-orang ikut memakai cincin dari emas, maka Rasulullah shallallahu 'alaihi wasallam pun membuang cincinnya dan diikuti oleh mereka. Beliau kemudian membuat cincin dari perak yang beliau gunakan untuk mensetempel, dan tidak memakainya.\""},"4863":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُثْمَانَ بْنِ أَبِي صَفْوَانَ الثَّقَفِيُّ مِنْ وَلَدِ عُثْمَانَ بْنِ أَبِي الْعَاصِ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْوَزِيرِ قَالَ حَدَّثَنَا نَافِعُ بْنُ عُمَرَ الْجُمَحِيُّ عَنْ أَبِي بَكْرِ بْنِ أَبِي شَيْخٍ قَالَكُنْتُ جَالِسًا مَعَ سَالِمٍ فَمَرَّ بِنَا رَكْبٌ لِأُمِّ الْبَنِينَ مَعَهُمْ أَجْرَاسٌ فَحَدَّثَ نَافِعًا سَالِمٌ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصْحَبُ الْمَلَائِكَةُ رَكْبًا مَعَهُمْ جُلْجُلٌ كَمْ تَرَى مَعَ هَؤُلَاءٍ مِنْ الْجُلْجُلِ","id":"Telah mengabarkan kepada kami [Muhammad bin Utsman bin Abu Shafwan Ats Tsaqafi] -termasuk anak dari Utsman bin Abu Waqash- ia berkata; telah menceritakan kepada kami [Ibrahim bin Abu Al Wazir] ia berkata; telah menceritakan kepada kami [Nafi' bin Umar Al Jumahi] dari [Abu Bakr bin Abu Syaikh] ia berkata, \"Ketika aku sedang duduk-duduk bersama Salim, rombongan unta Ummu Banin melintas di hadapan kami, sementara pada rombongan itu terdapat lonceng. [Salim] kemudian menceritakan kepada Nafi' sebuah hadits dari [bapaknya], dari Nabi shallallahu 'alaihi wasallam, bahwa beliau pernah bersabda: 'Malaikat tidak akan menyertai rombongan yang pada mereka terdapat genta.' Berapa banyak kau lihat mereka membawa genta.\""},"4864":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ الطُّرْسُوسِيُّ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَنْبَأَنَا نَافِعُ بْنُ عُمَرَ الْجُمَحِيُّ عَنْ أَبِي بَكْرِ بْنِ مُوسَى قَالَ كُنْتُ مَعَ سَالِمِ بْنِ عَبْدِ اللَّهِ فَحَدَّثَ سَالِمٌ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصْحَبُ الْمَلَائِكَةُ رُفْقَةً فِيهَا جُلْجُلٌ","id":"telah mengabarkan kepada kami ['Abdurrahman bin Muhammad bin Sallam Ath Thurtusi] ia berkata; telah menceritakan kepada kami [Yazid bin Harun] ia berkata; telah memberitakan kepada kami [Nafi' bin Umar Al Jumahi] dari [Abu Bakr bin Musa] ia berkata, \"Aku pernah bersama [Salim bin Abdullah], Salim kemudian menceritakan sebuah hadits dari [bapaknya], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Malaikat tidak akan menyertai rombongan yang pada mereka terdapat genta.\""},"4865":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا أَبُو هِشَامٍ الْمَخْزُومِيُّ قَالَ حَدَّثَنَا نَافِعُ بْنُ عُمَرَ عَنْ بُكَيْرِ بْنِ مُوسَى عَنْ سَالِمٍ عَنْ أَبِيهِ رَفَعَهُقَالَ لَا تَصْحَبُ الْمَلَائِكَةُ رُفْقَةً فِيهَا جُلْجُلٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Ibnul Mubarak] ia berkata; telah menceritakan kepada kami [Abu Hisyam Al Makhzumi] ia berkata; telah menceritakan kepada kami [Nafi' bin Umar] dari [Bukair bin Musa] dari [Salim] dari [Bapaknya] dan ia memarfu'kannya. Beliau bersabda: \"Malaikat tidak akan menyertai rombongan yang pada mereka terdapat genta.\""},"4866":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدِ بْنِ مُسْلِمٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي سُلَيْمَانُ بْنُ بَابَيْهِ مَوْلَى آلِ نَوْفَلٍ أَنَّ أُمَّ سَلَمَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَدْخُلُ الْمَلَائِكَةُ بَيْتًا فِيهِ جُلْجُلٌ وَلَا جَرَسٌ وَلَا تَصْحَبُ الْمَلَائِكَةُ رُفْقَةً فِيهَا جَرَسٌ","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id bin Muslim] ia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] ia berkata; telah mengabarkan kepadaku [Sulaiman bin Babaih] -mantan budak keluarga Nufail- bahwa [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Malaikat tidak akan masuk ke dalam rumah yang di dalamnya terdapat genta dan lonceng. Dan malaikat tidak akan menyertai rombongan yang di dalamnya terdapat lonceng.\""},"4867":{"ar":"أَخْبَرَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِيهِ قَالَكُنْتُ جَالِسًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَآنِي رَثَّ الثِّيَابِ فَقَالَ أَلَكَ مَالٌ قُلْتُ نَعَمْ يَا رَسُولَ اللَّهِ مِنْ كُلِّ ال��مَالِ قَالَ فَإِذَا آتَاكَ اللَّهُ مَالًا فَلْيُرَ أَثَرُهُ عَلَيْكَ","id":"Telah mengabarkan kepada kami [Abu Kuraib Muhammad Ibnul 'Ala] ia berkata; telah menceritakan kepada kami [Abu Bakr bin Ayyasy] ia berkata; telah menceritakan kepada kami [Abu Ishaq] dari [Abu Al Ahwash] dari [Bapaknya] ia berkata, \"Saat aku duduk di sisi Rasulullah shallallahu 'alaihi wasallam, beliau melihatku mengenakan pakaian yang usang. Maka beliau pun bertanya: \"Apakah engkau mempunyai harta?\" Aku menjawab, \"Tentu wahai Rasulullah, apapun aku punya.\" Beliau bersabda: \"Jika Allah memberimu harta, maka perlihatkanlah wujudnya.\""},"4868":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِيهِأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَوْبٍ دُونٍ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَكَ مَالٌ قَالَ نَعَمْ مِنْ كُلِّ الْمَالِ قَالَ مِنْ أَيِّ الْمَالِ قَالَ قَدْ آتَانِي اللَّهُ مِنْ الْإِبِلِ وَالْغَنَمِ وَالْخَيْلِ وَالرَّقِيقِ قَالَ فَإِذَا آتَاكَ اللَّهُ مَالًا فَلْيُرَ عَلَيْكَ أَثَرُ نِعْمَةِ اللَّهِ وَكَرَامَتِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Abu Nu'aim] ia berkata; telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Bapaknya], bahwasanya ia pernah berkunjung menemui Nabi shallallahu 'alaihi wasallam dengan mengenakan pakaian yang telah usang, maka Nabi shallallahu 'alaihi wasallam pun bertanya kepadanya: \"Apakah engkau memiliki harta?\" ia menjawab, \"Tentu wahai Rasulullah, semuanya aku punya.\" Beliau bertanya lagi: \"Apa saja itu?\" ia menjawab, \"Allah telah memberiku unta, kambing, kuda dan budak.\" Beliau lantas bersabda: \"Jika Allah telah memberikan harta kepadamu maka perlihatkanlah wujud dari nikmat dan kemuliaan-Nya kepadamu.\""},"4869":{"ar":"أَخْبَرَنَا ابْنُ السُّنِّيِّ قِرَاءَةً قَالَ حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ أَحْمَدُ بْنُ شُعَيْبٍ لَفْظًا قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ وَهُوَ ابْنُ سُلَيْمَانَ قَالَ سَمِعْتُ مَعْمَرًا عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسٌ مِنْ الْفِطْرَةِ قَصُّ الشَّارِبِ وَنَتْفُ الْإِبْطِ وَتَقْلِيمُ الْأَظْفَارِ وَالِاسْتِحْدَادُ وَالْخِتَانُ","id":"Telah mengabarkan kepada kami Ibnu As Sunni dengan jalan membaca, ia berkata; telah menceritakan kepada kami Abu 'Abdurrahman Ahmad bin Syu'aib secara lafadz, ia berkata; telah memberitakan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Al Mu'tamir] -dia adalah Ibnu Sulaiman- ia berkata; Aku mendengar [Ma'mar] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lima hal termasuk fitrah adalah memotong kumis, mencabut bulu ketiak, memotong kuku, mencabut bulu kemaluan dan khitan.\""},"4870":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَحْفُوا الشَّوَارِبَ وَأَعْفُوا اللِّحَى","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] ia berkata; telah menceritakan kepada kami [Yahya] dari [Ubaidullah] ia berkata; telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Cukurlah kumis dan peliharalah jenggot.\""},"4871":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ مُحَمَّدَ بْنَ أَبِي يَعْقُوبَ عَنْ الْحَسَنِ بْنِ سَعْدٍ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَأَمْهَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آلَ جَعْفَرٍ ثَلَاثَةً أَنْ يَأْتِيَهُمْ ثُمَّ أَتَاهُمْ فَقَالَ لَا تَبْكُوا عَلَى أَخِي بَعْدَ الْيَوْمِ ثُمَّ قَالَ ادْعُوا إِلَيَّ بَنِي أَخِي فَجِيءَ بِنَا كَأَنَّا أَفْرُخٌ فَقَالَ ادْعُوا إِلَيَّ الْحَلَّاقَ فَأَمَرَ بِحَلْقِ رُءُوسِنَا مُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] ia berkata; telah memberitakan kepada kami [Wahb bin Jarir] ia berkata; telah menceritakan kepada kami [Bapakku] ia berkata; Aku mendengar [Muhammad bin Abu Ya'qub] dari [Al Hasan bin Sa'd] menceritakan dari [Abdullah bin Ja'far] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menunda kunjungannya kepada keluarga Ja'far selama tiga hari, setelah itu beliau mengunjungi mereka. Beliau bersabda: \"Setelah hari ini janganlah kalian tangisi saudaraku.\" Kemudian beliau bersabda lagi: \"Bawalah kemari anak-anak saudaraku.\" Maka kami pun dibawa ke hadapan beliau layaknya anak-anak burung, beliau lantas bersabda: \"Panggilkan tukang cukur kemari.\" Beliau kemudian memerintahkan tukang cukur itu untuk mencukur rambut kami.\""},"4872":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدَةَ قَالَ أَنْبَأَنَا حَمَّادٌ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْقَزَعِ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdah] ia berkata; telah memberitakan kepada kami [Hammad] ia berkata; telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] berkata, \"Nabi shallallahu 'alaihi wasallam melarang Al qaza' (mencukur sebagian kepala dan membiarkan sebagian yang lain).\""},"4873":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عُبَيْدُ اللَّهِ عَنْ نَافِعٍ أَنَّهُ أَخْبَرَهُ أَنَّهُ سَمِعَ ابْنَ عُمَرَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ الْقَزَعِ","id":"Telah mengabarkan kepadaku [Ibrahim Ibnul Hasan] ia berkata; telah menceritakan kepada kami [Hajjaj] ia berkata; [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Ubaidullah] dari [Nafi'] bahwasanya ia mengabarkan kepadanya, bahwa ia pernah mendengar [Ibnu Umar] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam melarang Al qaza' (mencukur sebagian kepala dan membiarkan sebagian yang lain).\""},"4874":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ عُمَرَ بْنِ نَافِعٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْقَزَعِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Muhammad bin Bisyr] ia berkata; telah menceritakan kepada kami [Ubaidullah] dari [Umar bin Nafi'] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari Al qaza' (mencukur sebagian kepala dan membiarkan sebagian yang lain).\""},"4875":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ قَالَ أَخْبَرَنِي عُمَرُ بْنُ نَافِعٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْقَزَعِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] ia berkata; telah menceritakan kepada kami [Yahya] ia berkata; telah menceritakan kepada kami [Ubaidullah] ia berkata; telah mengabarkan kepadaku [Umar bin Nafi'] dari [Nafi'] dari [Ibnu Umar] berkata, \"Nabi shallallahu 'alaihi wasallam melarang dari Al qaza' (mencukur sebagian kepala dan membiarkan sebagian yang lain).\""},"4876":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ الْحُسَيْنِ عَنْ أُمَيَّةَ بْنِ خَالِدٍ عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجِلًا مَرْبُوعًا عَرِيضَ مَا بَيْنَ الْمَنْكِبَيْنِ كَثَّ اللِّحْيَةِ تَعْلُوهُ حُمْرَةٌ جُمَّتُهُ إِلَى شَحْمَتَيْ أُذُنَيْهِ لَقَدْ رَأَيْتُهُ فِي حُلَّةٍ حَمْرَاءَ مَا رَأَيْتُ أَحْسَنَ مِنْهُ","id":"Telah mengabarkan kepada kami [Ali bin Al Husain] dari [Umayyah bin Khalid] dari [Syu'bah] dari [Abu Ishaq] dari [Al Bara] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam adalah seorang laki-laki yang berperawakan sedang (tidak tinggi dan tidak tidak pendek), dadanya bidang melebar antara dua pundaknya, janggutnya sedang, warna kulitnya kemerah-merahan dan rambutnya menjuntai hingga daun telinga. Aku melihat beliau mengenakan pakaian merah, dan aku tidak pernah melihat orang yang lebih bagus dari beliau.\""},"4877":{"ar":"أَخْبَرَنَا حَاجِبُ بْنُ سُلَيْمَانَ عَنْ وَكِيعٍ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَمَا رَأَيْتُ مِنْ ذِي لِمَّةٍ أَحْسَنَ فِي حُلَّةٍ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَهُ شَعْرٌ يَضْرِبُ مَنْكِبَيْهِ","id":"Telah mengabarkan kepada kami [Hajib bin Sulaiman] dari [Waki'] dari [Sufyan] dari [Abu Ishaq] dari [Al Bara] ia berkata, \"Aku tidak pernah melihat orang yang berambut panjang dan memakai pakaian yang indah melebihi keindahan Rasulullah shallallahu 'alaihi wasallam. Dan beliau memiliki rambut yang panjang menjuntai hingga kedua bahunya.\""},"4878":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَكَانَ شَعْرُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى نِصْفِ أُذُنَيْهِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] ia berkata; telah memberitakan kepada kami [Isma'il] dari [Humaid] dari [Anas] ia berkata, \"Rambut Nabi shallallahu 'alaihi wasallam menjuntai hingga setengah daun telinganya.\""},"4879":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا حَبَّانُ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَضْرِبُ شَعْرُهُ إِلَى مَنْكِبَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] ia berkata; telah menceritakan kepada kami [Habban] ia berkata; telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas] berkata, \"Rambut Rasulullah shallallahu 'alaihi wasallam memanjang hingga kedua bahunya.\""},"4880":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ خَشْرَمٍ قَالَ أَنْبَأَنَا عِيسَى عَنْ الْأَوْزَاعِيِّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّهُ قَالَأَتَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَأَى رَجُلًا ثَائِرَ الرَّأْسِ فَقَالَ أَمَا يَجِدُ هَذَا مَا يُسَكِّنُ بِهِ شَعْرَهُ","id":"Telah mengabarkan kepada kami [Ali bin Khasyram] ia berkata; telah memberitakan kepada kami [Isa] dari [Al Auza'i] dari [Hassan bin Athiah] dari [Muhammad Ibnul Munkadir] dari [Jabir bin Abdullah] bahwasanya ia berkata, \"Nabi shallallahu 'alaihi wasallam berkata datang menemui kami dan melihat seorang laki-laki yang rambutnya tampak kusut, maka beliau bersabda: \"Apakah orang ini tidak mendapatkan sesuatu yang dapat merapikan rambutnya.\""},"4881":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عُمَرُ بْنُ عَلِيِّ بْنِ مُقَدَّمٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ أَبِي قَتَادَةَ قَالَكَانَتْ لَهُ جُمَّةٌ ضَخْمَةٌ فَسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ أَنْ يُحْسِنَ إِلَيْهَا وَأَنْ يَتَرَجَّلَ كُلَّ يَوْمٍ","id":"Telah mengabarkan kepada kami [Amru bin Ali] ia berkata; telah menceritakan kepada kami [Umar bin Ali bin Miqdam] ia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muhammad Ibnul Munkadir] dari [Abu Qatadah] ia berkata, \"Bahwasanya ia mempunyai rambut yang panjang, ia lalu bertanya Nabi shallallahu 'alaihi wasallam mengenai rambutnya. Maka beliau pun memerintahkan kepadanya untuk merawatnya dengan baik, dan mensisirnya setiap hari.\""},"4882":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسْدُلُ شَعْرَهُ وَكَانَ الْمُشْرِكُونَ يَفْرُقُونَ شُعُورَهُمْ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ مُوَافَقَةَ أَهْلِ الْكِتَابِ فِيمَا لَمْ يُؤْمَرْ فِيهِ بِشَيْءٍ ثُمَّ فَرَقَ رَسُ��لُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] ia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam biasa membiarkan rambutnya terurai, sementara orang-orang musyrik membelah rambut mereka. Rasulullah shallallahu 'alaihi wasallam biasanya suka berkesesuaian dengan orang-orang ahli kitab dalam hal-hal yang tidak ada perintah di dalamnya, setelah itu Rasulullah shallallahu 'alaihi wasallam membelah rambutnya.\""},"4883":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ الْجُرَيْرِيِّ عَنْ عَبْدِ اللَّهِ بْنُ بُرَيْدَةَ أَنَّ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَالُ لَهُ عُبَيْدٌ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْهَى عَنْ كَثِيرٍ مِنْ الْإِرْفَاهِسُئِلَ ابْنُ بُرَيْدَةَ عَنْ الْإِرْفَاهِ قَالَ مِنْهُ التَّرَجُّلُ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] ia berkata; telah menceritakan kepada kami [Ibnu Ulayyah] dari [Al Jurairi] dari [Abdullah bin Buraidah] ia berkata, \"Seorang laki-laki dari sahabat Nabi shallallahu 'alaihi wasallam yang bernama [Ubaid] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang untuk bermewah-mewah.\" [Ibnu Buraidah] lalu ditanya tentang (maksud) bermewah-mewah?\" maka ia menjawab, \"Di antaranya adalah At Tarajjul (selalu membuat rambut rapi, bersih dan membenahinya).\""},"4884":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي الْأَشْعَثُ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَوَذَكَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُحِبُّ التَّيَامُنَ مَا اسْتَطَاعَ فِي طُهُورِهِ وَتَنَعُّلِهِ وَتَرَجُّلِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Khalid] ia berkata; telah menceritakan kepada kami [Syu'bah] ia berkata; telah mengabarkan kepadaku [Al Asy'ats] ia berkata; Aku mendengar [Bapakku] menceritakan dari [Masruq] dari ['Aisyah], ia menyebutkan bahwa Rasulullah shallallahu 'alaihi wasallam suka untuk selalu mendahulukan yang kanan sebisa mungkin, baik saat bersuci, memaki sandal atau menyisir.\""},"4885":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ وَسُلَيْمَانَ بْنِ يَسَارٍ أَنَّهُمَا سَمِعَا أَبَا هُرَيْرَةَ يُخْبِرُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْيَهُودَ وَالنَّصَارَى لَا يَصْبُغُونَ فَخَالِفُوهُمْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dan [Sulaiman bin Yasar] bahwa keduanya mendengar [Abu Hurairah] mengabarkan dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya orang-orang Yahudi dan Nashara tidak mewarnai (rambut atau janggut), maka selisihilah mereka.\""},"4886":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ وَهُوَ ابْنُ الْحَارِثِ قَالَ حَدَّثَنَا عَزْرَةُ وَهُوَ ابْنُ ثَابِتٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَبِي قُحَافَةَ وَرَأْسُهُ وَلِحْيَتُهُ كَأَنَّهُ ثَغَامَةٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيِّرُوا أَوْ اخْضِبُوا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Khalid] -yaitu Ibnul Harits- ia berkata; telah menceritakan kepada kami [Azrah] -yaitu Ibnu Tsabit- dari [Abu Az Zubair] - dari [Jabir] ia berkata, \"Didatangkan Abu Quhafah kepada Nabi shallallahu 'alaihi wasallam, sementara rambut dan janggutnya seperti Tsaghamah (semacam tumbuhan yang bunganya berwarna putih). Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Ubah dan catlah rambutmu.\""},"4887":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَكِيمٍ قَالَ حَدَّثَنَا أَبُو قُتَيْبَةَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عُبَيْدٍ قَالَرَأَيْتُ ابْنَ عُمَرَ يُصَفِّرُ لِحْيَتَهُ فَقُلْتُ لَهُ فِي ذَلِكَ فَقَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَفِّرُ لِحْيَتَهُ","id":"Telah mengabarkan kepada kami [Yahya bin Hakim] ia berkata; telah menceritakan kepada kami [Abu Qutaibah] ia berkata; telah menceritakan kepada kami ['Abdurrahman bin Abdullah bin Dinar] dari [Zaid bin Aslam] dari [Ubaid] ia berkata, \"Aku pernah melihat Ibnu Umar memberi warna kuning pada janggutnya, maka aku bertanya kepadanya tentang hal itu. [Ibnu Umar] lalu menjawab, \"Aku pernah melihat Nabi shallallahu 'alaihi wasallam memberi warna kuning pada janggutnya.\""},"4888":{"ar":"أَخْبَرَنَا عَبْدَةُ بْنُ عَبْدِ الرَّحِيمِ قَالَ أَنْبَأَنَا عَمْرُو بْنُ مُحَمَّدٍ قَالَ أَنْبَأَنَا ابْنُ أَبِي رَوَّادٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْبَسُ النِّعَالَ السِّبْتِيَّةَ وَيُصَفِّرُ لِحْيَتَهُ بِالْوَرْسِ وَالزَّعْفَرَانِ وَكَانَ ابْنُ عُمَرَ يَفْعَلُ ذَلِكَ","id":"Telah mengabarkan kepada kami [Abdah bin Abdurrahim] ia berkata; telah memberitakan kepada kami [Amru bin Muhammad] ia berkata; telah memberitakan kepada kami [Ibnu Abu Rawwad] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Nabi shallallahu 'alaihi wasallam memakai sandal As Sibtiyyah (yang terbuat dari kulit yang disamak) dan memberi warna kuning pada janggutnya dengan waras (semacam tumbuhan yang berwarna kuning dan berbau harum) dan Za'farat.\" Dan Ibnu Umar selalu melakukan hal itu.\""},"4889":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَسَمِعْتُ مُعَاوِيَةَ وَهُوَ عَلَى الْمِنْبَرِ بِالْمَدِينَةِ وَأَخْرَجَ مِنْ كُمِّهِ قُصَّةً مِنْ شَعْرٍ فَقَالَ يَا أَهْلَ الْمَدِينَةِ أَيْنَ عُلَمَاؤُكُمْ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ مِثْلِ هَذِهِ وَقَالَ إِنَّمَا هَلَكَتْ بَنُو إِسْرَائِيلَ حِينَ اتَّخَذَ نِسَاؤُهُمْ مِثْلَ هَذَا","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Humaid bin 'Abdurrahman] ia berkata; Aku mendengar [Mu'awiyah] berkhutbah di atas mimbar Madinah, ia mengeluarkan rambut dari dalam saku bajunya seraya mengatakan, \"Wahai penduduk Madinah, dimanakah ulama kalian! Aku pernah mendengar Nabi shallallahu 'alaihi wasallam melarang dari yang seperti ini, beliau bersabda: \"Bani Israil celaka ketika wanita-wanita mereka mengambil (memakai) yang seperti ini.\""},"4890":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدِ بْنِ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَقَدِمَ مُعَاوِيَةُ الْمَدِينَةَ فَخَطَبَنَا وَأَخَذَ كُبَّةً مِنْ شَعْرٍ قَالَ مَا كُنْتُ أَرَى أَحَدًا يَفْعَلُهُ إِلَّا الْيَهُودَ وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلَغَهُ فَسَمَّاهُ الزُّورَ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] dan [Muhammad bin Basysyar] dari [Muhammad bin Ja'far] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Amru bin Murrah] dari [Sa'id Ibnul Musayyab] ia berkata, \"Saat [Mu'awiyah] tiba di Madinah ia berkhutbah di hadapan kami, ia lalu mengeluarkan gulungan rambut dan berkata, \"Aku tidak pernah melihat seorang pun yang melakukannya selain orang Yahudi, Rasulullah shallallahu 'alaihi wasallam juga telah menyampaikannya, yang kemudian beliau menyebutnya dengan kedustaan.\""},"4891":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَحْيَى بْنِ الْحَارِثِ قَالَ حَدَّثَنَا مَحْبُوبُ بْنُ مُوسَى قَالَ أَنْبَأَنَا ابْنُ الْمُبَارَكِ عَنْ يَعْقُوبَ بْنِ الْقَعْقَاعِ عَنْ قَتَادَةَ عَنْ ابْنِ الْمُسَيَّبِ عَنْ مُعَاوِيَةَأَنَّهُ قَالَ يَا أَيُّهَا النَّاسُ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَاكُمْ عَنْ الزُّورِ قَالَ وَجَاءَ بِخِرْقَةٍ سَوْدَاءَ فَأَلْقَاهَا بَيْنَ أَيْدِيهِمْ فَقَالَ هُوَ هَذَا تَجْعَلُهُ الْمَرْأَةُ فِي رَأْسِهَا ثُمَّ تَخْتَمِرُ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Amru bin Yahya Ibnul Harits] ia berkata; telah menceritakan kepada kami [Mahbub bin Musa] ia berkata; telah memberitakan kepada kami [Ibnul Mubarak] dari [Ya'qub Ibnul Qa'qa'] dari [Qatadah] dari [Ibnul Musyyab] dari [Mu'awiyah] ia berkata, \"Wahai manusia, sesungguhnya Nabi shallallahu 'alaihi wasallam telah melarang kalian dari berbuat dusta.\" Ibnul Musayyab berkata, \"Kemudian Mu'awiyah datang dengan membawa sobekan kain berwarna hitam dan melemparkannya di depan para sahabat. Kemudian Ia berkata, \"Inilah kedustaan tersebut, para wanita mengambil dan memasangnya di kepala sebagai penutup.\""},"4892":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنَا أَسَدُ بْنُ مُوسَى قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ هِشَامِ بْنِ أَبِي عَبْدِ اللَّهِ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ مُعَاوِيَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الزُّورِ وَالزُّورُ الْمَرْأَةُ تَلُفُّ عَلَى رَأْسِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Abdurrahim] ia berkata; telah menceritakan kepada kami [Asad bin Musa] ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Hisyam bin Abu Abdullah] dari [Qatadah] dari [Sa'id Ibnul Musayyab] dari [Mu'awiyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang berkata dusta, dan dustanya seorang wanita adalah memasang gulungan rambut pada kepalanya.\""},"4893":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَلِيٌّ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ الْوَاصِلَةَ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] ia berkata; telah menceritakan kepada kami [Ali] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat wanita yang menyambung rambut.\""},"4894":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ حَدَّثَتْنِي فَاطِمَةُ عَنْ أَسْمَاءَأَنَّ امْرَأَةً جَاءَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ بِنْتًا لِي عَرُوسٌ وَإِنَّهَا اشْتَكَتْ فَتَمَزَّقَ شَعْرُهَا فَهَلْ عَلَيَّ جُنَاحٌ إِنْ وَصَلْتُ لَهَا فِيهِ فَقَالَ لَعَنَ اللَّهُ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] ia berkata; telah menceritakan kepada kami [Yahya] dari [Hisyam] ia berkata; telah menceritakan kepadaku [Fatimah] dari [Asma] berkata, \"Seorang wanita datang menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya puteriku akan menikah, tetapi rambutnya rontok. Maka apakah aku berdosa jika aku sambung rambutnya?\" beliau lalu menjawab: \"Allah melaknat wanita yang menyambung rambut dan wanita yang minta untuk disambung rambutnya.\""},"4895":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَاصِلَةَ وَالْمُوتَصِلَةَ وَالْوَاشِمَةَ وَالْمُوتَشِمَةَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Muhammad bin Biysr] ia berkata; telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat wanita yang menyambung rambut dan wanita yang minta untuk disambung rambutnya. Wanita yang mentato dan wanita yang mint untuk ditato.\""},"4896":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَعَنَ اللَّهُ الْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ أَلَا أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] ia berkata; telah menceritakan kepada kami [Muhammad] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Ibrahim] dari [Alqamah] dari [Abdullah] ia berkata, \"Allah melaknat wanita yang mencukur bulu alis dan wanita yang merenggangkan giginya. Ketahuilah, aku akan melaknat orang yang Rasulullah shallallahu 'alaihi wasallam telah melaknatnya.\""},"4897":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ الْأَعْمَشَ يُحَدِّثُ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَاشِمَاتِ وَالْمُتَفَلِّجَاتِ وَالْمُتَنَمِّصَاتِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Ahmad bin Sa'id] ia berkata; telah menceritakan kepada kami [Wahb bin Jarir] ia berkata; telah menceritakan kepada kami [Bapakku] ia berkata; Aku mendengar [Al A'masy] menceritakan dari [Ibrahim] dari [Alqamah] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat Wanita yang mentato, wanita yang merenggangkan giginya dan wanita yang mencukur bulu alis dengan mengubah ciptaan Allah Azza Wa Jalla.\""},"4898":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ مُحَمَّدٍ قَالَ حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ قَالَ حَدَّثَنَا أَبِي عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ قَالَلَعَنَ اللَّهُ الْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ وَالْمُتَوَشِّمَاتِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ فَأَتَتْهُ امْرَأَةٌ فَقَالَتْ أَنْتَ الَّذِي تَقُولُ كَذَا وَكَذَا قَالَ وَمَا لِي لَا أَقُولُ مَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin Muhammad] ia berkata; telah menceritakan kepada kami [Umar bin Hafsh] ia berkata; telah menceritakan kepada kami [Bapakku] dari [Al A'masy] dari [Ibrahim] dari [Abu Ubaidah] dari [Abdullah] ia berkata, \"Allah melaknat wanita yang mencukur bulu alis, wanita yang merenggangkan giginya, dan wanita yang minta untuk disambung rambutnya dengan mengubah ciptaan Allah.\" Lalu seorang wanita datang menemuinya dan berkata, \"Kamukah orang yang mengatakan begini dan begini?\" Abu Ubaidah menjawab, \"Kenapa aku tidak (berani) mengatakan sesuatu yang Rasulullah shallallahu 'alaihi wasallam telah mengatakannya!\""},"4899":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ قَالَكَانَ عَبْدُ اللَّهِ يَقُولُ لَعَنَ اللَّهُ الْمُتَوَشِّمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ أَلَا أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Musanna] ia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Sulaiman Al A'masy] dari [Ibrahim] ia berkata, \" [Abdullah] berkata, \"Allah melaknat wanita yang minta untuk disambung rambutnya, wanita yang mencukur bulu alis dan wanita yang merenggangkan giginya. Ketahuilah, aku akan melaknat orang yang Rasulullah shallallahu 'alaihi wasallam telah melaknatnya.\""},"4900":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ عَنْ إِسْمَعِيلَ عَنْ عَبْدِ الْعَزِيزِ عَنْ أَنَسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَتَزَعْفَرَ الرَّجُلُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dari [Isma'il] dari [Abdul Aziz] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang seorang laki-laki yang memakai za'faran.\""},"4901":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ عَلِيِّ بْنِ مُقَدَّمٍ قَالَ حَدَّثَنَا زَكَرِيَّا بْنُ يَحْيَى بْنِ عُمَارَةَ الْأَنْصَارِيُّ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُزَعْفِرَ الرَّجُلُ جِلْدَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Umar bin Ali bin Miqdam] ia berkata; telah menceritakan kepada kami [Zakariya bin Yahya bin Umarah Al Anshari] dari [Abdul Aziz bin Shuhaib] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang seorang laki-laki yang mengolesi kulitnya dengan za'faran.\""},"4902":{"ar":"أَخْبَرَنَا إِسْحَقُ قَالَ أَنْبَأَنَا وَكِيعٌ قَالَ حَدَّثَنَا عَزْرَةُ بْنُ ثَابِتٍ عَنْ ثُمَامَةَ بْنِ عَبْدِ اللَّهِ بْنِ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُتِيَ بِطِيبٍ لَمْ يَرُدَّهُ","id":"Telah mengabarkan kepada kami [Ishaq] ia berkata; telah memberitakan kepada kami [Waki'] ia berkata; telah menceritakan kepada kami [Azrah bin Tsabit] dari [Tsumamah bin Abdullah bin Anas] dari [Anas bin Malik] ia berkata, \"Jika Nabi shallallahu 'alaihi wasallam diberi minyak wangi, maka beliau tidak pernah menolaknya.\""},"4903":{"ar":"أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ فَضَالَةَ بْنِ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ قَالَ حَدَّثَنَا سَعِيدٌ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ أَبِي جَعْفَرٍ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ عُرِضَ عَلَيْهِ طِيبٌ فَلَا يَرُدَّهُ فَإِنَّهُ خَفِيفُ الْمَحْمَلِ طَيِّبُ الرَّائِحَةِ","id":"Telah mengabarkan kepadaku [Ubaidullah bin Fadlalah bin Ibrahim] ia berkata; telah memberitakan kepada kami [Abdullah bin Yazid Al Muqri] ia berkata; telah menceritakan kepada kami [Sa'id] ia berkata; telah menceritakan kepadaku [Ubaidullah bin Abu Ja'far] dari [Al A'raj] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa ditawari minyak wangi maka jangan menolaknya, sesungguhnya minyak wangi itu ringan membawanya namun wangi baunya.\""},"4904":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ ابْنِ عَجْلَانَ عَنْ بُكَيْرٍ ح وَأَنْبَأَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ ابْنِ عَجْلَانَ قَالَ حَدَّثَنِي بُكَيْرُ بْنُ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا شَهِدَتْ إِحْدَاكُنَّ الْعِشَاءَ فَلَا تَمَسَّ طِيبًا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Jarir] dari [Ibnu 'Ajlan] dari [Bukair]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Ubaidullah bin Sa'id] ia berkata; telah menceritakan kepada kami [Yahya] dari [Ibnu 'Ajlan] ia berkata; telah menceritakan kepadaku [Bukair bin Abdullah bin Al Asyaj] dari [Busr bin Sa'id] dari [Zainab] isteri Abdullah, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian (kaum wanita) ikut menghadiri shalat isya, maka janganlah memakai minyak wangi.\""},"4905":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ هِشَامٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ أَخْبَرَتْنِي زَيْنَبُ الثَّقَفِيَّةُ امْرَأَةُ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهَا إِذَا خَرَجْتِ إِلَى الْعِشَاءِ فَلَا تَمَسِّ طِيبًا","id":"Telah mengabarkan kepada kami [Ahmad bin Sa'id] ia berkata; telah menceritakan kepada kami [Ya'qub bin Ibrahim] ia berkata; telah menceritakan kepada kami [Bapakku] dari [Shalih] dari [Muhammad bin Abdullah bin Amru bin Hisyam] dari [Bukair bin Abdullah bin Al Asyaj] dari [Busr bin Sa'id] berkata; telah mengabarkan kepadaku [Zainab Ats Tsaqafiah] isteri Abdullah, bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda kepadanya: \"Jika engkau keluar untuk shalat isya, maka janganlah engkau memakai wewangian.\""},"4906":{"ar":"و حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ أَبِي جَعْفَرٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْنَبَ الثَّقَفِيَّةِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيَّتُكُنَّ خَرَجَتْ إِلَى الْمَسْجِدِ فَلَا تَقْرَبَنَّ طِيبًا","id":"Telah menceritakan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Abu Ja'far] dari [Bukair bin Abdullah bin Al Asyaj] dari [Busr bin Sa'id] dari [Zainab Ats Tsaqafiah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Siapapun dari kalian (para wanita) yang ikut menghadiri shalat isya, maka jangan sekali-kali memakai wewangian.\""},"4907":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ هِشَامِ بْنِ عِيسَى قَالَ حَدَّثَنَا أَبُو عَلْقَمَةَ الْفَرْوِيُّ عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنِي يَزِيدُ بْنُ خُصَيْفَةَ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا امْرَأَةٍ أَصَابَتْ بَخُورًا فَلَا تَشْهَدْ مَعَنَا الْعِشَاءَ الْآخِرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Hisyam bin Isa] ia berkata; telah menceritakan kepada kami [Abu Alqamah Al Farwi Abdullah bin Muhammad] ia berkata; telah menceritakan kepadaku [Yazid bin Khushaifah] dari [Busr bin Sa'id] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita mana saja yang memakai bakhur (asap kayu wangi), maka jangan ikut menghadiri shalat isya yang akhir bersama kami.\""},"4908":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ غَزْوَانَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ خُلَيْدِ بْنِ جَعْفَرٍ وَالْمُسْتَمِرُ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَذَكَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرَأَةً حَشَتْ خَاتَمَهَا بِالْمِسْكِ فَقَالَ وَهُوَ أَطْيَبُ الطِّيبِ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Ishaq] ia berkata; telah menceritakan kepada kami ['Abdurrahman bin Ghazwan] ia berkata; telah memberitakan kepada kami [Syu'bah] dari [Khulaid bin Ja'far] dan [Al Mustamir] dari [Abu Nadlrah] dari [Abu Sa'id] ia berkata, \"Nabi shallallahu 'alaihi wasallam menyebutkan seorang wanita yang mengolesi cincinnya dengan misik (minyak wangi), beliau lalu bersabda: \"Itu adalah minyak yang paling wangi.\""},"4909":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى وَيَزِيدُ وَمُعْتَمِرٌ وَبِشْرُ بْنُ الْمُفَضَّلِ قَالُوا حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ أَبِي مُوسَىأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ أَحَلَّ لِإِنَاثِ أُمَّتِي الْحَرِيرَ وَالذَّهَبَ وَحَرَّمَهُ عَلَى ذُكُورِهَا","id":"Telah mengabarkan kepada kami [Amru bin Ali] ia berkata; telah menceritakan kepada kami [Yahya] dan [Yazid] dan [Mu'tamir] dan [Bisyr Ibnul Mufadldal] mereka berkata; telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Sa'id bin Abu Hind] dari [Abu Musa] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah menghalalkan sutera dan emas bagi kaum wanita dari umatku, dan mengharamkannya dari yang laki-laki.\""},"4910":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْوَلِيدِ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بَكْرِ بْنِ حَفْصٍ عَنْ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ ابْنِ عَبَّاسٍ قَالَنُهِيتُ عَنْ الثَّوْبِ الْأَحْمَرِ وَخَاتَمِ الذَّهَبِ وَأَنْ أَقْرَأَ وَأَنَا رَاكِعٌ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Walid] ia berkata; telah menceritakan kepada kami [Muhammad] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Bukair bin Hafsh] dari [Abdullah bin Hunain] dari [Ibnu Abbas] ia berkata, \"Aku dilarang untuk memakai kain yang berwarna merah, memakai cincin emas dan membaca? Al-Qur'an saat rukuk.\""},"4911":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى عَنْ ابْنِ عَجْلَانَ قَالَ أَخْبَرَنِي إِبْرَاهِيمُ بْنُ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ عَنْ عَلِيٍّ قَالَنَهَ��نِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ خَاتَمِ الذَّهَبِ وَأَنْ أَقْرَأَ الْقُرْآنَ وَأَنَا رَاكِعٌ وَعَنْ الْقَسِّيِّ وَعَنْ الْمُعَصْفَرِ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] ia berkata; telah menceritakan kepada kami [Yahya] dari [Ibnu 'Ajlan] ia berkata; telah mengabarkan kepadaku [Ibrahim bin Abdullah bin Hunain] dari [Bapaknya] dari [Ibnu Abbas] dari [Ali] ia berkata, \"Nabi shallallahu 'alaihi wasallam melarangku memakai cincin emas, membaca? Al-Qur'an saat rukuk, memakai kain yang bersulam sutera dan kain yang dicelup dengan warna kuning.\""},"4912":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ عَنْ اللَّيْثِ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّهُ سَمِعَ عَلِيًّا يَقُولُنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ خَاتَمِ الذَّهَبِ وَعَنْ لُبُوسِ الْقَسِّيِّ وَالْمُعَصْفَرِ وَقِرَاءَةِ الْقُرْآنِ وَأَنَا رَاكِعٌ","id":"Telah mengabarkan kepada kami [Isa bin Hammad] dari [Al Laits] dari [Yazid bin Abu Habib] dari [Ibrahim bin Abdullah bin Hunain] bahwa [Bapaknya] menceritakan kepadanya, bahwasanya ia mendengar [Ali] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku memakai cincin emas, memakai kain yang bersulam sutera, kain yang dicelup dengan warna kuning dan membaca? Al-Qur'an saat rukuk.\""},"4913":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِ عَنْ عَلِيٍّ قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْقِرَاءَةِ فِي الرُّكُوعِ","id":"Berkata [Al Harits bin Miskin] dengan dibacakan kepadanya, dan aku mendengar dari [Al Qasim] berkata, telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Ibrahim bin Abdullah bin Hunain] dari [bapaknya] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku membaca? Al-Qur'an saat rukuk.\""},"4914":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنَا حَرْبٌ عَنْ يَحْيَى حَدَّثَنِي عَمْرُو بْنُ سَعْدٍ الْفَدَكِيُّ أَنَّ نَافِعًا أَخْبَرَهُ حَدَّثَنِي ابْنُ حُنَيْنٍ أَنَّ عَلِيًّا حَدَّثَهُ قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثِيَابِ الْمُعَصْفَرِ وَعَنْ خَاتَمِ الذَّهَبِ وَلُبْسِ الْقَسِّيِّ وَأَنْ أَقْرَأَ وَأَنَا رَاكِعٌ","id":"Telah mengabarkan kepadaku [Harun bin Abdullah] ia berkata; telah menceritakan kepada kami [Abdu Ash Shamad bin Abdul Warits] ia berkata; telah menceritakan kepada kami [Harb] dari [Yahya] berkata, telah menceritakan kepadaku [Amru bin Sa'd Al Fadaki] bahwa [Nafi'] mengabarkan kepadanya, ia berkata; telah menceritakan kepadaku [Ibnu Hunain] bahwa [Ali] menceritakan kepadanya, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku memakai kain yang dicelup dengan warna kuning, memakai cincin emas, memakai kain yang bersulam sutera dan membaca? Al-Qur'an saat rukuk.\""},"4915":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ دُرُسْتَ قَالَ حَدَّثَنَا أَبُو إِسْمَعِيلَ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ أَنَّ مُحَمَّدَ بْنَ إِبْرَاهِيمَ حَدَّثَهُ عَنْ ابْنِ حُنَيْنٍ عَنْ عَلِيٍّ قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَرْبَعٍ عَنْ لُبْسِ ثَوْبٍ مُعَصْفَرٍ وَعَنْ التَّخَتُّمِ بِخَاتَمِ الذَّهَبِ وَعَنْ لُبْسِ الْقَسِّيَّةِ وَأَنْ أَقْرَأَ الْقُرْآنَ وَأَنَا رَاكِعٌ","id":"Telah mengabarkan kepada kami [Yahya bin Durust] ia berkata; telah menceritakan kepada kami [Abu Isma'il] ia berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] bahwa [Muhammad bin Ibrahim] menceritakan kepadanya dari [Ibnu Hunain] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku dari empat hal; memakai kain yang dicelup dengan warna kuning, memakai cincin emas, memakai kain yang bersulam sutera dan membaca? Al-Qur'an saat rukuk.\""},"4916":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى أَخْبَرَنِي خَالِدُ بْنُ مَعْدَانَ أَنَّ ابْنَ حُنَيْنٍ حَدَّثَهُ أَنَّ عَلِيًّا قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثِيَابِ الْمُعَصْفَرِ وَعَنْ الْحَرِيرِ وَأَنْ يَقْرَأَ وَهُوَ رَاكِعٌ وَعَنْ خَاتَمِ الذَّهَبِ","id":"Telah mengabarkan kepadaku [Ibrahim bin Ya'qub] ia berkata; telah menceritakan kepada kami [Al Hasan bin Musa] ia berkata; telah menceritakan kepada kami [Syaiban] dari [Yahya] ia berkata, telah mengabarkan kepadaku [Khalid bin Ma'dan] bahwa [Ibnu Hunain] menceritakan kepadanya, bahwa [Ali] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku memakai kain yang dicelup dengan warna kuning, sutera, membaca? Al-Qur'an saat rukuk dan memakai cincin emas.\""},"4917":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ النَّضْرَ بْنَ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ خَاتَمِ الذَّهَبِ","id":"Telah mengabarkan kepada kami [Muhammad Ibnul Mutsanna] ia berkata; telah menceritakan kepada kami [Muhammad] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] ia berkata; Aku mendengar [An Nadlr bin Anas] dari [Basyir bin Nahik] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau melarang untuk memakai cincin emas.\""},"4918":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ الْحَجَّاجِ وَهُوَ ابْنُ الْحَجَّاجِ عَنْ قَتَادَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُبَيْدٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ تَخَتُّمِ الذَّهَبِ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh bin Abdullah] berkata, telah menceritakan kepadaku [Bapakku] ia berkata; telah menceritakan kepadaku [Ibrahim bin Thahwan] dari [Al Hajjaj] -dia adalah Ibnul Hajjaj- dari [Qatadah] dari [Abdul Malik bin Ubaid] dari [Basyir bin Nahik] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang memakai cincin.\""},"4919":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ عَنْ إِسْمَعِيلَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَاتَّخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمَ الذَّهَبِ فَلَبِسَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاتَّخَذَ النَّاسُ خَوَاتِيمَ الذَّهَبِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي كُنْتُ أَلْبَسُ هَذَا الْخَاتَمَ وَإِنِّي لَنْ أَلْبَسَهُ أَبَدًا فَنَبَذَهُ فَنَبَذَ النَّاسُ خَوَاتِيمَهُمْ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dari [Isma'il] dari [Abdullah bin Dinar] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam membuat cincin emas dan memakainya, ketika lalu orang-orang ikut memakai cincin emas. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Aku pernah memakai cincin emas, sekarang aku tidak akan pernah memakainya lagi untuk selama-lamanya, \" beliau lalu membuang cincinnya dan orang-orang pun ikut melakukannya.\""},"4920":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ نَقْشُ خَاتَمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحَمَّدٌ رَسُولُ اللَّهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Muhammad bin Bisyr] ia berkata; telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Ukiran pada cincin Rasulullah shallallahu 'alaihi wasallam berbunyi 'Muhammad Rasulullah'.\""},"4921":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ أَنْبَأَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ خَاتَمًا مِنْ وَرِقٍ وَفَصُّهُ حَبَشِيٌّ وَنَقْشُهُ مُحَمَّدٌ رَسُولُ اللَّهِ","id":"Telah mengabarkan kepada kami [Al Abbas bin Abdul Azhim] ia berkata; telah menceritakan kepada kami [Utsman bin Umar] ia berkata; telah memberitakan kepada kami [Yunus] dari [Az Zuhri] dari [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam memakai cincin dari perak, mata cincinnya dari Habsyah dan diukir dengan tulisan 'Muhammad Rasulullah'.\""},"4922":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ بِشْرٍ وَهُوَ ابْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَأَرَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَكْتُبَ إِلَى الرُّومِ فَقَالُوا إِنَّهُمْ لَا يَقْرَءُونَ كِتَابًا إِلَّا مَخْتُومًا فَاتَّخَذَ خَاتَمًا مِنْ فِضَّةٍ كَأَنِّي أَنْظُرُ إِلَى بَيَاضِهِ فِي يَدِهِ وَنُقِشَ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Biysr] -ia adalah Ibnul Mufdldlal- ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bermaksud menulis surat kepada (Raja) Rum, para sahabat lalu berkata, \"Mereka tidak mau membaca surat kecuali ada stempel di dalamnya.\" Beliau kemudian mengambil cincin dari perak, dan seakan aku melihat putihnya cincin tersebut melingkar di tangannya. Dan pada cincin tersebut bertuliskan 'Muhammad Rasulullah'.\""},"4923":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ خَاتَمًا مِنْ وَرِقٍ وَفَصُّهُ حَبَشِيٌّ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Az Zuhri] dari [Anas] berkata, \"Rasulullah shallallahu 'alaihi wasallam memakai cincin perak, dan mata cincinnya dari Habasyah.\""},"4924":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ الْحَسَنِ وَهُوَ ابْنُ صَالِحٍ عَنْ عَاصِمٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَكَانَ خَاتَمُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فِضَّةٍ وَفَصُّهُ مِنْهُ","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakariya] ia berkata; telah menceritakan kepada kami [Ubaidullah] dari [Al Hasan] -ia adalah Ibnu Shalih- dari [Ashim] dari [Humaid] dari [Anas] ia berkata, \"Cincin Nabi shallallahu 'alaihi wasallam dari perak, demikian juga dengan mata cincinnya.\""},"4925":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَلِيُّ بْنُ حُجْرٍ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا إِسْمَعِيلُ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ اصْطَنَعْنَا خَاتَمًا وَنَقَشْنَا عَلَيْهِ نَقْشًا فَلَا يَنْقُشْ عَلَيْهِ أَحَدٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dan [Ali bin Hujr] -dan ini adalah lafadznya- keduanya berkata; telah menceritakan kepada kami [Isma'il] dari [Abdul Aziz bin Shuhaib] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami telah membuat cincin dan mengukirnya (Muhammad Rasulullah), maka jangan seorang pun membuat ukiran (dengan ukiran yang sama).\""},"4926":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اصْطَنَعَ خَاتَمًا فَقَالَ إِنَّا قَدْ اتَّخَذْنَا خَاتَمًا وَنَقَشْنَا عَلَيْهِ نَقْشًا فَلَا يَنْقُشْ عَلَيْهِ أَحَدٌ وَإِنِّي لَأَرَى بَرِيقَهُ فِي خِنْصَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Imran bin Musa] ia berkata; telah menceritakan kepada kami [Abdul Warits] dari [Abdul Aziz] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: 'Kami telah membuat cincin dan mengukirnya dengan suatu ukiran, maka jangan seorang pun membuat ukiran (dengan ukiran yang sama).' Sungguh, aku benar-benar melihat kilatan (cincin) di jari kelingking Rasulullah shallallahu 'alaihi wasallam.\""},"4927":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى قَالَ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَخَتَّمُ فِي يَمِينِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Amir] ia berkata; telah menceritakan kepada kami [Muhammad bin Isa] ia berkata; telah menceritakan kepada kami [Abbad Ibnul Awwam] dari [Sa'id] dari [Qatadah] dari [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam mengenakan cincin pada tangan kanannya.\""},"4928":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ عِيسَى الْبِسْطَامِيُّ قَالَ حَدَّثَنَا سَلْمُ بْنُ قُتَيْبَةَ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَكَأَنِّي أَنْظُرُ إِلَى بَيَاضِ خَاتَمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِصْبَعِهِ الْيُسْرَى","id":"Telah mengabarkan kepada kami [Al Husain bin Isa Al Bisyhami] ia berkata; telah menceritakan kepada kami [Salm bin Qutaibah] dari [Syu'bah] dari [Qatadah] dari [Anas] ia berkata, \"Seakan-akan aku melihat putihnya cincin Nabi shallallahu 'alaihi wasallam di jari tangan kirinya.\""},"4929":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ نَافِعٍ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا ثَابِتٌأَنَّهُمْ سَأَلُوا أَنَسًا عَنْ خَاتَمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَأَنِّي أَنْظُرُ إِلَى وَبِيصِ خَاتَمِهِ مِنْ فِضَّةٍ وَرَفَعَ إِصْبَعَهُ الْيُسْرَى الْخِنْصَرَ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Nafi'] ia berkata; telah menceritakan kepada kami [Bahz bin Asad] ia berkata; telah menceritakan kepada kami [Hammad] ia berkata; telah menceritakan kepada kami [Tsabit] berkata, \"Mereka bertanya kepada [Anas] tentang cincin Rasulullah shallallahu 'alaihi wasallam, maka Anas menjawab, \"Seakan-akan aku melihat putihnya cincin beliau yang terbuat dari perak, beliau mengangkat tangan kirinya, yakni jari kelingking.\""},"4930":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِي بُرْدَةَ قَالَ سَمِعْتُ عَلِيًّا يَقُولُنَهَانِي نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَاتَمِ فِي السَّبَّابَةِ وَالْوُسْطَى","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] ia berkata; telah menceritakan kepada kami [Muhammad] berkata; telah menceritakan kepada kami [Syu'bah] dari [Ashim bin Kulaib] dari [Abu Burdah] ia berkata, \"Aku mendengar [Ali] berkata, \"Nabi Allah shallallahu 'alaihi wasallam melarangku memakai cincin pada jari telunjuk dan jari tengah.\""},"4931":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي الْأَحْوَصِ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِي بُرْدَةَ عَنْ عَلِيٍّ قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَلْبَسَ فِي إِصْبَعِي هَذِهِ وَفِي الْوُسْطَى وَالَّتِي تَلِيهَا","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Al Ahwash] dari [Ashim bin Kulaib] dari [Abu Burdah] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku memakai cincin pada dua jariku ini; jari tengah dan jari setelahnya.\""},"4932":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَتَّمُ بِخَاتَمٍ مِنْ ذَهَبٍ ثُمَّ طَرَحَهُ وَلَبِسَ خَاتَمًا مِنْ وَرِقٍ وَنُقِشَ عَلَيْهِ مُحَمَّدٌ رَسُولُ اللَّهِ ثُمَّ قَالَ لَا يَنْبَغِي لِأَحَدٍ أَنْ يَنْقُشَ عَلَى نَقْشِ خَاتَمِي هَذَا وَجَعَلَ فَصَّهُ فِي بَطْنِ كَفِّهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub bin Musa] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memakai cincin emas kemudian membuangnya. Setelah itu beliau memakai cincin perak dan memberi ukiran 'Muhammad Rasulullah'. Beliau kemudian bersabda: 'Tidak sepantasnya seseorang membuat ukiran sebagaimana ukiranku.' Kemudian beliau menghadapkan mata cincinnya ke arah telapak tangan.\""},"4933":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ حَرْبٍ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ سُلَيْمَانَ الشَّيْبَانِيِّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ خَاتَمًا فَلَبِسَهُ قَالَ شَغَلَنِي هَذَا عَنْكُمْ مُنْذُ الْيَوْمَ إِلَيْهِ نَظْرَةٌ وَإِلَيْكُمْ نَظْرَةٌ ثُمَّ أَلْقَاهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ali bin Harb] ia berkata; telah menceritakan kepada kami [Utsman bin Umar] ia berkata; telah menceritakan kepada kami [Malik bin Mighwal] dari [Sulaiman Asy Syaibani] dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam membuat cincin dan memakainya. Beliau bersabda: 'Sejak hari itu cincin ini telah menyibukkan aku dari urusan kalian, aku melihat kepadanya dan melihat kepada kalian.' Setelah itu beliau membuangnya.\""},"4934":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اصْطَنَعَ خَاتَمًا مِنْ ذَهَبٍ وَكَانَ يَلْبَسُهُ فَجَعَلَ فَصَّهُ فِي بَاطِنِ كَفِّهِ فَصَنَعَ النَّاسُ ثُمَّ إِنَّهُ جَلَسَ عَلَى الْمِنْبَرِ فَنَزَعَهُ وَقَالَ إِنِّي كُنْتُ أَلْبَسُ هَذَا الْخَاتَمَ وَأَجْعَلُ فَصَّهُ مِنْ دَاخِلٍ فَرَمَى بِهِ ثُمَّ قَالَ وَاللَّهِ لَا أَلْبَسُهُ أَبَدًا فَنَبَذَ النَّاسُ خَوَاتِيمَهُمْ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam membuat cincin dari emas dan memakainya, beliau menghadapkan mata cincinnya ke arah telapak tangannya, lalu orang-orang ikut membuat. Setelah itu beliau duduk di atas mimbar dan melepas cincinnya, beliau bersabda: 'Aku pernah memakai cincin ini, dan aku menghadapkan mata cincinnya ke arah telapak tangan.' Lalu beliau membuangnya, setelah itu beliau bersabda lagi: 'Demi Allah, aku tidak akan memakainya lagi untuk selama-lamanya.' Orang-orang pun ikut membuang cincin mereka.\""},"4935":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ قِرَاءَةً عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسٍأَنَّهُ رَأَى فِي يَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا مِنْ وَرِقٍ يَوْمًا وَاحِدًا فَصَنَعُوهُ فَلَبِسُوهُ فَطَرَحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَطَرَحَ النَّاسُ","id":"Telah mengabarkan kepada kami [Muhammad bin Sulaiman] secara bacaan, dari [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Anas] ia pernah melihat pada tangan beliau sebuah cincin perak selama satu hari, kemudian mereka ikut membuat dan memakainya. Lalu beliau membuangnya, dan mereka pun melakukan hal yang sama.\""},"4936":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ خَاتَمًا مِنْ ذَهَبٍ وَكَانَ جَعَلَ فَصَّهُ فِي بَاطِنِ كَفِّهِ فَاتَّخَذَ النَّاسُ خَوَاتِيمَ مِنْ ذَهَبٍ فَطَرَحَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَرَحَ النَّاسُ خَوَاتِيمَهُمْ وَاتَّخَذَ خَاتَمًا مِنْ فِضَّةٍ فَكَانَ يَخْتِمُ بِهِ وَلَا يَلْبَسُهُ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Abu Awanah] dari [Abu Bisyr] dari [Nafi'] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam memakai cincin emas, dan beliau menghadapkan mata cincinnya ke arah telapak tangannya. Lalu orang-orang ikut memakai cincin dari emas, maka Rasulullah shallallahu 'alaihi wasallam pun membuang cincinnya dan diikuti oleh mereka. Setelah itu beliau membuat cincin dari perak yang beliau gunakan untuk menstempel, dan tidak memakainya.\""},"4937":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَاتَّخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا مِنْ ذَهَبٍ وَجَعَلَ فَصَّهُ مِمَّا يَلِي بَطْنَ كَفِّهِ فَاتَّخَذَ النَّاسُ الْخَوَاتِيمَ فَأَلْقَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا أَلْبَسُهُ أَبَدًا ثُمَّ اتَّخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا مِنْ وَرِقٍ فَأَدْخَلَهُ فِي يَدِهِثُمَّ كَانَ فِي يَدِ أَبِي بَكْرٍ ثُمَّ كَانَ فِي يَدِ عُمَرَ ثُمَّ كَانَ فِي يَدِ عُثْمَانَ حَتَّى هَلَكَ فِي بِئْرِ أَرِيسٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Muhammad bin Bisyr] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memakai cincin emas, beliau menghadapkan mata cincinnya ke arah telapak tangan bagian dalam. Lalu orang-orang ikut memakai cincin hingga Rasulullah shallallahu 'alaihi wasallam membuang cincin miliknya seraya bersabda: \"Selamanya aku tidak akan memakainya lagi!\" Setelah itu beliau memakai cincin perak, beliau lalu memasukkan cincinnya ke dalam tangannya, cincin itu kemudian pindah ke tangan Abu Bakar, kemudian pindah ke tangan Umar, kemudian pindah ke tangan Utsman hingga akhirnya cincin itu hilang di sumur Aris.\""},"4938":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِيهِ قَالَدَخَلْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَآنِي سَيِّئَ الْهَيْئَةِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَكَ مِنْ شَيْءٍ قَالَ نَعَمْ مِنْ كُلِّ الْمَالِ قَدْ آتَانِي اللَّهُ فَقَالَ إِذَا كَانَ لَكَ مَالٌ فَلْيُرَ عَلَيْكَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Muhammad bin Yazid] ia berkata; telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Bapaknya] ia berkata, \"Aku masuk menemui Rasulullah shallallahu 'alaihi wasallam, lalu beliau melihatku dalam keadaan yang kurang rapi (seperti pengemis). Nabi shallallahu 'alaihi wasallam kemudian bersabda: \"Apakah kamu mempunyai harta?\" ia menjawab, \"Ya, semua harta telah Allah berikan kepadaku.\" Beliau lantas bersabda: \"Jika engkau mempunyai harta hendaklah engkau perlihatkan pada dirimu.\""},"4939":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ بْنِ الْخَطَّابِأَنَّهُ رَأَى حُلَّةَ سِيَرَاءَ تُبَاعُ عِنْدَ بَابِ الْمَسْجِدِ فَقُلْتُ يَا رَسُولَ اللَّهِ لَوْ اشْتَرَيْتَ هَذَا لِيَوْمِ الْجُمُعَةِ وَلِلْوَفْدِ إِذَا قَدِمُوا عَلَيْكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا يَلْبَسُ هَذِهِ مَنْ لَا خَلَاقَ لَهُ فِي الْآخِرَةِ قَالَ فَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدُ مِنْهَا بِحُلَلٍ فَكَسَانِي مِنْهَا حُلَّةً فَقَالَ يَا رَسُولَ اللَّهِ كَسَوْتَنِيهَا وَقَدْ قُلْتَ فِيهَا مَا قُلْتَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ أَكْسُكَهَا لِتَلْبَسَهَا إِنَّمَا كَسَوْتُكَهَا لِتَكْسُوَهَا أَوْ لِتَبِيعَهَا فَكَسَاهَا عُمَرُ أَخًا لَهُ مِنْ أُمِّهِ مُشْرِكًا","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] ia berkata; telah memberitakan kepada kami [Abdullah bin Numair] ia berkata; telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dari [Umar Ibnul Khaththab], bahwasanya ia pernah melihat pakaian yang bersulam sutera dijual di depan pintu masjid, lalu aku berkata, \"Wahai Rasulullah, sekiranya engkau membeli pakaian ini untuk engkau pakai di hari jum'at, atau saat para utusan datang kepadamu?\" Beliau lalu bersabda: \"Orang yang memakai pakaian ini adalah mereka-mereka yang tidak akan mendapatkan bagian di akhirat.\" Umar berkata, \"Setelah itu, kain-kain itu didatangkan kepada Rasulullah shallallahu 'alaihi wasallam, beliau lalu memakaikan salah satu pakaian tersebut kepadaku.\" Umar lalu berkata, \"Wahai Rasulullah, kenapa pakaian itu engkau kenakan untukku, padahal engkau telah mengatakan tentang pakaian itu sebagaimana yang telah engkau katakan tadi!\" Nabi shallallahu 'alaihi wasallam menjawab: \"Aku pakaikan itu bukan untuk engkau pakai, aku pakaikan itu agar engkau berikan kepada orang lain atau engkau jual kembali.\" Maka Umar pun memberikan pakaian itu kepada saudaranya seibu yang masih musyrik.\""},"4940":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍ قَالَرَأَيْتُ عَلَى زَيْنَبَ بِنْتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَمِيصَ حَرِيرٍ سِيَرَاءَ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits] ia berkata; telah menceritakan kepada kami [Isa bin Yunus] dari [Ma'mar] dari [Az Zuhri] dari [Anas] ia berkata, \"Aku pernah melihat binti Nabi shallallahu 'alaihi wasallam memakai kain yang bersulam sutera.\""},"4941":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ عَنْ بَقِيَّةَ حَدَّثَنِي الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ حَدَّثَنِيأَنَّهُ رَأَى عَلَى أُمِّ كُلْثُومٍ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُرْدَ سِيَرَاءَ وَالسِّيَرَاءُ الْمُضَلَّعُ بِالْقَزِّ","id":"Telah mengabarkan kepada kami [Amru bin Utsman] dari [Baqiyyah] ia berkata, telah menceritakan kepadaku [Az Zubaidi] dari [Az Zuhri] dari [Anas bin Malik], ia menceritakan kepadaku, bahwa Ummu Kultsum puteri Rasulullah shallallahu 'alaihi wasallam memakai selimut yang bersulam sutera.\""},"4942":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا النَّضْرُ وَأَبُو عَامِرٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ أَبِي عَوْنٍ الثَّقَفِيِّ قَالَ سَمِعْتُ أَبَا صَالِحٍ الْحَنَفِيَّ يَقُولُ سَمِعْتُ عَلِيًّا يَقُولُأُهْدِيَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُلَّةُ سِيَرَاءَ فَبَعَثَ بِهَا إِلَيَّ فَلَبِسْتُهَا فَعَرَفْتُ الْغَضَبَ فِي وَجْهِهِ فَقَالَ أَمَا إِنِّي لَمْ أُعْطِكَهَا لِتَلْبَسَهَا فَأَمَرَنِي فَأَطَرْتُهَا بَيْنَ نِسَائِي","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [An Nadlr] dan [Abu Amir] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Aun Ats Tsaqafi] ia berkata; Aku mendengar [Abu Shalih Al Hanafi] ia berkata; Aku mendengar [Ali] berkata, \"Rasulullah shallallahu 'alaihi wasallam mendapat hadiah kain yang bersulam sutera, kemudian beliau mengirimkannya kepadaku, hingga aku pun memakainya. Namun aku melihat raut kemarahan pada wajah beliau, beliau bersabda: \"Aku memberikan itu bukan untuk engkau pakai!\" Lalu beliau memerintahkan aku untuk memberikan kain tersebut kepada orang lain, maka kain itu aku berikan di antara isteri-isteriku.\""},"4943":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْحَارِثِ الْمَخْزُومِيُّ عَنْ حَنْظَلَةَ بْنِ أَبِي سُفْيَانَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ قَالَ سَمِعْتُ ابْنَ عُمَرَ يُحَدِّثُأَنَّ عُمَرَ خَرَجَ فَرَأَى حُلَّةَ إِسْتَبْرَقٍ تُبَاعُ فِي السُّوقِ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ اشْتَرِهَا فَالْبَسْهَا يَوْمَ الْجُمُعَةِ وَحِينَ يَقْدَمُ عَلَيْكَ الْوَفْدُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا يَلْبَسُ هَذَا مَنْ لَا خَلَاقَ لَهُ ثُمَّ أُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثَلَاثِ حُلَلٍ مِنْهَا فَكَسَا عُمَرَ حُلَّةً وَكَسَا عَلِيًّا حُلَّةً وَكَسَا أُسَامَةَ حُلَّةً فَأَتَاهُ فَقَالَ يَا رَسُولَ اللَّهِ قُلْتَ فِيهَا مَا قُلْتَ ثُمَّ بَعَثْتَ إِلَيَّ فَقَالَ بِعْهَا وَاقْضِ بِهَا حَاجَتَكَ أَوْ شَقِّقْهَا خُمُرًا بَيْنَ نِسَائِكَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Abdullah Ibnul Harits Al Makhzumi] dari [Hanzhalah bin Abu Sufyan] dari [Salim bin Abdullah] ia berkata; Aku mendengar [Ibnu Umar] menceritakan, bahwa Umar keluar dan melihat pakaian yang bersulam sutera dijual di pasar, ia lantas mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, belilah pakaian itu hingga engkau dapat memakainya di hari jum'at atau saat utusan datang kepadamu.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Orang yang memakai ini tidak akan mendapatkan bagian di akhirat.\" Setelah itu dihadapkan kepada Nabi shallallahu 'alaihi wasallam tiga buah pakaian tersebut, beliau lalu memakaikan salah satunya kepada Umar, kain satunya kepada Ali dan kain lainnya kepada Usamah. Kemudian Umar mendatangi Rasulullah dan berkata, \"Wahai Rasulullah, engkau telah bersabda tentangnya sebagaimana yang engkau sabdakan, tetapi kenapa engkau kirimkan kain itu kepadaku?\" Beliau menjawab: \"Jual dan penuhilah kebutuhanmu dengannya, atau sobek dan jadikanlah kerudung untuk isteri-isterimu.\""},"4944":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا يَحْيَى وَهُوَ ابْنُ أَبِي إِسْحَقَ قَالَ قَالَ سَالِمٌ مَا الْإِسْتَبْرَقُ قُلْتُ مَا غَلُظَ مِنْ الدِّيبَاجِ وَخَشُنَ مِنْهُ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُرَأَى عُمَرُ مَعَ رَجُلٍ حُلَّةَ سُنْدُسٍ فَأَتَى بِهَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اشْتَرِ هَذِهِ وَسَاقَ الْحَدِيثَ","id":"Telah mengabarkan kepada kami [Imran bin Musa] ia berkata; telah menceritakan kepada kami [Abdul Warits] ia berkata; telah menceritakan kepada kami [Yahya] -yaitu Ibnu Abu Ishaq- ia berkata, \" [Salim] bertanya, \"Apa yang itu istibraq?\" aku menjawab, \"Kain yang dicampur dengan dibaj (sejenis sutera).\" Ia lalu berkata, \"Aku pernah mendengar [Abdullah bin Umar] berkata, \"Umar bersama seorang laki-laki melihat kain sundus (kain yang lebih halus dari sutera), lalu kain tersebut ia bawa menghadap Nabi shallallahu 'alaihi wasallam, maka beliau pun bersabda: \"Belilah kain ini…lalu ia menyebutkan hadits tersebut dengan sempurna.\""},"4945":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا ابْنُ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ أَبِي لَيْلَى وَيَزِيدُ بْنُ أَبِي زِيَادٍ عَنْ ابْنِ أَبِي لَيْلَى وَأَبُو فَرْوَةَ عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ قَالَاسْتَسْقَى حُذَيْفَةُ فَأَتَاهُ دُهْقَانٌ بِمَاءٍ فِي إِنَاءٍ مِنْ فِضَّةٍ فَحَذَفَهُ ثُمَّ اعْتَذَرَ إِلَيْهِمْ مِمَّا صَنَعَ بِهِ وَقَالَ إِنِّي نُهِيتُهُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَشْرَبُوا فِي إِنَاءِ الذَّهَبِ وَالْفِضَّةِ وَلَا تَلْبَسُوا الدِّيبَاجَ وَلَا الْحَرِيرَ فَإِنَّهَا لَهُمْ فِي الدُّنْيَا وَلَنَا فِي الْآخِرَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid] ia berkata; telah menceritakan kepada kami [Sufyan] ia berkata; telah menceritakan kepada kami [Ibnu Abu Najih] dari [Mujahid] dari [Abu Laila], dan [Yazid bin Abu Ziyad] dari [Ibnu Abu Laila], dan [Abu Farwah] dari [Abdullah bin Ukaim] ia berkata, \"Suatu ketika Hudzaifah meminta minum, lalu seorang kepala kampung datang dengan membawa air dalam wadah yang terbuat dari perak. [Hudzaifah] lantas menumpahkan air tersebut seraya meminta maaf atas apa yang ia lakukan, ia lalu berkata, \"Aku telah dilarang dari yang demikian, aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian minum dalam wadah yang terbuat dari emas dan perak, jangan memakai kain dibaj (sejenis sutera) dan sutera, karena kain itu diperuntukkan bagi mereka di dunia dan bagi kita di akhirat.\""},"4946":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ قَزَعَةَ عَنْ خَالِدٍ وَهُوَ ابْنُ الْحَارِثِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ وَاقِدِ بْنِ عَمْرِو بْنِ سَعْدِ بْنِ مُعَاذٍ قَالَدَخَلْتُ عَلَى أَنَسِ بْنِ مَالِكٍ حِينَ قَدِمَ الْمَدِينَةَ فَسَلَّمْتُ عَلَيْهِ فَقَالَ مِمَّنْ أَنْتَ قُلْتُ أَنَا وَاقِدُ بْنُ عَمْرِو بْنِ سَعْدِ بْنِ مُعَاذٍ قَالَ إِنَّ سَعْدًا كَانَ أَعْظَمَ النَّاسِ وَأَطْوَلَهُ ثُمَّ بَكَى فَأَكْثَرَ الْبُكَاءَ ثُمَّ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ إِلَى أُكَيْدِرٍ صَاحِبِ دُومَةَ بَعْثًا فَأَرْسَلَ إِلَيْهِ بِجُبَّةِ دِيبَاجٍ مَنْسُوجَةٍ فِيهَا الذَّهَبُ فَلَبِسَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَامَ عَلَى الْمِنْبَرِ وَقَعَدَ فَلَمْ يَتَكَلَّمْ وَنَزَلَ فَجَعَلَ النَّاسُ يَلْمِسُونَهَا بِأَيْدِيهِمْ فَقَالَ أَتَعْجَبُونَ مِنْ هَذِهِ لَمَنَادِيلُ سَعْدٍ فِي الْجَنَّةِ أَحْسَنُ مِمَّا تَرَوْنَ","id":"Telah mengabarkan kepada kami [Al Hasan bin Qaza'ah] dari [Khalid] -yakni Ibnul Harits- ia berkata; telah menceritakan kepada kami [Muhammad bin Amru] dari [Waqid bin Amru bin Sa'd bin Mu'adz] ia berkata, \"Ketika [Anas bin Malik] datang ke Madinah, aku masuk menemuinya seraya memberi salam. Anas lalu bertanya, \"Siapa kamu?\" Aku menjawab, \"Aku Waqid bin Amru bin Sa'd bin Mu'adz.\" Anas kemudian berkata, \"Sungguh, Sa'd adalah orang yang paling tinggi dan besar.\" Kemudian ia menangis dan tangisnya semakin menjadi, setelah itu ia berkata lagi, \"Rasulullah shallallahu 'alaihi wasallam pernah mengutus utusan kepada Ukaidar, penguasa Dumah. Kemudian Ukaidar mengirimkan kepada Rasulullah shallallahu 'alaihi wasallam kain dibaj (kain sejenis sutera) yang ditenun dengan benang emas. Rasulullah shallallahu 'alaihi wasallam kemudian memakainya dan naik ke atas mimbar, beliau duduk tanpa berbicara sepatah kata pun. Setelah itu beliau turun hingga orang-orang (berusaha) menyentuh kain tersebut dengan tangan mereka. Beliau lalu bersabda: \"Apakah kalian merasa ta'ajub dengan kain ini? Sungguh, sapu tangan Sa'd di surga lebih bagus dari apa yang kalian lihat ini.\""},"4947":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا يَقُولُلَبِسَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِبَاءً مِنْ دِيبَاجٍ أُهْدِيَ لَهُ ثُمَّ أَوْشَكَ أَنْ نَزَعَهُ فَأَرْسَلَ بِهِ إِلَى عُمَرَ فَقِيلَ لَهُ قَدْ أَوْشَكَ مَا نَزَعْتَهُ يَا رَسُولَ اللَّهِ قَالَ نَهَانِي عَنْهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَجَاءَ عُمَرُ يَبْكِي فَقَالَ يَا رَسُولَ اللَّهِ كَرِهْتَ أَمْرًا وَأَعْطَيْتَنِيهِ قَالَ إِنِّي لَمْ أُعْطِكَهُ لِتَلْبَسَهُ إِنَّمَا أَعْطَيْتُكَهُ لِتَبِيعَهُ فَبَاعَهُ عُمَرُ بِأَلْفَيْ دِرْهَمٍ","id":"Telah menceritakan kepada kami [Yusuf bin Sa'id] ia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] ia berkata; telah mengabarkan kepadaku [Abu Az Zubair] bahwasanya ia mendengar [Jabir] berkata, \"Nabi shallallahu 'alaihi wasallam mengenakan jubah dari dibaj (sejenis sutera) yang dihadiahkan kepadanya, beliau kemudian melepas dan mengirimkannya kepada Umar. Maka dikatakan kepada beliau, 'Kenapa engkau langsung melepasnya ya Rasulullah? ' Beliau menjawab: 'Jibril 'Alaihis Salam telah melarangku.' Kemudian Umar datang kepada beliau sambil menangis, ia berkata, \"Wahai Rasulullah, engkau membenci sesuatu, tapi memberikannya kepadaku?\" Beliau bersabda: 'Aku memberikannya bukan untuk engkau pakai, aku berikan itu agar engkau menjualnya.' Umar pun menjualnya dengan harga dua ribu dirham.\""},"4948":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ وَهُوَ عَلَى الْمِنْبَرِ يَخْطُبُ وَيَقُولُقَالَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَبِسَ الْحَرِيرَ فِي الدُّنْيَا فَلَنْ يَلْبَسَهُ فِي الْآخِرَةِ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Hammad] dari [Tsabit] ia berkata; Aku mendengar [Abdullah bin Az Zubair] -waktu itu ia sedang berkhutbah di atas mimbar- ia mengatakan, \"Muhammad shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memakai sutera di dunia, maka sekali-kali ia tidak akan memakainya di akhirat.\""},"4949":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ أَنْبَأَنَا النَّضْرُ بْنُ شُمَيْلٍ قَالَ أَنْبَأَنَا شُعْبَةُ قَالَ حَدَّثَنَا خَلِيفَةُ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ قَالَلَا تُلْبِسُوا نِسَاءَكُمْ الْحَرِيرَ فَإِنِّي سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَبِسَهُ فِي ��لدُّنْيَا لَمْ يَلْبَسْهُ فِي الْآخِرَةِ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] ia berkata; telah memberitakan kepada kami [An Nadlr bin Syumail] ia berkata; telah memberitakan kepada kami [Syu'bah] ia berkata; telah menceritakan kepada kami [Khalifah] ia berkata; Aku mendengar [Abdullah bin Az Zubair] ia berkata, \"Janganlah engkau pakaikan isteri-isterimu kain sutera, karena aku pernah mendengar [Umar Ibnul Khaththab] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memakainya di dunia, maka ia tidak akan memakainya di akhirat.\""},"4950":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ قَالَ أَنْبَأَنَا حَرْبٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي عِمْرَانُ بْنُ حِطَّانَ أَنَّهُ سَأَلَ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ عَنْ لُبْسِ الْحَرِيرِ فَقَالَ سَلْ عَائِشَةَ فَسَأَلَتْ عَائِشَةَ قَالَتْ سَلْ عَبْدَ اللَّهِ بْنَ عُمَرَ فَسَأَلْتُ ابْنَ عُمَرَ فَقَالَ حَدَّثَنِي أَبُو حَفْصٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَبِسَ الْحَرِيرَ فِي الدُّنْيَا فَلَا خَلَاقَ لَهُ فِي الْآخِرَةِ","id":"Telah mengabarkan kepada kami [Amru bin Manshur] ia berkata; telah menceritakan kepada kami [Abdullah bin Raja] ia berkata; telah memberitakan kepada kami [Harb] dari [Yahya bin Abu Katsir] ia berkata; telah menceritakan kepadaku [Imran bin Khiththan], bahwa ia pernah bertanya Abdullah bin Abbas tentang hukum mengenakan kain sutera, maka ia menjawab, \"Bertanyalah kepada 'Aisyah.\" Maka aku bertanya 'Aisyah, ia lalu menjawab, \"Bertanyalah kepada Abdullah bin Umar?\" maka aku pun bertanya [Abdullah bin Umar], ia lalu menjawab, \" [Abu Hafsh] meriwayatkan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengenakan kain sutera di dunia, maka ia tidak akan mendapatkan bagian di akhirat.\""},"4951":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ سَلْمٍ قَالَ أَنْبَأَنَا النَّضْرُ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ وَبِشْرِ بْنِ الْمُحْتَفِزِ عَنْ ابْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا يَلْبَسُ الْحَرِيرَ مَنْ لَا خَلَاقَ لَهُ","id":"Telah mengabarkan kepada kami [Sulaiman bin Salm] ia berkata; telah memberitakan kepada kami [An Nadlr] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Bakr bin Abdullah] dan [Bisyr Ibnul Muhtafiz] dari [Ibnu Umar] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Hanyasanya yang mengenakan kain sutera adalah orang-orang yang tidak mendapatkan bagian di akhirat.\""},"4952":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا أَبُو النُّعْمَانِ سَنَةَ سَبْعٍ وَمِائَتَيْنِ قَالَ حَدَّثَنَا الصَّعْقُ بْنُ حَزْنٍ عَنْ قَتَادَةَ عَنْ عَلِيٍّ الْبَارِقِيِّ قَالَأَتَتْنِي امْرَأَةٌ تَسْتَفْتِينِي فَقُلْتُ لَهَا هَذَا ابْنُ عُمَرَ فَاتَّبَعَتْهُ تَسْأَلُهُ وَاتَّبَعْتُهَا أَسْمَعُ مَا يَقُولُ قَالَتْ أَفْتِنِي فِي الْحَرِيرِ قَالَ نَهَى عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepadaku [Ibrahim bin Ya'qub] ia berkata; telah menceritakan kepada kami [Abu An Nu'man] tahun dua ratus tujuh Hijriah, ia berkata; telah menceritakan kepada kami [Ash Sha'q bin Huzn] dari [Qatadah] dari [Ali Al Bariqi] ia berkata, \"Ada seorang wanita datang kepadaku meminta fatwa, lalu aku berkata kepadanya, \"Ini ada [anaknya Umar].\" Wanita itu lalu mengikutinya dan bertanya kepadanya, sementara aku mengikutinya dari belakang untuk mendengarkan apa yang ia katakan. Wanita itu berkata, \"Berilah fatwa kepadaku tentang kain sutera!\" Ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam telah melarangku darinya.\""},"4953":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ مُعَاوِيَةَ بْنِ سُوَيْدٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَبْعٍ وَنَهَانَا عَنْ سَبْعٍ نَهَانَا عَنْ خَوَاتِيمِ الذَّهَبِ وَعَنْ آنِيَةِ الْفِضَّةِ وَعَنْ الْمَيَاثِرِ وَالْقَسِّيَّةِ وَالْإِسْتَبْرَقِ وَالدِّيبَاجِ وَالْحَرِيرِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Manshur] ia berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Asy'ats bin Abu Asy Sya'tsa] dari [Mu'awiyah bin Suwaid] dari [Al Barra bin Azib] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kepada kami dengan tujuh perkara dan melarang dari tujuh perkara; beliau melarang kami memakai cincin emas, gelas perak, alas pelana dari sutera, memakai kain yang bersulam sutera, kain yang bercampur dengan sutera, dibaj (sejenis sutera) dan kain sutera.\""},"4954":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عِيسَى بْنُ يُونُسَ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْخَصَ لِعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَالزُّبَيْرِ بْنِ الْعَوَّامِ فِي قُمُصِ حَرِيرٍ مِنْ حِكَّةٍ كَانَتْ بِهِمَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Isa bin Yunus] ia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas] berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi keringanan 'Abdurrahman bin Auf dan Az Zubair bin Al Awwam untuk memakai kemeja dari sutera karena penyakit gatal yang mereka derita.\""},"4955":{"ar":"أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ لِعَبْدِ الرَّحْمَنِ وَالزُّبَيْرِ فِي قُمُصِ حَرِيرٍ كَانَتْ بِهِمَا يَعْنِي لِحِكَّةٍ","id":"Telah mengabarkan kepada kami [Nashr bin Ali] ia berkata; telah menceritakan kepada kami [Khalid] ia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam memberi keringanan 'Abdurrahman bin Aun dan Az Zubair memakai baju dari sutera karena sesuatu yang mereka alami, yakni penyakit gatal.\""},"4956":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ قَالَكُنَّا مَعَ عُتْبَةَ بْنِ فَرْقَدٍ فَجَاءَ كِتَابُ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَلْبَسُ الْحَرِيرَ إِلَّا مَنْ لَيْسَ لَهُ مِنْهُ شَيْءٌ فِي الْآخِرَةِ إِلَّا هَكَذَا وَقَالَ أَبُو عُثْمَانَ بِأُصْبُعَيْهِ اللَّتَيْنِ تَلِيَانِ الْإِبْهَامَ فَرَأَيْتُهُمَا أَزْرَارَ الطَّيَالِسَةِ حَتَّى رَأَيْتُ الطَّيَالِسَةَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Jarir] dari [Sulaiman At Taimi] dari [Abu Utsman An Nahdi] ia berkata, \"Ketika kami sedang bersama Utsbah bin Farqad, datanglah surat [Umar] kepada kami, ia mengabarkan bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan memakai sutera kecuali orang yang tidak mendapat bagian darinya di akhirat, kecuali sekian.\" Utsman berkata dengan berisyarat dua jari setelah ibu jari. Lalu aku melihat keduanya sebesar kancing baju Ath Thayalisah (baju yang kainnya kasar).\""},"4957":{"ar":"أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَخْلَدٌ قَالَ حَدَّثَنَا مِسْعَرٌ عَنْ وَبَرَةَ عَنْ الشَّعْبِيِّ عَنْ سُوَيْدِ بْنِ غَفَلَةَ ح و أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي حَصِينٍ عَنْ إِبْرَاهِيمَ عَنْ سُوَيْدِ بْنِ غَفَلَةَ عَنْ عُمَرَأَنَّهُ لَمْ يُرَخِّصْ فِي الدِّيبَاجِ إِلَّا مَوْضِعَ أَرْبَعِ أَصَابِعَ","id":"Telah mengabarkan kepada kami [Abdul Hamid bin Muhammad] ia berkata; telah menceritakan kepada kami [Makhlad] ia berkata; telah menceritakan kepada kami [Mis'ar] dari [Wabarah] dari [Asy Sya'bi] dari [Suwaid bin Ghafalah]. (dalam jalur lain disebutkan) Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Ubaidullah] ia berkata; telah menceritakan kepada kami [Israil] dari [Abu Hashin] dari [Ibrahim] dari [Suwaid bin Ghafalah] dari [Umar], bahwasanya ia tidak memberi keringanan untuk memakai kain dibaj (sejenis sutera) kecuali selebar empat jari.\""},"4958":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ حُلَّةٌ حَمْرَاءُ مُتَرَجِّلًا لَمْ أَرَ قَبْلَهُ وَلَا بَعْدَهُ أَحَدًا هُوَ أَجْمَلُ مِنْهُ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] ia berkata; telah menceritakan kepada kami [Husyaim] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Bara] ia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam mengenakan pakaian berwarna merah dengan rambut yang tersisir rapi. Dan aku tidak pernah melihat seorang yang lebih bagus dari beliau, baik sebelum atau sesudahnya.\""},"4959":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَكَانَ أَحَبُّ الثِّيَابِ إِلَى نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحِبَرَةَ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] ia berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] ia berkata; telah menceritakan kepadaku [Bapakku] dari [Qatadah] dari [Anas] ia berkata, \"Pakaian yang paling disukai oleh Nabi Allah shallallahu 'alaihi wasallam adalah Hibarah (kain yang direnda dengan wool).\""},"4960":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ وَهُوَ ابْنُ الْحَارِثِ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ أَنَّ خَالِدَ بْنَ مَعْدَانَ أَخْبَرَهُ أَنَّ جُبَيْرَ بْنَ نُفَيْرٍ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عَمْرٍوأَنَّهُ رَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ ثَوْبَانِ مُعَصْفَرَانِ فَقَالَ هَذِهِ ثِيَابُ الْكُفَّارِ فَلَا تَلْبَسْهَا","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] ia berkata; telah menceritakan kepada kami [Khalid] -yaitu Ibnul Harits- ia berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abu Katsir] dari [Muhammad bin Ibrahim] bahwa [Khalid bin Ma'dan] mengabarkan kepadanya, bahwa [Jubair bin Nufair] mengabarkan kepadanya, bahwa [Abdullah bin Amru] pernah terlihat oleh Rasulullah shallallahu 'alaihi wasallam mengenakan dua kain yang dicelup dengan warna kuning, maka beliau pun bersabda: \"Ini adalah pakaian orang kafir, jangan engkau pakai lagi.\""},"4961":{"ar":"أَخْبَرَنِي حَاجِبُ بْنُ سُلَيْمَانَ عَنْ ابْنِ أَبِي رَوَّادٍ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ ثَوْبَانِ مُعَصْفَرَانِ فَغَضِبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ اذْهَبْ فَاطْرَحْهُمَا عَنْكَ قَالَ أَيْنَ يَا رَسُولَ اللَّهِ قَالَ فِي النَّارِ","id":"Telah mengabarkan kepadaku [Hajib bin Sulaiman] dari [Ibnu Abu Dawud] ia berkata; telah menceritakan kepada kami [Ibnu Juraij] dari [Ibnu Thawus] dari [Bapaknya] dari [Abdullah bin Amru], bahwasanya ia pernah mendatangi Nabi shallallahu 'alaihi wasallam dengan mengenakan dua kain yang dicelup dengan warna kuning. Maka Nabi shallallahu 'alaihi wasallam pun marah dan bersabda: \"Pergi dan buanglah dua kain itu dari dirimu.\" Abdullah pun bertanya, \"Kemana ya Rasulullah?\" Beliau menjawab: \"Buanglah ke dalam api.\""},"4962":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ يَزِيد�� بْنِ أَبِي حَبِيبٍ أَنَّ إِبْرَاهِيمَ بْنَ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ أَخْبَرَهُ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّهُ سَمِعَ عَلِيًّا يَقُولُنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ خَاتَمِ الذَّهَبِ وَعَنْ لُبُوسِ الْقَسِّيِّ وَالْمُعَصْفَرِ وَقِرَاءَةِ الْقُرْآنِ وَأَنَا رَاكِعٌ","id":"Telah mengabarkan kepada kami [Isa bin Hammad] ia berkata; telah memberitakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] bahwa [Ibrahim bin Abdullah bin Hunain] mengabarkan kepadanya, bahwa [Bapaknya] menceritakan kepadanya, bahwasanya ia mendengar [Ali] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku memakai cincin emas, memakai kain yang bersulam sutera, kain yang dicelup dengan warna kuning dan membaca Al-Qur'an saat rukuk.\""},"4963":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ مُحَمَّدٍ قَالَ أَنْبَأَنَا أَبُو نُوحٍ قَالَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ إِيَادِ بْنِ لَقِيطٍ عَنْ أَبِي رِمْثَةَ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ ثَوْبَانِ أَخْضَرَانِ","id":"Telah mengabarkan kepada kami [Al Abbas bin Muhammad] ia berkata; telah memberitakan kepada kami [Abu Nuh] ia berkata; telah menceritakan kepada kami [Jarir bin Hazim] dari [Abdul Malik bin Umair] dari [Iyad bin Laqith] dari [Abu Rimtsah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar menemui kami dengan mengenakan dua kain yang berwarna hijau.\""},"4964":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ الْمُثَنَّى عَنْ يَحْيَى عَنْ إِسْمَعِيلَ قَالَ حَدَّثَنَا قَيْسٌ عَنْ خَبَّابِ بْنِ الْأَرَتِّ قَالَشَكَوْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُتَوَسِّدٌ بُرْدَةً لَهُ فِي ظِلِّ الْكَعْبَةِ فَقُلْنَا أَلَا تَسْتَنْصِرُ لَنَا أَلَا تَدْعُو اللَّهَ لَنَا","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dan [Muhammad Ibnul Mutsanna] dari [Yahya] dari [Isma'il] ia berkata; telah menceritakan kepada kami [Qais] dari [Khabbab Ibnul Arat] ia berkata, \"Kami pernah mengeluh kepada Rasulullah shallallahu 'alaihi wasallam -ketika itu beliau sedang tiduran di atas kain burdah miliknya di bawah naungan Ka'bah-, kami berkata, \"Tidakkah engkau meminta pertolongan untuk kami, tidakkah engkau berdoa untuk kami?\""},"4965":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ أَنْبَأَنَا يَعْقُوبُ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَجَاءَتْ امْرَأَةٌ بِبُرْدَةٍ قَالَ سَهْلٌ هَلْ تَدْرُونَ مَا الْبُرْدَةُ قَالُوا نَعَمْ هَذِهِ الشَّمْلَةُ مَنْسُوجٌ فِي حَاشِيَتِهَا فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي نَسَجْتُ هَذِهِ بِيَدِي أَكْسُوكَهَا فَأَخَذَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحْتَاجًا إِلَيْهَا فَخَرَجَ إِلَيْنَا وَإِنَّهَا لَإِزَارُهُ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah memberitakan kepada kami [Ya'qub] dari [Abu Hazim] dari [Sahl bin Sa'd] ia berkata, \"Seorang wanita datang dengan membawa kain burdah.\" Sahl melanjutkan, \"Apakah kalian tahu apa yang dimaksud dengan kain burdah?\" mereka menjawab, \"Tentu, yaitu kain mantel yang pinggirnya diberi tenunan.\" Wanita itu lalu berkata, \"Wahai Rasulullah, aku tenun kain ini untuk engkau pakai!\" Karena Rasulullah shallallahu 'alaihi wasallam membutuhkan kain itu, maka beliau pun mengambilnya. Beliau lalu keluar menemui kami, sementara wanita itu beliau beri sarung miliknya.\""},"4966":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ أَبِي عَرُوبَةَ يُحَدِّثُ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَسُوا مِنْ ثِيَابِكُمْ الْبَيَاضَ فَإِنَّهَا أَطْهَرُ وَأَطْيَبُ وَكَفِّنُوا فِيهَا مَوْتَاكُمْقَالَ يَحْيَى لَمْ أَكْتُبْهُ قُلْتُ لِمَ قَالَ اسْتَغْنَيْتُ بِحَدِيثِ مَيْمُونِ بْنِ أَبِي شَبِيبٍ عَنْ سَمُرَةَ","id":"Telah mengabarkan kepada kami [Amru bin Ali] ia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] ia berkata; Aku mendengar [Sa'id bin Abu Arubah] menceritakan dari [Ayyub] dari [Abu Qilabah] dari [Abu Al Muhallib] dari [Samurah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pakailah pakaian kalian yang berwarna putih, karena itu lebih bersih dan lebih baik. Dan kafanilah orang yang meninggal di antara kalian dengannya.\" Yahya berkata, \"Aku belum menulisnya (hadits ini).\" Aku berkata, \"kenapa?\" Ia menjawab, \"Aku telah mencukupkan diri dengan hadits Maimun bin Abu Syabib bin Samurah.\""},"4967":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ بِالْبَيَاضِ مِنْ الثِّيَابِ فَلْيَلْبَسْهَا أَحْيَاؤُكُمْ وَكَفِّنُوا فِيهَا مَوْتَاكُمْ فَإِنَّهَا مِنْ خَيْرِ ثِيَابِكُمْ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Abu Qilabah] dari [Samurah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah kalian memakai pakaian yang berwarna putih, hendaklah orang yang hidup dari kalian memakainya dan hendaklah kalian kafani orang yang meninggal dari kalian dengannya. Sesungguhnya ia adalah sebaik-baik pakaian kalian.\""},"4968":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ قَالَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْبِيَةً وَلَمْ يُعْطِ مَخْرَمَةَ شَيْئًا فَقَالَ مَخْرَمَةُ يَا بُنَيَّ انْطَلِقْ بِنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقْتُ مَعَهُ قَالَ ادْخُلْ فَادْعُهُ لِي قَالَ فَدَعَوْتُهُ فَخَرَجَ إِلَيْهِ وَعَلَيْهِ قَبَاءٌ مِنْهَا فَقَالَ خَبَّأْتُ هَذَا لَكَ فَنَظَرَ إِلَيْهِ فَلَبِسَهُ مَخْرَمَةُ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Abu Mulaikah] dari [Al Miswar bin Makhzumah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam membagi-bagikan aqbiah (sejenis jubah), namun beliau tidak memberi Makhramah sesuatu pun. Makhramah lalu berkata, \"Wahai anakku, mari ikut kami pergi menemui Rasulullah shallallahu 'alaihi wasallam.\" Maka aku pun pergi bersamanya. Makhramah berkata, \"Masuk dan mintakanlah untukku.\" Miswar berkata, \"Aku lalu memintakan untuknya, kemudian beliau keluar menemuinya (Makhramah) dengan membawa Quba (sejenis jubah). Beliau bersabda: \"Aku sembunyikan ini khusus untukmu.\" Makhramah pun melihat jubah tersebut dan memakainya.\""},"4969":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِعَرَفَاتٍ فَقَالَ مَنْ لَمْ يَجِدْ إِزَارًا فَلْيَلْبَسْ السَّرَاوِيلَ وَمَنْ لَمْ يَجِدْ نَعْلَيْنِ فَلْيَلْبَسْ خُفَّيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] ia berkata; telah menceritakan kepada kami [Muhammad] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Amru bin Dinar] dari [Jabir bin Zaid] dari [Ibnu Abbas] bahwasanya ia mendengar Nabi shallallahu 'alaihi wasallam bersabda di Arafah: \"Barangsiapa tidak mendapatkan sarung hendaklah memakai celana panjang, dan barangsiapa tidak mendapatkan sandal hendaklah memakai khuff.\""},"4970":{"ar":"أَخْبَرَنَا وَهْبُ بْنُ بَيَانٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَنَّ سَالِمًا أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا رَجُلٌ يَجُرُّ إِزَارَهُ مِنْ الْخُيَلَاءِ خُسِفَ بِهِ فَهُوَ يَتَجَلْجَلُ فِي الْأَرْضِ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Wahb bin Bayan] ia berkata; telah menceritakan kepada kami [Ibnu Wahb] ia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] bahwa [Salim] mengabarkan kepadanya, bahwa [Abdullah bin Umar] menceritakan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saat seorang laki-laki berjalan dengan menjulurkan kainnya karena sombong, ia ditenggelamkan ke dasar bumi dan terus terguncang-guncang sampai datangnya hari kiamat.\""},"4971":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ ح وَأَنْبَأَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرٌ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَرَّ ثَوْبَهُ أَوْ قَالَ إِنَّ الَّذِي يَجُرُّ ثَوْبَهُ مِنْ الْخُيَلَاءِ لَمْ يَنْظُرْ اللَّهُ إِلَيْهِ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi']. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Isma'il bin Mas'ud] ia berkata; telah menceritakan kepada kami [Bisyr] ia berkata; telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjulurkan kain sarungnya, atau beliau mengatakan: \"Sesungguhnya orang yang menjulurkan kainnya karena sombong, maka Allah tidak akan melihatnya pada hari kiamat.\""},"4972":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مُحَارِبٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ جَرَّ ثَوْبَهُ مِنْ مَخِيلَةٍ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ لَمْ يَنْظُرْ إِلَيْهِ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Khalid] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Muharib] ia berkata; Aku mendengar [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjulurkan kainnya karena sombong, sesungguhnya Allah Azza Wa Jalla tidak akan melihatnya pada hari kiamat.\""},"4973":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ قُدَامَةَ عَنْ جَرِيرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي إِسْحَقَ عَنْ مُسْلِمِ بْنِ نُذَيْرٍ عَنْ حُذَيْفَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَوْضِعُ الْإِزَارِ إِلَى أَنْصَافِ السَّاقَيْنِ وَالْعَضَلَةِ فَإِنْ أَبَيْتَ فَأَسْفَلَ فَإِنْ أَبَيْتَ فَمِنْ وَرَاءِ السَّاقِ وَلَا حَقَّ لِلْكَعْبَيْنِ فِي الْإِزَارِوَاللَّفْظُ لِمُحَمَّدٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dan [Muhammad bin Qudamah] dari [Jarir] dari [Al A'masy] dari [Abu Ishaq] dari [Muslim bin Nudzair] dari [Hudzaifah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Batas pemakaian kain sarung adalah sampai pertengahan kedua betis, jika kamu tidak suka maka boleh lebih rendah, jika kamu tidak suka maka boleh hingga tulang belakang betis, dan tidak ada hak bagi dua mata kaki dalam pemakaian kain (tidak punya hak untuk tertutup kain).\""},"4974":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ وَهُوَ ابْنُ الْحَارِثِ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنِي أَبُو يَعْقُوبَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَحْتَ الْكَعْبَيْنِ مِنْ الْإِزَارِ فَفِي النَّارِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] ia berkata; telah menceritakan kepada kami [Khalid] -yaitu Ibnul Harits- ia berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Muhammad bin Ibrahim] ia berkata; telah menceritakan kepadaku [Abu Ya'qub] bahwasanya ia mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kain sarung yang ada di bawah mata kaki tempatnya adalah di neraka.\""},"4975":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي سَعِيدٌ الْمَقْبُرِيُّ وَقَدْ كَانَ يُخْبِرُ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَسْفَلَ مِنْ الْكَعْبَيْنِ مِنْ الْإِزَارِ فَفِي النَّارِ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] ia berkata; telah menceritakan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Syu'bah] ia berkata; telah mengabarkan kepadaku [Sa'id Al Maqburi] ia mengabarkan dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kain sarung yang ada di bawah mata kaki tempatnya adalah di neraka.\""},"4976":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عَقِيلٍ قَالَ حَدَّثَنِي جَدِّي قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَشْعَثَ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَا يَنْظُرُ إِلَى مُسْبِلِ الْإِزَارِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Ubaid bin Aqil] ia berkata; telah menceritakan kepadaku [Kakekku] berkata; telah menceritakan kepada kami [Syu'bah] dari [Asy'ats] ia berkata; Aku mendengar [Sa'id bin Jubair] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah 'azza wajalla tidak melihat orang yang kain sarungnya isbal (di bawah mata kaki).\""},"4977":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ قَالَ سَمِعْتُ سُلَيْمَانَ بْنَ مِهْرَانَ الْأَعْمَشَ عَنْ سُلَيْمَانَ بْنِ مُسْهِرٍ عَنْ خَرَشَةَ بْنِ الْحُرِّ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ الْمَنَّانُ بِمَا أَعْطَى وَالْمُسْبِلُ إِزَارَهُ وَالْمُنَفِّقُ سَلْعَتَهُ بِالْحَلِفِ الْكَاذِبِ","id":"Telah mengabarkan kepada kami [Bisyr bin Khalid] ia berkata; telah menceritakan kepada kami [Ghundar] dari [Syu'bah] ia berkata; aku mendengar [Sulaiman bin Mihran Al A'masy] dari [Sulaiman bin Mushir] dari [Kharasyah Ibnul Har] dari [Abu Dzar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga orang yang tidak akan diajak bicara oleh Allah pada hari kiamat, tidak dibersihkan dari dosa dan bagi mereka siksa yang pedih; orang yang mengungkit-ungkit dalam pemberiannya, orang yang kain sarungnya isbal (menutupi mata kaki) dan orang yang melariskan dagangannya dengan sumpah palsu.\""},"4978":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنْ عَبْدِ الْعَزِيزِ بْنِ أَبِي رَوَّادٍ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْإِسْبَالُ فِي الْإِزَارِ وَالْقَمِيصِ وَالْعِمَامَةِ مَنْ جَرَّ مِنْهَا شَيْئًا خُيَلَاءَ لَا يَنْظُرُ اللَّهُ إِلَيْهِ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] ia berkata; telah menceritakan kepada kami [Husain bin Ali] dari [Abdul Aziz bin Abu Rawwad] dari [Salim] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Isbal (memanjangkan kain) itu terjadi pada kain sarung, gamis dan surban, maka barangsiapa memanjangkan salah satu darinya karena sombong Allah tidak akan melihatnya pada hari kiamat.\""},"4979":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ جَرَّ ثَوْبَهُ مِنْ الْخُيَلَاءِ لَا يَنْظُرُ اللَّهُ إِلَيْهِ يَوْمَ الْقِيَامَةِ قَالَ أَبُو بَكْرٍ يَا رَسُولَ اللَّهِ إِنَّ أَحَدَ شِقَّيْ إِزَارِي يَسْتَرْخِي إِلَّا أَنْ أَتَعَاهَدَ ذَلِكَ مِنْهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكَ لَسْتَ مِمَّنْ يَصْنَعُ ذَلِكَ خُيَلَاءَ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] ia berkata; telah menceritakan kepada kami [Isma'il] ia berkata; telah menceritakan kepada kami [Musa bin Uqbah] dari [Salim] dari [Bapaknya] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memanjangkan kainnya karena sombong maka Allah tidak akan melihatnya pada hari kiamat.\" Abu Bakar berkata, \"Wahai Rasulullah, terkadang salah satu dari kainku turun, kecuali jika aku selalu menjaganya?\" Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Engkau bukan termasuk orang yang melakukan hal itu karena sombong.\""},"4980":{"ar":"أَخْبَرَنَا نُوحُ بْنُ حَبِيبٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَرَّ ثَوْبَهُ مِنْ الْخُيَلَاءِ لَمْ يَنْظُرْ اللَّهُ إِلَيْهِ قَالَتْ أُمُّ سَلَمَةَ يَا رَسُولَ اللَّهِ فَكَيْفَ تَصْنَعُ النِّسَاءُ بِذُيُولِهِنَّ قَالَ تُرْخِينَهُ شِبْرًا قَالَتْ إِذًا تَنْكَشِفَ أَقْدَامُهُنَّ قَالَ تُرْخِينَهُ ذِرَاعًا لَا تَزِدْنَ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Nuh bin Habib] ia berkata; telah menceritakan kepada kami [Abdurrazaq] ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memanjangkan kainnya karena sombong maka Allah tidak akan melihatnya.\" Ummu Salamah bertanya, \"Wahai Rasulullah, apa yang harus dilakukan oleh para wanita dengan kain mereka?\" Beliau menjawab: \"Kalian boleh memanjangkannya sejengkal.\" Ummu Salamah bertanya lagi, \"Jika begitu, maka kaki mereka akan terbuka!\" Beliau menjawab: \"Kalian boleh menambahkan satu hasta dan jangan lebih.\""},"4981":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ بْنِ مَزْيَدٍ قَالَ أَخْبَرَنِي أَبِي قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ نَافِعٍ عَنْ أُمِّ سَلَمَةَأَنَّهَا ذَكَرَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذُيُولَ النِّسَاءِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرْخِينَ شِبْرًا قَالَتْ أُمُّ سَلَمَةَ إِذًا يَنْكَشِفَ عَنْهَا قَالَ تُرْخِي ذِرَاعًا لَا تَزِيدُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Al Abbas Ibnul Walid bin Mazid] ia berkata; telah mengabarkan kepadaku [Bapakku] ia berkata; telah menceritakan kepada kami [Al Auza'i] ia berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] ia [Nafi'] dari [Ummu Salamah], bahwasanya ia pernah menanyakan tentang kain wanita kepada Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mereka boleh memanjangkannya satu jengkal.\" Ummu Salamah berkata, \"Jika begitu, maka kaki mereka akan terbuka!? Beliau menjawab: \"Silahkan engkau panjangkan satu hasta dan jangan lebih.\""},"4982":{"ar":"أَخْبَرَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ بْنِ عَبْدِ الْجَبَّارِ عَنْ سُفْيَانَ قَالَ حَدَّثَنِي أَيُّوبُ بْنُ مُوسَى عَنْ نَافِعٍ عَنْ صَفِيَّةَ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا ذُكِرَ فِي الْإِزَارِ مَا ذُكِرَ قَالَتْ أُمُّ سَلَمَةَ فَكَيْفَ بِالنِّسَاءِ قَالَ يُرْخِينَ شِبْرًا قَالَتْ إِذًا تَبْدُوَ أَقْدَامُهُنَّ قَالَ فَذِرَاعًا لَا يَزِدْنَ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Abdul Jabbar Ibnul 'Ala bin Abdul Jabbar] dari [Sufyan] ia berkata; telah menceritakan kepadaku [Ayyub bin Musa] dari [Nafi'] dari [Shafiah] dari [Ummu Salamah], bahwa ketika disebutkan di sisi Rasulullah shallallahu 'alaihi wasallam tentang kain wanita seperti apa yang telah disebutkan, Ummu Salamah berkata, \"Lalu bagaimana dengan kain kaum wanita?\" Beliau menjawab: \"Mereka boleh memanjangkan satu jengkal.\" Ummu Salamah berkata lagi, \"Kalau begitu, maka telapak kaki-kaki mereka akan terlihat!\" Beliau lantas bersabda: \"Mereka boleh menambahkan satu hasta dan tidak boleh lebih.\""},"4983":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا النَّضْرُ قَالَ حَدَّثَنَا الْمُعْتَمِرُ وَهُوَ ابْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أُمِّ سَلَمَةَ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمْ تَجُرُّ الْمَرْأَةُ مِنْ ذَيْلِهَا قَالَ شِبْرًا قَالَتْ إِذًا يَنْكَشِفَ عَنْهَا قَالَ ذِرَاعٌ لَا تَزِيدُ عَلَيْهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [An Nadlr] ia berkata; telah menceritakan kepada kami [Al Mu'tamir] -ia adalah Ibnu Salamah- ia berkata; telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Sulaiman bin Yasar] dari [Ummu Salamah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya 'Berapa panjang seorang wanita boleh melebihkan kainnya? ' Beliau menjawab: \"Satu jengkal.\" Ummu Salamah berkata, \"Jika begitu maka kaki mereka akan terlihat!? Beliau pun menjawab: \"Boleh satu hasta dan tidak boleh lebih.\""},"4984":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اشْتِمَالِ الصَّمَّاءِ وَأَنْ يَحْتَبِيَ فِي ثَوْبٍ وَاحِدٍ لَيْسَ عَلَى فَرْجِهِ مِنْهُ شَيْءٌ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah] dari [Abu Sa'id] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang memakai baju kurung dan duduk ihtiba (duduk di atas bokong dengan mendekap kedua lututnya menempel dada) dengan satu kain tanpa ada sesuatu yang menutupinya.\""},"4985":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اشْتِمَالِ الصَّمَّاءِ وَأَنْ يَحْتَبِيَ الرَّجُلُ فِي ثَوْبٍ وَاحِدٍ لَيْسَ عَلَى فَرْجِهِ مِنْهُ شَيْءٌ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits] ia berkata; telah memberitakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Atha bin Yazid] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang memakai baju kurung dan seorang laki-laki yang duduk ihtiba (duduk di atas bokong dengan mendekap kedua lututnya menempel dada) dengan satu kain tanpa ada sesuatu yang menutupinya.\""},"4986":{"ar":"حَدَّثَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ اشْتِمَالِ الصَّمَّاءِ وَأَنْ يَحْتَبِيَ فِي ثَوْبٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Abu Az Zubair] dari [Jabir] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang memakai baju kurung dan duduk ihtiba (duduk di atas bokong dengan mendekap kedua lututnya menempel dada) dengan satu kain.\""},"4987":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مُسَاوِرٍ الْوَرَّاقِ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ حُرَيْثٍ عَنْ أَبِيهِ قَالَرَأَيْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِمَامَةً حَرْقَانِيَّةً","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin 'Abdurrahman] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Musawir Al Warraq] dari [Ja'far bin Amru bin Huraits] dari [Bapaknya] ia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam mengenakan imamah harqaniah (surban berwarna hitam).\""},"4988":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ يَوْمَ فَتْحِ مَكَّةَ وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُ بِغَيْرِ إِحْرَامٍ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Mu'awiyah bin Ammar] ia berkata; telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] berkata, \"Pada hari pembukaan Kota Makkah Rasulullah shallallahu 'alaihi wasallam masuk (Makkah) dengan mengenakan surban berwarna hitam, dan bukan dalam keadaan ihram.\""},"4989":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ عَنْ شَرِيكٍ عَنْ عَمَّارٍ الدُّهْنِيِّ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُ","id":"Telah mengabarkan kepada kami [Amru bin Manshur] ia berkata; telah menceritakan kepada kami [Al Fadll bin Dukain] dari [Syarik] dari [Ammar Ad Duhni] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Nabi shallallahu 'alaihi wasallam masuk -Kota Makkah- saat pembukaan Kota Makkah dengan memakai surban hitam.\""},"4990":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ أَبَانَ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ مُسَاوِرٍ الْوَرَّاقِ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ أُمَيَّةَ عَنْ أَبِيهِ قَالَكَأَنِّي أَنْظُرُ السَّاعَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُ قَدْ أَرْخَى طَرَفَهَا بَيْنَ كَتِفَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Aban] ia berkata; telah menceritakan kepada kami [Abu Usamah] dari [Musawir] ia berkata; telah menceritakan kepada kami [Ja'far bin Amru bin Umayyah] dari [Bapaknya] ia berkata, \"Seakan aku pernah melihat Rasulullah shallallahu 'alaihi wasallam berdiri di atas mimbar dengan memakai surban berwarna hitam, beliau menurunkan ujung surbannya di antara dua pundak.\""},"4991":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ أَبِي طَلْحَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَدْخُلُ الْمَلَائِكَةُ بَيْتًا فِيهِ كَلْبٌ وَلَا صُورَةٌ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Abu Thalhah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Malaikat tidak akan masuk ke dalam rumah yang di dalamnya terdapat anjing atau gambar.\""},"4992":{"ar":"أَنْبَأَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ أَبِي طَلْحَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَدْخُلُ الْمَلَائِكَةُ بَيْتًا فِيهِ كَلْبٌ وَلَا صُورَةُ تَمَاثِيلَ","id":"Telah memberitakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] ia berkata; telah menceritakan kepada kami [Yazid] berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Abu Thalhah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Malaikat tidak akan masuk ke dalam rumah yang di dalamnya terdapat anjing atau gambar patung.\""},"4993":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ شُعَيْبٍ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ عَنْ أَبِي النَّضْرِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِأَنَّهُ دَخَلَ عَلَى أَبِي طَلْحَةَ الْأَنْصَارِيِّ يَعُودُهُ فَوَجَدَ عِنْدَهُ سَهْلَ بْنَ حُنَيْفٍ فَأَمَرَ أَبُو طَلْحَةَ إِنْسَانًا يَنْزَعُ نَمَطًا تَحْتَهُ فَقَالَ لَهُ سَهْلٌ لِمَ تَنْزِعُ قَالَ لِأَنَّ فِيهِ تَصَاوِيرُ وَقَدْ قَالَ فِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قَدْ عَلِمْتَ قَالَ أَلَمْ يَقُلْ إِلَّا مَا كَانَ رَقْمًا فِي ثَوْبٍ قَالَ بَلَى وَلَكِنَّهُ أَطْيَبُ لِنَفْسِي","id":"Telah mengabarkan kepada kami [Ali bin Syu'aib] ia berkata; telah menceritakan kepada kami [Ma'n] ia berkata; telah menceritakan kepada kami [Malik] dari [Abu An Nadlr] dari [Ubaidullah bin Abdullah], bahwasanya ia pernah masuk menemui [Abu Thalhah Al Anshari] untuk menjenguknya, dan ia mendapati di dalam rumah telah ada Sahl bin Hunaif. Abu Thalhah kemudian memerintahkan seseorang untuk menarik permadani yang ada di bawahnya, sehingga [Sahl] bertanya kepadanya, \"Kenapa harus ditarik?\" Abu Thalhah menjawab, \"Karena di dalamnya terdapat gambar, dan Rasulullah shallallahu 'alaihi wasallam telah bersabda dalam masalah tersebut sebagaimana yang engkau ketahui.\" Sahl berkata, \"Bukankah beliau mengatakan 'kecuali gambar yang ada dikain'? Abu Thalhah menjawab, \"Benar, namun hal itu lebih membuat hatiku nyaman.\""},"4994":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي بُكَيْرٌ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ خَالِدٍ عَنْ أَبِي طَلْحَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَدْخُلُ الْمَلَائِكَةُ بَيْتًا فِيهِ صُورَةٌقَالَ بُسْرٌ ثُمَّ اشْتَكَى زَيْدٌ فَعُدْنَاهُ فَإِذَا عَلَى بَابِهِ سِتْرٌ فِيهِ صُورَةٌ قُلْتُ لِعُبَيْدِ اللَّهِ الْخَوْلَانِيِّ أَلَمْ يُخْبِرْنَا زَيْدٌ عَنْ الصُّورَةِ يَوْمَ الْأَوَّلِ قَالَ قَالَ عُبَيْدُ اللَّهِ أَلَمْ تَسْمَعْهُ يَقُولُ إِلَّا رَقْمًا فِي ثَوْبٍ","id":"Telah mengabarkan kepada kami [Isa bin Hammad] ia berkata; telah menceritakan kepada kami [Al Laits] ia berkata; telah menceritakan kepadaku [Bukair] dari [Busr bin Sa'id] dari [Zaid bin Khalid] dari [Abu Thalhah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Malaikat tidak akan masuk ke dalam rumah yang di dalamnya terdapat gambar.\" Busr berkata, \"Zaid pernah mengeluh (tentang hadits ini), maka kami pun menjenguknya, dan ternyata di atas pintunya terdapat gambar. Aku lalu berkata kepada Abdullah Al Khaulani, \"Bukankah sejak hari pertama Zaid mengabarkan kepada kita?\" Busr berkata, \"Ubaidullah berkata, \"Tidakkah engkau telah mendengarnya mengatakan, 'kecuali gambar pada kain'?\""},"4995":{"ar":"حَدَّثَنَا مَسْعُودُ بْنُ جُوَيْرِيَةَ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَلِيٍّ قَالَصَنَعْتُ طَعَامًا فَدَعَوْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ فَدَخَلَ فَرَأَى سِتْرًا فِيهِ تَصَاوِيرُ فَخَرَجَ وَقَالَ إِنَّ الْمَلَائِكَةَ لَا تَدْخُلُ بَيْتًا فِيهِ تَصَاوِيرُ","id":"Telah menceritakan kepada kami [Mas'ud bin Juwairiah] ia berkata; telah menceritakan kepada kami [Waki'] dari [Hisyam] dari [Qatadah] dari [Sa'id Ibnul Musayyab] dari [Ali] ia berkata, \"Aku pernah memasak makanan, lalu aku memanggil Nabi shallallahu 'alaihi wasallam. Beliau kemudian datang dan masuk ke dalam rumah, saat melihat kain yang bergambar beliau keluar seraya bersabda: \"Sesungguhnya malaikat tidak masuk ke dalam rumah yang di dalamnya terdapat gambar.\""},"4996":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرْجَةً ثُمَّ دَخَلَ وَقَدْ عَلَّقْتُ قِرَامًا فِيهِ الْخَيْلُ أُولَاتُ الْأَجْنِحَةِ قَالَتْ فَلَمَّا رَآهُ قَالَ انْزِعِيهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] ia berkata; telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar sebentar lantas masuk kembali, sementara aku telah menggantungkan sehelai kain tipis bergambar kuda yang memiliki sayap. 'Aisyah berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam melihatnya, beliau bersabda: \"Lepaslah kain itu.\""},"4997":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ قَالَ حَدَّثَنَا عَزْرَةُ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ ابْنِ هِشَامٍ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ لَنَا سِتْرٌ فِيهِ تِمْثَالُ طَيْرٍ مُسْتَقْبِلَ الْبَيْتِ إِذَا دَخَلَ الدَّاخِلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَائِشَةُ حَوِّلِيهِ فَإِنِّي كُلَّمَا دَخَلْتُ فَرَأَيْتُهُ ذَكَرْتُ الدُّنْيَاقَالَتْ وَكَانَ لَنَا قَطِيفَةٌ لَهَا عَلَمٌ فَكُنَّا نَلْبَسُهَا فَلَمْ نَقْطَعْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Bazi'] ia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] ia berkata; telah menceritakan kepada kami [Dawud bin Abu Hind] ia berkata; telah menceritakan kepada kami [Azrah] dari [Humaid bin 'Abdurrahman] dari [Ibnu Hisyam] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata, \"Kami memiliki kain bergambar burung yang diletakkan di ruangan rumah bagian depan, sebagai penutup jika ada orang yang masuk. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai 'Aisyah, pindahkanlah kain itu. Sebab saat aku masuk dan melihatnya, aku selalu ingat dengan dunia.\" 'Aisyah berkata, \"Kami juga memiliki selembar kain bergambar, kami biasa memakainya dan tidak memotongnya.\""},"4998":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ الْقَاسِمِ يُحَدِّثُ عَنْ عَائِشَةَ قَالَتْكَانَ فِي بَيْتِي ثَوْبٌ فِيهِ تَصَاوِيرُ فَجَعَلْتُهُ إِلَى سَهْوَةٍ فِي الْبَيْتِ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي إِلَيْهِ ثُمَّ قَالَ يَا عَائِشَةُ أَخِّرِيهِ عَنِّي فَنَزَعْتُهُ فَجَعَلْتُهُ وَسَائِدَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Khalid] ia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Abdurrahman Ibnul Qasim] dari [Al Qasim] menceritakan dari ['Aisyah] ia berkata, \"Di rumah aku memiliki kain yang bergambar, aku menjadikan kain itu sebagai penutup fentilasi rumahku. Saat Rasulullah shallallahu 'alaihi wasallam shalat dan menghadap ke arahnya, beliau bersabda: 'Wahai 'Aisyah, singkirkanlah kain itu dariku.' Akhirnya kain itu aku jadikan beberapa bantal.\""},"4999":{"ar":"أَخْبَرَنَا وَهْبُ بْنُ بَيَانٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنَا عَمْرٌو قَالَ حَدَّثَنَا بُكَيْرٌ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ أَنَّ أَبَاهُ حَدَّثَهُ عَنْ عَائِشَةَأَنَّهَا نَصَبَتْ سِتْرًا فِيهِ تَصَاوِيرُ فَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَعَهُ فَقَطَعَتْهُ وِسَادَتَيْنِقَالَ رَجُلٌ فِي الْمَجْلِسِ حِينَئِذٍ يُقَالُ لَهُ رَبِيعَةُ بْنُ عَطَاءٍ أَنَا سَمِعْتُ أَبَا مُحَمَّدٍ يَعْنِي الْقَاسِمَ عَنْ عَائِشَةَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْتَفِقُ عَلَيْهِمَا","id":"Telah mengabarkan kepada kami [Wahb bin Bayan] ia berkata; telah menceritakan kepada kami [Ibnu Wahb] ia berkata; telah menceritakan kepada kami [Amru] ia berkata; telah menceritakan kepada kami [Bukair] ia berkata; telah menceritakan kepadaku ['Abdurrahman Ibnul Qasim] bahwa [Bapaknya] menceritakan kepadanya dari ['Aisyah], bahwa ia pernah memasang kain bergambar untuk menjadi satir, saat Rasulullah shallallahu 'alaihi wasallam masuk beliau langsung melepasnya, maka 'Aisyah memotong kain tersebut dan menjadikannya dua bantal. Seorang laki-laki yang bernama [Rabi'ah bin 'Atha] -waktu itu dalam sebuah majlis- berkata, \"Aku mendengar [Abu Muhammad] -yakni Al Qasim-, menceritakan dari ['Aisyah], ia berkata, \"Rasulullah shallallahu 'alaihi wasallam biasa bersandar pada kedua bantal tersebut.\""},"5000":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ سَفَرٍ وَقَدْ سَتَّرْتُ بِقِرَامٍ عَلَى سَهْوَةٍ لِي فِيهِ تَصَاوِيرُ فَنَزَعَهُ وَقَالَ أَشَدُّ النَّاسِ عَذَابًا يَوْمَ الْقِيَامَةِ الَّذِينَ يُضَاهُونَ بِخَلْقِ اللَّهِ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Abdurrahman Ibnul Qasim] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam datang dari suatu perjalanan, aku telah memasang kain satir yang bergambar di cendelaku, beliau kemudian melepas kain itu seraya bersabda: \"Sesungguhnya siksa yang paling pedih pada hari kiamat nanti adalah orang-orang yang menyerupakan ciptaan Allah.\""}};
